function normalizeTranscriptText(text) {
  return String(text || "").replace(/\s+/g, " ").trim();
}

function appendTranscriptChunk(current, chunk) {
  const existing = normalizeTranscriptText(current);
  const cleanChunk = normalizeTranscriptText(chunk);
  if (!cleanChunk) return existing;
  if (!existing) return cleanChunk;
  if (existing.includes(cleanChunk)) return existing;
  return `${existing} ${cleanChunk}`.trim();
}

function canUsePostTurnTranscription() {
  return Boolean(
    transcriptionAvailable
    && navigator.mediaDevices?.getUserMedia
    && typeof MediaRecorder !== "undefined"
  );
}

function mergePendingSpeechTranscript() {
  const merged = appendTranscriptChunk(voiceFinalTranscript || els.answerInput.value, voiceInterimTranscript);
  voiceFinalTranscript = merged;
  voiceInterimTranscript = "";
  els.answerInput.value = merged;
  liveSpeechDraftText = merged;
  renderLiveSpeechDraft();
  return merged;
}

