async function renderAnalysisTabEngineering() {
  const container = document.getElementById("analysis-tab-engineering");
  if (!container) return;
  await refreshJiraStatus();
  await refreshConfluenceStatus();
  const jiraBar = jiraStatusBarHtml();
  const confluenceBar = confluenceStatusBarHtml();
  const steps = analysisGridSteps();
  if (!steps.length) {
    container.innerHTML = jiraBar + confluenceBar + `<div class="summary-item">No workflow steps yet. Capture a process to build the engineering doc.</div>`;
    if (jiraStatus.connected) populateJiraProjects();
    return;
  }

  const wf = state.workflowGrid || {};
  const truncate = (s, n) => (s.length > n ? s.slice(0, n) : s);
  const sectionHead = (barStyle, title, meta) => `
    <div class="ds-section-head">
      <div class="ds-section-title"><span class="ds-grad-bar-v" style="${barStyle}"></span>${title}</div>
      <div class="ds-section-meta">${meta}</div>
    </div>`;

  // --- Section 1: document header -------------------------------------------
  const baseline = (wf.dataSensitivityBaseline?.value || "").trim();
  const baseSens = engSensitivity(baseline);
  const sensBadge = baseline
    ? `<span class="ds-badge" style="color:${baseSens.color};background:${baseSens.color}1a;border:1px solid ${baseSens.color}40;">${escapeHtml(baseline)}</span>`
    : "";
  const section1 = `
    <div class="ds-panel" style="padding:20px;margin-bottom:16px;">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;">
        <div>
          <div style="font-size:1.2rem;font-weight:700;color:#e8f4ff;margin-bottom:8px;">${escapeHtml(wf.workflowName || "Workflow Engineering Spec")}</div>
          <div style="font-size:0.75rem;color:#445566;">AI Engineering Specification · Auto-generated from workflow analysis</div>
        </div>
        <div style="display:flex;gap:8px;flex-wrap:wrap;">
          ${sensBadge}
          <span class="ds-badge ds-badge-dim">${steps.length} steps</span>
          <span class="ds-badge ds-badge-dim">v1.0</span>
          ${wf.stepListLocked ? `<span class="ds-badge ds-badge-teal">Locked</span>` : ""}
        </div>
      </div>
      <div class="ds-grad-bar" style="margin-top:14px;"></div>
      <div style="margin-top:12px;display:flex;gap:8px;align-items:center;">
        <div style="display:flex;gap:8px;align-items:flex-start;background:rgba(168,85,247,0.06);border:1px solid rgba(168,85,247,0.2);border-radius:8px;padding:10px 14px;">
          <span style="color:#a855f7;font-size:0.8rem;">ⓘ</span>
          <span style="font-size:0.75rem;color:#8899aa;line-height:1.5;">Fields marked "inferred by AI" were derived from document analysis and pattern matching. Confirm critical fields before implementation.</span>
        </div>
      </div>
    </div>`;

  // --- Export toolbar (preserved) -------------------------------------------
  const tealBtn = "background:#00d4b4;color:#0d1b2e;border:none;border-radius:6px;padding:8px 16px;font-weight:600;cursor:pointer;transition:opacity 0.2s;";
  const toolbar = `
    <div style="margin-bottom:16px;display:flex;flex-wrap:wrap;gap:8px;align-items:center;">
      <button class="secondary-button compact" type="button" id="exportEngineeringDocBtn">Export Engineering Doc</button>
      <button type="button" id="engineering-export-btn" style="${tealBtn}">⬇ Download DOCX</button>
      <button type="button" id="engineering-pdf-btn" style="${tealBtn}">⬇ Download PDF</button>
      <button type="button" id="exportWordEngineeringBtn" class="ds-btn-ghost" style="margin-left:auto;display:inline-flex;align-items:center;gap:6px;">
        <i data-lucide="download" style="width:14px;height:14px;"></i>Export to Word
      </button>
    </div>`;

  // --- Section 2: colour-coded gantt ----------------------------------------
  const ganttSorted = steps
    .map((step, index) => ({ step, index, priority: engStepPriority(step) }))
    .sort((a, b) => a.priority - b.priority || a.index - b.index);
  const bands = { 1: [25, 45], 2: [45, 75], 3: [75, 100] };
  const bandCounts = { 1: 0, 2: 0, 3: 0 };
  ganttSorted.forEach((r) => { bandCounts[r.priority] += 1; });
  const bandSeen = { 1: 0, 2: 0, 3: 0 };
  const ganttRows = ganttSorted.map(({ step, index, priority }) => {
    const name = stepDisplayName(step, index);
    const [lo, hi] = bands[priority];
    const count = bandCounts[priority];
    const pos = bandSeen[priority]++;
    const width = count <= 1 ? hi : lo + (pos / (count - 1)) * (hi - lo);
    // Bar colour is driven by the gated opportunity tier (width logic unchanged).
    const tier = getStepOpportunityMeta(step).tier;
    const fill = tier === "compliance"
      ? "background:#ef4444;border:2px dashed #ef4444;box-sizing:border-box;"
      : tier === "speculative"
        ? "background:#f59e0b;"
        : tier === "quick-win"
          ? "background:#00d4b4;"
          : "background:#a855f7;";
    const chip = priority === 1
      ? { label: "Days", color: "#00d4b4" }
      : priority === 2
        ? { label: "Weeks", color: "#a855f7" }
        : { label: "Months", color: "#f59e0b" };
    return `
      <div style="display:flex;align-items:center;gap:12px;margin-bottom:8px;">
        <span style="font-size:0.75rem;color:#8899aa;width:140px;flex-shrink:0;" title="${escapeHtml(name)}">${escapeHtml(truncate(name, 18))}</span>
        <div style="flex:1;height:22px;background:#09131f;border-radius:4px;overflow:hidden;position:relative;">
          <div style="height:100%;border-radius:4px;width:${width.toFixed(0)}%;${fill}">
            <span style="display:block;font-size:0.65rem;color:#0d1b2e;padding-left:8px;line-height:22px;white-space:nowrap;">${escapeHtml(truncate(name, 10))}</span>
          </div>
        </div>
        <span class="ds-chip" style="font-size:0.68rem;color:${chip.color};">${chip.label}</span>
      </div>`;
  }).join("");
  const legendSquare = (color, label) =>
    `<span style="display:flex;align-items:center;gap:6px;"><span style="width:8px;height:8px;border-radius:2px;background:${color};display:inline-block;"></span>${label}</span>`;
  const section2 = `
    <div class="ds-card" style="padding:20px;margin-bottom:16px;">
      ${sectionHead("height:14px;", "Implementation timeline", "estimated build sequence by priority")}
      <div style="display:flex;gap:16px;margin-bottom:16px;font-size:0.7rem;color:#8899aa;flex-wrap:wrap;">
        ${legendSquare("#00d4b4", "Quick win")}
        ${legendSquare("#a855f7", "Strategic")}
        ${legendSquare("#f59e0b", "Speculative")}
        ${legendSquare("#ef4444", "Compliance")}
      </div>
      ${ganttRows}
    </div>`;

  // --- Section 3: data sensitivity bars -------------------------------------
  let anyUnconfirmedSens = false;
  const sensRows = steps.map((step, index) => {
    const name = stepDisplayName(step, index);
    const value = gridCellValue(step, "dataSensitivity");
    const { level, color } = engSensitivity(value);
    if (gridCellState(step, "dataSensitivity") !== "confirmed") anyUnconfirmedSens = true;
    return `
      <div class="ds-bar-row">
        <span class="ds-bar-name" style="width:140px;" title="${escapeHtml(name)}">${escapeHtml(truncate(name, 16))}</span>
        <div class="ds-bar-track"><div class="ds-bar-fill" style="width:${((level / 4) * 100).toFixed(0)}%;background:${color};"></div></div>
        <span class="ds-bar-val" style="color:${color};">${escapeHtml(truncate(value, 10))}</span>
      </div>`;
  }).join("");
  const sensWarning = anyUnconfirmedSens
    ? `<div style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.25);border-radius:8px;padding:10px 14px;margin-top:12px;font-size:0.75rem;color:#f87171;">⚠ One or more sensitivity fields are unconfirmed. Review before connecting to production data sources.</div>`
    : "";
  const section3 = `
    <div class="ds-card" style="padding:20px;margin-bottom:16px;">
      ${sectionHead("height:14px;background:linear-gradient(180deg,#ff4fc8,#a855f7);", "Data sensitivity by step", "risk level per workflow step")}
      ${sensRows}
      ${sensWarning}
    </div>`;

  // --- Section 4: expandable step cards -------------------------------------
  const cards = steps.map((step, index) => {
    const name = stepDisplayName(step, index);
    const priority = engStepPriority(step);
    const pattern = stepPrimaryPattern(step);
    const nameProv = engProvenance(gridCellState(step, "name"));
    let dots = "";
    for (let d = 0; d < 3; d += 1) {
      dots += `<span style="color:${d < priority ? "#00d4b4" : "#2a3f5f"};">${d < priority ? "●" : "○"}</span>`;
    }
    const meta = getStepOpportunityMeta(step);
    const priorityBadge = `<span class="ds-badge ${opportunityTierBadgeClass(meta.tier)}">${escapeHtml(meta.label)}</span>`;
    const patternBadge = pattern ? `<span class="ds-badge ds-badge-teal">${escapeHtml(pattern)}</span>` : "";

    const painWarn = gridCellState(step, "painFriction") !== "confirmed"
      ? `<div style="background:rgba(245,158,11,0.08);border:1px solid rgba(245,158,11,0.2);border-radius:6px;padding:8px 12px;margin-bottom:14px;font-size:0.72rem;color:#d97706;">⚠ Pain/Friction field is unconfirmed — validate with process owner before prioritising.</div>`
      : "";

    const fieldRows = ENG_FIELD_ORDER.map((key) => {
      const value = gridCellValue(step, key);
      const stateName = gridCellState(step, key);
      if (!value && stateName === "empty") return "";
      const prov = engProvenance(stateName);
      const detail = value
        ? `<span style="color:#c8d8e8;">${escapeHtml(value)}</span>`
        : `<span style="color:#2a3f5f;">—</span>`;
      return `
        <tr>
          <td style="padding:6px 10px;border-bottom:1px solid #0f1e30;vertical-align:top;color:#556a7e;font-size:0.72rem;white-space:nowrap;">${escapeHtml(CELL_PLAIN_NAMES[key] || key)}</td>
          <td style="padding:6px 10px;border-bottom:1px solid #0f1e30;vertical-align:top;">${detail}</td>
          <td style="padding:6px 10px;border-bottom:1px solid #0f1e30;vertical-align:top;"><span class="ds-badge ${prov.badge}">${prov.label}</span></td>
        </tr>`;
    }).join("");
    const table = `
      <table style="width:100%;border-collapse:collapse;font-size:0.75rem;">
        <thead>
          <tr style="background:#09131f;">
            <th style="padding:6px 10px;color:#445566;text-align:left;border-bottom:1px solid #152236;font-weight:500;width:140px;">Field</th>
            <th style="padding:6px 10px;color:#445566;text-align:left;border-bottom:1px solid #152236;font-weight:500;">Detail</th>
            <th style="padding:6px 10px;color:#445566;text-align:left;border-bottom:1px solid #152236;font-weight:500;">Provenance</th>
          </tr>
        </thead>
        <tbody>${fieldRows}</tbody>
      </table>`;

    const systems = gridCellValue(step, "systemsTools");
    let flow = "";
    if (systems) {
      const trigger = gridCellValue(step, "trigger") || "Manual trigger";
      const output = gridCellValue(step, "output") || "Result";
      const handoffValue = gridCellValue(step, "handoff");
      flow = `
        <div class="ds-micro" style="margin-top:14px;margin-bottom:8px;">Integration flow</div>
        <div style="background:#04080f;border:1px solid #152236;border-radius:8px;padding:14px 16px;font-family:monospace;font-size:0.72rem;color:#00d4b4;overflow-x:auto;">
          <div style="color:#445566;"># Step ${index + 1}: ${escapeHtml(name)}</div>
          <div style="color:#8899aa;">[INPUT]  ${escapeHtml(trigger)}</div>
          <div style="color:#00d4b4;">→ [SYSTEM] ${escapeHtml(systems)}</div>
          <div style="color:#a855f7;">→ [OUTPUT] ${escapeHtml(output)}</div>
          ${handoffValue ? `<div style="color:#f59e0b;">→ [HANDOFF] ${escapeHtml(handoffValue)}</div>` : ""}
        </div>`;
    }

    return `
      <div class="ds-card" style="margin-bottom:10px;overflow:hidden;">
        <div data-eng-card-header style="display:flex;justify-content:space-between;align-items:center;padding:16px 20px;cursor:pointer;">
          <div style="display:flex;align-items:center;gap:10px;">
            <span class="ds-chip" style="font-size:0.68rem;color:#445566;">Step ${index + 1}</span>
            <span style="font-weight:600;color:#dde8f2;font-size:0.88rem;">${escapeHtml(name)}</span>
            ${patternBadge}
            <span title="Step name: ${nameProv.label}" style="display:inline-block;width:7px;height:7px;border-radius:50%;background:${nameProv.color};"></span>
          </div>
          <div style="display:flex;align-items:center;gap:8px;">
            <span style="font-size:0.9rem;letter-spacing:1px;">${dots}</span>
            ${priorityBadge}
            <span data-eng-chevron style="color:#445566;">▸</span>
          </div>
        </div>
        <div data-eng-card-body style="display:none;padding:0 20px 20px;">
          ${jiraStatus.connected ? `<div style="margin-bottom:12px;"><button data-jira-step="${step.id}" onclick="pushStepToJira('${step.id}')" class="ds-btn-ghost" style="font-size:12px;padding:4px 10px;">↑ Push to Jira</button></div>` : ""}
          ${painWarn}
          ${table}
          ${flow}
        </div>
      </div>`;
  }).join("");
  const section4 = `
    <div style="margin-bottom:16px;">
      ${sectionHead("height:14px;", "Step implementation details", `${steps.length} steps`)}
      ${cards}
    </div>`;

  container.innerHTML = jiraBar + confluenceBar + section1 + toolbar + section2 + section3 + section4 + businessCaseBlockForCurrentWorkflow() + scoringTransparencyBlockForCurrentWorkflow();
  if (jiraStatus.connected) populateJiraProjects();

  container.querySelector("#exportEngineeringDocBtn")?.addEventListener("click", exportEngineeringDoc);
  container.querySelector("#exportWordEngineeringBtn")?.addEventListener("click", () => exportWorkflowWord("engineering"));
  const engineeringExportBtn = container.querySelector("#engineering-export-btn");
  engineeringExportBtn?.addEventListener("click", handleEngineeringExport);
  container.querySelector("#engineering-pdf-btn")?.addEventListener("click", handleEngineeringPdfExport);
  syncEngineeringExportButton(engineeringExportBtn);
  wireScoringCards(container);

  // Expandable cards: toggle the body div between display none/block.
  container.querySelectorAll("[data-eng-card-header]").forEach((header) => {
    header.addEventListener("click", () => {
      const body = header.parentElement.querySelector("[data-eng-card-body]");
      const chevron = header.querySelector("[data-eng-chevron]");
      if (!body) return;
      const open = body.style.display !== "none";
      body.style.display = open ? "none" : "block";
      if (chevron) chevron.textContent = open ? "▸" : "▾";
    });
  });
}

// Mirrors syncRecipeExportButton: keep the button clickable whenever the
// Engineering Doc tab is shown (it only renders once steps exist), so the click
// always reaches handleEngineeringExport, which guards the empty case.
function syncEngineeringExportButton(btn) {
  if (!btn) return;
  btn.disabled = false;
  btn.style.opacity = "1";
  btn.style.cursor = "pointer";
}

async function handleEngineeringExport() {
  const btn = document.getElementById("engineering-export-btn");
  if (!btn) return;

  const notify = (message) => (typeof toast === "function" ? toast(message) : alert(message));
  const workflowName = analysisWorkflowName() || "Workflow";
  const steps = analysisGridSteps().map((step, index) => ({
    name: stepDisplayName(step, index),
    systemsTools: gridCellValue(step, "systemsTools"),
    dataProcessing: gridCellValue(step, "dataProcessing"),
    rulesDecisionLogic: gridCellValue(step, "rulesDecisionLogic"),
    exceptionBranching: gridCellValue(step, "exceptionBranching"),
    regulatoryContext: gridCellValue(step, "regulatoryContext"),
    humanCheckpoint: gridCellValue(step, "humanCheckpoint")
  }));

  const hasContent = steps.some((step) =>
    step.systemsTools.trim() || step.dataProcessing.trim() || step.rulesDecisionLogic.trim() ||
    step.exceptionBranching.trim() || step.regulatoryContext.trim() || step.humanCheckpoint.trim()
  );
  if (!hasContent) {
    notify("Capture engineering details (systems, data processing, rules, etc.) before exporting.");
    return;
  }

  btn.textContent = "Preparing…";
  btn.disabled = true;
  btn.style.opacity = "0.4";
  btn.style.cursor = "not-allowed";
  try {
    const response = await fetch("/api/engineering-doc-export", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ workflowName, steps })
    });
    if (!response.ok) {
      let message = `Engineering doc export failed (${response.status}).`;
      try {
        const data = await response.json();
        if (data?.error) message = data.error;
      } catch (_) { /* non-JSON error body */ }
      throw new Error(message);
    }

    const blob = await response.blob();
    const safeName = workflowName.replace(/[^a-z0-9]+/gi, "-").replace(/^-+|-+$/g, "").toLowerCase() || "workflow";
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    anchor.href = url;
    anchor.download = `${safeName}-engineering-doc.docx`;
    anchor.style.display = "none";
    document.body.appendChild(anchor);
    anchor.click();
    anchor.remove();
    URL.revokeObjectURL(url);
  } catch (error) {
    notify(error?.message || "Engineering doc export failed.");
  } finally {
    btn.textContent = "⬇ Download DOCX";
    syncEngineeringExportButton(btn);
  }
}

function exportEngineeringDoc() {
  const steps = analysisGridSteps();
  const workflowName = analysisWorkflowName() || "workflow";
  const lines = [`=== ENGINEERING DOC: ${workflowName} ===`, ""];

  lines.push("## Implementation Gantt");
  steps.forEach((step, index) => {
    const pattern = stepPrimaryPattern(step) || "n/a";
    const complexity = patternComplexity(stepPrimaryPattern(step));
    const endWeek = ganttEndWeek(complexity);
    lines.push(`- Step ${index + 1}: ${stepDisplayName(step, index)} | Pattern: ${pattern} | Complexity: ${complexity} | Phase 1 -> end week ${endWeek}`);
  });
  lines.push("");

  lines.push("## Data Sensitivity Profile");
  steps.forEach((step, index) => {
    const level = sensitivityLevel(step).toUpperCase();
    const raw = gridCellValue(step, "dataSensitivity") || "Not captured";
    lines.push(`- Step ${index + 1}: ${stepDisplayName(step, index)} | ${level} | ${raw}`);
  });
  lines.push("");

  lines.push("## Open Gaps");
  const gapRows = [];
  steps.forEach((step, index) => {
    stepGapCells(step).forEach((key) => {
      gapRows.push({ index, name: stepDisplayName(step, index), key, label: CELL_PLAIN_NAMES[key] || key, state: gridCellState(step, key) });
    });
  });
  gapRows.sort((a, b) => a.index - b.index || GRID_CELL_KEYS.indexOf(a.key) - GRID_CELL_KEYS.indexOf(b.key));
  if (!gapRows.length) {
    lines.push("All cells addressed — ready to generate outputs.");
  } else {
    gapRows.forEach((g) => lines.push(`- ${g.name} | ${g.label} | ${g.state}`));
  }
  lines.push("");

  const safeName = workflowName.replace(/[^a-z0-9]+/gi, "-").replace(/^-+|-+$/g, "").toLowerCase() || "workflow";
  downloadTextFile(`${safeName}-engineering-doc.txt`, lines.join("\n"));
}

// --- TAB 5: Pattern Handoff ---------------------------------------------------

const HANDOFF_TEAL_BUTTON =
  "background:#00d4b4;color:#0d1b2e;border:none;border-radius:6px;padding:8px 16px;font-weight:600;cursor:pointer;transition:opacity 0.2s;";

// First comma/newline/semicolon-separated value from a cell — the "primary".
function handoffPrimaryValue(step, key) {
  const raw = gridCellValue(step, key);
  if (!raw) return "";
  return raw.split(/[,;\n]/)[0].trim();
}

// Confidence (0-1) of a step's primary AI pattern entry, or null when unset.
function handoffStepConfidence(step) {
  const value = step?.cells?.aiPattern?.value;
  if (!Array.isArray(value) || !value.length) return null;
  const num = Number(value[0]?.confidence);
  return Number.isFinite(num) ? num : null;
}

function handoffConfidenceColor(confidence) {
  if (confidence === null || confidence < 0.4) return "#5b7186"; // grey
  if (confidence >= 0.8) return "#00d4b4"; // teal
  return "#f59e0b"; // amber (0.4 - 0.79)
}

// --- Dump mode: "Tell me anything" free-text extraction -----------------------
// A textarea + "Extract and Fill" that turns a raw description into structured
// steps. State is module-level (no schema change): the typed text, the pending
// extraction result, and a loading flag.
let dumpText = "";
let dumpExtractResult = null; // { workflowName, steps:[...] } awaiting Apply/Discard, or null
let dumpExtracting = false;

function renderDumpMode() {
  const container = document.getElementById("dumpModePanel");
  if (!container) return;

  let confirmHtml = "";
  if (dumpExtractResult) {
    const steps = Array.isArray(dumpExtractResult.steps) ? dumpExtractResult.steps : [];
    const split = (value) => String(value || "").split(/[,;\n]/).map((part) => part.trim()).filter(Boolean);
    const personas = new Set();
    const systems = new Set();
    steps.forEach((step) => {
      split(step.personaActors).forEach((p) => personas.add(p.toLowerCase()));
      split(step.systemsTools).forEach((s) => systems.add(s.toLowerCase()));
    });
    const plural = (n) => (n === 1 ? "" : "s");
    confirmHtml = `
      <div style="margin-top:12px;background:#0d1b2a;border:1px solid #1a2a3a;border-radius:8px;padding:12px;">
        <p style="font-size:13px;color:#dde8f5;margin:0 0 10px;">Found: ${steps.length} step${plural(steps.length)}, ${personas.size} persona${plural(personas.size)}, ${systems.size} system${plural(systems.size)} — Apply to grid?</p>
        <div style="display:flex;gap:8px;">
          <button type="button" id="dumpApplyBtn" style="background:#00d4b4;color:#0d1b2e;border:none;border-radius:6px;padding:8px 16px;font-weight:600;font-size:13px;cursor:pointer;">Apply</button>
          <button type="button" id="dumpDiscardBtn" style="background:#4b5563;color:#dde8f5;border:none;border-radius:6px;padding:8px 16px;font-weight:600;font-size:13px;cursor:pointer;">Discard</button>
        </div>
      </div>`;
  }

  container.innerHTML = `
    <div style="background:#0d2137;border:1px solid #1c3b57;border-radius:10px;padding:16px;margin-bottom:14px;">
      <label for="dumpModeTextarea" style="display:block;font-size:13px;font-weight:600;color:#dde8f5;margin-bottom:8px;">Describe this process in your own words</label>
      <textarea id="dumpModeTextarea" rows="4" placeholder="Paste meeting notes, a rough description, an email — anything. I'll extract what's relevant." style="width:100%;box-sizing:border-box;background:#06101d;border:1px solid #1a2a3a;border-radius:6px;color:#dde8f5;font-size:13px;padding:10px;resize:vertical;">${escapeHtml(dumpText)}</textarea>
      <button type="button" id="dumpExtractBtn" style="margin-top:10px;background:#00d4b4;color:#0d1b2e;border:none;border-radius:6px;padding:8px 16px;font-weight:600;font-size:13px;cursor:pointer;transition:opacity 0.2s;">${dumpExtracting ? "Extracting…" : "Extract and Fill"}</button>
      ${confirmHtml}
    </div>`;

  const textarea = container.querySelector("#dumpModeTextarea");
  textarea?.addEventListener("input", () => { dumpText = textarea.value; });
  container.querySelector("#dumpExtractBtn")?.addEventListener("click", handleDumpExtract);
  container.querySelector("#dumpApplyBtn")?.addEventListener("click", handleDumpApply);
  container.querySelector("#dumpDiscardBtn")?.addEventListener("click", handleDumpDiscard);
}

// Called from render(): don't clobber the textarea while the user is typing.
function renderDiscoveryDumpMode() {
  const container = document.getElementById("dumpModePanel");
  if (!container) return;
  const active = document.activeElement;
  if (active && container.contains(active) && active.tagName === "TEXTAREA") return;
  renderDumpMode();
}

async function handleDumpExtract() {
  if (dumpExtracting) return; // soft guard; button is never hard-disabled
  if (!dumpText.trim()) {
    toast("Type or paste a description first.");
    return;
  }
  dumpExtracting = true;
  renderDumpMode();
  try {
    const response = await fetch("/api/dump-extract", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ text: dumpText, grid: state.workflowGrid })
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(data?.error || `Request failed (${response.status}).`);
    const extracted = data.extracted && typeof data.extracted === "object" ? data.extracted : null;
    if (!extracted || !Array.isArray(extracted.steps) || !extracted.steps.length) {
      dumpExtractResult = null;
      toast("Couldn't find any workflow steps in that text.");
    } else {
      dumpExtractResult = extracted;
    }
  } catch (error) {
    toast(error?.message || "Extraction failed.");
  } finally {
    dumpExtracting = false;
    renderDumpMode();
  }
}

// Merge extracted steps into the grid: match existing steps by name, add new
// ones otherwise, and never overwrite a cell that is already "confirmed".
function handleDumpApply() {
  const result = dumpExtractResult;
  if (!result) return;
  if (!state.workflowGrid || typeof state.workflowGrid !== "object") state.workflowGrid = newWorkflowGrid();
  const grid = state.workflowGrid;
  if (!Array.isArray(grid.steps)) grid.steps = [];

  if (typeof result.workflowName === "string" && result.workflowName.trim() && !String(grid.workflowName || "").trim()) {
    grid.workflowName = result.workflowName.trim();
  }

  const norm = (value) => String(value || "").trim().toLowerCase();
  const fields = ["personaActors", "systemsTools", "painFriction", "output"];

  (Array.isArray(result.steps) ? result.steps : []).forEach((extracted) => {
    const exName = String(extracted.name || "").trim();
    if (!exName) return;
    let step = grid.steps.find((item) => norm(item?.cells?.name?.value) === norm(exName));
    if (!step) {
      step = newGridStep();
      patchField(step, "layer1", "name", exName, "doc-extracted", 0.6);
      grid.steps.push(step);
    }
    fields.forEach((key) => {
      const value = String(extracted[key] || "").trim();
      if (!value) return;
      // doc-extracted + refresh: a re-paste replaces earlier same/lower
      // provenance values, but patchField still refuses to overwrite anything
      // the user stated (rank precedence — the old "never overwrite confirmed").
      patchField(step, null, key, value, "doc-extracted", 0.6, { refresh: true });
    });
  });

  dumpExtractResult = null;
  dumpText = "";
  persistState();
  render();
  toast("Workflow updated from your description");
}

function handleDumpDiscard() {
  dumpExtractResult = null;
  renderDumpMode();
}

// --- AI Understanding ("AI Mirror") -------------------------------------------
// Live plain-English summary of the current workflow grid. Summary + loading are
// module-level (survive re-renders within the page session; no state schema
// change). The Refresh button re-calls /api/ai-mirror.
let aiMirrorSummary = "";
let aiMirrorLoading = false;

function renderAiMirror() {
  const container = document.getElementById("aiMirrorPanel");
  if (!container) return;
  const body = aiMirrorLoading
    ? `<p style="font-size:13px;color:#5b7186;font-style:italic;margin:0;">Analysing workflow…</p>`
    : aiMirrorSummary
      ? `<p style="font-size:13px;color:#dde8f5;line-height:1.55;margin:0;">${escapeHtml(aiMirrorSummary)}</p>`
      : `<p style="font-size:13px;color:#7a93b4;margin:0;">Click Refresh to generate a plain-English summary of the workflow so far.</p>`;
  container.innerHTML = `
    <div style="background:#0d2137;border:1px solid #1c3b57;border-radius:10px;padding:16px;margin-bottom:14px;">
      <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;">
        <h3 style="font-size:13px;font-weight:700;color:#dde8f5;margin:0;text-transform:uppercase;letter-spacing:0.04em;flex:1;">AI Understanding</h3>
        <button type="button" id="aiMirrorRefreshBtn" style="background:#00d4b4;color:#0d1b2e;border:none;border-radius:6px;padding:6px 14px;font-weight:600;font-size:13px;cursor:pointer;transition:opacity 0.2s;">Refresh</button>
      </div>
      ${body}
    </div>`;
  container.querySelector("#aiMirrorRefreshBtn")?.addEventListener("click", handleAiMirrorRefresh);
}

async function handleAiMirrorRefresh() {
  if (aiMirrorLoading) return; // soft re-entrancy guard (button is never hard-disabled)
  const steps = analysisGridSteps();
  if (!steps.length) {
    toast("Capture some workflow steps before generating a summary.");
    return;
  }
  aiMirrorLoading = true;
  renderAiMirror();
  try {
    const response = await fetch("/api/ai-mirror", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ grid: state.workflowGrid })
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(data?.error || `Request failed (${response.status}).`);
    aiMirrorSummary = typeof data.summary === "string" ? data.summary : "";
  } catch (error) {
    toast(error?.message || "Could not generate the summary.");
  } finally {
    aiMirrorLoading = false;
    renderAiMirror();
  }
}

// Pattern interview, hosted on the Discovery page as three stacked blocks.
function renderPatternInterview(container) {
  if (!container) return;
  state.handoffAnswers = state.handoffAnswers || {};
  state.handoffQuestions = Array.isArray(state.handoffQuestions) ? state.handoffQuestions : [];
  state.handoffPatterns = Array.isArray(state.handoffPatterns) ? state.handoffPatterns : [];
  state.handoffOverrides = state.handoffOverrides || {};

  const steps = analysisGridSteps();
  if (!steps.length) {
    container.innerHTML = `<div class="summary-item">No workflow steps yet. Capture a process in the interview to prepare the pattern interview.</div>`;
    return;
  }

  const sectionTitleStyle = "font-size:13px;font-weight:700;color:#dde8f5;margin:0 0 10px;text-transform:uppercase;letter-spacing:0.04em;";
  const blockStyle = "background:#0d2137;border:1px solid #1c3b57;border-radius:10px;padding:16px;margin-bottom:14px;";

  // BLOCK 1 — read-only step pattern overview (no API).
  const zone1Cards = steps.map((step, index) => {
    const name = stepDisplayName(step, index);
    const persona = handoffPrimaryValue(step, "personaActors") || "—";
    const system = handoffPrimaryValue(step, "systemsTools") || "—";
    const pattern = gridCellValue(step, "aiPattern") || "Unset";
    const confidence = handoffStepConfidence(step);
    const color = handoffConfidenceColor(confidence);
    const confidenceLabel = confidence === null ? "No score" : `${Math.round(confidence * 100)}%`;
    return `
      <div style="background:#0d1b2a;border:1px solid #1a2a3a;border-left:3px solid ${color};border-radius:8px;padding:12px;">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;">
          <span style="font-size:10px;color:#5b7186;letter-spacing:0.06em;">${String(index + 1).padStart(2, "0")}</span>
          <strong style="font-size:14px;color:#dde8f5;flex:1;">${escapeHtml(name)}</strong>
          <span class="sensitivity-badge" style="background:${color}22;color:${color};">${escapeHtml(confidenceLabel)}</span>
        </div>
        <div style="display:grid;grid-template-columns:auto 1fr;gap:4px 10px;font-size:12px;">
          <span style="color:#5b7186;">Persona</span><span style="color:#9fb3c8;">${escapeHtml(persona)}</span>
          <span style="color:#5b7186;">System</span><span style="color:#9fb3c8;">${escapeHtml(system)}</span>
          <span style="color:#5b7186;">AI pattern</span><span style="color:${color};font-weight:600;">${escapeHtml(pattern)}</span>
        </div>
      </div>`;
  }).join("");

  // BLOCK 2 — AI-generated questions with answer textareas.
  const questionCards = state.handoffQuestions.length
    ? state.handoffQuestions.map((q) => `
        <div style="background:#0d1b2a;border:1px solid #1a2a3a;border-radius:8px;padding:12px;margin-bottom:8px;">
          <div style="font-size:10px;color:#5b7186;letter-spacing:0.06em;margin-bottom:4px;">${escapeHtml(q.stepName || "Workflow")}</div>
          <p style="font-size:13px;color:#dde8f5;margin:0 0 8px;">${escapeHtml(q.text || "")}</p>
          <textarea data-handoff-answer="${escapeHtml(q.id)}" rows="2" placeholder="Answer in plain operational language..." style="width:100%;box-sizing:border-box;background:#06101d;border:1px solid #1a2a3a;border-radius:6px;color:#dde8f5;font-size:13px;padding:8px;resize:vertical;">${escapeHtml(state.handoffAnswers[q.id] || "")}</textarea>
        </div>`).join("")
    : `<p style="font-size:12px;color:#7a93b4;">No questions yet. Click "Surface Key Questions" to generate them.</p>`;

  // PR 27: the standalone "AI Pattern Analysis" block (with the per-step
  // override inputs) is removed — pattern info now shows inline on step cards.
  container.innerHTML = `
    <section style="${blockStyle}">
      <h3 style="${sectionTitleStyle}">Step Pattern Overview</h3>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:10px;">${zone1Cards}</div>
    </section>
    <section style="${blockStyle}margin-bottom:0;">
      <h3 style="${sectionTitleStyle}">Key Questions</h3>
      <button type="button" id="handoffQuestionsBtn" style="${HANDOFF_TEAL_BUTTON}margin-bottom:12px;">Surface Key Questions</button>
      <div>${questionCards}</div>
    </section>`;

  container.querySelector("#handoffQuestionsBtn")?.addEventListener("click", handleHandoffQuestions);
  container.querySelectorAll("[data-handoff-answer]").forEach((textarea) => {
    textarea.addEventListener("input", () => {
      state.handoffAnswers[textarea.dataset.handoffAnswer] = textarea.value;
    });
    textarea.addEventListener("change", persistState);
  });
  refreshIcons();
}

function patternInterviewContainer() {
  return document.getElementById("discoveryPatternInterview");
}

// Called from render(): re-render the Discovery pattern interview, but never
// clobber an answer/override field the user is currently editing.
function renderDiscoveryPatternInterview() {
  const container = patternInterviewContainer();
  if (!container) return;
  const active = document.activeElement;
  if (active && container.contains(active) && (active.tagName === "TEXTAREA" || active.tagName === "INPUT")) return;
  renderPatternInterview(container);
}

// Force a refresh (used by the handlers after questions/analysis/confirm change).
function rerenderPatternInterview() {
  renderPatternInterview(patternInterviewContainer());
}

async function handleHandoffQuestions() {
  const btn = document.getElementById("handoffQuestionsBtn");
  const steps = analysisGridSteps();
  if (!steps.length) {
    toast("Capture a workflow before surfacing questions.");
    return;
  }
  if (btn) {
    btn.textContent = "Working…";
    btn.style.opacity = "0.4";
    btn.style.cursor = "not-allowed";
  }
  try {
    const response = await fetch("/api/pattern-handoff", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ mode: "questions", workflowName: analysisWorkflowName() || "Workflow", steps })
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(data?.error || `Request failed (${response.status}).`);
    state.handoffQuestions = Array.isArray(data.questions) ? data.questions : [];
    persistState();
    rerenderPatternInterview();
  } catch (error) {
    toast(error?.message || "Could not surface questions.");
  } finally {
    if (btn) {
      btn.textContent = "Surface Key Questions";
      btn.style.opacity = "1";
      btn.style.cursor = "pointer";
    }
  }
}

async function handleHandoffAnalyse() {
  const btn = document.getElementById("handoffAnalyseBtn");
  const steps = analysisGridSteps();
  if (!steps.length) {
    toast("Capture a workflow before generating analysis.");
    return;
  }
  if (btn) {
    btn.textContent = "Working…";
    btn.style.opacity = "0.4";
    btn.style.cursor = "not-allowed";
  }
  try {
    const response = await fetch("/api/pattern-handoff", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        mode: "analyse",
        workflowName: analysisWorkflowName() || "Workflow",
        steps,
        answers: state.handoffAnswers || {}
      })
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(data?.error || `Request failed (${response.status}).`);
    state.handoffPatterns = Array.isArray(data.patterns) ? data.patterns : [];
    persistState();
    rerenderPatternInterview();
  } catch (error) {
    toast(error?.message || "Could not generate analysis.");
  } finally {
    if (btn) {
      btn.textContent = "Generate AI Analysis";
      btn.style.opacity = "1";
      btn.style.cursor = "pointer";
    }
  }
}

// Write confirmed patterns back into the workflow grid. For each analysed
// pattern, the user's override (state.handoffOverrides[stepId]) wins over the
// AI suggestion. The aiPattern cell stores an ARRAY of { pattern, confidence }
// entries (see newAiPatternEntry / GRID_CELL_KEYS) — writing a bare string
// would break stepPatternList/handoffStepConfidence and leave Zone 1 grey — so
// we set value to a single confirmed entry at confidence 1.
function handleHandoffConfirm() {
  const patterns = Array.isArray(state.handoffPatterns) ? state.handoffPatterns : [];
  if (!patterns.length) {
    toast("Generate AI analysis before confirming patterns.");
    return;
  }
  state.handoffOverrides = state.handoffOverrides || {};
  const steps = Array.isArray(state.workflowGrid?.steps) ? state.workflowGrid.steps : [];
  patterns.forEach((entry) => {
    const stepId = entry.stepId;
    const step = steps.find((item) => item.id === stepId);
    if (!step?.cells?.aiPattern) return;
    const override = (state.handoffOverrides[stepId] || "").trim();
    const patternValue = override || (entry.pattern || "").trim();
    if (!patternValue) return;
    // User confirmed (or overrode) the pattern — user-stated provenance.
    patchField(step, "meta", "aiPattern", [{ pattern: patternValue, confidence: 1 }], "user-stated", 1);
  });
  persistState();
  // Re-render the blocks so Block 1's confidence dots flip to teal immediately.
  rerenderPatternInterview();
  toast("Patterns confirmed and saved to grid");
}

// --- PDF export (Recipe Book + Engineering Doc) -------------------------------
// Mirrors the DOCX export handlers: post the same { workflowName, steps } data
// to /api/pdf-export, which builds the PDF programmatically with pdfkit (no
// browser/Chromium). The server picks the layout from `kind`.

function pdfSafeName(workflowName) {
  return (workflowName || "workflow").replace(/[^a-z0-9]+/gi, "-").replace(/^-+|-+$/g, "").toLowerCase() || "workflow";
}

async function downloadPdf(payload, filename, btn) {
  const notify = (message) => (typeof toast === "function" ? toast(message) : alert(message));
  if (btn) {
    btn.textContent = "Preparing…";
    btn.disabled = true;
    btn.style.opacity = "0.4";
    btn.style.cursor = "not-allowed";
  }
  try {
    const response = await fetch("/api/pdf-export", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });
    if (!response.ok) {
      let message = `PDF export failed (${response.status}).`;
      try {
        const data = await response.json();
        if (data?.error) message = data.error;
      } catch (_) { /* non-JSON error body */ }
      throw new Error(message);
    }
    const blob = await response.blob();
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    anchor.href = url;
    anchor.download = filename;
    anchor.style.display = "none";
    document.body.appendChild(anchor);
    anchor.click();
    anchor.remove();
    URL.revokeObjectURL(url);
  } catch (error) {
    notify(error?.message || "PDF export failed.");
  } finally {
    if (btn) {
      btn.textContent = "⬇ Download PDF";
      btn.disabled = false;
      btn.style.opacity = "1";
      btn.style.cursor = "pointer";
    }
  }
}

async function handleRecipePdfExport() {
  const notify = (message) => (typeof toast === "function" ? toast(message) : alert(message));
  const workflowName = analysisWorkflowName() || "Workflow";
  const steps = analysisGridSteps().map((step, index) => ({
    name: stepDisplayName(step, index),
    aiPattern: stepPrimaryPattern(step),
    prompt: state.recipeCache?.[step.id] || ""
  }));
  if (!steps.some((step) => step.prompt.trim() || step.aiPattern.trim())) {
    notify("Generate at least one recipe prompt before exporting.");
    return;
  }
  await downloadPdf(
    { kind: "recipe", workflowName, steps },
    `${pdfSafeName(workflowName)}-recipe-book.pdf`,
    document.getElementById("recipe-pdf-btn")
  );
}

async function handleEngineeringPdfExport() {
  const notify = (message) => (typeof toast === "function" ? toast(message) : alert(message));
  const workflowName = analysisWorkflowName() || "Workflow";
  const steps = analysisGridSteps().map((step, index) => ({
    name: stepDisplayName(step, index),
    systemsTools: gridCellValue(step, "systemsTools"),
    dataProcessing: gridCellValue(step, "dataProcessing"),
    rulesDecisionLogic: gridCellValue(step, "rulesDecisionLogic"),
    exceptionBranching: gridCellValue(step, "exceptionBranching"),
    regulatoryContext: gridCellValue(step, "regulatoryContext"),
    humanCheckpoint: gridCellValue(step, "humanCheckpoint")
  }));
  const hasContent = steps.some((step) =>
    step.systemsTools.trim() || step.dataProcessing.trim() || step.rulesDecisionLogic.trim() ||
    step.exceptionBranching.trim() || step.regulatoryContext.trim() || step.humanCheckpoint.trim()
  );
  if (!hasContent) {
    notify("Capture engineering details (systems, data processing, rules, etc.) before exporting.");
    return;
  }
  await downloadPdf(
    { kind: "engineering", workflowName, steps },
    `${pdfSafeName(workflowName)}-engineering-doc.pdf`,
    document.getElementById("engineering-pdf-btn")
  );
}

function renderAppMode() {
  const docMode = state.appMode === "document"; // PR 17: document mode is a placeholder until PR 18
  const active = state.appMode === "analysis" ? "analysis" : "interview";
  document.body.dataset.appMode = active;
  document.querySelectorAll(".mode-tab").forEach((button) => {
    const selected = button.dataset.appMode === active;
    button.classList.toggle("active", selected);
    button.setAttribute("aria-selected", selected ? "true" : "false");
  });
  document.querySelectorAll("[data-app-panel]").forEach((panel) => {
    // In document mode every built-in panel is hidden; the placeholder shows instead.
    panel.hidden = docMode ? true : panel.dataset.appPanel !== active;
  });
  renderDocumentModePlaceholder(docMode);
}

// PR 18: document-mode upload panel. Lazily created as a sibling of the app
// panels and toggled rather than rebuilt. Default content is (re)rendered on
// every show EXCEPT while an upload is in flight, so the loading state is never
// clobbered by an incidental re-render. Inline hex only; no new CSS variables
// (the spinner reuses the existing `spin` keyframes).
let docUploadInProgress = false;

function renderDocumentModePlaceholder(show) {
  let el = document.getElementById("documentModePlaceholder");
  if (!show) {
    if (el) el.hidden = true;
    return;
  }
  if (!el) {
    const anchor = document.querySelector('[data-app-panel="interview"]')
      || document.querySelector('[data-app-panel="analysis"]');
    if (!anchor || !anchor.parentElement) return;
    el = document.createElement("div");
    el.id = "documentModePlaceholder";
    anchor.parentElement.appendChild(el);
  }
  // Order matters: a live upload keeps the loading state; pending multi-workflow
  // detection shows the selection panel; otherwise the default upload zone.
  if (docUploadInProgress) {
    // leave the loading state in place
  } else if (Array.isArray(state.pendingWorkflows) && state.pendingWorkflows.length > 1) {
    renderWorkflowSelectionPanel(el);
  } else {
    renderDocUploadDefault(el);
  }
  el.hidden = false;
}

function renderDocUploadDefault(el) {
  el.innerHTML = `
    <div style="width:100%;min-height:400px;display:flex;align-items:center;justify-content:center;">
      <div id="docUploadZone" style="border:2px dashed #1e3350;border-radius:12px;padding:48px;text-align:center;background:#0d1b2e;max-width:480px;cursor:pointer;">
        <div style="font-size:48px;line-height:1;">📄</div>
        <div style="color:#ffffff;font-size:18px;font-weight:600;margin:16px 0 8px;">Upload a document</div>
        <div style="color:#8899aa;font-size:14px;">Word, PDF, or screenshot — AI will map it to the 3-layer workflow grid</div>
        <div style="color:#445566;font-size:12px;margin-top:8px;">Supports .docx, .pdf, .png, .jpg, .xlsx</div>
        <input type="file" id="docUploadInput" accept=".pdf,.docx,.xlsx,.png,.jpg,.jpeg,.webp" style="display:none;" />
      </div>
    </div>`;
  wireDocUploadZone(el);
}

function renderDocUploadLoading(el) {
  el.innerHTML = `
    <div style="width:100%;min-height:400px;display:flex;align-items:center;justify-content:center;">
      <div style="border:2px dashed #1e3350;border-radius:12px;padding:48px;text-align:center;background:#0d1b2e;max-width:480px;">
        <div style="display:flex;align-items:center;justify-content:center;gap:10px;color:#8899aa;font-size:14px;">
          <span style="width:16px;height:16px;border:2px solid #1a2a3a;border-top-color:#00d4b4;border-radius:50%;display:inline-block;animation:spin 1.1s linear infinite;"></span>
          Reading and extracting workflow…
        </div>
      </div>
    </div>`;
}

function wireDocUploadZone(el) {
  const zone = el.querySelector("#docUploadZone");
  const input = el.querySelector("#docUploadInput");
  if (!zone || !input) return;
  // Guard against the input's own bubbled click re-triggering the picker.
  zone.addEventListener("click", (event) => {
    if (event.target === input) return;
    input.click();
  });
  input.addEventListener("change", (event) => {
    const file = event.target.files?.[0];
    event.target.value = ""; // allow re-selecting the same filename later
    if (file) handleDocumentUpload(file, el);
  });
  zone.addEventListener("dragover", (event) => {
    event.preventDefault();
    zone.style.borderColor = "#00d4b4";
  });
  zone.addEventListener("dragleave", () => {
    zone.style.borderColor = "#1e3350";
  });
  zone.addEventListener("drop", (event) => {
    event.preventDefault();
    zone.style.borderColor = "#1e3350";
    const file = event.dataTransfer?.files?.[0];
    if (file) handleDocumentUpload(file, el);
  });
}

// Uploads the chosen file to the existing /api/extract-document endpoint. A
// single detected workflow is mapped into state.workflowGrid via
// buildWorkflowGridFromExtraction (the shared EXTRACTION_CELL_KEY_MAP mapper)
// and lands on the Analysis Studio grid tab; multiple workflows open the
// selection panel. Soft-fails back to the upload zone.
async function handleDocumentUpload(file, el) {
  // Phase 10a: large documents are sent to OpenAI — confirm before uploading.
  // (Sensitivity isn't known pre-analysis, so size is the available signal.)
  if (file && file.size > 500 * 1024) {
    showSensitivityConfirmModal(() => runDocumentUpload(file, el), {
      heading: "Large document",
      body: "This is a large document. It will be sent to OpenAI for analysis. Only proceed if this is permitted under your firm's data handling policy."
    });
    return;
  }
  return runDocumentUpload(file, el);
}

async function runDocumentUpload(file, el) {
  docUploadInProgress = true;
  toast("Analysing document…");
  renderDocUploadLoading(el);

  let payload;
  try {
    const formData = new FormData();
    formData.append("file", file);
    const response = await fetch("/api/extract-document", { method: "POST", body: formData });
    payload = await response.json();
  } catch {
    payload = { success: false, error: "Document extraction failed — try again" };
  }

  if (!payload || payload.success !== true) {
    docUploadInProgress = false;
    renderDocUploadDefault(el);
    toast((payload && payload.error) || "Document extraction failed — try again");
    return;
  }

  // PR 19: the endpoint now returns a workflows[] array. More than one means the
  // document describes several distinct processes — let the user pick which to map.
  const workflows = Array.isArray(payload.workflows) ? payload.workflows : [];
  if (workflows.length > 1) {
    docUploadInProgress = false;
    state.pendingWorkflows = workflows;
    state.extractionWarning = typeof payload.extractionWarning === "string" ? payload.extractionWarning : "";
    renderWorkflowSelectionPanel(el);
    return;
  }

  // Single workflow (or a legacy single-shape response) → map and land directly.
  const single = workflows[0] || payload.grid;
  state.workflowGrid = buildWorkflowGridFromExtraction(single);
  state.extractionWarning = typeof payload.extractionWarning === "string" ? payload.extractionWarning : "";
  if (payload.extractionWarning) toast(payload.extractionWarning);
  toast("Workflow extracted — review your grid");
  // Land on the Analysis Studio Workflow Grid tab so the populated 3-layer grid
  // is immediately visible (analysisActiveTab drives that tab, not activeWorkbenchTab).
  state.appMode = "analysis";
  state.analysisActiveTab = "grid";
  docUploadInProgress = false;
  persistState();
  render();
}

// PR 19: tier colours for the 5 Finance/MC workflow families (inline hex only).
const WORKFLOW_FAMILY_COLOR = {
  "Regulatory & Compliance": "#ff4fc8",
  "Finance & Reporting": "#00d4b4",
  "Capital Markets & Trading Ops": "#f59e0b",
  "Project & Delivery": "#a855f7",
  "Data & Analytics": "#00d4b4"
};

// Replaces the upload zone with a one-card-per-workflow selection panel when a
// document yields more than one workflow. Rendered inside #documentModePlaceholder
// so an incidental re-render keeps it (see renderDocumentModePlaceholder).
function renderWorkflowSelectionPanel(el) {
  el = el || document.getElementById("documentModePlaceholder");
  if (!el) return;
  const workflows = Array.isArray(state.pendingWorkflows) ? state.pendingWorkflows : [];
  const cards = workflows.map((wf, index) => {
    const family = String(wf?.workflowFamily || "").trim();
    const color = WORKFLOW_FAMILY_COLOR[family] || "#8899aa";
    const stepCount = Array.isArray(wf?.steps) ? wf.steps.length : 0;
    const name = wf?.workflowName || "Untitled workflow";
    return `
      <div data-workflow-card="${index}" role="button" tabindex="0" style="background:#162438;border:1px solid #1e3350;border-radius:8px;padding:16px;cursor:pointer;transition:border-color 0.15s ease;margin-bottom:12px;">
        <div style="color:${color};font-size:12px;font-weight:600;letter-spacing:0.04em;margin-bottom:6px;">${escapeHtml(family || "Workflow")}</div>
        <div style="color:#ffffff;font-size:14px;font-weight:700;">${escapeHtml(name)}</div>
        <div style="color:#8899aa;font-size:12px;margin-top:4px;">${stepCount} step${stepCount === 1 ? "" : "s"}</div>
      </div>`;
  }).join("");
  el.innerHTML = `
    <div style="width:100%;min-height:400px;display:flex;align-items:center;justify-content:center;padding:24px;box-sizing:border-box;">
      <div style="max-width:520px;width:100%;">
        <div style="color:#ffffff;font-size:16px;font-weight:600;margin-bottom:6px;">Multiple workflows detected</div>
        <div style="color:#8899aa;font-size:13px;margin-bottom:16px;">This document contains ${workflows.length} workflows. Select one to map.</div>
        ${cards}
      </div>
    </div>`;
  el.querySelectorAll("[data-workflow-card]").forEach((card) => {
    card.addEventListener("mouseenter", () => { card.style.borderColor = "#00d4b4"; });
    card.addEventListener("mouseleave", () => { card.style.borderColor = "#1e3350"; });
    card.addEventListener("click", () => selectPendingWorkflow(Number(card.dataset.workflowCard)));
  });
}

function selectPendingWorkflow(index) {
  const workflows = Array.isArray(state.pendingWorkflows) ? state.pendingWorkflows : [];
  const wf = workflows[index];
  if (!wf) return;
  state.workflowGrid = buildWorkflowGridFromExtraction(wf);
  state.pendingWorkflows = null;
  state.appMode = "analysis";
  state.analysisActiveTab = "grid";
  persistState();
  render();
  toast("Workflow loaded — review your grid");
}

function renderHeaderContext() {
  if (!els.headerWorkflowName) return;
  els.headerWorkflowName.textContent = state.fields.workflowName || "Workflow TBD";
  els.headerWorkflowCategory.textContent = categoryLabel();
  els.headerValidationStatus.textContent = state.fields.ideaValidationStatus === "unknown" ? "Needs discovery" : state.fields.ideaValidationStatus;
  els.headerBuildReadiness.textContent = state.fields.buildReadiness === "unknown" ? "Build readiness TBD" : `Build ${state.fields.buildReadiness}`;
  els.headerCommercialContext.textContent = state.fields.commercialContext === "unknown" ? "Commercial TBD" : state.fields.commercialContext;
  els.headerValidationStatus.className = `context-chip ${state.fields.ideaValidationStatus === "Validated" ? "success" : state.fields.ideaValidationStatus === "Not a good AI candidate" || state.fields.buildReadiness === "Blocked" ? "risk" : "warn"}`;
  els.headerBuildReadiness.className = `context-chip ${state.fields.buildReadiness === "High" ? "success" : state.fields.buildReadiness === "Blocked" || state.fields.buildReadiness === "Low" ? "risk" : "warn"}`;
}

function renderBlueprintInspector() {
  if (!els.blueprintInspector) return;
  const productBrief = deriveProductBrief();
  const engineeringBrief = deriveEngineeringBrief();
  const businessBrief = deriveBusinessBrief();
  const solutionBuildRecipe = deriveSolutionBuildRecipe(productBrief, engineeringBrief, businessBrief);
  const solutionBuildSpec = deriveSolutionBuildSpec(solutionBuildRecipe);
  const enterpriseConnectorContracts = deriveEnterpriseConnectorContracts(solutionBuildSpec);
  const combinedHandoff = deriveCombinedHandoff(productBrief, engineeringBrief, businessBrief, solutionBuildRecipe);
  const governance = governanceRoute();
  const lanes = readinessInspectorLanes(productBrief, engineeringBrief, businessBrief, governance);
  const blockerItems = readinessPriorityBlockers(productBrief, engineeringBrief, businessBrief);
  const routing = questionRoutingGroups().slice(0, 5);
  const primaryBlocker = blockerItems[0];
  const weakestLane = lanes.filter((lane) => !lane.advisory).sort((a, b) => a.score - b.score)[0] || lanes[0];
  const docs = [
    readinessDocumentCard("Product PDR", "package-check", productBrief.readiness, productBrief.readinessLabel, productBrief.sections, "Scope, users, value, metrics, MVP, and recommendation."),
    readinessDocumentCard("Engineering Brief", "wrench", engineeringBrief.readiness, engineeringBrief.readinessLabel, engineeringBrief.sections, "Technical inputs, platform fit, data, requirements, architecture, and controls."),
    readinessDocumentCard("Business Value", "badge-dollar-sign", businessBrief.readiness, businessBrief.readinessLabel, businessBrief.sections, "Baseline, value levers, measurement plan, impact estimate, and portfolio decision."),
    readinessDocumentCard("Governance Inputs", "shield-check", governanceReadinessScore(), governance.path, governanceReadinessSections(), "Basic data, environment, human review, and evidence inputs for later governance review.")
  ];
  els.blueprintInspector.innerHTML = `
    <div class="readiness-inspector-hero inspector-command-hero">
      <div>
        <p class="eyebrow">Readiness Inspector</p>
        <h2>${escapeHtml(combinedHandoff.readiness)}% handoff readiness</h2>
        <p>${escapeHtml(readinessNextActionSummary(productBrief, engineeringBrief, businessBrief, governance))}</p>
      </div>
      <span>${escapeHtml(combinedHandoff.readinessLabel)}</span>
    </div>
    <section class="readiness-command-board">
      <article class="readiness-next-action-card">
        <div>
          <p class="eyebrow">Highest-Impact Next Question</p>
          <h3>${escapeHtml(primaryBlocker?.question || "Review outputs with Product, Engineering, and Business owners.")}</h3>
        </div>
        <p>${escapeHtml(primaryBlocker ? `${primaryBlocker.route} blocker: ${primaryBlocker.label}. ${primaryBlocker.detail}` : `${weakestLane.label} is currently the lowest Product/Engineering/Business readiness lane.`)}</p>
      </article>
      <div class="readiness-lane-bars">
        ${lanes.map(readinessLaneBarCard).join("")}
      </div>
    </section>
    <section class="readiness-workbench-grid">
      <div class="readiness-priority-panel">
        <div class="readiness-panel-head">
          <p class="eyebrow">Completion Blockers</p>
          <h3>What to fix before handoff</h3>
        </div>
        <div class="readiness-blocker-stack">
          ${blockerItems.slice(0, 6).map((item, index) => readinessPriorityBlockerCard(item, index)).join("")}
        </div>
      </div>
      <div class="readiness-routing-panel-compact">
        <div class="readiness-panel-head">
          <p class="eyebrow">Owner Routing</p>
          <h3>Who should answer next</h3>
        </div>
        <div class="readiness-route-stack">
          ${routing.map(readinessRouteQueueCard).join("")}
        </div>
      </div>
    </section>
    <div class="readiness-document-grid readiness-document-grid-compact">
      ${docs.join("")}
    </div>
  `;
  refreshIcons();
}

function readinessInspectorLanes(productBrief, engineeringBrief, businessBrief, governance) {
  const checklist = handoffChecklistSections();
  const byTitle = (title) => checklist.find((section) => section.title === title) || { items: [] };
  const lane = ({ title, label, icon, score, status, detail, advisory = false }) => {
    const section = byTitle(title);
    const openItems = (section.items || []).filter((item) => item.status !== "captured");
    return {
      label,
      icon,
      score: Math.max(4, Math.min(100, Number(score) || 0)),
      status,
      detail,
      advisory,
      captured: (section.items || []).filter((item) => item.status === "captured").length,
      total: (section.items || []).length,
      blockers: openItems.slice(0, 3)
    };
  };
  return [
    lane({
      title: "Product",
      label: "Product PDR",
      icon: "package-check",
      score: productBrief.readiness,
      status: productBrief.readinessLabel,
      detail: "Problem, users, MVP slice, metrics, assumptions, and product recommendation."
    }),
    lane({
      title: "Engineering",
      label: "Engineering Brief",
      icon: "wrench",
      score: engineeringBrief.readiness,
      status: engineeringBrief.readinessLabel,
      detail: "Process, systems, data, access mode, output contract, architecture, and controls."
    }),
    lane({
      title: "Business",
      label: "Business Value",
      icon: "badge-dollar-sign",
      score: businessBrief.readiness,
      status: businessBrief.readinessLabel,
      detail: "Baseline volume, value levers, KPI proof, capacity, reuse, and business recommendation."
    }),
    lane({
      title: "Governance Inputs",
      label: "Governance Inputs",
      icon: "shield-check",
      score: governanceReadinessScore(),
      status: "Later review input",
      detail: `Basic inputs only for post-build review. Current path: ${governance.path}.`,
      advisory: true
    })
  ];
}

function readinessLaneBarCard(lane) {
  const blockers = lane.blockers.length ? lane.blockers : [{ label: "No major blocker detected.", detail: "Review with lane owner before package handoff." }];
  return `
    <article class="readiness-lane-card ${lane.advisory ? "advisory" : ""}" style="--lane-score:${lane.score}%;">
      <div class="readiness-lane-head">
        <span><i data-lucide="${escapeHtml(lane.icon)}"></i></span>
        <div>
          <strong>${escapeHtml(lane.label)}</strong>
          <small>${escapeHtml(lane.status)} · ${lane.captured}/${lane.total || 1} checklist signals</small>
        </div>
        <b>${lane.score}%</b>
      </div>
      <p>${escapeHtml(lane.detail)}</p>
      <div class="readiness-meter lane-meter"><i></i></div>
      <div class="readiness-lane-gaps">
        ${blockers.map((item) => `<em>${escapeHtml(item.label)}</em>`).join("")}
      </div>
    </article>
  `;
}

function readinessPriorityBlockers(productBrief, engineeringBrief, businessBrief) {
  const documentSections = {
    Product: productBrief.sections,
    Engineering: engineeringBrief.sections,
    Business: businessBrief.sections,
    "Governance Inputs": governanceReadinessSections()
  };
  const checklistBlockers = rankedHandoffChecklistGaps("auto").map((gap) => ({
    route: gap.section,
    label: gap.item.label,
    detail: gap.item.detail,
    status: gap.item.status,
    question: questionForHandoffChecklistGap(gap)
  }));
  const documentBlockers = Object.entries(documentSections).flatMap(([route, sections]) =>
    sections
      .flatMap((section) => section.fields || [])
      .filter((field) => field.status === "Missing")
      .slice(0, 3)
      .map((field) => ({
        route,
        label: field.label,
        detail: `Missing from ${route} output.`,
        status: "missing",
        question: `${route}: what should we capture for ${field.label.toLowerCase()}?`
      }))
  );
  const completionQuestions = topCompletionQuestions(6).map((question) => ({
    route: "Next Question",
    label: "Completion question",
    detail: "Generated from current intake gaps.",
    status: "review",
    question
  }));
  const seen = new Set();
  const isGovItem = (item) => item.route === "Governance Inputs" || readinessQuestionIsGovernanceInput(item.question);
  return [
    ...checklistBlockers.filter((item) => !isGovItem(item)),
    ...completionQuestions.filter((item) => !isGovItem(item)),
    ...documentBlockers.filter((item) => !isGovItem(item)),
    ...checklistBlockers.filter(isGovItem),
    ...completionQuestions.filter(isGovItem),
    ...documentBlockers.filter(isGovItem)
  ]
    .filter((item) => {
      const key = `${item.route}|${item.label}|${item.question}`;
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    })
    .slice(0, 10);
}

function readinessQuestionIsGovernanceInput(question) {
  return /governance|msa|client data|data boundary|deployment environment|privacy|model risk|cyber|legal|approved sandbox|client vdi|client tenant/i.test(String(question || ""));
}

function readinessPriorityBlockerCard(item, index) {
  return `
    <article class="readiness-blocker-card status-${escapeHtml(item.status || "review")}">
      <span>${String(index + 1).padStart(2, "0")}</span>
      <div>
        <strong>${escapeHtml(item.route)} · ${escapeHtml(item.label)}</strong>
        <p>${escapeHtml(item.question)}</p>
        <small>${escapeHtml(item.detail)}</small>
      </div>
    </article>
  `;
}

function readinessRouteQueueCard(group) {
  return `
    <article class="readiness-route-queue-card">
      <div>
        <span><i data-lucide="${escapeHtml(group.icon)}"></i></span>
        <div>
          <strong>${escapeHtml(group.route)}</strong>
          <small>${escapeHtml(group.owner)}</small>
        </div>
        <b>${group.questions.length}</b>
      </div>
      <p>${escapeHtml(group.questions[0] || "No major blocker detected.")}</p>
    </article>
  `;
}

function readinessDocumentCard(title, icon, readiness, label, sections = [], detail = "") {
  const fields = sections.flatMap((section) => section.fields || []);
  const counts = {
    captured: fields.filter((field) => field.status === "Captured").length,
    inferred: fields.filter((field) => field.status === "Inferred").length,
    missing: fields.filter((field) => field.status === "Missing").length
  };
  const missing = fields
    .filter((field) => field.status === "Missing")
    .slice(0, 3)
    .map((field) => field.label);
  return `
    <article class="readiness-document-card" style="--doc-score:${Math.max(4, Math.min(100, Number(readiness) || 0))}%;">
      <div class="readiness-document-head">
        <span><i data-lucide="${escapeHtml(icon)}"></i></span>
        <div>
          <strong>${escapeHtml(title)}</strong>
          <small>${escapeHtml(label || templateReadinessLabel(readiness))}</small>
        </div>
        <b>${readiness}%</b>
      </div>
      <p>${escapeHtml(detail)}</p>
      <div class="readiness-meter document-meter"><i></i></div>
      <div class="readiness-document-counts">
        <span>${counts.captured} captured</span>
        <span>${counts.inferred} inferred</span>
        <span>${counts.missing} missing</span>
      </div>
      <div class="readiness-missing-list">
        ${(missing.length ? missing : ["No major template blocker detected."]).map((item) => `<em>${escapeHtml(item)}</em>`).join("")}
      </div>
    </article>
  `;
}

function governanceReadinessScore() {
  const signals = [
    state.fields.msaBoundary !== "Unknown",
    inferOverallDataSensitivity() !== "Unknown",
    state.fields.deploymentEnvironment !== "Unknown",
    governanceRoute().path !== "Multiple / TBD",
    state.decisions.length || state.steps.some((step) => isCapturedValue(step.decision)),
    state.steps.length || (state.evidenceArtifacts || []).length
  ];
  return Math.round((signals.filter(Boolean).length / signals.length) * 100);
}

function isWorkshopPrepOpportunity() {
  const text = [
    state.fields.workflowCategory,
    state.fields.workflowName,
    state.fields.submittedWorkflowTask,
    state.fields.workshopType,
    state.fields.projectPhase
  ].join(" ");
  return /pre-delivery|workshop prep|workshop preparation|facilitation pack/i.test(text);
}

function workshopUseCaseContext() {
  if (!isWorkshopPrepOpportunity()) return "";
  return "Strategy-origin, cross-practice pattern. Treat as a lower-technical-density benchmark that can apply before client work or during client delivery when teams prepare workshops, working sessions, or reusable client materials.";
}

function governanceReadinessSections() {
  const governance = governanceRoute();
  return [
    templateSection("Governance Input Checklist", [
      templateField("MSA boundary", state.fields.msaBoundary, "Confirm whether internal-only, sanitized, client-approved, client tenant, or MSA review applies.", { ownerRoute: "Governance Inputs", treatment: "Later review input", supplementLater: state.fields.msaBoundary === "Unknown" }),
      templateField("Data sensitivity", inferOverallDataSensitivity(), "Confirm data classification and allowed AI/tooling boundary.", { ownerRoute: "Governance Inputs", treatment: "Later review input", supplementLater: inferOverallDataSensitivity() === "Unknown" }),
      templateField("Deployment environment", state.fields.deploymentEnvironment, "Confirm company internal, client VDI/tenant, approved sandbox, or other environment.", { ownerRoute: "Governance Inputs", treatment: "Later review input", supplementLater: state.fields.deploymentEnvironment === "Unknown" }),
      templateField("Governance path", governance.path, "Confirm whether standard AI review, privacy, cyber, legal/MSA, client approval, or multiple routes apply.", { ownerRoute: "Governance Inputs", treatment: "Later review input", supplementLater: governance.path === "Multiple / TBD" }),
      templateField("Human review", humanReviewGateSummary(), "Name the accountable reviewer and approval point before pilot use.", { inferred: true, ownerRoute: "Governance Inputs", treatment: "Confirm before pilot" }),
      templateField("Evidence trail", governanceEvidenceNeedSummary(), "", { inferred: true, ownerRoute: "Governance Inputs", treatment: "Later review input", supplementLater: true }),
      templateField("Retention/logging input", retentionLoggingSummary(), "", { inferred: true, ownerRoute: "Governance Inputs", treatment: "Confirm with platform/security", supplementLater: true })
    ])
  ];
}

function readinessRouteCard(group) {
  return `
    <article class="readiness-routing-card">
      <div>
        <p class="eyebrow">${escapeHtml(group.route)}</p>
        <h3>${group.questions.length} open</h3>
      </div>
      <p>${escapeHtml(group.questions[0] || "No major blocker detected.")}</p>
    </article>
  `;
}

function readinessNextActionSummary(productBrief, engineeringBrief, businessBrief, governance) {
  const weakest = [
    ["Product", productBrief.readiness],
    ["Engineering", engineeringBrief.readiness],
    ["Business", businessBrief.readiness]
  ].sort((a, b) => a[1] - b[1])[0];
  return `${weakest[0]} is the lowest-readiness lane at ${weakest[1]}%. Route the next follow-up there before treating the packet as Product, Engineering, and Business ready. Governance is tracked as a post-build review input, not as a primary preparedness driver. Current governance path: ${governance.path}.`;
}

function inspectorBlock(title, icon, items) {
  const safeItems = items.length ? items : ["Nothing captured yet."];
  return `
    <section class="inspector-block">
      <h3><i data-lucide="${icon}"></i>${escapeHtml(title)}</h3>
      <ul>${safeItems.map((item) => `<li>${escapeHtml(item)}</li>`).join("")}</ul>
    </section>
  `;
}

function inspectorKnownFacts() {
  return [
    state.fields.submittedIdea ? `Submitted idea: ${truncateUi(state.fields.submittedIdea, 92)}` : "",
    state.fields.workflowCategory !== "unknown" ? `Category: ${state.fields.workflowCategory}` : "",
    state.fields.practice !== "unknown" ? `Practice: ${state.fields.practice}` : "",
    state.fields.workflowName ? `Workflow: ${state.fields.workflowName}` : "",
    state.fields.startPoint || state.fields.endPoint ? `Boundary: ${state.fields.startPoint || "Start TBD"} -> ${state.fields.endPoint || "End TBD"}` : "",
    state.steps.length ? `${state.steps.length} workflow step${state.steps.length === 1 ? "" : "s"} captured` : "",
    `Lifecycle: ${lifecycleCurrentStage()}`,
    `Gate A signal: ${gateAssessment().decision}`,
    state.fields.commercialContext !== "unknown" ? `Commercial context: ${state.fields.commercialContext}` : "",
    state.fields.commercialValuePath !== "unknown" ? `Value path: ${state.fields.commercialValuePath}` : ""
  ].filter(Boolean).slice(0, 7);
}

function inspectorUnknowns() {
  const items = [];
  if (state.fields.workflowCategory === "unknown") items.push("Workflow category is not selected.");
  if (state.fields.practice === "unknown") items.push("Practice / domain is not classified.");
  if (state.fields.ideaValidationStatus === "unknown") items.push("Submitted idea has not been validated.");
  if (!state.fields.workflowName) items.push("Workflow name is not confirmed.");
  if (!state.fields.startPoint || !state.fields.endPoint) items.push("Start/end boundary is incomplete.");
  if (!state.steps.length) items.push("A-Z process steps are not captured.");
  const gap = firstMatrixGap();
  if (gap) items.push(`Step detail missing: ${gap.stepName} -> ${gap.label}.`);
  if (state.fields.workflowCategory === "Pre-delivery / workshop prep" && !state.fields.expectedWorkshopOutput) {
    items.push("Workshop output / ready-to-run definition is missing.");
  }
  if (state.fields.commercialContext === "unknown" || state.fields.commercialValuePath === "unknown") {
    items.push("Commercial context or value path can be supplemented later by Finance, Ops, Account Reporting, PMO, or Product.");
  }
  if (state.fields.dataSensitivity === "Unknown" || state.fields.msaBoundary === "Unknown" || state.fields.deploymentEnvironment === "Unknown") {
    items.push("Data sensitivity, MSA boundary, or deployment environment is still TBD.");
  }
  return items.slice(0, 7);
}

function inspectorRiskFlags() {
  const governance = governanceRoute();
  return [
    dataSignalLabel(),
    riskSignalLabel(),
    governance.primaryFlag,
    governance.path ? `Post-build review path: ${governance.path}` : "",
    governance.environment ? `Deployment target: ${governance.environment}` : "",
    state.fields.humanJudgmentArea ? `Human judgment: ${truncateUi(state.fields.humanJudgmentArea, 90)}` : "",
    state.steps.some((step) => isCapturedValue(step.dataSensitivity)) ? "Step-level data sensitivity exists." : "",
    state.steps.some((step) => isCapturedValue(step.accessMode)) ? "Access/source modes captured for at least one step." : "",
    (state.evidenceArtifacts || []).length ? `${state.evidenceArtifacts.length} optional evidence add-on${state.evidenceArtifacts.length === 1 ? "" : "s"} uploaded.` : "No optional evidence uploaded."
  ].filter(Boolean).slice(0, 6);
}

function renderLifecyclePanel() {
  if (!els.lifecycleStagePanel && !els.gateScorePanel && !els.governanceRoutePanel) return;
  const currentStage = lifecycleCurrentStage();
  const suggestedStage = suggestedLifecycleStage();
  const currentIndex = lifecycleIndex(currentStage);
  const gate = gateAssessment();
  const governance = governanceRoute();

  if (els.lifecycleStagePanel) {
    els.lifecycleStagePanel.innerHTML = `
      <div class="lifecycle-hero">
        <div>
          <p class="eyebrow">AI Infusion Lifecycle</p>
          <h3>${escapeHtml(currentStage)}</h3>
          <p>${escapeHtml(currentLifecycleReference()?.purpose || "Use the lifecycle to orient this intake from idea through value realization.")}</p>
        </div>
        <span>${Math.max(1, currentIndex + 1)} / ${lifecycleReference.length}</span>
      </div>
      <div class="lifecycle-timeline">
        ${lifecycleReference.map((item, index) => lifecycleStagePill(item, index, currentIndex)).join("")}
      </div>
      <div class="lifecycle-current-output">
        <div>
          <span>Primary owner</span>
          <strong>${escapeHtml(currentLifecycleReference()?.owner || state.fields.stageOwner || "TBD")}</strong>
        </div>
        <div>
          <span>Required output</span>
          <strong>${escapeHtml(currentLifecycleReference()?.output || "TBD")}</strong>
        </div>
        <div>
          <span>Suggested next stage</span>
          <strong>${escapeHtml(suggestedStage)}</strong>
        </div>
      </div>
    `;
  }

  if (els.gateScorePanel) {
    els.gateScorePanel.innerHTML = `
      <div class="gate-hero" style="--gate-score:${gate.overall};">
        <div>
          <p class="eyebrow">Gate A Signal</p>
          <h3>${escapeHtml(gate.decision)}</h3>
          <p>${escapeHtml(gate.rationale)}</p>
        </div>
        <div class="gate-score-orb"><span>${gate.overall}</span><small>/100</small></div>
      </div>
      <div class="gate-score-grid">
        ${gate.dimensions.map((item) => gateDimensionCard(item)).join("")}
      </div>
      <div class="gate-recommendation">
        <strong>${escapeHtml(gate.action)}</strong>
        <p>${escapeHtml(gate.nextQuestion)}</p>
      </div>
    `;
  }

  if (els.governanceRoutePanel) {
    els.governanceRoutePanel.innerHTML = `
      <div class="governance-route">
        <div class="route-card accent-cyan">
          <span>MSA boundary</span>
          <strong>${escapeHtml(governance.boundary)}</strong>
          <p>${escapeHtml(governance.boundaryNote)}</p>
        </div>
        <div class="route-card accent-pink">
          <span>Data sensitivity</span>
          <strong>${escapeHtml(governance.sensitivity)}</strong>
          <p>${escapeHtml(governance.dataNote)}</p>
        </div>
        <div class="route-card accent-blue">
          <span>Deployment</span>
          <strong>${escapeHtml(governance.environment)}</strong>
          <p>${escapeHtml(governance.environmentNote)}</p>
        </div>
        <div class="route-card accent-violet">
          <span>Post-build review path</span>
          <strong>${escapeHtml(governance.path)}</strong>
          <p>${escapeHtml(governance.pathNote)}</p>
        </div>
      </div>
      <div class="route-flags">
        ${governance.flags.map((flag) => `<span>${escapeHtml(flag)}</span>`).join("") || "<span>No governance flags yet</span>"}
      </div>
    `;
  }
}

function lifecycleCurrentStage() {
  if (referenceLists.lifecycleStages.includes(state.fields.lifecycleStage)) return state.fields.lifecycleStage;
  return suggestedLifecycleStage();
}

function currentLifecycleReference() {
  const current = lifecycleCurrentStage();
  return lifecycleReference.find((item) => item.stage === current) || lifecycleReference[1];
}

function lifecycleIndex(stage) {
  return Math.max(0, lifecycleReference.findIndex((item) => item.stage === stage));
}

function suggestedLifecycleStage() {
  if (!state.steps.length || state.fields.ideaValidationStatus === "unknown") return "2 - Problem Deep Dive and Intake";
  if (!isCapturedValue(state.fields.valueHypothesis) && !isCapturedValue(state.fields.biggestPain) && !isCapturedValue(state.fields.businessOutcome)) {
    return "3 - Business Validation";
  }
  const gate = gateAssessment({ skipSuggestedStage: true });
  if (gate.overall >= 72 && state.fields.solutionHypothesis && state.fields.mvpScope) return "Gate A - Prioritization / Build Gate";
  if (gate.overall >= 58 || isCapturedValue(state.fields.solutionHypothesis)) return "4 - AI Fit Assessment & Solution Designing";
  return "3 - Business Validation";
}

function lifecycleStagePill(item, index, currentIndex) {
  const status = index < currentIndex ? "done" : index === currentIndex ? "current" : index === currentIndex + 1 ? "next" : "future";
  return `
    <button class="lifecycle-stage-pill ${status}" type="button" title="${escapeHtml(item.purpose)}">
      <span>${String(index + 1).padStart(2, "0")}</span>
      <strong>${escapeHtml(item.stage.replace(/^\d+\s-\s|^Gate\s/, ""))}</strong>
    </button>
  `;
}

function gateAssessment() {
  const dimensions = gateDimensionRows();
  const totalWeight = dimensions.reduce((sum, item) => sum + item.weight, 0);
  const overall = Math.round(dimensions.reduce((sum, item) => sum + item.score * item.weight, 0) / totalWeight);
  const decision = gateDecisionSuggestion(overall);
  const firstGap = dimensions.find((item) => item.score < 60 && !item.advisory);
  return {
    overall,
    decision,
    dimensions,
    rationale: gateDecisionRationale(overall, decision),
    action: firstGap ? `Improve ${firstGap.label.toLowerCase()} before build prioritization.` : "Ready to discuss prioritization with Product and Engineering.",
    nextQuestion: firstGap?.question || topCompletionQuestions(1)[0] || "What should Product or Engineering validate next?"
  };
}

function gateDimensionRows() {
  const fieldConfidence = scoreByLevel(state.fields.fieldConfidence, { Low: 35, Medium: 65, High: 90 }, 55);
  const governance = governanceRoute();
  const matrixCompleteness = state.steps.length && !firstMatrixGap() ? 85 : state.steps.length ? 58 : 20;
  const valueScore = scoreBySignals(
    `${state.fields.valueHypothesis} ${state.fields.businessImpact} ${state.fields.biggestPain} ${state.fields.qualityImpactHypothesis} ${state.fields.reusePotential} ${state.fields.submittedExpectedImpact}`,
    [state.fields.valueHypothesis, state.fields.businessImpact, state.fields.biggestPain, state.fields.qualityImpactHypothesis, state.fields.reusePotential, state.fields.submittedExpectedImpact],
    18
  );
  const aiScore = scoreBySignals(
    `${state.fields.solutionHypothesis} ${state.fields.mvpScope} ${state.fields.toolFitRecommendation} ${state.fields.solutionType} ${state.fields.automationPotential}`,
    [state.fields.solutionHypothesis, state.fields.mvpScope, state.fields.toolFitRecommendation, state.fields.solutionType !== "unknown" ? state.fields.solutionType : "", state.fields.automationPotential !== "Not a candidate" ? state.fields.automationPotential : ""],
    16
  );
  const governanceScore = Math.max(25, 100 - governance.flags.length * 14 - (governance.path === "Multiple / TBD" ? 12 : 0) - (governance.sensitivity === "Unknown" ? 10 : 0));
  const changeScore = scoreByLevel(state.fields.changeImpact, { Low: 88, Medium: 70, High: 52, "Role redesign likely": 36, unknown: 55 }, 55);
  const reuseScore = scoreBySignals(
    `${state.fields.reusePotential} ${state.fields.qualityBenefits} ${state.fields.workflowCategory} ${state.fields.capacityTeamCompositionImpact}`,
    [state.fields.reusePotential, state.fields.qualityBenefits, state.fields.capacityTeamCompositionImpact],
    22
  );
  return [
    {
      label: "Intake clarity",
      score: Math.round((scoreBySignals(`${state.fields.workflowName} ${state.fields.workflowCategory} ${state.fields.currentStateSummary}`, [state.fields.workflowName, state.fields.workflowCategory !== "unknown"], 25) + matrixCompleteness) / 2),
      weight: 1.35,
      detail: "Workflow boundary, step skeleton, and process matrix coverage.",
      question: topCompletionQuestions(1)[0] || "Can you confirm the A-Z workflow and missing step details?"
    },
    {
      label: "Directional value",
      score: valueScore,
      weight: 0.55,
      detail: "Pain, quality, reuse, outcome, and rough value signal. Finance/Ops metrics can supplement later.",
      question: "What pain, delay, rework, quality issue, or reuse opportunity makes this worth exploring?"
    },
    {
      label: "AI/tool fit",
      score: aiScore,
      weight: 1.05,
      detail: "Fit for ChatGPT Enterprise, Copilot, agents, and MVP scope.",
      question: "Which part of the current workflow should ChatGPT, Copilot, or an agent handle first?"
    },
    {
      label: "Governance inputs",
      score: governanceScore,
      weight: 0.35,
      advisory: true,
      detail: "Basic MSA boundary, data sensitivity, environment, and review path for post-build governance.",
      question: "What minimum data boundary and deployment environment should be captured for the later governance review?"
    },
    {
      label: "Confidence",
      score: Math.round((fieldConfidence + evidenceConfidenceScore()) / 2),
      weight: 0.85,
      detail: "Evidence quality, playback confirmation, and interview confidence.",
      question: "What would confirm that we captured the workflow accurately?"
    },
    {
      label: "Reuse and change",
      score: Math.round((reuseScore + changeScore) / 2),
      weight: 0.9,
      detail: "Reuse potential, enablement impact, and adoption/change effort.",
      question: "Could this workflow pattern be reused across other practices or engagements?"
    }
  ];
}

function gateDecisionSuggestion(overall) {
  if (state.fields.automationPotential === "Not a candidate" || state.fields.ideaValidationStatus === "Not a good AI candidate") return "Reject";
  if (!state.steps.length || state.fields.workflowCategory === "unknown") return "More discovery";
  if (overall >= 82) return "Build now";
  if (overall >= 68) return "Backlog";
  if (overall >= 52) return "More discovery";
  return "Hold";
}

function gateDecisionRationale(overall, decision) {
  if (decision === "Build now") return "The intake has enough current-state evidence, value signal, and AI/tool fit to discuss an MVP build, with governance inputs captured for later review.";
  if (decision === "Backlog") return "The opportunity appears promising, but Product and Engineering still need sharper scope or validation before active build.";
  if (decision === "More discovery") return "The idea is still missing handoff-critical details such as workflow steps, value path, basic data boundaries, or decision owners.";
  if (decision === "Reject") return "The evidence suggests this is not a strong AI candidate or automation potential is low for now.";
  return "There are unresolved intake, access, or evidence issues that should be cleared before prioritization.";
}

function gateDimensionCard(item) {
  return `
    <article class="gate-dimension-card" style="--gate-dim-score:${item.score};">
      <div>
        <strong>${escapeHtml(item.label)}</strong>
        <span>${item.score}%</span>
      </div>
      <p>${escapeHtml(item.detail)}</p>
      <div class="gate-meter"><i></i></div>
    </article>
  `;
}

function governanceRoute() {
  const sensitivity = inferOverallDataSensitivity();
  const boundary = state.fields.msaBoundary || "Unknown";
  const environment = state.fields.deploymentEnvironment || "Unknown";
  const path = inferGovernancePath(sensitivity, boundary, environment);
  const flags = [];
  if (["PII", "MNPI", "PCI", "PHI", "Regulated model/data"].includes(sensitivity)) flags.push(`Regulated or sensitive data: ${sensitivity}`);
  if (["Client Confidential", "Confidential"].includes(sensitivity)) flags.push(`Sensitive artifacts: ${sensitivity}`);
  if (/client data access|msa review|Unknown/i.test(boundary)) flags.push(`Boundary needs confirmation: ${boundary}`);
  if (/Client|On-prem|restricted|Unknown/i.test(environment)) flags.push(`Deployment environment needs review: ${environment}`);
  if (/Legal|MSA|Client approval|Multiple|Data privacy|Model risk|Cybersecurity/i.test(path)) flags.push(`${path} likely`);
  return {
    sensitivity,
    boundary,
    environment,
    path,
    flags: [...new Set(flags)].slice(0, 6),
    primaryFlag: flags[0] || "No major governance flag inferred yet.",
    boundaryNote: boundary === "Unknown" ? "Ask where the solution can run and whether client data access is allowed." : "Use this to decide if a client approval or MSA path is needed.",
    dataNote: sensitivity === "Unknown" ? "Capture data categories and sensitivity for each major step." : "Use the highest-sensitivity data category when routing governance.",
    environmentNote: environment === "Unknown" ? "Confirm whether this stays internal, runs in client tenant/VDI, or needs a sandbox." : "Deployment choice affects authentication, storage, and audit design.",
    pathNote: path === "Multiple / TBD" ? "Route cannot be finalized until data and environment are clearer." : "Use this as the likely later enterprise review lane."
  };
}

function inferOverallDataSensitivity() {
  const values = [
    state.fields.dataSensitivity,
    ...state.steps.map((step) => step.dataSensitivity),
    ...state.data.map((item) => item.sensitivity)
  ].filter(isCapturedValue);
  if (!values.length) return "Unknown";
  const ranks = {
    Unknown: 0,
    Public: 1,
    Internal: 2,
    Confidential: 3,
    "Client Confidential": 4,
    PII: 5,
    MNPI: 6,
    PCI: 6,
    PHI: 6,
    "Regulated model/data": 7
  };
  return values
    .map((value) => normalizeReferenceValue(value, referenceLists.dataSensitivity))
    .sort((a, b) => (ranks[b] || 0) - (ranks[a] || 0))[0] || "Unknown";
}

function inferGovernancePath(sensitivity, boundary, environment) {
  if (state.fields.governancePath && state.fields.governancePath !== "Multiple / TBD") return state.fields.governancePath;
  if (/Requires client data access|Likely MSA/i.test(boundary)) return "Legal/MSA review";
  if (/Client/.test(environment)) return "Client approval required";
  if (["PII", "MNPI", "PCI", "PHI"].includes(sensitivity)) return "Data privacy review";
  if (sensitivity === "Regulated model/data") return "Model risk review";
  if (/On-prem|restricted/i.test(environment)) return "Cybersecurity review";
  if (sensitivity === "Unknown" || /Unknown/i.test(boundary) || /Unknown/i.test(environment)) return "Multiple / TBD";
  if (sensitivity === "Public" && /Company internal|SaaS approved/i.test(environment)) return "No governance review";
  return "Standard AI review";
}

function normalizeReferenceValue(value, options) {
  const text = String(value || "").trim();
  if (!text) return "Unknown";
  const exact = options.find((option) => option.toLowerCase() === text.toLowerCase());
  if (exact) return exact;
  const partial = options.find((option) => text.toLowerCase().includes(option.toLowerCase()) || option.toLowerCase().includes(text.toLowerCase()));
  return partial || text;
}

function scoreByLevel(value, mapping, fallback = 50) {
  const normalized = normalizeReferenceValue(value, Object.keys(mapping));
  return normalized in mapping ? mapping[normalized] : fallback;
}

function evidenceConfidenceScore() {
  const confirmed = state.fields.playbackConfirmed === "yes" ? 16 : 0;
  const evidenceBoost = Math.min(16, (state.evidenceArtifacts || []).length * 6);
  const stepConfidence = state.steps.filter((step) => /high/i.test(step.evidenceConfidence || "")).length * 4;
  return Math.min(100, scoreByLevel(state.fields.fieldConfidence, { Low: 35, Medium: 62, High: 86 }, 50) + confirmed + evidenceBoost + stepConfidence);
}

function categoryLabel() {
  return state.fields.workflowCategory === "unknown" ? "Category TBD" : state.fields.workflowCategory;
}

function truncateUi(value, length = 120) {
  const text = String(value || "").replace(/\s+/g, " ").trim();
  return text.length > length ? `${text.slice(0, length - 1)}...` : text;
}

function formatDateTime(value) {
  if (!value) return "Not saved yet";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "Not saved yet";
  return date.toLocaleString([], {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit"
  });
}

function renderWorkbenchTabs() {
  const active = normalizeWorkbenchTab(state.activeWorkbenchTab);
  if (state.activeWorkbenchTab !== active) state.activeWorkbenchTab = active;
  document.querySelectorAll("[data-workbench-tab]").forEach((button) => {
    const selected = button.dataset.workbenchTab === active;
    button.classList.toggle("active", selected);
    button.setAttribute("aria-selected", selected ? "true" : "false");
    button.setAttribute("aria-pressed", selected ? "true" : "false");
  });
  document.querySelectorAll("[data-workbench-panel]").forEach((panel) => {
    panel.hidden = panel.dataset.workbenchPanel !== active;
  });
}

function normalizeWorkbenchTab(tab) {
  const aliasMap = {
    intake: "handoff",
    lifecycle: "business",
    matrix: "library",
    review: "business",
    controls: "business",
    pulse: "library",
    providers: "addons",
    connectors: "addons"
  };
  const normalized = aliasMap[tab] || tab || "handoff";
  const available = ["library", "evidence", "addons", "handoff", "inspector", "blueprint", "business"];
  return available.includes(normalized) ? normalized : "handoff";
}

function renderCurrentQuestion(section = getActiveSection()) {
  const question = getDisplayQuestion(section);
  els.currentQuestion.textContent = cleanQuestionLabel(question.text);
  renderQuestionLensBar();
}

const OPENING_DISCOVERY_QUESTION = "What task or workflow do you want to talk about? Briefly describe what happens, the business outcome, and the main output.";
const DOMAIN_CONTEXT_QUESTION = "What practice or domain does this task or workflow usually belong to? If it spans multiple practices, name them.";
const WORK_CONTEXT_QUESTION = "Where is this work done today: internally at the firm, on a client delivery project, for business development, at the client site, or somewhere else?";
const WORKFLOW_FRAME_PRIMARY_QUESTION = "What do you call this workflow?";
// Back-compat alias: existing routing references WORKFLOW_FRAME_QUESTION as the
// "frame" question. It now resolves to the single primary question only.
const WORKFLOW_FRAME_QUESTION = WORKFLOW_FRAME_PRIMARY_QUESTION;
// One-question-at-a-time model for the workflow frame (prototype scope).
// The primary asks only for the name; the remaining frame details become
// ordered, optional single-question follow-ups. The output follow-up reuses
// matrixPromptFor("output"); startPoint/endPoint have no matrixPromptFor entry,
// so they are phrased from their field labels.
const WORKFLOW_FRAME_QUESTION_MODEL = {
  id: "workflow-frame",
  primary: WORKFLOW_FRAME_PRIMARY_QUESTION,
  targetField: "workflowName",
  followUps: [
    { field: "startPoint", text: "Where does this workflow start?" },
    { field: "endPoint", text: "Where does this workflow end?" },
    { field: "deliverableType", text: `${matrixPromptFor("output").replace(/^./, (c) => c.toUpperCase())}?` }
  ]
};
const WORKFLOW_COMPONENT_OVERVIEW_QUESTION = "Before we get into the detail — what are the main moving parts of this workflow at a high level?";
const WORKFLOW_DATA_TOOLS_OVERVIEW_QUESTION = "Before we get into each step — which tools or systems tend to show up across this workflow overall?";
const PROCESS_MAP_QUESTION = "Walk me through this from beginning to end — what kicks it off, what happens at each stage, and what comes out the other side?";

function cleanQuestionLabel(text) {
  return String(text || "")
    .replace(/^\s*(next\s+question|question)\s*:\s*/i, "")
    .replace(/\s+/g, " ")
    .trim();
}

// The 9 merged grid fields in next-best-question priority order. Each field maps
// to one natural-language question and the underlying grid cell keys that carry
// its data (keys mirror GRID_LAYER_DEF). The strip walks this list against the
// CURRENT step's extraction confidence and asks about the first "missing" field.
// Order is fixed by spec: Flow & Dependencies first, Step Name last.
const NEXT_QUESTION_PRIORITY = [
  { field: "flowAndDependencies", keys: ["trigger", "output", "handoff"], question: "What kicks this off, what does it produce, and what does it depend on or hand off?" },
  { field: "whoIsInvolved", keys: ["personaActors"], question: "Who owns this step, who else touches it, and who has to approve before it moves on?" },
  { field: "dataFlow", keys: ["dataProcessing"], question: "What data is actually moving here — what form is it in, and where does it go?" },
  { field: "volume", keys: ["frequencyVolume", "timeTaken"], question: "How often does this happen, and roughly how long does each instance take?" },
  { field: "systemsTools", keys: ["systemsTools"], question: "Which specific tools or systems are being used in this step?" },
  { field: "painAndRules", keys: ["painFriction", "rulesDecisionLogic", "exceptionBranching"], question: "Where does this step usually go wrong, and are there rules or exceptions that govern it?" },
  { field: "whatHappens", keys: ["description"], question: "Can you describe in more detail what actually happens in this step?" },
  { field: "sensitivity", keys: ["dataSensitivity", "regulatoryContext"], question: "How sensitive is the data involved — is any of it confidential or regulated?" },
  { field: "stepName", keys: ["name"], question: "What would you call this step in one short phrase?" }
];

// The grid step currently in focus on Discovery. state.steps and the
// workflowGrid.steps are kept parallel by name, so we match on the active
// step's name and fall back to index alignment. Returns null when no grid
// exists yet (first turn, before any extraction).
function currentGridStep() {
  const grid = analysisGridSteps();
  if (!grid.length) return null;
  const activeName = String(getCurrentStep()?.name || "").trim().toLowerCase();
  if (activeName) {
    const byName = grid.find((step) => String(step.cells?.name?.value || "").trim().toLowerCase() === activeName);
    if (byName) return byName;
  }
  return grid[getCurrentStepIndex()] || grid[grid.length - 1] || null;
}

// Collapse a field's cell keys into a single extraction-confidence verdict that
// mirrors the API's confirmed / inferred / missing model:
//   - "missing"   → no key holds a value yet
//   - "confirmed" → at least one key was confirmed by the user
//   - "inferred"  → values exist but only AI-inferred (state empty/unknown/inferred)
function gridFieldConfidence(step, keys) {
  if (!step) return "missing";
  let hasValue = false;
  let hasConfirmed = false;
  for (const key of keys) {
    if (gridCellValue(step, key) !== "") {
      hasValue = true;
      if (gridCellState(step, key) === "confirmed") hasConfirmed = true;
    }
  }
  if (!hasValue) return "missing";
  return hasConfirmed ? "confirmed" : "inferred";
}

// Pick the next-best question from the current step's confidence:
//   - no grid yet (first turn) → default to the flowAndDependencies question (#6)
//   - first field whose confidence is "missing", in priority order (#2)
//   - nothing missing → null, so the strip shows the "ready to analyse" message.
//     (#4 names the all-confirmed case; an all-inferred step has no missing gap
//     left to ask about, so it also reads as covered.)
function nextBestGridQuestion() {
  const step = currentGridStep();
  if (!step) return NEXT_QUESTION_PRIORITY[0];
  for (const field of NEXT_QUESTION_PRIORITY) {
    if (gridFieldConfidence(step, field.keys) === "missing") return field;
  }
  return null;
}

function copySuggestedQuestionToAnswer(question) {
  if (!els.answerInput || !question) return;
  els.answerInput.value = question;
  els.answerInput.focus();
  toast("Suggested question copied to the answer box");
}

// The narrow strip under the current question. It surfaces the next-best
// discovery question — the first field on the current step whose extraction
// confidence is still "missing" — and is tappable to copy that question into
// the main answer box. Recomputed on every render(), i.e. after each
// Accept & Analyze cycle once the new grid confidence has landed.
function renderQuestionLensBar() {
  if (!els.questionLensBar) return;
  const next = nextBestGridQuestion();
  if (!next) {
    els.questionLensBar.innerHTML = `
      <div class="ds-panel ds-border-teal" style="width:100%;box-sizing:border-box;padding:12px 16px;">
        <div class="ds-micro" style="margin-bottom:4px;">SUGGESTED NEXT QUESTION</div>
        <div style="font-size:0.9rem;color:#e2e8f0;line-height:1.4;">All key areas covered — ready to analyse.</div>
      </div>
    `;
    return;
  }
  els.questionLensBar.innerHTML = `
    <div class="ds-panel ds-border-teal" role="button" tabindex="0" title="Tap to copy this question into the answer box" style="width:100%;box-sizing:border-box;padding:12px 16px;cursor:pointer;">
      <div class="ds-micro" style="margin-bottom:4px;">SUGGESTED NEXT QUESTION</div>
      <div style="font-size:0.9rem;color:#e2e8f0;line-height:1.4;">${escapeHtml(next.question)}</div>
    </div>
  `;
  const panel = els.questionLensBar.firstElementChild;
  if (panel) {
    panel.addEventListener("click", () => copySuggestedQuestionToAnswer(next.question));
    panel.addEventListener("keydown", (event) => {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        copySuggestedQuestionToAnswer(next.question);
      }
    });
  }
}

// Phase 1 Frame Builder — State 3. The display-only workflow breadcrumb/anchor
// strip ("WORKFLOW | 1 step now | 2 step ...") was removed from the Discovery
// page. Step tracking (state.steps, getCurrentStepIndex, drilldown) is untouched
// — only the rendered bar is gone.

function renderCurrentStepPanel() {
  if (!els.currentStepPanel) return;
  if (!state.steps.length) {
    els.currentStepPanel.innerHTML = `
      <div class="step-workspace-empty">
        <span><i data-lucide="list-ordered"></i></span>
        <div>
          <p class="eyebrow">Step Workspace</p>
          <strong>Waiting for the rough A-to-Z workflow</strong>
          <p>Ask for a numbered list first. Once steps exist, this card will guide one step at a time.</p>
        </div>
      </div>
    `;
    refreshIcons();
    return;
  }
  advanceToNextIncompleteStep();
  const step = getCurrentStep();

  if (state.drilldown?.status === "confirmSkeleton") {
    renderWorkflowSkeletonPanel();
    return;
  }

  const index = getCurrentStepIndex();
  const missing = stepMissingFields(step);
  const complete = stepCompletion(step);
  const activeCluster = currentDrilldownCluster(step);
  els.currentStepPanel.innerHTML = `
    <div class="step-workspace-header">
      <div>
        <p class="eyebrow">Guided Step Drill-Down</p>
        <h3>${escapeHtml(step.name || step.action || `Step ${index + 1}`)}</h3>
        <span class="step-workspace-subtitle">Step ${index + 1} of ${state.steps.length}${activeCluster ? ` · ${escapeHtml(activeCluster.label)}` : ""}</span>
      </div>
      <div class="step-workspace-score">
        <span>${complete}%</span>
        <small>complete</small>
      </div>
    </div>
    <p class="step-workspace-action">${escapeHtml(step.action || "Action still needs to be described.")}</p>
    <div class="drilldown-cluster-rail">
      ${drilldownClusters(step).map((cluster) => drilldownClusterPill(step, cluster, activeCluster)).join("")}
    </div>
    <div class="step-field-chips">
      ${stepFieldStatusList(step).map((item) => stepFieldChip(item)).join("")}
    </div>
    ${stepIntakeSnapshotHtml(step, activeCluster)}
    <div class="step-workspace-actions">
      <button class="secondary-button compact" id="previousStepButton" type="button" ${index === 0 ? "disabled" : ""}>
        <i data-lucide="arrow-left"></i>
        Previous
      </button>
      <button class="secondary-button compact" id="confirmStepButton" type="button">
        <i data-lucide="badge-check"></i>
        Mark Confirmed
      </button>
      <button class="secondary-button compact" id="nextStepButton" type="button" ${index >= state.steps.length - 1 ? "disabled" : ""}>
        Next Step
        <i data-lucide="arrow-right"></i>
      </button>
    </div>
    ${missing.length ? `<p class="step-missing-note">Missing next: ${escapeHtml(missing.slice(0, 4).map((item) => item.label).join(", "))}</p>` : `<p class="step-missing-note ready">This step is ready for review. Move to the next step or confirm the map.</p>`}
  `;
  document.getElementById("previousStepButton")?.addEventListener("click", () => setCurrentStepIndex(index - 1));
  document.getElementById("nextStepButton")?.addEventListener("click", () => setCurrentStepIndex(index + 1));
  document.getElementById("confirmStepButton")?.addEventListener("click", confirmCurrentStep);
  els.currentStepPanel.querySelectorAll("[data-step-field]").forEach((button) => {
    button.addEventListener("click", () => focusStepField(button.dataset.stepField));
  });
  refreshIcons();
}

// Phase 1 Frame Builder — State 2 (Confirm). The three simple in-card anchors.
// Handoff/wait is intentionally NOT here yet (Stage 2). Each anchor maps onto an
// existing step field so edits here pre-fill the Phase 2 deep dive.
const FRAME_ANCHORS = [
  { key: "tool", label: "Tools", icon: "wrench" },
  { key: "input", label: "Data", icon: "database" },
  { key: "actor", label: "People", icon: "user" }
];

function frameAnchorValue(step, key) {
  return String(step?.[key] || "").trim();
}

// State 2 — the rough frame reflected back as editable step columns (left to
// right, with connectors), an "add step" card, and an honest confirm bar.
function renderWorkflowSkeletonPanel() {
  const columns = state.steps.map((step, index) => workflowFrameColumn(step, index)).join("");
  els.currentStepPanel.innerHTML = `
    <div class="frame-confirm-panel">
      <div class="frame-confirm-header">
        <div>
          <p class="eyebrow">Workflow Frame</p>
          <h3>Here's the rough shape I heard</h3>
          <p>Click any card to fix it, or confirm to go step by step.</p>
        </div>
        <span class="frame-step-count">${state.steps.length} step${state.steps.length === 1 ? "" : "s"}</span>
      </div>
      <div class="frame-column-rail" aria-label="Workflow frame steps">
        ${columns}
        <button class="frame-add-step" id="frameAddStepButton" type="button" title="Add a step I missed">
          <span class="frame-add-step-icon"><i data-lucide="plus"></i></span>
          <span class="frame-add-step-label">Add step</span>
        </button>
      </div>
      <div class="frame-confirm-bar">
        <button class="primary-button" id="frameConfirmButton" type="button">
          <i data-lucide="check-circle-2"></i>
          Looks right — go step by step
        </button>
        <button class="secondary-button" id="frameKeepTalkingButton" type="button">
          <i data-lucide="mic"></i>
          Keep talking
        </button>
      </div>
    </div>
  `;
  document.getElementById("frameConfirmButton")?.addEventListener("click", confirmWorkflowSkeleton);
  document.getElementById("frameKeepTalkingButton")?.addEventListener("click", keepTalkingFromFrame);
  document.getElementById("frameAddStepButton")?.addEventListener("click", addFrameStep);
  wireFrameInlineEdits();
  refreshIcons();
}

function workflowFrameColumn(step, index) {
  const label = step.name || step.action || `Step ${index + 1}`;
  const anchors = FRAME_ANCHORS.map((anchor) => {
    const value = frameAnchorValue(step, anchor.key);
    const filled = Boolean(value);
    return `
      <button class="frame-anchor ${filled ? "filled" : "empty"}" type="button" data-frame-edit="anchor" data-step-index="${index}" data-anchor-key="${anchor.key}" title="Edit ${anchor.label.toLowerCase()}">
        <span class="frame-anchor-icon"><i data-lucide="${anchor.icon}"></i></span>
        <span class="frame-anchor-body">
          <small>${anchor.label}</small>
          <span class="frame-anchor-value">${filled ? escapeHtml(value) : "—"}</span>
        </span>
      </button>
    `;
  }).join("");
  return `
    <div class="frame-column ${index === getCurrentStepIndex() ? "active" : ""}">
      <div class="frame-column-head">
        <span class="frame-step-number">${index + 1}</span>
        <button class="frame-step-name" type="button" data-frame-edit="name" data-step-index="${index}" title="Rename step">
          <span>${escapeHtml(label)}</span>
          <i data-lucide="pencil"></i>
        </button>
      </div>
      <div class="frame-anchor-stack">
        ${anchors}
      </div>
    </div>
  `;
}

// Inline edit: swap the clicked name/anchor for an input, commit on Enter/blur,
// cancel on Escape. Anchors may be cleared back to a dim dash.
function wireFrameInlineEdits() {
  els.currentStepPanel.querySelectorAll("[data-frame-edit]").forEach((node) => {
    node.addEventListener("click", () => beginFrameEdit(node));
  });
}

function beginFrameEdit(node) {
  const index = Number(node.dataset.stepIndex);
  const step = state.steps[index];
  if (!step) return;
  const editType = node.dataset.frameEdit;
  const key = editType === "name" ? "name" : node.dataset.anchorKey;
  const current = editType === "name"
    ? (step.name || step.action || `Step ${index + 1}`)
    : frameAnchorValue(step, key);
  const input = document.createElement("input");
  input.className = "frame-inline-input";
  input.value = current;
  input.setAttribute("aria-label", editType === "name" ? `Step ${index + 1} name` : `Step ${index + 1} ${key}`);
  node.replaceWith(input);
  input.focus();
  input.select();
  let settled = false;
  const commit = (save) => {
    if (settled) return;
    settled = true;
    if (save) {
      const value = input.value.trim();
      if (editType === "name") {
        if (value) {
          step.name = value;
          if (!String(step.action || "").trim()) step.action = value;
          step.evidenceConfidence = step.evidenceConfidence || "Medium";
        }
      } else {
        step[key] = value;
      }
      persistState();
    }
    render();
  };
  input.addEventListener("keydown", (event) => {
    if (event.key === "Enter") {
      event.preventDefault();
      commit(true);
    } else if (event.key === "Escape") {
      event.preventDefault();
      commit(false);
    }
  });
  input.addEventListener("blur", () => commit(true));
}

function addFrameStep() {
  ensureDrilldownState();
  const step = { ...newRecord("steps"), name: "", action: "", evidenceConfidence: "Low", interviewNotes: "Added from frame confirm" };
  state.steps.push(step);
  const newIndex = state.steps.length - 1;
  state.activeStepIndex = newIndex;
  state.drilldown.status = "confirmSkeleton";
  state.drilldown.skeletonConfirmed = false;
  state.activeSection = "workflow";
  persistState();
  render();
  const nameNode = els.currentStepPanel?.querySelector(`[data-frame-edit="name"][data-step-index="${newIndex}"]`);
  if (nameNode) beginFrameEdit(nameNode);
}

// "Keep talking" — stay in the confirm view and invite more of the broad
// overview. New answers extend the frame (syncGuidedDrilldownAfterExtraction
// keeps us in confirmSkeleton) instead of jumping into the deep dive.
function keepTalkingFromFrame() {
  ensureDrilldownState();
  state.drilldown.status = "confirmSkeleton";
  state.drilldown.skeletonConfirmed = false;
  state.drilldown.manualStepFocus = false;
  state.activeSection = "workflow";
  state.currentQuestionOverride = "No problem — keep going. Add any steps, tools, data, or people I missed and I'll extend the frame.";
  state.currentQuestionSource = "Keep talking";
  state.drilldown.lastPrompt = state.currentQuestionOverride;
  persistState();
  render();
  els.aiChatInput?.focus();
  toast("Keep going — tell me what else happens and I'll extend the frame.");
}

function stepFieldChip(item) {
  const active = activeStepFieldKeys().includes(item.key);
  return `
    <button class="step-field-chip ${item.status} ${active ? "active" : ""}" data-step-field="${item.key}" type="button" title="${escapeHtml(item.prompt)}">
      <i data-lucide="${item.icon}"></i>
      <span>${escapeHtml(item.label)}</span>
    </button>
  `;
}

function stepIntakeSnapshotHtml(step, activeCluster) {
  const captured = stepCapturedFacts(step);
  const missing = stepMissingFields(step).slice(0, 4).map((item) => item.label).join(", ") || "No required step fields missing";
  const why = stepHandoffReason(activeCluster);
  return `
    <div class="step-intake-snapshot">
      <div>
        <span>Captured so far</span>
        <p>${escapeHtml(captured || "Waiting for the first concrete detail for this step.")}</p>
      </div>
      <div>
        <span>Missing next</span>
        <p>${escapeHtml(missing)}</p>
      </div>
      <div>
        <span>Why it matters</span>
        <p>${escapeHtml(why)}</p>
      </div>
    </div>
  `;
}

function stepCapturedFacts(step) {
  const facts = [
    step.actor ? `Actor: ${step.actor}` : "",
    step.tool ? `Tools: ${step.tool}` : "",
    step.accessMode ? `Access: ${step.accessMode}` : "",
    step.input ? `Input: ${step.input}` : "",
    step.output ? `Output: ${step.output}` : "",
    step.handoff ? `Handoff: ${step.handoff}` : "",
    step.time ? `Time: ${step.time}` : "",
    step.decision ? `Review: ${step.decision}` : "",
    step.dataSensitivity ? `Sensitivity: ${step.dataSensitivity}` : ""
  ].filter(Boolean);
  return facts.slice(0, 4).join(" | ");
}

function stepHandoffReason(cluster) {
  if (!cluster) return "This keeps Product and Engineering aligned on what this step needs before handoff.";
  if (cluster.id === "who_where") return "Engineering needs this to understand users, tools, permissions, and source access.";
  if (cluster.id === "inputs_data") return "This clarifies data categories, sensitivity, and whether raw client data can be avoided.";
  if (cluster.id === "outputs_flow") return "This defines the output contract, downstream handoff, and where a solution must fit.";
  if (cluster.id === "time_judgment") return "This supports the value case and shows where human review must remain.";
  return "This separates automation-friendly repetition from exceptions that should stay human-led.";
}

function drilldownClusterPill(step, cluster, activeCluster) {
  const complete = clusterComplete(step, cluster);
  const active = activeCluster?.id === cluster.id;
  return `
    <span class="drilldown-cluster-pill ${complete ? "complete" : ""} ${active ? "active" : ""}">
      <i data-lucide="${cluster.icon}"></i>
      ${escapeHtml(cluster.label)}
    </span>
  `;
}

function renderInterviewGuide(section = getActiveSection()) {
  if (!els.interviewGuide) return;
  const focus = interviewFocus(section);
  els.interviewGuide.innerHTML = `
    <div class="guide-card primary">
      <span><i data-lucide="${focus.icon}"></i></span>
      <div>
        <strong>${escapeHtml(focus.title)}</strong>
        <p>${escapeHtml(focus.description)}</p>
      </div>
    </div>
    <div class="guide-card">
      <span><i data-lucide="table-2"></i></span>
      <div>
        <strong>Fills</strong>
        <p>${escapeHtml(focus.fills)}</p>
      </div>
    </div>
    <div class="guide-card">
      <span><i data-lucide="search-check"></i></span>
      <div>
        <strong>Listen for</strong>
        <p>${escapeHtml(focus.listenFor)}</p>
      </div>
    </div>
  `;
  refreshIcons();
}

function setCaptureStage(stage, label = "") {
  state.captureStage = stage;
  if (label && els.voiceStatus) els.voiceStatus.textContent = label;
  els.voiceStatus?.classList.toggle("active", stage !== "idle");
  document.body.dataset.captureStage = stage;
  updateAiTurnStatus(stage);
  renderTurnSignalPanel();
  renderCaptureCoach();
  refreshIcons();
}

function updateAiTurnStatus(stage = state.captureStage || "idle") {
  if (!els.aiTurnStatus) return;
  const meta = {
    offline: { label: "AI offline", icon: "cloud-off" },
    idle: { label: aiAvailable || realtimeAvailable ? "AI ready" : "AI offline", icon: aiAvailable || realtimeAvailable ? "sparkles" : "cloud-off" },
    listening: { label: "Listening", icon: "mic" },
    analyzing: { label: "Thinking", icon: "loader" },
    followup: { label: "Summary ready", icon: "message-circle-check" }
  }[stage] || { label: "AI ready", icon: "sparkles" };
  els.aiTurnStatus.className = `ai-turn-status ${escapeHtml(stage)}`;
  els.aiTurnStatus.innerHTML = `<i data-lucide="${meta.icon}"></i>${escapeHtml(meta.label)}`;
  refreshIcons();
}

function renderCaptureCoach() {
  if (!els.captureCoach) return;
  const text = els.answerInput.value.trim() || latestUserMessage();
  const placement = suggestedPlacement();
  const confidence = captureConfidence(text, placement);
  const stage = captureStageMeta();
  els.captureCoach.innerHTML = `
    <div class="turn-card ${stage.key}">
      <div class="turn-card-copy">
        <span>${escapeHtml(stage.kicker)}</span>
        <strong>${escapeHtml(stage.title)}</strong>
        <p>${escapeHtml(stage.detail)}</p>
      </div>
      <div class="turn-flow">
        ${turnStep("idle", "Ready", "circle-dot")}
        ${turnStep("listening", "Listening", "mic")}
        ${turnStep("analyzing", "Analyzing", "sparkles")}
        ${turnStep("followup", "Follow-up", "message-circle")}
      </div>
    </div>
    <div class="coach-item">
      <span><i data-lucide="captions"></i></span>
      <div>
        <strong>What is being recorded</strong>
        <p>${escapeHtml(text || "Waiting for speech, chat, or typed notes.")}</p>
      </div>
    </div>
    <div class="coach-item">
      <span><i data-lucide="corner-down-right"></i></span>
      <div>
        <strong>Suggested placement</strong>
        <p>${escapeHtml(placement)}</p>
      </div>
    </div>
    <div class="coach-item ${confidence.className}">
      <span><i data-lucide="${confidence.icon}"></i></span>
      <div>
        <strong>${escapeHtml(confidence.label)}</strong>
        <p>${escapeHtml(confidence.detail)}</p>
      </div>
    </div>
  `;
  refreshIcons();
}

function renderTurnSignalPanel() {
  if (!els.turnSignalPanel) return;
  const stage = captureStageMeta();
  const stages = validationStages();
  const active = currentValidationStage(stages);
  const progress = validationFlowProgress(stages);
  const matrixScore = matrixCompletionScore();
  const focus = validQuestionFocus(state.questionFocus);
  const currentStep = getCurrentStep();
  const lastAnswer = latestUserMessage();
  const nextQuestion = cleanQuestionLabel(state.lastRecap?.nextQuestion || getDisplayQuestion(getActiveSection()).text || stepInterviewQuestion());
  const blockerItems = topCompletionQuestionItems(4, { includeSupplemental: true });
  // Grid cells the interview raised but the interviewee could not answer. These
  // are intentionally NOT surfaced as "Ask now" cards (which come from the
  // legacy completion checklist, not grid cells) — they are listed separately.
  const askedUnknown = unknownGridCells();
  els.turnSignalPanel.className = `turn-signal-panel ${escapeHtml(stage.key)}`;
  els.turnSignalPanel.innerHTML = `
    <div class="discovery-pulse-heading">
      <div>
        <p class="eyebrow">Session Pulse</p>
        <h3>What still needs attention</h3>
        <p>${escapeHtml(stage.detail)}</p>
      </div>
      <div class="pulse-score" title="Overall validation progress for this discovery session">
        <strong>${progress}%</strong>
        <span>validation</span>
      </div>
    </div>
    <div class="discovery-pulse-track" aria-label="Session progress">
      <span style="width: ${progress}%"></span>
    </div>
    <div class="turn-signal-flow" title="Voice turn status">
      ${turnStep("idle", "Ready", "circle-dot")}
      ${turnStep("listening", "Listening", "mic")}
      ${turnStep("analyzing", "Thinking", "sparkles")}
      ${turnStep("followup", "Next", "message-circle")}
    </div>
    <div class="question-focus-bar" data-help="Optional operator control: keep Auto on for the normal guided interview, or steer the next handoff question toward one audience.">
      <span>Question focus</span>
      <div>
        ${questionFocusOptions()
          .map(
            (option) => `
              <button class="${option.id === focus ? "active" : ""}" data-question-focus="${option.id}" type="button" title="${escapeHtml(option.help)}">
                ${escapeHtml(option.label)}
              </button>
            `
          )
          .join("")}
      </div>
    </div>
    <div class="discovery-pulse-grid">
      <div class="pulse-mini-card" title="The current part of the discovery flow that needs attention">
        <span>Current focus</span>
        <strong>${escapeHtml(active.label)}</strong>
        <p>${escapeHtml(truncateUi(active.question, 120))}</p>
      </div>
      <div class="pulse-mini-card" title="How complete the step-by-step process matrix is">
        <span>Process matrix</span>
        <strong>${matrixScore}% filled</strong>
        <p>${escapeHtml(currentStep ? `Current step: ${currentStep.name || currentStep.action || `Step ${getCurrentStepIndex() + 1}`}` : "Waiting for the rough A-to-Z step list.")}</p>
      </div>
      <div class="pulse-mini-card" title="The latest spoken or typed answer being interpreted">
        <span>Latest answer</span>
        <strong>${escapeHtml(truncateUi(lastAnswer || "Waiting for input", 44))}</strong>
        <p>${escapeHtml(truncateUi(nextQuestion, 120))}</p>
      </div>
    </div>
    <div class="discovery-pulse-next discovery-blocker-panel" title="The highest-value answers to add next">
      <div class="blocker-panel-head">
        <span><i data-lucide="list-checks"></i></span>
        <div>
          <strong>Most useful answers next</strong>
          <p>Answer the current question, or use these blockers to batch-fill what the AI still needs.</p>
        </div>
      </div>
      <div class="blocker-card-grid">
        ${(blockerItems.length ? blockerItems : [{ question: "No major open question detected.", lane: "Ready", treatment: "Review", source: "Session pulse", bucket: "ask" }])
          .slice(0, 4)
          .map(discoveryBlockerCard)
          .join("")}
      </div>
    </div>
    ${askedUnknown.length ? `
      <div class="discovery-asked-panel" title="Raised in the interview but no specific answer was available — these are not open gaps to re-ask.">
        <div class="asked-panel-head">
          <strong>Asked — no answer available</strong>
          <p>Raised in the interview; the interviewee could not give a specific answer. Not counted as open gaps.</p>
        </div>
        <div class="asked-pill-row">
          ${askedUnknown.map((item) => `<span class="asked-pill" data-cell-state="unknown">? ${escapeHtml(item.stepName)} · ${escapeHtml(item.label)}</span>`).join("")}
        </div>
      </div>
    ` : ""}
  `;
  els.turnSignalPanel.querySelectorAll("[data-question-focus]").forEach((button) => {
    button.addEventListener("click", () => setQuestionFocus(button.dataset.questionFocus));
  });
  refreshIcons();
}

function discoveryBlockerCard(item = {}) {
  const treatmentClass = item.bucket === "supplement" ? "supplement" : item.bucket === "infer" ? "infer" : "ask";
  return `
    <article class="blocker-card ${treatmentClass}">
      <div class="blocker-card-top">
        <span>${escapeHtml(item.lane || "Discovery")}</span>
        <em>${escapeHtml(item.treatment || "Ask now")}</em>
      </div>
      <p>${escapeHtml(truncateUi(item.question, 148))}</p>
      <small>${escapeHtml(item.source || "Discovery gap")}</small>
    </article>
  `;
}

function questionFocusOptions() {
  return [
    { id: "auto", label: "Auto", help: "Let the app pick the highest-priority discovery or handoff gap." },
    { id: "product", label: "Product", help: "Bias the next handoff question toward PDR, MVP, user, and scope gaps." },
    { id: "engineering", label: "Engineering", help: "Bias the next handoff question toward process, systems, data, access, and output gaps." },
    { id: "business", label: "Business", help: "Bias the next handoff question toward value, frequency, capacity, and commercial context gaps." },
    { id: "governance", label: "Gov Inputs", help: "Bias the next handoff question toward basic data boundary, review path, controls, and risk inputs." }
  ];
}

function validQuestionFocus(value) {
  return questionFocusOptions().some((option) => option.id === value) ? value : "auto";
}

function questionFocusLabel(value = state.questionFocus) {
  return questionFocusOptions().find((option) => option.id === validQuestionFocus(value))?.label || "Auto";
}

function setQuestionFocus(value) {
  const focus = validQuestionFocus(value);
  state.questionFocus = focus;
  if (focus !== "auto") {
    const question = topHandoffChecklistQuestions(1, focus)[0];
    if (question) {
      state.currentQuestionOverride = question;
      state.currentQuestionSource = `${questionFocusLabel(focus)} focus`;
    }
  } else {
    const route = nextQuestionRouteAfterExtraction({});
    if (route?.text) {
      state.currentQuestionOverride = route.text;
      state.currentQuestionSource = route.source;
    }
  }
  persistState();
  render();
  toast(`Question focus: ${questionFocusLabel(focus)}.`);
}

function inferenceLensData() {
  const gate = gateAssessment();
  const governance = governanceRoute();
  const known = inspectorKnownFacts().slice(0, 4);
  const inferred = [
    `Lifecycle stage: ${lifecycleCurrentStage()}`,
    `Gate A signal: ${gate.decision} (${gate.overall}/100)`,
    `Post-build review path: ${governance.path}`,
    `Data sensitivity: ${inferOverallDataSensitivity()}`,
    state.steps.length ? `Likely step coverage: ${matrixCompletionScore()}% matrix detail` : "",
    state.fields.solutionType !== "unknown" ? `Solution type: ${state.fields.solutionType}` : "",
    state.fields.automationPotential ? `Automation potential: ${state.fields.automationPotential}` : ""
  ].filter(Boolean).slice(0, 6);
  return {
    known,
    inferred,
    questions: topCompletionQuestions(3),
    confidence: handoffReadinessScore(),
    gateDecision: gate.decision
  };
}

function inferenceLensRows() {
  const lens = inferenceLensData();
  return [
    ["Area", "Item"],
    ["Handoff readiness confidence", `${lens.confidence}%`],
    ["Gate A signal", lens.gateDecision],
    ...lens.known.map((item) => ["Known fact", item]),
    ...lens.inferred.map((item) => ["AI approximation", item]),
    ...lens.questions.map((item, index) => [`Completion question ${index + 1}`, item])
  ];
}

function captureStageMeta() {
  const stage = state.captureStage || "idle";
  const messages = {
    idle: {
      key: "idle",
      kicker: "Ready when you are",
      title: "Tap Start Talking",
      detail: "Answer the highlighted question. The transcript will appear below as you talk or type."
    },
    listening: {
      key: "listening",
      kicker: "Your turn",
      title: "Listening to your answer",
      detail: "Speak naturally. Tap Stop Talking when this answer is complete."
    },
    analyzing: {
      key: "analyzing",
      kicker: "AI status",
      title: "Thinking",
      detail: "The AI is quietly digesting the transcript and updating the intake behind the scenes."
    },
    followup: {
      key: "followup",
      kicker: "Next question ready",
      title: "Answer captured",
      detail: "The app keeps the structured detail and moves to the next useful follow-up unless you correct it."
    }
  };
  return messages[stage] || messages.idle;
}

function turnStep(key, label, icon) {
  const order = ["idle", "listening", "analyzing", "followup"];
  const current = order.indexOf(state.captureStage || "idle");
  const index = order.indexOf(key);
  const className = index === current ? "active" : index < current ? "done" : "";
  return `
    <span class="turn-step ${className}">
      <i data-lucide="${icon}"></i>
      <small>${escapeHtml(label)}</small>
    </span>
  `;
}

function interviewFocus(section) {
  const gap = firstMatrixGap();
  if (section.id === "idea") {
    return {
      icon: "clipboard-list",
      title: "Start with the work",
      description: "Capture the task or workflow in plain language before pushing the user into categories or business-case fields.",
      fills: "Submitted idea snapshot, workflow category, candidate AI assist hypothesis",
      listenFor: "Task/workflow, what happens, main output, business outcome, where the work happens today"
    };
  }
  if (section.id === "validate") {
    return {
      icon: "search-check",
      title: "Validate the working description",
      description: "Check whether the submitted idea matches the real current-state workflow, and capture practice/domain or work context.",
      fills: "Idea validation, build readiness, primary time driver, practice/domain, work context",
      listenFor: "Cross-practice applicability, client delivery, internal firm work, business development, client site, current-state facts"
    };
  }
  if (section.id === "workflow") {
    return {
      icon: "route",
      title: state.steps.length ? `Enrich ${gap?.stepName || "the step matrix"}` : "Build the A-Z skeleton",
      description: state.steps.length ? "Fill the missing cells for each captured step, including tools, access/source mode, data movement, handoffs, decisions, and sensitivity." : "Ask for a rough numbered list first. Details can be incomplete.",
      fills: "Workflow boundary, workshop fields when relevant, A-Z process, and Discovery Template rows",
      listenFor: "Step names, order, action performed, tools, inputs, outputs, access mode, start point, final output"
    };
  }
  if (section.id === "evidence") {
    return {
      icon: "paperclip",
      title: "Use evidence as an optional add-on",
      description: "Attach screenshots, transcripts, decks, trackers, workshop examples, or notes only when they help confirm the workflow.",
      fills: "Evidence add-ons and artifact notes",
      listenFor: "Screenshots, transcripts, decks, SharePoint links, Miro boards, trackers, examples, assumptions to confirm"
    };
  }
  if (section.id === "value") {
    return {
      icon: "timer",
      title: "Capture friction, not a finance model",
      description: "Capture what is slow, manual, repetitive, risky, or high-rework. Detailed capacity, margin, volume, and cost assumptions can be supplemented later.",
      fills: "Pain, time, quality, reuse, directional value, and supplement-later business fields",
      listenFor: "Manual effort, delays, rework, quality issues, risk reduction, reusable assets, rough timing if known"
    };
  }
  if (section.id === "aiFit") {
    return {
      icon: "sparkles",
      title: "Validate fit after current state is clear",
      description: "Compare the submitted AI assist hypothesis against the validated workflow and the available ChatGPT/Copilot toolset.",
      fills: "Solution hypothesis, MVP scope, tool fit, user stories, acceptance criteria, success metrics",
      listenFor: "ChatGPT Enterprise, M365 Copilot, Copilot Studio, agent roles, human review, reusable assets"
    };
  }
  if (section.id === "blueprint") {
    return {
      icon: "workflow",
      title: "Review the workflow blueprint",
      description: "Check triggers, handoffs, human controls, AI patterns, access constraints, and open questions across the whole workflow.",
      fills: "Blueprint, trigger model, AI pattern map, current process map",
      listenFor: "Branching paths, approvals, exceptions, dependencies, evidence, source traceability"
    };
  }
  return {
    icon: "badge-check",
    title: "Review and package",
    description: "Confirm the A-Z workflow, missing cells, and PDR-ready notes.",
    fills: "Closeout, Output Package, Engineering handoff",
    listenFor: "Corrections, open questions, evidence artifacts, pilot owner"
  };
}

function latestUserMessage() {
  const last = [...(state.conversation || []), ...(state.aiChat || [])].reverse().find((message) => message.role === "user");
  return last?.text || "";
}

function suggestedPlacement() {
  const gap = firstMatrixGap();
  if (gap) return `${gap.stepName} -> ${gap.label}`;
  return `${getActiveSection().label} -> ${getDisplayQuestion(getActiveSection()).source}`;
}

function captureConfidence(text, placement) {
  if (!text) {
    return { label: "No live capture yet", detail: "Use Start My Answer, type notes, or chat with the copilot.", className: "", icon: "circle-dashed" };
  }
  if (placement.includes("->") && text.length > 35) {
    return { label: "Ready to analyze", detail: "Tap Done Talking or AI Analyze Answer to place this into the step matrix.", className: "good", icon: "badge-check" };
  }
  return { label: "Needs confirmation", detail: "The text is short or ambiguous. The AI may ask a follow-up before filling the matrix.", className: "warn", icon: "circle-alert" };
}

function getCurrentStepIndex() {
  if (!state.steps.length) return 0;
  const index = Number.isFinite(state.activeStepIndex) ? state.activeStepIndex : 0;
  return Math.max(0, Math.min(index, state.steps.length - 1));
}

function getCurrentStep() {
  return state.steps[getCurrentStepIndex()] || null;
}

function setCurrentStepIndex(index) {
  if (!state.steps.length) return;
  state.activeStepIndex = Math.max(0, Math.min(index, state.steps.length - 1));
  state.activeSection = "workflow";
  ensureDrilldownState();
  state.drilldown.manualStepFocus = true;
  state.currentQuestionOverride = stepInterviewQuestion();
  state.currentQuestionSource = state.drilldown?.status === "confirmSkeleton" ? "Skeleton confirmation" : "Step-by-step interview";
  state.drilldown.currentClusterId = currentDrilldownCluster()?.id || "";
  persistState();
  render();
}

// Freezes the workflowGrid step list once Q3 confirmation is resolved and
// step-by-step drilling begins. After this, harvest/merge may only update
// existing steps — never create new ones (prevents step-count inflation and
// corrupted coverage stats). Idempotent; reset to false on a new session and
// by reviseWorkflowSkeleton() when the user re-opens the list to edit it.
function lockWorkflowStepList() {
  if (state.workflowGrid) state.workflowGrid.stepListLocked = true;
}

function confirmWorkflowSkeleton() {
  ensureDrilldownState();
  if (!state.steps.length) return;
  state.drilldown.skeletonConfirmed = true;
  state.drilldown.status = "active";
  lockWorkflowStepList();
  state.drilldown.manualStepFocus = false;
  state.activeStepIndex = Math.max(0, firstIncompleteStepIndex(0));
  state.activeSection = "workflow";
  const cluster = currentDrilldownCluster(getCurrentStep());
  state.drilldown.currentClusterId = cluster?.id || "";
  state.currentQuestionOverride = stepInterviewQuestion();
  state.currentQuestionSource = "Step-by-step interview";
  state.drilldown.lastPrompt = state.currentQuestionOverride;
  state.lastRecap = {
    title: "Workflow skeleton confirmed",
    summary: `Confirmed ${state.steps.length} major workflow steps. Now we can walk one step at a time through actors, tools, inputs, data, outputs, handoffs, time, decisions, and gaps.`,
    confidence: "medium",
    fields: ["Workflow skeleton", "Process steps"],
    nextQuestion: state.currentQuestionOverride,
    time: new Date().toISOString()
  };
  persistState();
  render();
  toast("Workflow skeleton confirmed. Moving into step-by-step discovery.");
}

function reviseWorkflowSkeleton() {
  ensureDrilldownState();
  state.drilldown.status = "confirmSkeleton";
  state.drilldown.skeletonConfirmed = false;
  state.drilldown.manualStepFocus = false;
  // Re-opening the step list for edits allows new steps again until re-confirmed.
  if (state.workflowGrid) state.workflowGrid.stepListLocked = false;
  state.activeSection = "workflow";
  state.currentQuestionOverride = "What should I add, remove, rename, merge, split, or reorder in these major workflow steps?";
  state.currentQuestionSource = "Skeleton revision";
  state.drilldown.lastPrompt = state.currentQuestionOverride;
  persistState();
  render();
  toast("Tell me how to revise the workflow skeleton, or edit the step names directly.");
}

function confirmCurrentStep() {
  const step = getCurrentStep();
  const confirmedIndex = getCurrentStepIndex();
  if (!step) return;
  step.evidenceConfidence = "High";
  step.openQuestions = step.openQuestions || "";
  const nextIndex = firstIncompleteStepIndex(Math.min(confirmedIndex + 1, state.steps.length - 1));
  if (nextIndex >= 0 && nextIndex !== confirmedIndex) {
    state.activeStepIndex = nextIndex;
    ensureDrilldownState();
    state.drilldown.manualStepFocus = false;
  }
  state.lastRecap = {
    title: `Step ${confirmedIndex + 1} confirmed`,
    summary: `${step.name || step.action || "Current step"} marked high confidence for Product/Engineering review.`,
    confidence: "high",
    fields: stepFieldStatusList(step).filter((item) => item.status === "captured").map((item) => item.label),
    nextQuestion: stepInterviewQuestion(),
    time: new Date().toISOString()
  };
  persistState();
  render();
  toast("Current step marked confirmed.");
}

function focusStepField(key) {
  const step = getCurrentStep();
  if (!step) return;
  const meta = stepFieldMeta().find((item) => item.key === key);
  if (!meta) return;
  state.activeSection = sectionForStepField(key);
  state.currentQuestionOverride = `For "${step.name || step.action || `Step ${getCurrentStepIndex() + 1}`}", ${meta.prompt}?`;
  state.currentQuestionSource = "Step field focus";
  persistState();
  render();
}

function sectionForStepField(key) {
  if (["time", "pain"].includes(key)) return "value";
  if (["trigger", "handoff", "decision", "exceptions", "pattern", "toolFit", "openQuestions"].includes(key)) return "blueprint";
  return "workflow";
}

function stepFieldMeta() {
  return [
    { key: "action", label: "Action", icon: "play-circle", prompt: "what action is performed in this step", required: true },
    { key: "actor", label: "Actor", icon: "user-round", prompt: "who performs this step", required: true },
    { key: "tool", label: "Tools", icon: "monitor-cog", prompt: "what systems, tools, templates, folders, or communications are used", required: true },
    { key: "accessMode", label: "Access", icon: "key-round", prompt: "whether this step uses direct system access, Microsoft 365 files, exports, screenshots, transcripts, or user-provided inputs", required: true },
    { key: "input", label: "Input", icon: "log-in", prompt: "what information, file, event, or artifact is needed before this step can start", required: true },
    { key: "dataHandling", label: "Data Handling", icon: "database", prompt: "what is done with the data or content during the step", required: true },
    { key: "output", label: "Output", icon: "corner-down-right", prompt: "what output, artifact, record, message, or decision is produced", required: true },
    { key: "handoff", label: "Handoff", icon: "send", prompt: "who or what receives the output next", required: true },
    { key: "trigger", label: "Trigger", icon: "radio-tower", prompt: "what triggers this step or gates it from the previous step", required: true },
    { key: "time", label: "Time", icon: "timer", prompt: "roughly how long this step takes each time", required: true },
    { key: "decision", label: "Decision", icon: "git-branch", prompt: "whether a human decision, approval, review, or escalation happens", required: true },
    { key: "pain", label: "Pain", icon: "triangle-alert", prompt: "what makes this step repetitive, slow, painful, or risky", required: false },
    { key: "exceptions", label: "Variations", icon: "split", prompt: "what exceptions, variants, edge cases, or special handling happen", required: false },
    { key: "dataSensitivity", label: "Sensitivity", icon: "shield-check", prompt: "whether this step involves client, confidential, regulated, personal, financial, or internal data", required: true },
    { key: "evidenceConfidence", label: "Confidence", icon: "badge-check", prompt: "how confident we are in this captured step: high, medium, low, or unknown", required: false }
  ];
}

function stepFieldStatusList(step) {
  return stepFieldMeta().map((item) => {
    const value = stepFieldValue(step, item.key);
    const captured = isCapturedValue(value);
    const inferred = !captured && ["pain", "pattern", "toolFit"].includes(item.key);
    return {
      ...item,
      value,
      status: captured ? "captured" : inferred ? "inferred" : item.required ? "missing" : "open"
    };
  });
}

function stepMissingFields(step) {
  return stepFieldStatusList(step).filter((item) => item.required && item.status === "missing");
}

function stepCompletion(step) {
  const required = stepFieldMeta().filter((item) => item.required);
  const captured = required.filter((item) => isCapturedValue(stepFieldValue(step, item.key))).length;
  return Math.round((captured / required.length) * 100);
}

function stepLabel(step, index = state.steps.indexOf(step)) {
  return step?.name || step?.action || `Step ${(index >= 0 ? index : getCurrentStepIndex()) + 1}`;
}

function stepQuestionForCluster(step, cluster) {
  if (!step || !cluster) return "";
  const missing = cluster.keys
    .map((key) => stepFieldMeta().find((item) => item.key === key))
    .filter((item) => item && !isCapturedValue(stepFieldValue(step, item.key)));
  if (!missing.length) return cluster.question;
  const capturedLabels = cluster.keys
    .map((key) => stepFieldMeta().find((item) => item.key === key))
    .filter((item) => item && isCapturedValue(stepFieldValue(step, item.key)))
    .map((item) => item.label.toLowerCase());
  const archetypeQuestion = archetypeStepQuestionForCluster(step, cluster, missing, capturedLabels);
  if (archetypeQuestion) return archetypeQuestion;
  if (missing.length === cluster.keys.length) return cluster.question;
  const missingRequired = missing.filter((item) => item.required);
  const priority = missingRequired.length ? missingRequired : missing;
  const prompt = missingFieldPrompt(priority);
  const captured = capturedPrefixForCluster(cluster, capturedLabels);
  return `For "${stepLabel(step)}", ${captured}${captured ? capitalizeSentence(prompt) : prompt}`;
}

function capitalizeSentence(text = "") {
  const trimmed = String(text || "").trim();
  return trimmed ? `${trimmed.charAt(0).toUpperCase()}${trimmed.slice(1)}` : "";
}

function capturedPrefixForCluster(cluster, capturedLabels = []) {
  if (!capturedLabels.length) return "";
  if (cluster?.id === "who_where") return `I captured ${capturedLabels.join(", ")}. `;
  if (capturedLabels.length >= 2 && cluster?.id !== "time_judgment") return `I captured ${capturedLabels.join(", ")}. `;
  return "";
}

function missingFieldPrompt(fields = []) {
  const keys = fields.map((item) => item.key);
  if (keys.length === 1) {
    const item = fields[0];
    if (item.key === "actor") return "who performs this step?";
    if (item.key === "tool") return "what systems, tools, templates, folders, files, or communications are used?";
    if (item.key === "accessMode") return "how is the work accessed: direct system access, Microsoft 365 files, exports/screenshots, transcripts, or user-provided inputs?";
    if (item.key === "input") return "what information, file, event, or artifact is needed before this step can start?";
    if (item.key === "dataHandling") return "what is done with the data or content during this step?";
    if (item.key === "dataSensitivity") return "what sensitivity category should we assume: internal, client confidential, regulated, personal, financial, or unknown?";
    if (item.key === "output") return "what output, artifact, record, message, or decision is produced?";
    if (item.key === "handoff") return "who or what receives the output next?";
    if (item.key === "trigger") return "what triggers this step or gates it from the prior step?";
    if (item.key === "time") return "roughly how long does this step take each time?";
    if (item.key === "decision") return "what human judgment, review, approval, or escalation happens?";
    return `${item.prompt}?`;
  }
  const labels = fields.map((item) => item.label.toLowerCase());
  const prompts = fields.map((item) => item.prompt).join("; ");
  return `what are the missing ${labels.join(" and ")} details (${prompts})?`;
}

function archetypeStepQuestionForCluster(step, cluster, missing = [], capturedLabels = []) {
  if (!step || !cluster || !missing.length) return "";
  if (capturedLabels.length && missing.length < cluster.keys.length) {
    const missingRequired = missing.filter((item) => item.required);
    const priority = missingRequired.length ? missingRequired : missing;
    const prompt = missingFieldPrompt(priority);
    const captured = capturedPrefixForCluster(cluster, capturedLabels);
    return `For "${stepLabel(step)}", ${captured}${captured ? capitalizeSentence(prompt) : prompt}`;
  }
  const archetype = activeUseCaseArchetype();
  const promptMap = archetypeClusterPrompts(archetype.id);
  const prompt = promptMap[cluster.id];
  if (!prompt) return "";
  const prefix = capturedLabels.length
    ? `For "${stepLabel(step)}", I captured ${capturedLabels.join(", ")}. `
    : `For "${stepLabel(step)}", `;
  return `${prefix}${capturedLabels.length ? capitalizeSentence(prompt) : prompt}`;
}

function archetypeClusterPrompts(archetypeId = "") {
  const maps = {
    "testing-qa-automation": {
      who_where: "who owns this testing work, and which requirement tool, test manager, repo, CI log, template, or data source do they use?",
      inputs_data: "what requirement, story, PR diff, test data, fixture, or CI log goes in, and what sensitivity or synthetic-data rule applies?",
      outputs_flow: "what test artifact, coverage map, failure summary, ticket, or script comes out, and who reviews or uses it next?",
      time_judgment: "how long does this take today, and who approves the generated tests, automation update, or failure-triage recommendation?",
      friction_variants: "what usually creates rework: unclear requirements, flaky tests, missing data, CI noise, environment issues, or reviewer disagreement?"
    },
    "uat-test-script-automation": {
      who_where: "which role writes or reviews this UAT work, and which requirements, process-flow, test-script, or client template tools are used?",
      inputs_data: "what requirement, user story, process flow, or data condition feeds the test script, and what client-data rules apply?",
      outputs_flow: "what script, expected result, defect note, or signoff artifact comes out, and who receives it?",
      time_judgment: "how long does this take per script or sprint, and who validates coverage before execution?",
      friction_variants: "what varies across clients or programs: templates, source inputs, approval rules, test data, or defect handling?"
    },
    "requirements-traceability": {
      who_where: "who turns the ask into structured requirements, and which meeting notes, Jira items, diagrams, data catalogs, or spreadsheets are used?",
      inputs_data: "what source notes, business rules, data mappings, or acceptance criteria go in, and how are assumptions separated from facts?",
      outputs_flow: "what story, diagram, mapping, RTM, or acceptance-test artifact comes out, and who reviews it?",
      time_judgment: "how long does drafting or mapping take, and where does SME or product-owner judgment happen?",
      friction_variants: "what causes rework: unclear asks, missing SMEs, conflicting data definitions, edge cases, or compliance traceability?"
    },
    "governance-summarization": {
      who_where: "who creates this governance output, and which Teams meetings, transcripts, notes, Jira/Confluence updates, templates, or repositories are used?",
      inputs_data: "what meeting, status, decision, risk, or action data goes in, and what should be treated as source evidence?",
      outputs_flow: "what approved minutes, status report, decision log, or project summary comes out, and where is it distributed or archived?",
      time_judgment: "how long does this take per meeting or reporting cycle, and who approves accuracy and client-safe language?",
      friction_variants: "what breaks the flow: missing notes, inconsistent templates, late workstream inputs, unclear owners, or sensitive wording?"
    },
    "agile-ceremony-planning": {
      who_where: "who runs this ceremony work, and which Jira/Jira Align, Teams, Confluence, backlog, deck, or repository sources are used?",
      inputs_data: "what backlog, attendance, scope, release, dependency, or demo data goes in, and what must be kept traceable?",
      outputs_flow: "what plan, sprint board update, demo pack, release note, or status artifact comes out, and who receives it?",
      time_judgment: "how long does this take in the sprint or PI cycle, and who approves scope, sequencing, and exceptions?",
      friction_variants: "what varies by client or framework: SAFe rules, team cadence, backlog quality, attendance, or artifact standards?"
    },
    "document-review-upload": {
      who_where: "who reviews or uploads the document, and which folders, document systems, CRM screens, templates, or approval trackers are used?",
      inputs_data: "what document type, metadata, approval evidence, or extracted field goes in, and what client/legal sensitivity applies?",
      outputs_flow: "what CRM record, uploaded document, missing-document note, or approval status comes out, and who gets notified?",
      time_judgment: "how long does review/upload take per document set, and who confirms the document type and field accuracy?",
      friction_variants: "what causes exceptions: missing documents, mismatched metadata, duplicate records, unclear approval, or system constraints?"
    },
    "data-quality-exceptions": {
      who_where: "who owns this exception, and which DQ tool, API, SQL script, dashboard, tracker, ticketing system, or source system is used?",
      inputs_data: "what error context, source record, business rule, or comparison data goes in, and what sensitivity category applies?",
      outputs_flow: "what analysis, suggested fix, routed ticket, dashboard update, or closure evidence comes out, and who receives it?",
      time_judgment: "how long does this exception take today, and who validates ownership, SQL/fix recommendations, and closure?",
      friction_variants: "what varies across exceptions: source ownership, error taxonomy, missing data, ticket routing, or approval rules?"
    },
    "risk-assessment": {
      who_where: "who performs the assessment, and which architecture docs, NFRs, ServiceNow records, repositories, or risk templates are used?",
      inputs_data: "what architecture, control, vulnerability, system, or client-context evidence goes in, and how sensitive is it?",
      outputs_flow: "what risk scope, assessment finding, control note, or ServiceNow update comes out, and who reviews it?",
      time_judgment: "how long does scoping or assessment take, and who decides risk severity, prioritization, and acceptance?",
      friction_variants: "what creates uncertainty: missing architecture records, unclear ownership, inconsistent controls, or client-specific standards?"
    },
    "analytics-insights": {
      who_where: "who uses this insight, and which databases, market sources, spreadsheets, RM tools, or client systems are used?",
      inputs_data: "what client, market, position, volume, profitability, or public data goes in, and what sensitivity or model-risk constraints apply?",
      outputs_flow: "what insight, recommendation, alert, report, or RM action comes out, and who decides what to do with it?",
      time_judgment: "how often is this analysis run, how long does it take, and who validates the recommendation before use?",
      friction_variants: "what varies by client or market condition: source availability, data freshness, thresholds, interpretation, or actionability?"
    },
    "research-benchmarking": {
      who_where: "who performs the research, and which research subscriptions, project repositories, decks, PowerPoint files, or knowledge sources are used?",
      inputs_data: "what market, competitor, vendor, prior-deliverable, or thought-leadership source goes in, and what citation is required?",
      outputs_flow: "what brief, benchmark, POV, proposal input, or outbound artifact comes out, and who reviews it?",
      time_judgment: "how long does research and synthesis take, and who approves claims before reuse or external use?",
      friction_variants: "what slows this down: source access, citation confidence, stale research, inconsistent prior work, or SME review?"
    },
    "workshop-acceleration": {
      who_where: "who owns this workshop step, and which SharePoint folders, prior decks, Teams notes, PowerPoint templates, Miro/Mural boards, or trackers are used?",
      inputs_data: "what objective, attendee context, prior collateral, client note, or hypothesis goes in, and what sensitivity applies?",
      outputs_flow: "what agenda, pre-read, facilitation prompt, breakout activity, board, deck, or synthesis artifact comes out, and who receives it?",
      time_judgment: "how long does this take, and where do partner, facilitator, or client-sponsor judgment and approval happen?",
      friction_variants: "what varies across workshops: audience, commercial context, client politics, reusable assets, facilitation style, or output format?"
    },
    "pursuit-response": {
      who_where: "who owns this proposal step, and which RFP, CRM, content library, SharePoint folder, Word/PowerPoint template, or pricing/legal source is used?",
      inputs_data: "what RFP requirement, credential, case study, pricing assumption, or SME answer goes in, and what confidentiality rule applies?",
      outputs_flow: "what compliance matrix, response section, proposal deck, review note, or packaged response comes out, and who reviews it?",
      time_judgment: "how long does this take under deadline, and who approves client claims, pricing, legal language, and final response quality?",
      friction_variants: "what changes by pursuit: RFP format, content reuse, SME availability, credential confidence, pricing, or legal review?"
    },
    "post-delivery-assets": {
      who_where: "who owns closeout reuse, and which final decks, SharePoint folders, lessons learned, trackers, or practice library tools are used?",
      inputs_data: "what final deliverable, client context, reusable template, lesson, or artifact goes in, and what must be sanitized?",
      outputs_flow: "what reusable asset, metadata record, sanitized summary, or practice-library entry comes out, and who approves it?",
      time_judgment: "how long does closeout packaging take, and who decides what is safe and valuable enough to reuse?",
      friction_variants: "what prevents reuse: client sensitivity, unclear final files, missing metadata, low ownership, or review delay?"
    }
  };
  return maps[archetypeId] || {};
}

function drilldownClusters(step) {
  const stepIndex = state.steps.indexOf(step);
  const stepName = stepLabel(step, stepIndex);
  return [
    {
      id: "who_where",
      label: "Who + where",
      icon: "users-round",
      keys: ["actor", "tool", "accessMode"],
      question: `For "${stepName}", who does this step, where does it happen, and what systems, folders, templates, or files are used? If you know, include whether access is direct, Microsoft 365 file-based, export/screenshot-based, transcript-based, or unknown.`
    },
    {
      id: "inputs_data",
      label: "Inputs + data",
      icon: "database",
      keys: ["input", "dataHandling", "dataSensitivity"],
      question: `For "${stepName}", what information goes in, what is done to it, and what sensitivity category should we assume?`
    },
    {
      id: "outputs_flow",
      label: "Output + handoff",
      icon: "send",
      keys: ["output", "handoff", "trigger"],
      question: `For "${stepName}", what triggers it, what comes out, and who or what receives the output next?`
    },
    {
      id: "time_judgment",
      label: "Time + judgment",
      icon: "timer",
      keys: ["time", "decision"],
      question: `For "${stepName}", how long does it usually take, and what human review, judgment, approval, or escalation happens?`
    },
    {
      id: "friction_variants",
      label: "Friction + variants",
      icon: "triangle-alert",
      keys: ["pain", "exceptions"],
      optional: true,
      question: `For "${stepName}", what makes this step slow, repetitive, risky, or variable across projects?`
    }
  ];
}

function clusterComplete(step, cluster) {
  return cluster.keys.every((key) => isCapturedValue(stepFieldValue(step, key)));
}

function currentDrilldownCluster(step = getCurrentStep()) {
  if (!step) return null;
  const clusters = drilldownClusters(step);
  return clusters.find((cluster) => !clusterComplete(step, cluster)) || clusters[clusters.length - 1];
}

function activeStepFieldKeys() {
  const cluster = currentDrilldownCluster();
  return cluster?.keys || [];
}

function explicitStepIndexFromAnswer(answer = "") {
  if (!state.steps.length) return -1;
  const text = String(answer || "").toLowerCase();
  const wordNumbers = {
    one: 1,
    two: 2,
    three: 3,
    four: 4,
    five: 5,
    six: 6,
    seven: 7,
    eight: 8,
    nine: 9,
    ten: 10
  };
  const ordinalNumbers = {
    first: 1,
    second: 2,
    third: 3,
    fourth: 4,
    fifth: 5,
    sixth: 6,
    seventh: 7,
    eighth: 8,
    ninth: 9,
    tenth: 10
  };
  const stepMatch = text.match(/\bstep\s+(\d{1,2}|one|two|three|four|five|six|seven|eight|nine|ten)\b/i)
    || text.match(/\b(first|second|third|fourth|fifth|sixth|seventh|eighth|ninth|tenth)\s+step\b/i);
  const raw = stepMatch?.[1]?.toLowerCase();
  const number = Number(raw) || wordNumbers[raw] || ordinalNumbers[raw] || 0;
  if (!number || number < 1 || number > state.steps.length) return -1;
  return number - 1;
}

function firstIncompleteStepIndex(startIndex = 0) {
  if (!state.steps.length) return -1;
  for (let index = startIndex; index < state.steps.length; index += 1) {
    if (stepMissingFields(state.steps[index]).length) return index;
  }
  for (let index = 0; index < startIndex; index += 1) {
    if (stepMissingFields(state.steps[index]).length) return index;
  }
  return -1;
}

function advanceToNextIncompleteStep() {
  ensureDrilldownState();
  if (!state.steps.length || state.drilldown.status !== "active") return false;
  const currentIndex = getCurrentStepIndex();
  const earliestIncompleteIndex = firstIncompleteStepIndex(0);
  if (!state.drilldown.manualStepFocus && earliestIncompleteIndex >= 0 && earliestIncompleteIndex < currentIndex) {
    state.activeStepIndex = earliestIncompleteIndex;
    const earliestCluster = currentDrilldownCluster(state.steps[earliestIncompleteIndex]);
    state.drilldown.currentClusterId = earliestCluster?.id || "";
    return true;
  }
  const current = state.steps[currentIndex];
  if (current && stepMissingFields(current).length) return false;
  const nextIndex = firstIncompleteStepIndex(Math.min(currentIndex + 1, state.steps.length - 1));
  if (nextIndex < 0 || nextIndex === currentIndex) return false;
  state.activeStepIndex = nextIndex;
  const cluster = currentDrilldownCluster(state.steps[nextIndex]);
  state.drilldown.currentClusterId = cluster?.id || "";
  return true;
}

function syncGuidedDrilldownAfterExtraction({ beforeStepCount = 0, touchedStepIndex = -1, force = false } = {}) {
  ensureDrilldownState();
  if (!state.drilldown.enabled || !state.steps.length) return false;
  state.drilldown.manualStepFocus = false;

  // Phase 1 Frame Builder — State 2. While the rough frame is awaiting the user's
  // explicit confirmation, keep merging captured steps into it but never auto-
  // advance into the Phase 2 deep dive. The user advances via the confirm bar
  // ("Looks right — go step by step") or a "yes" answer.
  if (state.drilldown.status === "confirmSkeleton" && !force) {
    state.activeSection = "workflow";
    return true;
  }

  const hadNewSkeleton = beforeStepCount === 0 && state.steps.length > 0;
  const currentIndex = getCurrentStepIndex();
  const currentStillNeedsDetail = state.steps[currentIndex] && stepMissingFields(state.steps[currentIndex]).length > 0;
  let targetIndex = touchedStepIndex >= 0 ? touchedStepIndex : currentIndex;
  if ((beforeStepCount || 0) > 0 && currentStillNeedsDetail && touchedStepIndex !== currentIndex) {
    targetIndex = currentIndex;
  }
  if (hadNewSkeleton && !force && !state.drilldown.skeletonConfirmed) {
    // Phase 1 Frame Builder — State 2. The broad overview just produced the rough
    // frame for the first time; surface the confirm view instead of jumping
    // straight into the step-by-step deep dive.
    state.activeSection = "workflow";
    state.activeStepIndex = 0;
    state.drilldown.skeletonConfirmed = false;
    state.drilldown.status = "confirmSkeleton";
    state.currentQuestionOverride = skeletonConfirmationQuestion();
    state.currentQuestionSource = "Frame confirmation";
    state.drilldown.lastPrompt = state.currentQuestionOverride;
    return true;
  }

  if (hadNewSkeleton || force) {
    targetIndex = firstIncompleteStepIndex(0);
  } else if (targetIndex >= 0 && stepMissingFields(state.steps[targetIndex]).length === 0) {
    const next = firstIncompleteStepIndex(Math.min(targetIndex + 1, state.steps.length - 1));
    if (next >= 0 && next !== targetIndex) targetIndex = next;
  }

  if (targetIndex < 0) {
    state.drilldown.status = "readyForMapReview";
    state.currentQuestionOverride = "The step details look filled enough for a first pass. Can you review the process map and tell me what is missing, duplicated, or out of order?";
    state.currentQuestionSource = "Guided step drill-down";
    state.activeSection = "review";
    return true;
  }

  state.activeStepIndex = targetIndex;
  state.activeSection = "workflow";
  const cluster = currentDrilldownCluster(state.steps[targetIndex]);
  state.drilldown.status = "active";
  lockWorkflowStepList();
  state.drilldown.currentClusterId = cluster?.id || "";
  state.currentQuestionOverride = stepInterviewQuestion();
  state.currentQuestionSource = "Guided step drill-down";
  state.drilldown.lastPrompt = state.currentQuestionOverride;
  return true;
}

function skeletonConfirmationQuestion() {
  if (!state.steps.length) return "Walk me through this from start to finish — what's the first thing that happens, and where does it end up?";
  const preview = state.steps
    .slice(0, 6)
    .map((step, index) => `${index + 1}. ${step.name || step.action || `Step ${index + 1}`}`)
    .join("; ");
  const suffix = state.steps.length > 6 ? `; plus ${state.steps.length - 6} more` : "";
  return `I captured these as the major workflow steps: ${preview}${suffix}. I will use this as the working skeleton and start with Step 1 details. Correct, rename, add, remove, merge, split, or reorder steps anytime.`;
}

function stepInterviewQuestion() {
  if (!state.steps.length) return "Can you give me the rough numbered A-to-Z workflow before we fill in details?";
  if (state.drilldown?.status === "confirmSkeleton") return skeletonConfirmationQuestion();
  advanceToNextIncompleteStep();
  const step = getCurrentStep();
  const cluster = currentDrilldownCluster(step);
  if (cluster && (!cluster.optional || !clusterComplete(step, cluster))) return stepQuestionForCluster(step, cluster);
  const nextIndex = firstIncompleteStepIndex(Math.min(getCurrentStepIndex() + 1, state.steps.length - 1));
  if (nextIndex >= 0 && nextIndex !== getCurrentStepIndex()) {
    const nextStep = state.steps[nextIndex];
    const nextCluster = currentDrilldownCluster(nextStep);
    return nextCluster?.question || `Tell me more about Step ${nextIndex + 1} (${nextStep.name || nextStep.action || "the next step"}): who does it, what systems or files are used, what goes in and comes out, how often or how long it takes, and where human judgment happens?`;
  }
  return "The captured steps look filled enough for a first pass. Review the process map and tell me what is missing, duplicated, out of order, or unusually high-friction.";
}

function renderNav() {
  els.sectionNavs.forEach((nav) => {
    nav.innerHTML = "";
    getVisibleSections().forEach((section) => {
      const status = getSectionStatus(section);
      const button = document.createElement("button");
      button.type = "button";
      button.className = `section-button ${state.activeSection === section.id ? "active" : ""} ${status.className}`;
      button.innerHTML = `
        <span class="section-icon"><i data-lucide="${section.icon || "circle"}"></i></span>
        <span class="section-copy">
          <span class="section-name">${section.label}</span>
          <span class="section-score">${status.label}</span>
        </span>
      `;
      button.addEventListener("click", () => {
        state.activeSection = section.id;
        state.currentQuestionOverride = "";
        state.currentQuestionSource = "Intake guide";
        persistState();
        render();
      });
      nav.appendChild(button);
    });
  });
}

function renderConversation() {
  els.conversationLog.innerHTML = "";
  const messages = state.conversation?.length ? state.conversation : [];
  const visibleMessages = messages.slice(-2);
  const hiddenCount = Math.max(0, messages.length - visibleMessages.length);
  if (hiddenCount) {
    const note = document.createElement("div");
    note.className = "conversation-history-note";
    note.textContent = `${hiddenCount} older turn${hiddenCount === 1 ? "" : "s"} saved in full history`;
    els.conversationLog.appendChild(note);
  }
  visibleMessages.forEach((message) => {
    const item = document.createElement("div");
    const fullText = String(message.text || "").trim();
    const text = compactConversationMessage(message);
    const isLong = fullText.replace(/\s+/g, " ").trim().length > text.length;
    item.className = `message ${message.role === "user" ? "user" : "assistant"}`;
    item.innerHTML = `
      <div class="message-meta">
        <span>${message.role === "user" ? "User" : "AI"}</span>
        <span>${escapeHtml(message.section || "")}</span>
      </div>
      <div>
        <span class="message-preview">${escapeHtml(text)}</span>
        ${isLong ? `
          <details class="message-expand" name="transcript-turn">
            <summary>Show full turn</summary>
            <p>${escapeHtml(fullText)}</p>
          </details>
        ` : ""}
      </div>
    `;
    els.conversationLog.appendChild(item);
  });
  els.conversationLog.scrollTop = els.conversationLog.scrollHeight;
}

function compactConversationMessage(message = {}) {
  const text = String(message.text || "").replace(/\s+/g, " ").trim();
  return truncateUi(text, message.role === "user" ? 145 : 128);
}

function renderLiveSpeechDraft() {
  if (!els.liveSpeechDraft) return;
  const text = liveSpeechDraftText.trim();
  els.liveSpeechDraft.hidden = !text;
  els.liveSpeechDraft.innerHTML = text
    ? `
      <div class="message user live-draft">
        <div class="message-meta">
          <span>Recording</span>
          <span>Live draft</span>
        </div>
        <div>${escapeHtml(text)}</div>
      </div>
    `
    : "";
}

function renderAiChat() {
  els.aiChatLog.innerHTML = "";
  const messages = state.aiChat?.length ? state.aiChat : [];
  messages.forEach((message) => {
    const item = document.createElement("div");
    item.className = `message ${message.role === "user" ? "user" : "assistant"}`;
    item.innerHTML = `
      <div class="message-meta">
        <span>${message.role === "user" ? "You" : "AI"}</span>
        <span>${new Date(message.time || Date.now()).toLocaleTimeString([], { hour: "numeric", minute: "2-digit" })}</span>
      </div>
      <div>${escapeHtml(message.text)}</div>
    `;
    els.aiChatLog.appendChild(item);
  });
  els.aiChatLog.scrollTop = els.aiChatLog.scrollHeight;
}

function renderTextIntakeAssist() {
  if (!els.textIntakeAssist || !els.answerNudges) return;
  const draft = els.aiChatInput?.value.trim() || els.answerInput?.value.trim() || "";
  const route = inferTextIntakeRoute(draft);
  const missing = currentMissingTextFields();
  const caution = textDataCaution(draft);
  els.textIntakeAssist.innerHTML = `
    <div class="intake-router-card ${escapeHtml(route.tone)}">
      <div class="router-heading">
        <span><i data-lucide="${route.icon}"></i></span>
        <div>
          <p class="eyebrow">Closest intake area</p>
          <strong>${escapeHtml(route.area)}</strong>
        </div>
      </div>
      <p>${escapeHtml(route.reason)}</p>
      <div class="router-chip-row">
        ${route.fields.map((field) => `<span>${escapeHtml(field)}</span>`).join("")}
      </div>
      ${missing ? `<small>Missing next: ${escapeHtml(missing)}</small>` : ""}
      ${caution ? `<small class="router-caution"><i data-lucide="shield-alert"></i>${escapeHtml(caution)}</small>` : ""}
    </div>
  `;
  els.answerNudges.innerHTML = `
    <div class="answer-nudge-heading">
      <span>Helpful answer shape</span>
      <small>${escapeHtml(route.cta)}</small>
    </div>
    <div class="answer-nudge-row">
      ${answerNudgeTemplates().map((item) => `
        <button type="button" data-answer-nudge="${escapeHtml(item.template)}">
          <i data-lucide="${item.icon}"></i>
          ${escapeHtml(item.label)}
        </button>
      `).join("")}
    </div>
  `;
  refreshIcons();
}

function inferTextIntakeRoute(text = "") {
  const lower = String(text || "").toLowerCase();
  const currentStep = getCurrentStep();
  if (!lower.trim()) {
    const cluster = currentDrilldownCluster(currentStep);
    return {
      area: currentStep ? `Current step: ${cluster?.label || "Step detail"}` : "Workflow frame",
      icon: currentStep ? cluster?.icon || "corner-down-right" : "file-question",
      tone: "idle",
      reason: currentStep ? "Type or paste what you know. The app will place it into the active step matrix." : "Start with the idea, workflow boundary, or a rough numbered A-to-Z process.",
      fields: currentStep ? activeStepFieldKeys().map((key) => stepFieldMeta().find((item) => item.key === key)?.label).filter(Boolean) : ["Idea", "Category", "A-Z process"],
      cta: currentStep ? "Mention the missing details if you know them." : "A rough description is enough to begin."
    };
  }

  const signals = [
    {
      area: "Step actor, tools, and access",
      icon: "monitor-cog",
      tone: "strong",
      terms: ["manager", "lead", "analyst", "team", "sharepoint", "teams", "email", "outlook", "excel", "powerpoint", "word", "tracker", "folder", "file-based", "direct access", "system access", "export", "screenshot", "transcript"],
      fields: ["Actor", "Tools", "Access mode"],
      reason: "This looks like who performs the step and where the work happens.",
      cta: "Actor + tools + access is the right bundle here."
    },
    {
      area: "Inputs, data handling, and sensitivity",
      icon: "database",
      tone: "risk",
      terms: ["input", "data", "client", "customer", "confidential", "pii", "mnpi", "regulated", "sensitive", "raw", "sanitize", "anonym"],
      fields: ["Input", "Data handling", "Sensitivity"],
      reason: "This looks like source data or client-data boundary context.",
      cta: "Name categories, not raw client data."
    },
    {
      area: "Output and handoff",
      icon: "send",
      tone: "strong",
      terms: ["output", "deliverable", "deck", "report", "memo", "email", "send", "handoff", "final", "package", "artifact"],
      fields: ["Output", "Handoff", "Trigger"],
      reason: "This looks like what the step produces and who receives it.",
      cta: "Include recipient and format if known."
    },
    {
      area: "Timing, value, and friction",
      icon: "timer",
      tone: "warn",
      terms: ["hour", "hours", "day", "daily", "weekly", "month", "frequency", "often", "manual", "slow", "rework", "pain", "capacity", "time"],
      fields: ["Time", "Frequency", "Pain"],
      reason: "This helps quantify value and prioritize the opportunity.",
      cta: "Rough estimates are fine."
    },
    {
      area: "Human judgment and review",
      icon: "git-branch",
      tone: "warn",
      terms: ["review", "approve", "approval", "judgment", "decision", "escalation", "sign off", "qa", "quality"],
      fields: ["Decision", "Approval", "Risk"],
      reason: "This clarifies where human control must remain.",
      cta: "Name the reviewer and decision criteria."
    }
  ];
  const scored = signals
    .map((signal) => ({ ...signal, score: signal.terms.filter((term) => lower.includes(term)).length }))
    .sort((a, b) => b.score - a.score);
  const winner = scored[0];
  if (winner?.score) return winner;
  return {
    area: currentStep ? "Current step notes" : "Workflow context",
    icon: currentStep ? "corner-down-right" : "workflow",
    tone: "idle",
    reason: currentStep ? "This will be checked against the active step and any missing Product/Engineering handoff fields." : "This will help classify the workflow and decide the next question.",
    fields: currentStep ? activeStepFieldKeys().map((key) => stepFieldMeta().find((item) => item.key === key)?.label).filter(Boolean) : ["Workflow", "Context", "Open question"],
    cta: "Add enough detail for a colleague to understand the work."
  };
}

function currentMissingTextFields() {
  const step = getCurrentStep();
  if (!step) return topCompletionQuestions(1)[0] || "";
  const cluster = currentDrilldownCluster(step);
  const missing = cluster?.keys
    .map((key) => stepFieldMeta().find((item) => item.key === key))
    .filter((item) => item && !isCapturedValue(stepFieldValue(step, item.key)))
    .map((item) => item.label);
  return missing?.join(", ") || stepMissingFields(step).slice(0, 3).map((item) => item.label).join(", ");
}

function textDataCaution(text = "") {
  const lower = String(text || "").toLowerCase();
  if (!/(client|customer|confidential|pii|mnpi|regulated|sensitive|account|transaction|claim)/.test(lower)) return "";
  return "Client/customer data signal: capture categories, access path, and sensitivity; avoid raw data in the intake.";
}

function activeUseCaseArchetype() {
  return inferUseCaseArchetypeFromText(useCaseArchetypeSourceText());
}

function useCaseArchetypeSourceText(extra = "") {
  return [
    extra,
    state.fields.useCaseArchetype,
    state.fields.submittedIdea,
    state.fields.submittedWorkflowTask,
    state.fields.submittedWhereToday,
    state.fields.submittedCandidateAiAssist,
    state.fields.submittedExpectedImpact,
    state.fields.submittedNotes,
    state.fields.workflowName,
    state.fields.currentStateSummary,
    state.fields.solutionHypothesis,
    state.fields.domain,
    state.steps.map((step) => `${step.name} ${step.action} ${step.tool} ${step.input} ${step.output}`).join(" ")
  ].filter(Boolean).join(" ");
}

function inferUseCaseArchetypeFromText(text = "") {
  const lower = String(text || "").toLowerCase();
  const storedArchetype = String(state.fields.useCaseArchetype || "").toLowerCase();
  const explicit = useCaseArchetypes.find((item) => (
    item.id.toLowerCase() === storedArchetype
    || item.label.toLowerCase() === storedArchetype
  ));
  if (explicit && (!lower.trim() || lower.includes(explicit.id.toLowerCase()) || lower.includes(explicit.label.toLowerCase()))) return { ...explicit, score: 99, inferred: false };
  const scored = useCaseArchetypes
    .map((item) => ({
      ...item,
      score: item.cues.reduce((sum, cue) => sum + (lower.includes(cue.toLowerCase()) ? 1 : 0), 0)
    }))
    .sort((a, b) => b.score - a.score);
  if (scored[0]?.score) return { ...scored[0], inferred: true };
  return {
    id: "unknown",
    label: "Unknown",
    icon: "scan-search",
    category: state.fields.workflowCategory || "unknown",
    cues: [],
    firstQuestion: "What kind of work is this closest to: testing, requirements, governance, document review, data quality, analytics, research, workshop, pursuit, or post-delivery synthesis?",
    pdrFocus: "Classify the work pattern before routing Product and Engineering questions.",
    score: 0,
    inferred: false
  };
}

function archetypeConfidenceLabel(archetype = activeUseCaseArchetype()) {
  if (!archetype || archetype.id === "unknown") return "Needs lens";
  if (archetype.inferred) return "Inferred lens";
  return "Confirmed lens";
}

function archetypeReadinessScore(archetype = activeUseCaseArchetype()) {
  if (!archetype || archetype.id === "unknown") return 20;
  const evidence = [
    state.fields.useCaseArchetype !== "unknown" ? state.fields.useCaseArchetype : "",
    state.fields.workflowCategory !== "unknown" ? state.fields.workflowCategory : "",
    state.fields.submittedWorkflowTask,
    state.fields.currentStateSummary,
    state.steps.length >= 3 ? "steps" : "",
    state.fields.candidateAiAssistValidation
  ].filter(isCapturedValue).length;
  return Math.min(100, 30 + evidence * 12 + Math.min(20, (archetype.score || 0) * 4));
}

function archetypeFollowUpQuestion(archetype = activeUseCaseArchetype()) {
  if (!archetype || archetype.id === "unknown") return "Which use-case pattern is this closest to, and which submitted details are just hypotheses versus confirmed current-state facts?";
  if (!state.steps.length) return archetype.firstQuestion;
  if (!isCapturedValue(state.fields.candidateAiAssistValidation) && isCapturedValue(state.fields.submittedCandidateAiAssist)) {
    return `For this ${archetype.label.toLowerCase()} use case, which part of the submitted AI idea is confirmed by the current workflow, and which part is still just a hypothesis?`;
  }
  if (!isCapturedValue(state.fields.submittedExpectedImpact) && !isCapturedValue(state.fields.valueHypothesis)) {
    return `For this ${archetype.label.toLowerCase()} use case, what impact should we test first: time saved, quality, rework, risk reduction, reuse, or delivery speed?`;
  }
  return archetype.firstQuestion;
}

function answerNudgeTemplates() {
  const step = getCurrentStep();
  const cluster = currentDrilldownCluster(step);
  if (!step || !cluster) {
    return [
      { label: "Idea", icon: "lightbulb", template: "Idea / workflow: \nWhere it happens today: \nWhy it matters: " },
      { label: "A-Z steps", icon: "list-ordered", template: "1. \n2. \n3. \n4. " },
      { label: "Context", icon: "briefcase-business", template: "Practice / project context: \nCommercial context: \nCurrent pain: " }
    ];
  }
  if (cluster.id === "who_where") {
    return [
      { label: "Who", icon: "user-round", template: "Actor / role: " },
      { label: "Tools", icon: "monitor-cog", template: "Tools, files, folders, or systems: " },
      { label: "Access", icon: "key-round", template: "Access mode: Microsoft 365 files / direct system / export / screenshot / transcript / user-provided inputs. " }
    ];
  }
  if (cluster.id === "inputs_data") {
    return [
      { label: "Input", icon: "log-in", template: "Input: " },
      { label: "Data", icon: "database", template: "Data handled: " },
      { label: "Sensitivity", icon: "shield-check", template: "Sensitivity: internal / client confidential / regulated / PII / unknown. " }
    ];
  }
  if (cluster.id === "outputs_flow") {
    return [
      { label: "Trigger", icon: "radio-tower", template: "Trigger: " },
      { label: "Output", icon: "corner-down-right", template: "Output: " },
      { label: "Handoff", icon: "send", template: "Handoff / recipient: " }
    ];
  }
  return [
    { label: "Timing", icon: "timer", template: "Timing / frequency: " },
    { label: "Review", icon: "git-branch", template: "Human decision or review: " },
    { label: "Friction", icon: "triangle-alert", template: "Pain, rework, exception, or risk: " }
  ];
}

function handleAnswerNudgeClick(event) {
  const button = event.target.closest("[data-answer-nudge]");
  if (!button || !els.aiChatInput) return;
  const template = button.dataset.answerNudge || "";
  const current = els.aiChatInput.value.trim();
  els.aiChatInput.value = current ? `${current}\n${template}` : template;
  els.aiChatInput.focus();
  renderTextIntakeAssist();
}

function renderValidationFlow() {
  if (!els.validationFlow) return;
  const stages = validationStages();
  const active = currentValidationStage(stages);
  els.validationFlow.innerHTML = `
    <div class="validation-flow-heading">
      <div>
        <p class="eyebrow">Validation Flow</p>
        <h3>${escapeHtml(active.label)}</h3>
      </div>
      <span>${validationFlowProgress(stages)}%</span>
    </div>
    <p class="validation-flow-question">${escapeHtml(active.question)}</p>
    <div class="validation-stage-list">
      ${stages.map((stage) => validationStageItem(stage, active.id)).join("")}
    </div>
    <button class="secondary-button compact validation-focus-button" id="focusValidationStageButton" type="button">
      <i data-lucide="corner-down-right"></i>
      Focus This
    </button>
  `;
  document.getElementById("focusValidationStageButton")?.addEventListener("click", () => focusValidationStage(active.id));
  els.validationFlow.querySelectorAll("[data-validation-stage]").forEach((button) => {
    button.addEventListener("click", () => focusValidationStage(button.dataset.validationStage));
  });
  refreshIcons();
}

function validationStageItem(stage, activeId) {
  return `
    <button class="validation-stage ${stage.status} ${stage.optional ? "optional" : ""} ${stage.id === activeId ? "active" : ""}" data-validation-stage="${escapeHtml(stage.id)}" type="button" title="${escapeHtml(stage.detail)}">
      <span><i data-lucide="${stage.icon}"></i></span>
      <strong>${escapeHtml(stage.shortLabel)}</strong>
    </button>
  `;
}

function validationStages() {
  const evidenceReady = hasEvidenceSignal();
  const mapConfirmed = state.mapReviews.some((item) => item.status === "confirmed");
  const matrixScore = matrixCompletionScore();
  const handoffScore = handoffReadinessScore();
  const handoffQuestion = topHandoffChecklistQuestions(1)[0];
  const submittedCaptured = isCapturedValue(state.fields.submittedIdea) || isCapturedValue(state.fields.submittedWorkflowTask);
  const workContextCaptured = isCapturedValue(state.fields.submittedWhereToday) || isCapturedValue(state.fields.engagementProjectType) || isCapturedValue(state.fields.projectPhase);
  const domainCaptured = isCapturedValue(state.fields.domain) || state.fields.practice !== "unknown";
  const boundaryCaptured = [state.fields.workflowName, state.fields.startPoint, state.fields.endPoint, state.fields.businessOutcome].filter(isCapturedValue).length;
  return [
    {
      id: "idea",
      shortLabel: "Idea",
      label: "Workflow snapshot",
      section: "idea",
      icon: "clipboard-list",
      status: submittedCaptured ? "complete" : "active",
      detail: "Start with the work itself: what happens, what output it creates, and what business outcome it supports.",
      question: OPENING_DISCOVERY_QUESTION
    },
    {
      id: "validation",
      shortLabel: "Context",
      label: "Practice and work context",
      section: "validate",
      icon: "search-check",
      status: domainCaptured && workContextCaptured ? "complete" : submittedCaptured ? "active" : "open",
      detail: "Capture where this work lives without turning the interview into a business-case or staffing conversation.",
      question: !domainCaptured ? DOMAIN_CONTEXT_QUESTION : WORK_CONTEXT_QUESTION
    },
    {
      id: "boundary",
      shortLabel: "Frame",
      label: "Frame current-state workflow",
      section: "workflow",
      icon: "route",
      status: boundaryCaptured >= 4 ? "complete" : boundaryCaptured ? "active" : "open",
      detail: "Define the real workflow boundary, start point, end point, output, and outcome.",
      question: WORKFLOW_FRAME_QUESTION
    },
    {
      id: "map",
      shortLabel: "Map",
      label: "Capture A-to-Z process map",
      section: "workflow",
      icon: "list-ordered",
      status: state.steps.length >= 3 && mapConfirmed ? "complete" : state.steps.length ? "active" : "open",
      detail: "Capture and confirm the rough numbered process map before deep-diving into automation.",
      question: state.steps.length ? "Does this A-to-Z process map look right, or are steps missing, duplicated, or out of order?" : PROCESS_MAP_QUESTION
    },
    {
      id: "detail",
      shortLabel: "Detail",
      label: "Enrich steps for handoff",
      section: firstMatrixGap() ? sectionForStepField(firstMatrixGap().key) : "workflow",
      icon: "table-2",
      status: matrixScore >= 70 ? "complete" : matrixScore > 0 ? "active" : "open",
      detail: "Fill actors, tools, inputs, data handling, outputs, handoffs, triggers, time, decisions, sensitivity, and exceptions.",
      question: firstMatrixGap() ? `For "${firstMatrixGap().stepName}", ${firstMatrixGap().prompt}?` : "Are actor, tool, input, data handling, output, handoff, trigger, time, decision, and sensitivity captured for each step?"
    },
    {
      id: "evidence",
      shortLabel: "Evidence",
      label: "Optional evidence add-ons",
      section: "evidence",
      icon: "paperclip",
      optional: true,
      status: evidenceReady ? "complete" : (state.evidenceArtifacts || []).length ? "active" : "optional",
      detail: "Use screenshots, trackers, SOPs, notes, or documents as supporting context when available. They are not required for the intake to work.",
      question: "Optional: are there any screenshots, trackers, SOPs, or example files that would help confirm the process map or data assumptions?"
    },
    {
      id: "candidate",
      shortLabel: "AI Fit",
      label: "Validate candidate AI assist",
      section: "aiFit",
      icon: "sparkles",
      status: isCapturedValue(state.fields.candidateAiAssistValidation) || isCapturedValue(state.fields.toolFitRecommendation) ? "complete" : state.steps.length >= 2 ? "active" : "open",
      detail: "Compare the originally proposed AI assist against the validated workflow rather than accepting it upfront.",
      question: "Now that the workflow is clearer, where does the proposed AI assist fit, where does it not fit, and what assumptions remain?"
    },
    {
      id: "handoff",
      shortLabel: "Handoff",
      label: "Product and Engineering readiness",
      section: "review",
      icon: "package-check",
      status: handoffScore >= 70 ? "complete" : handoffScore >= 35 ? "active" : "open",
      detail: "Confirm Product and Engineering readiness. Business metrics and detailed governance can be supplemented later.",
      question: handoffQuestion || "What must Product, Engineering, Business, or the governance input owner resolve before this becomes a buildable pilot?"
    }
  ];
}

function currentValidationStage(stages = validationStages()) {
  return stages.find((stage) => stage.status !== "complete" && !(stage.optional && stage.status === "optional")) || stages[stages.length - 1];
}

function validationFlowProgress(stages = validationStages()) {
  const coreStages = stages.filter((stage) => !stage.optional);
  const complete = coreStages.filter((stage) => stage.status === "complete").length;
  return Math.round((complete / coreStages.length) * 100);
}

function focusValidationStage(stageId) {
  const stage = validationStages().find((item) => item.id === stageId) || currentValidationStage();
  state.activeSection = stage.section;
  state.currentQuestionOverride = stage.question;
  state.currentQuestionSource = "Validation flow";
  if (stage.id === "detail" && firstMatrixGap()) {
    const gapStep = firstMatrixGap().step;
    state.activeStepIndex = Math.max(0, state.steps.indexOf(gapStep));
  }
  persistState();
  render();
}

function hasEvidenceSignal() {
  return isCapturedValue(state.fields.evidenceArtifacts) || (state.evidenceArtifacts || []).some((artifact) => artifact.applied || artifact.status === "reviewed");
}

function handoffReadinessScore() {
  const reviewItems = reviewCompletenessItems();
  const totalWeight = reviewItems.reduce((sum, item) => sum + (item.weight || 1), 0);
  return Math.round(reviewItems.reduce((sum, item) => sum + item.score * (item.weight || 1), 0) / totalWeight);
}

function getDisplayQuestion(section) {
  if (shouldUseWorkflowOverviewRouting(section)) {
    const overviewQuestion = workflowOverviewQuestion([]);
    if (overviewQuestion) return overviewQuestion;
    const coreQuestion = nextCoreDiscoveryQuestion([]);
    if (coreQuestion) return coreQuestion;
  }
  if (state.drilldown?.status === "active" && state.steps.length && ["workflow", "blueprint"].includes(section.id)) {
    return {
      text: stepInterviewQuestion(),
      source: "Step-by-step interview"
    };
  }
  if (isPrematureSupplementalQuestion(state.currentQuestionOverride)) {
    const coreQuestion = nextCoreDiscoveryQuestion([]);
    if (coreQuestion) return coreQuestion;
  }
  if (state.currentQuestionOverride) {
    return {
      text: state.currentQuestionOverride,
      source: state.currentQuestionSource || "From latest AI message"
    };
  }
  const activeValidation = currentValidationStage();
  if (section.id === activeValidation.section) {
    return {
      text: activeValidation.question,
      source: "Validation flow"
    };
  }
  const latestFromTranscript = (state.conversation?.length || 0) > 1 ? latestQuestionFromConversation() : "";
  if (latestFromTranscript && !isPrematureSupplementalQuestion(latestFromTranscript)) {
    return {
      text: latestFromTranscript,
      source: "Latest AI question from transcript"
    };
  }
  const matrixQuestion = stepMatrixFollowUpQuestion(section);
  if (matrixQuestion) {
    return {
      text: matrixQuestion,
      source: "Step matrix coverage"
    };
  }
  const handoffQuestion = handoffChecklistQuestionForSection(section.id);
  if (handoffQuestion) {
    return {
      text: handoffQuestion,
      source: "Handoff checklist"
    };
  }
  return {
    text: section.question,
    source: "Intake guide"
  };
}

function shouldUseWorkflowOverviewRouting(section = getActiveSection()) {
  if (!section || !["idea", "validate", "workflow", "blueprint"].includes(section.id)) return false;
  if (state.drilldown?.manualStepFocus) return false;
  const source = state.currentQuestionSource || "";
  if (!state.currentQuestionOverride) return true;
  return /intake guide|workflow overview|a-z process|ai extraction|latest ai question|guided step drill-down|step-by-step interview|next question|confirmed answer/i.test(source);
}

function stepMatrixFollowUpQuestion(section) {
  if (!state.steps.length) return "";
  if (!["workflow", "blueprint", "value"].includes(section.id)) return "";
  const gap = firstMatrixGap();
  if (!gap) return "The step matrix looks filled enough for a first pass. Review the A-to-Z map and tell me what is missing, duplicated, out of order, or unusually high-friction.";
  const { step, key, prompt, stepName } = gap;
  if (section.id === "workflow" && !["time", "pain"].includes(key)) {
    return `For "${stepName}", ${prompt}?`;
  }
  if (section.id === "value") return `For "${stepName}", about how long does it take, how often does it happen, and where is the commercial or capacity impact?`;
  if (section.id === "blueprint") return `For "${stepName}", what trigger, handoff, decision, access/source mode, AI pattern, or open question should the blueprint capture?`;
  return `For "${stepName}", ${prompt}?`;
}

function firstMatrixGap() {
  const requiredFields = matrixFields.filter(([, , required]) => required);
  const step = state.steps.find((item) => requiredFields.some(([key]) => !String(stepFieldValue(item, key) || "").trim()));
  if (!step) return null;
  const [key, label] = requiredFields.find(([field]) => !String(stepFieldValue(step, field) || "").trim());
  const stepName = step.name || step.action || `Step ${state.steps.indexOf(step) + 1}`;
  return {
    key,
    label,
    prompt: matrixPromptFor(key),
    step,
    stepName
  };
}

function matrixPromptFor(key) {
  return {
    actor: "who performs this step",
    tool: "which systems or tools are used",
    accessMode: "whether this step uses direct system access, exports, screenshots, files, transcripts, or client-provided answers",
    action: "what action is performed",
    input: "what input is used",
    dataHandling: "what data is handled or transformed in process",
    output: "what output is produced",
    handoff: "where the handoff goes next",
    trigger: "what triggers or gates this step",
    time: "how long this step takes",
    decision: "whether a human decision or approval happens",
    dataSensitivity: "what data sensitivity applies to this step",
    exceptions: "what exceptions or variations happen",
    evidenceConfidence: "how confident we are in the captured evidence",
    interviewNotes: "what notes belong with this step",
    openQuestions: "what remains open for Product, Engineering, Risk, Legal, or the business owner"
  }[key] || "what should be captured";
}

function latestQuestionFromConversation() {
  const messages = [...(state.conversation || []), ...(state.aiChat || [])].reverse();
  for (const message of messages) {
    if (message.role !== "assistant") continue;
    const question = extractQuestionFromText(message.text);
    if (question) return question;
  }
  return "";
}

function extractQuestionFromText(text) {
  const matches = String(text || "").match(/[^.?!]*\?/g);
  if (!matches?.length) return "";
  return matches[matches.length - 1].trim();
}

function sanitizeAiQuestion(text) {
  const cleaned = String(text || "").trim();
  if (!cleaned) return "";
  // Collapse a bundled multi-question suggestion down to a single question.
  return extractQuestionFromText(cleaned) || cleaned;
}

function renderSectionForm(section) {
  if (!els.sectionForm) return;
  const wrap = document.createElement("div");
  wrap.className = "section-capture-stack";
  const form = document.createElement("div");
  form.className = "field-grid";
  (section.fields || []).filter(shouldShowField).forEach(([key, label, type, options]) => {
    const field = document.createElement("div");
    field.className = type === "textarea" ? "field full" : "field";
    const value = state.fields[key] ?? "";
    if (type === "textarea") {
      field.innerHTML = `<label>${label}</label><textarea data-field="${key}">${escapeHtml(value)}</textarea>`;
    } else if (type === "select") {
      const opts = (Array.isArray(options) ? options : []).map((option) => `<option value="${escapeHtml(option)}" ${value === option ? "selected" : ""}>${escapeHtml(option)}</option>`).join("");
      field.innerHTML = `<label>${label}</label><select data-field="${key}">${opts}</select>`;
    } else {
      field.innerHTML = `<label>${label}</label><input data-field="${key}" value="${escapeHtml(value)}" />`;
    }
    form.appendChild(field);
  });
  form.querySelectorAll("[data-field]").forEach((input) => {
    input.addEventListener("input", (event) => {
      state.fields[event.target.dataset.field] = event.target.value;
      persistState();
      if (event.target.dataset.field === "workflowCategory") render();
      renderSummary();
      updateProgressUi();
      renderPdrPreview();
      renderBlueprintInspector();
    });
  });
  els.sectionForm.innerHTML = "";
  if (form.children.length) wrap.appendChild(form);
  if (section.recordType) wrap.appendChild(buildRecordSection(section.recordType));
  els.sectionForm.appendChild(wrap);
}

function renderRecordSection(recordType) {
  els.sectionForm.innerHTML = "";
  els.sectionForm.appendChild(buildRecordSection(recordType));
}

function buildRecordSection(recordType) {
  const list = document.createElement("div");
  list.className = "table-list";
  const records = state[recordType];
  records.forEach((record, index) => list.appendChild(recordCard(recordType, record, index)));

  const addButton = document.createElement("button");
  addButton.className = "secondary-button add-record";
  addButton.type = "button";
  addButton.innerHTML = `<i data-lucide="plus"></i> Add ${recordLabel(recordType)}`;
  addButton.addEventListener("click", () => {
    records.push(newRecord(recordType));
    persistState();
    render();
  });
  list.appendChild(addButton);

  return list;
}

function shouldShowField(fieldConfig) {
  const meta = fieldConfig[3];
  const rule = meta && !Array.isArray(meta) ? meta.showWhen : null;
  if (!rule) return true;
  return state.fields?.[rule.field] === rule.value;
}

function recordCard(type, record, index) {
  const card = document.createElement("div");
  card.className = "record-card";
  const title = recordTitle(type, record, index);
  // PR 27: show the step's AI pattern inline as a badge on the card header
  // (matches the teal pattern badge used elsewhere; only on step cards).
  const patternBadge = (type === "steps" && String(record.pattern || "").trim())
    ? `<span style="background:#00d4b4;color:#0d1b2e;font-size:0.65rem;font-weight:700;border-radius:99px;padding:2px 9px;text-transform:uppercase;letter-spacing:0.03em;margin-left:8px;">${escapeHtml(String(record.pattern).trim())}</span>`
    : "";
  card.innerHTML = `
    <div class="record-card-header">
      <span class="record-card-title">${escapeHtml(title)}</span>
      ${patternBadge}
      <span class="record-actions">
        <button class="mini-button" data-action="delete" title="Delete" type="button"><i data-lucide="trash-2"></i></button>
      </span>
    </div>
    <div class="field-grid">${recordFields(type, record, index)}</div>
  `;
  card.querySelector("[data-action='delete']").addEventListener("click", () => {
    state[type].splice(index, 1);
    persistState();
    render();
  });
  card.querySelectorAll("[data-record-field]").forEach((input) => {
    input.addEventListener("input", (event) => {
      state[type][index][event.target.dataset.recordField] = event.target.value;
      persistState();
      renderSummary();
      renderMap();
      renderPdrPreview();
      updateProgressUi();
    });
  });
  return card;
}

function recordFields(type, record) {
  const config = {
    steps: [
      ["name", "Step name", "input"],
      ["actor", "Actor", "input"],
      ["tool", "Tool/system", "input"],
      ["accessMode", "Access / source mode", "input"],
      ["action", "Action", "textarea"],
      ["input", "Input", "textarea"],
      ["dataHandling", "In-process data handling", "textarea"],
      ["output", "Output", "textarea"],
      ["handoff", "Handoff", "input"],
      ["trigger", "Trigger / dependency", "input"],
      ["time", "Time", "input"],
      ["decision", "Decision required?", "input"],
      ["pain", "Pain / friction", "textarea"],
      ["risk", "Risk / sensitivity", "textarea"],
      ["exceptions", "Exceptions / variations", "textarea"],
      ["dataSensitivity", "Data sensitivity", "input"],
      ["pattern", "AI pattern", "input"],
      ["toolFit", "Likely tool fit", "input"],
      ["evidenceConfidence", "Evidence confidence", "input"],
      ["interviewNotes", "Interview notes", "textarea"],
      ["openQuestions", "Open questions", "textarea"]
    ],
    data: [
      ["category", "Data category", "input"],
      ["source", "Source", "input"],
      ["format", "Format", "input"],
      ["sensitivity", "Sensitivity", "input"],
      ["usageMode", "Usage mode", "input"],
      ["processing", "Processing actions", "textarea"],
      ["tool", "Processing tool/system", "input"],
      ["storage", "Storage", "input"],
      ["access", "Access / permissions", "textarea"],
      ["avoidRaw", "Can avoid raw client data?", "input"],
      ["splitNotes", "Solution split notes", "textarea"]
    ],
    systems: [
      ["name", "Tool/system", "input"],
      ["purpose", "Purpose", "textarea"],
      ["access", "Access method", "input"],
      ["owner", "Owner", "input"],
      ["integration", "Integration notes", "textarea"],
      ["clientData", "Client data present?", "input"]
    ],
    decisions: [
      ["decision", "Decision", "textarea"],
      ["owner", "Owner", "input"],
      ["criteria", "Criteria", "textarea"],
      ["risk", "Risk if wrong", "textarea"],
      ["approval", "Human approval required?", "input"],
      ["escalation", "Escalation path", "input"]
    ],
    patterns: [
      ["step", "Step", "input"],
      ["pattern", "AI pattern", "input"],
      ["riskNote", "Risk / review note", "textarea"],
      ["toolFit", "Directional tool fit", "input"]
    ]
  };

  return config[type]
    .map(([key, label, inputType]) => {
      const value = record[key] ?? "";
      const full = inputType === "textarea" ? " full" : "";
      const control =
        inputType === "textarea"
          ? `<textarea data-record-field="${key}">${escapeHtml(value)}</textarea>`
          : `<input data-record-field="${key}" value="${escapeHtml(value)}" />`;
      return `<div class="field${full}"><label>${label}</label>${control}</div>`;
    })
    .join("");
}

function saveAnswerToSection() {
  const text = els.answerInput.value.trim();
  if (!text) {
    toast("Add an answer first.");
    return;
  }

  const section = getActiveSection();
  const before = intakeSnapshot();
  state.transcript = [state.transcript, text].filter(Boolean).join("\n\n");
  addConversationMessage("user", text, section.label);
  if (section.recordType === "steps") {
    state.steps.push({ ...newRecord("steps"), name: `Step ${state.steps.length + 1}`, action: text, evidenceConfidence: "Medium" });
    state.activeStepIndex = state.steps.length - 1;
    ensureDrilldownState();
    state.drilldown.skeletonConfirmed = true;
    state.drilldown.status = "active";
    lockWorkflowStepList();
  } else if (section.recordType === "data") {
    state.data.push({ ...newRecord("data"), category: text });
  } else if (section.recordType === "systems") {
    state.systems.push({ ...newRecord("systems"), name: text });
  } else if (section.recordType === "decisions") {
    state.decisions.push({ ...newRecord("decisions"), decision: text });
  } else if (section.recordType === "patterns") {
    state.steps.forEach((step) => {
      if (!step.pattern) step.pattern = text;
    });
  } else {
    const firstEmpty = section.fields?.find(([key]) => !state.fields[key]);
    if (firstEmpty) state.fields[firstEmpty[0]] = text;
    else state.fields.currentStateSummary = [state.fields.currentStateSummary, text].filter(Boolean).join("\n");
  }

  state.voiceCheckpoints.push({
    checkpoint: section.label,
    summary: text,
    confirmed: ""
  });
  addConversationMessage("assistant", manualCaptureReply(section));
  state.lastRecap = {
    title: "Manual note saved",
    summary: text,
    confidence: "medium",
    fields: [section.label],
    nextQuestion: stepInterviewQuestion(),
    time: new Date().toISOString()
  };
  els.answerInput.value = "";
  addIntakeDelta("Manual save", before, intakeSnapshot(), `Saved answer to ${section.label}.`);
  persistState();
  render();
  maybePromptMapCheckpoint(section.id);
  toast("Saved into the active checklist section.");
}

async function aiExtractAnswer(options = {}) {
  // A system-injected trigger (e.g. the post-extraction pivot) supplies its own
  // answer text and must never be read from, or written back to, the input box.
  const injected = typeof options.injectedAnswer === "string" && options.injectedAnswer.trim();
  const answer = injected ? options.injectedAnswer : (els.answerInput.value.trim() || latestTranscriptBlock());
  if (!answer) {
    toast("Add transcript, chat, or typed text first.");
    return;
  }

  if (isCorrectionAnswer(answer) && state.drilldown?.status === "confirmSkeleton") {
    if (!lastConversationTextIs("user", answer)) {
      addConversationMessage("user", answer, "Confirmation");
    }
    reviseWorkflowSkeleton();
    const reply = "Got it. What should I add, remove, rename, merge, split, or reorder in the major workflow steps?";
    els.answerInput.value = "";
    setCaptureStage("idle", "Voice idle");
    addConversationMessage("assistant", reply, "Skeleton revision");
    maybeSpeak(reply);
    persistState();
    render();
    return;
  }

  if (isConfirmationAnswer(answer) && (lastAssistantAskedConfirmation() || state.drilldown?.status === "confirmSkeleton")) {
    if (!lastConversationTextIs("user", answer)) {
      addConversationMessage("user", answer, "Confirmation");
    }
    if (state.drilldown?.status === "confirmSkeleton") {
      confirmWorkflowSkeleton();
      const nextQuestion = state.currentQuestionOverride || stepInterviewQuestion();
      els.answerInput.value = "";
      setCaptureStage("idle", "Voice idle");
      const reply = `Great, thank you. ${nextQuestion}`;
      addConversationMessage("assistant", reply, "Next question");
      maybeSpeak(reply);
      persistState();
      render();
      return;
    }
    const nextQuestion = isProceedPermissionQuestion(state.lastRecap?.nextQuestion)
      ? stepInterviewQuestion()
      : state.lastRecap?.nextQuestion || stepInterviewQuestion();
    state.currentQuestionOverride = nextQuestion;
    state.currentQuestionSource = "Confirmed answer";
    els.answerInput.value = "";
    setCaptureStage("idle", "Voice idle");
    const reply = `Great, thank you. ${nextQuestion}`;
    addConversationMessage("assistant", reply, "Next question");
    maybeSpeak(reply);
    persistState();
    render();
    return;
  }

  const button = document.getElementById("aiExtractButton");
  const original = button.innerHTML;
  button.disabled = true;
  button.innerHTML = `<i data-lucide="loader"></i> Analyzing`;
  setCaptureStage("analyzing", "AI analyzing");
  renderCurrentStepPanel();
  renderCurrentQuestion(getActiveSection());
  refreshIcons();

  try {
    const before = intakeSnapshot();
    const beforeStepCount = state.steps.length;
    const beforeActiveStepIndex = getCurrentStepIndex();
    const askedQuestion = getDisplayQuestion(getActiveSection()).text;
    if (!injected) state.transcript = [state.transcript, answer].filter(Boolean).join("\n\n");
    let result = await requestJson("/api/extract", {
      method: "POST",
      body: {
        currentSection: state.activeSection,
        answer,
        transcript: state.transcript,
        currentQuestion: askedQuestion,
        gridContext: buildGridContext(),
        gridSummary: gridSummaryForPrompt(state.workflowGrid),
        state
      }
    });
    result = sanitizeExtractionResult(result, { answer, askedQuestion });
    result._answer = answer;
    result._askedQuestion = askedQuestion;
    if (injected) {
      // Post-extraction pivot: surface the model's acknowledgement + confirm
      // question straight from the LLM. Never echo the synthetic trigger via
      // conciseAnswerSummary/buildAiReply, and never run the generic next-
      // question routing (it would override the pivot with a workflow-name
      // question). The grid is already populated by the document merge, so no
      // extraction is applied for this synthetic turn.
      const pivotQuestion = (result.nextQuestion || "").trim();
      const ack = (result.summary || "").trim();
      // The model's acknowledgement (ack) already contains the step list and the
      // confirm question, so only append pivotQuestion when ack does not already
      // include it — otherwise the question renders twice in the recap bubble.
      const reply = (ack && pivotQuestion && !ack.toLowerCase().includes(pivotQuestion.toLowerCase()))
        ? `${ack} ${pivotQuestion}`
        : (ack || pivotQuestion
          || "I've pulled your document into the grid. Do these steps look right, or is anything missing or named incorrectly?");
      state.currentQuestionOverride = pivotQuestion || reply;
      state.currentQuestionSource = "Document recap";
      setCaptureStage("followup", "Follow-up ready");
      addConversationMessage("assistant", reply, "Document recap");
      maybeSpeak(reply);
      persistState();
      render();
      return;
    }
    applyExtraction(result, { beforeStepCount, beforeActiveStepIndex, answer, askedQuestion });
    updateLiveGrid(result.gridState);
    mergeStepAnchorsFromAnswer(answer, { beforeStepCount, beforeActiveStepIndex });
    mergeCurrentStepDetailHintsFromAnswer(answer, { beforeStepCount, beforeActiveStepIndex });
    const after = intakeSnapshot();
    const delta = addIntakeDelta("AI Analyze Answer", before, after, result.summary || result.progressNotes || "Analyzed conversation context.");
    const nextRoute = nextQuestionRouteAfterExtraction(result);
    const routedNextQuestion = nextRoute?.text || nextQuestionAfterCapture(result);
    state.lastRecap = buildCaptureRecap(result, answer, routedNextQuestion);
    state.lastTranslationLens = state.lastRecap.translationLens;
    state.lastIntakeDelta = delta;
    const reply = buildAiReply(result, answer, routedNextQuestion);
    setCaptureStage("followup", state.lastRecap.nextQuestion ? "Follow-up ready" : "Captured");
    addConversationMessage("assistant", reply, "Next question");
    state.currentQuestionOverride = routedNextQuestion || stepInterviewQuestion();
    state.currentQuestionSource = nextRoute?.source || (state.steps.length ? "Step-by-step interview" : "Discovery queue");
    maybeSpeak(reply);
    if (!injected) {
      state.voiceCheckpoints.push({
        checkpoint: getActiveSection().label,
        summary: result.summary || answer,
        confirmed: ""
      });
      els.answerInput.value = "";
    }
    persistState();
    render();
    // Stage 1b: harvest grid updates from the conversation in the background.
    // Fire-and-forget — never awaited, never blocks the interview. Skipped for a
    // system-injected trigger, which carries no workflow content to harvest.
    if (!injected) harvestGridFromConversation(answer);
    toast(state.currentQuestionOverride ? `Captured. Next: ${state.currentQuestionOverride}` : "AI extraction applied.");
  } catch (error) {
    setCaptureStage("idle", "Voice idle");
    toast(String(error.message || error));
  } finally {
    button.disabled = !aiAvailable;
    button.innerHTML = original;
    refreshIcons();
  }
}

// Q2 is the mandatory pain/friction question. The process-map override must not
// jump ahead of it, so this returns true only once a genuine pain signal exists:
// a populated grid painFriction cell, a legacy step pain value, or the user
// actually mentioning pain/friction in the conversation. Field names are mapped
// to the real state shape (state.aiChat turns use `text`; there is no
// state.conversationHistory). dataSensitivityBaseline is intentionally excluded
// because it reflects data sensitivity — which a document can set — not pain.
function q2HasBeenAnswered() {
  const painPattern = /annoying|slow|painful|frustrat|pain|friction/i;
  const gridSteps = state.workflowGrid?.steps || [];
  if (gridSteps.some((step) => String(step?.cells?.painFriction?.value || "").trim())) return true;
  if ((state.steps || []).some((step) => String(step?.pain || "").trim())) return true;
  if ((state.aiChat || []).some((turn) => turn?.role === "user" && painPattern.test(String(turn?.text || "")))) return true;
  if (painPattern.test(String(state.transcript || ""))) return true;
  return false;
}

function sanitizeExtractionResult(result = {}, options = {}) {
  const answer = String(options.answer || "");
  const sanitized = {
    ...result,
    fields: { ...(result.fields || {}) },
    newRecords: { ...(result.newRecords || {}) }
  };

  if (isThinOpeningAnswer(answer, options.askedQuestion)) {
    const topic = compactStartingTopic(answer);
    const genericTopic = isGenericStartingTopic(topic);
    const allowedThinFields = new Set([
      "submittedIdea",
      "submittedWorkflowTask",
      "useCaseArchetype",
      "workflowCategory",
      "recordType",
      "ideaValidationStatus",
      "lifecycleStage",
      "lifecycleStatus",
      "gateDecision",
      "automationPotential",
      "fieldConfidence"
    ]);
    Object.keys(sanitized.fields).forEach((key) => {
      if (!allowedThinFields.has(key)) delete sanitized.fields[key];
    });
    sanitized.newRecords = {
      ...sanitized.newRecords,
      steps: [],
      data: [],
      systems: [],
      decisions: []
    };
    if (genericTopic) {
      delete sanitized.fields.submittedIdea;
      delete sanitized.fields.submittedWorkflowTask;
    } else if (topic && !isCapturedValue(sanitized.fields.submittedIdea)) {
      sanitized.fields.submittedIdea = topic;
    }
    if (/\bworkshop|working session|facilitation\b/i.test(answer)) {
      sanitized.fields.useCaseArchetype = "Workshop acceleration";
      sanitized.fields.workflowCategory = "Pre-delivery / workshop prep";
    }
    sanitized.summary = genericTopic ? "Need a named starting topic." : `Starting topic: ${topic || "early use-case idea"}.`;
    // Only force the process map once Q2 (pain) is done; before that, let the
    // LLM's returned nextQuestion through so Q2 is not skipped.
    if (genericTopic) {
      sanitized.nextQuestion = OPENING_DISCOVERY_QUESTION;
    } else if (q2HasBeenAnswered()) {
      sanitized.nextQuestion = PROCESS_MAP_QUESTION;
    }
  }

  if (questionAsksDataBoundary(options.askedQuestion) && answerLooksLikeDataBoundary(answer) && q2HasBeenAnswered()) {
    sanitized.nextQuestion = PROCESS_MAP_QUESTION;
  }

  if (processSkeletonStillNeededAfterAnswer(answer, options.askedQuestion, sanitized)) {
    sanitized.nextQuestion = PROCESS_MAP_QUESTION;
  }

  if (isSameQuestion(sanitized.nextQuestion, options.askedQuestion) && !processSkeletonStillNeededAfterAnswer(answer, options.askedQuestion, sanitized)) {
    sanitized.nextQuestion = "";
  }

  return sanitized;
}

function applyExtraction(result, options = {}) {
  if (typeof result.nextQuestion === "string") {
    result.nextQuestion = sanitizeAiQuestion(result.nextQuestion);
  }
  const extractedFields = result.fields || {};
  for (const [key, value] of Object.entries(extractedFields)) {
    if (typeof value === "string" && value.trim()) {
      const normalized = normalizeFieldValueForSchema(key, value);
      if (key in state.fields && isCapturedValue(normalized)) {
        state.fields[key] = normalized;
      }
    }
  }
  applyCurrentQuestionAnswer(options.answer, options.askedQuestion);
  mergeOverviewSignalsFromAnswer(options.answer, options.askedQuestion);

  const newRecords = result.newRecords || {};
  let touchedStepIndex = -1;
  const beforeActiveStepIndex = Number.isFinite(options.beforeActiveStepIndex) ? options.beforeActiveStepIndex : getCurrentStepIndex();
  const explicitStepIndex = explicitStepIndexFromAnswer(options.answer);
  const hadExistingSteps = (options.beforeStepCount || 0) > 0;
  for (const collection of ["steps", "data", "systems", "decisions", "patterns"]) {
    const records = Array.isArray(newRecords[collection]) ? newRecords[collection] : [];
    records.filter(hasMeaningfulValue).forEach((record) => {
      if (collection === "steps") touchedStepIndex = mergeStepRecord(record);
      else mergeCollectionRecord(collection, record);
    });
  }
  const shouldPreserveCurrentStep = hadExistingSteps
    && explicitStepIndex < 0
    && state.drilldown?.status === "active"
    && state.steps[beforeActiveStepIndex]
    && stepMissingFields(state.steps[beforeActiveStepIndex]).length > 0;
  if (explicitStepIndex >= 0) state.activeStepIndex = explicitStepIndex;
  else if (shouldPreserveCurrentStep) state.activeStepIndex = beforeActiveStepIndex;
  else if (touchedStepIndex >= 0) state.activeStepIndex = touchedStepIndex;
  else if (state.steps.length) state.activeStepIndex = getCurrentStepIndex();

  const ideas = Array.isArray(result.ideas) ? result.ideas : [];
  ideas.filter(hasMeaningfulValue).forEach((idea) => state.ideas.push(idea));

  if (result.nextQuestion && !isProceedPermissionQuestion(result.nextQuestion)) {
    result.aiSuggestedNextQuestion = result.nextQuestion;
  }

  syncGuidedDrilldownAfterExtraction({
    beforeStepCount: options.beforeStepCount || 0,
    touchedStepIndex: shouldPreserveCurrentStep ? beforeActiveStepIndex : explicitStepIndex >= 0 ? explicitStepIndex : touchedStepIndex
  });
  advanceWorkflowFrameGate(options.askedQuestion || result._askedQuestion || "");
  routeNextQuestionAfterExtraction(result);

  if (result.mapCheckpointRecommended) {
    state.mapReviews.push({
      checkpoint: "AI recommended map review",
      status: "shown",
      feedback: result.progressNotes || "",
      changes: ""
    });
  }
}

function routeNextQuestionAfterExtraction(result = {}) {
  const route = nextQuestionRouteAfterExtraction(result);
  if (!route?.text) return;
  state.currentQuestionOverride = route.text;
  state.currentQuestionSource = route.source;
}

function nextQuestionRouteAfterExtraction(result = {}) {
  const askedQuestion = result._askedQuestion || "";
  if (q2HasBeenAnswered() && processSkeletonStillNeededAfterAnswer(result._answer, askedQuestion, result)) {
    return { text: PROCESS_MAP_QUESTION, source: "A-Z process" };
  }
  if (state.drilldown?.status === "confirmSkeleton") {
    return { text: skeletonConfirmationQuestion(), source: "Skeleton confirmation" };
  }
  const overviewQuestion = workflowOverviewQuestion([askedQuestion]);
  if (overviewQuestion) return overviewQuestion;
  if (state.drilldown?.status === "active" && state.steps.length) {
    return { text: stepInterviewQuestion(), source: "Step-by-step interview" };
  }
  const coreQuestion = nextCoreDiscoveryQuestion([askedQuestion]);
  if (coreQuestion) {
    return coreQuestion;
  }
  const matrixQuestion = stepMatrixFollowUpQuestion(getActiveSection());
  if (matrixQuestion && firstMatrixGap() && !isSameQuestion(matrixQuestion, askedQuestion)) {
    return { text: matrixQuestion, source: "Step matrix coverage" };
  }
  const checklistQuestion = topHandoffChecklistQuestions(3)
    .find((question) => !isSameQuestion(question, askedQuestion) && !isSameQuestion(question, result.nextQuestion));
  if (checklistQuestion) {
    return { text: checklistQuestion, source: "Handoff checklist" };
  }
  if (result.nextQuestion && !isProceedPermissionQuestion(result.nextQuestion) && !isSameQuestion(result.nextQuestion, askedQuestion)) {
    return { text: result.nextQuestion, source: "AI extraction" };
  }
  return { text: currentValidationStage().question, source: "Validation flow" };
}

function nextCoreDiscoveryQuestion(avoidQuestions = []) {
  const route = (text, source) => {
    if (!text || avoidQuestions.some((question) => isSameQuestion(text, question))) return null;
    return { text, source };
  };
  if (!isSubmittedTopicCaptured()) return route(OPENING_DISCOVERY_QUESTION, "Intake guide");
  const overviewQuestion = workflowOverviewQuestion(avoidQuestions);
  if (overviewQuestion) return overviewQuestion;
  if (!state.steps.length && q2HasBeenAnswered()) return route(PROCESS_MAP_QUESTION, "A-Z process");
  const primary = topCompletionQuestionItems(4, { includeSupplemental: false })
    .find((item) => !avoidQuestions.some((question) => isSameQuestion(item.question, question)));
  if (primary?.question) return { text: primary.question, source: primary.source || primary.lane || "Discovery queue" };
  return null;
}

function workflowOverviewQuestion(avoidQuestions = []) {
  if (!isSubmittedTopicCaptured()) return null;
  const route = (text, source) => {
    if (!text || avoidQuestions.some((question) => isSameQuestion(text, question))) return null;
    return { text, source };
  };
  const signals = workflowOverviewSignals();
  if (!signals.frameCaptured) {
    const frameRoute = workflowFrameQuestionRoute(avoidQuestions);
    if (frameRoute) return frameRoute;
    // Frame gate spent (primary asked + at most one follow-up): fall through so
    // the overview advances instead of re-asking the frame question.
  }
  if (!state.steps.length && !signals.componentOverviewCaptured) {
    return route(componentOverviewQuestionText(signals), "Workflow overview");
  }
  if (state.steps.length && !signals.readyForStepDrilldown) {
    return route(WORKFLOW_DATA_TOOLS_OVERVIEW_QUESTION, "Workflow overview");
  }
  return null;
}

function workflowOverviewSignals() {
  const fields = state.fields || {};
  const submittedTopic = isSpecificSubmittedTopic(fields.submittedWorkflowTask)
    ? fields.submittedWorkflowTask
    : isSpecificSubmittedTopic(fields.submittedIdea)
      ? fields.submittedIdea
      : "";
  const frameCaptured = Boolean(
    isCapturedValue(fields.workflowName || submittedTopic)
    && (isCapturedValue(fields.startPoint) || isCapturedValue(fields.triggerSource) || state.steps.length)
    && (isCapturedValue(fields.endPoint) || isCapturedValue(fields.expectedWorkshopOutput) || state.steps.some((step) => isCapturedValue(step.output)))
  );
  const toolCaptured = Boolean(
    state.systems.length
    || state.steps.some((step) => isCapturedValue(step.tool))
    || hasToolSignals(fields.currentStateSummary)
  );
  const dataCaptured = Boolean(
    state.data.length
    || state.steps.some((step) => isCapturedValue(step.input) || isCapturedValue(step.dataHandling) || isCapturedValue(step.dataSensitivity))
    || hasDataSignals(fields.currentStateSummary)
  );
  const outputCaptured = Boolean(
    isCapturedValue(fields.expectedWorkshopOutput)
    || isCapturedValue(fields.businessOutcome)
    || isCapturedValue(fields.endPoint)
    || state.steps.some((step) => isCapturedValue(step.output))
    || hasOutputSignals(fields.currentStateSummary)
  );
  const componentOverviewCaptured = toolCaptured && dataCaptured && outputCaptured;
  return {
    frameCaptured,
    toolCaptured,
    dataCaptured,
    outputCaptured,
    componentOverviewCaptured,
    readyForStepDrilldown: toolCaptured && dataCaptured && outputCaptured
  };
}

function componentOverviewQuestionText(signals = workflowOverviewSignals()) {
  const missing = [];
  if (!signals.toolCaptured) missing.push("tools or systems");
  if (!signals.dataCaptured) missing.push("main inputs and data types");
  if (!signals.outputCaptured) missing.push("final outputs");
  if (!missing.length) return WORKFLOW_COMPONENT_OVERVIEW_QUESTION;
  return `Before we map out the steps, what ${joinNaturalList(missing)} should we capture across the workflow overall?`;
}

// Pure (no side effects) — safe to call during render. Decides which workflow
// frame question to show given the current gate state.
function workflowFrameQuestionRoute(avoidQuestions = []) {
  const model = WORKFLOW_FRAME_QUESTION_MODEL;
  const avoid = (text) => !text || avoidQuestions.some((q) => isSameQuestion(text, q));
  // An in-flight follow-up wins until it is answered.
  if (state.pendingFollowUp?.questionId === model.id) {
    return avoid(state.pendingFollowUp.text)
      ? null
      : { text: state.pendingFollowUp.text, source: "Workflow frame follow-up" };
  }
  // Our single follow-up was already used → let the interview move on.
  if (state.askedFollowUp) return null;
  // Primary stage: ask only for the name while it is still missing.
  if (!isCapturedValue(state.fields[model.targetField])) {
    return avoid(model.primary) ? null : { text: model.primary, source: "Workflow overview" };
  }
  // Name captured, nothing pending → nothing more to ask at the frame.
  return null;
}

// Side-effecting — called once per answer (from applyExtraction). Transitions
// the one-follow-up gate: primary -> (optional single follow-up) -> done.
function advanceWorkflowFrameGate(askedQuestion = "") {
  const model = WORKFLOW_FRAME_QUESTION_MODEL;
  // Case 1: the user just answered our single follow-up → close the gate.
  if (state.pendingFollowUp?.questionId === model.id
      && isSameQuestion(askedQuestion, state.pendingFollowUp.text)) {
    state.pendingFollowUp = null;
    return;
  }
  // Only react to the primary (name) question from here on.
  if (!isSameQuestion(askedQuestion, model.primary)) return;
  // Case 2a: extraction captured the name → advance with no follow-up.
  if (isCapturedValue(state.fields[model.targetField])) {
    state.pendingFollowUp = null;
    return;
  }
  // Case 2b: name still missing and follow-up not yet used → ask exactly one.
  if (!state.askedFollowUp) {
    const followUp = model.followUps.find((f) => !isCapturedValue(state.fields[f.field]))
      || model.followUps[0];
    state.pendingFollowUp = { questionId: model.id, field: followUp.field, text: followUp.text };
    state.askedFollowUp = true;
  }
}

function processSkeletonStillNeededAfterAnswer(answer = "", askedQuestion = "", result = {}) {
  if (!isSameQuestion(askedQuestion, PROCESS_MAP_QUESTION)) return false;
  if (state.steps.length) return false;
  const extractedSteps = Array.isArray(result.newRecords?.steps) ? result.newRecords.steps.filter(hasMeaningfulValue) : [];
  return !extractedSteps.length && !extractStepAnchorsFromText(answer).length;
}

function joinNaturalList(items = []) {
  const values = items.filter(Boolean);
  if (values.length <= 1) return values[0] || "";
  if (values.length === 2) return `${values[0]} and ${values[1]}`;
  return `${values.slice(0, -1).join(", ")}, and ${values[values.length - 1]}`;
}

function hasMeaningfulValue(record) {
  return Object.values(record || {}).some((value) => String(value || "").trim());
}

function mergeStepRecord(record) {
  const incoming = { ...newRecord("steps"), ...record };
  const incomingKey = normalizeStepKey(incoming.name || incoming.action);
  const existing = state.steps.find((step) => {
    const key = normalizeStepKey(step.name || step.action);
    return key && incomingKey && (key === incomingKey || key.includes(incomingKey) || incomingKey.includes(key));
  });
  if (!existing) {
    state.steps.push({ ...incoming, evidenceConfidence: incoming.evidenceConfidence || "Medium" });
    return state.steps.length - 1;
  }
  for (const [key, value] of Object.entries(incoming)) {
    if (String(value || "").trim() && !String(existing[key] || "").trim()) {
      existing[key] = value;
    }
  }
  return state.steps.indexOf(existing);
}

function mergeStepAnchorsFromAnswer(answer, options = {}) {
  const anchors = extractStepAnchorsFromText(answer);
  if (!anchors.length) return 0;
  let touched = 0;
  let lastTouchedIndex = -1;
  anchors.forEach((step) => {
    const before = state.steps.length;
    const index = mergeStepRecord(step);
    if (index >= 0) lastTouchedIndex = index;
    if (state.steps.length > before || index >= 0) touched += 1;
  });
  if (touched) {
    state.activeSection = "workflow";
    ensureDrilldownState();
    state.drilldown.skeletonConfirmed = true;
    state.drilldown.status = "active";
    state.drilldown.manualStepFocus = false;
    lockWorkflowStepList();
    const explicitIndex = explicitStepIndexFromAnswer(answer);
    const beforeActiveStepIndex = Number.isFinite(options.beforeActiveStepIndex) ? options.beforeActiveStepIndex : getCurrentStepIndex();
    if (anchors.length > 1 || (options.beforeStepCount || 0) === 0) {
      state.activeStepIndex = Math.max(0, firstIncompleteStepIndex(0));
    } else if (explicitIndex >= 0) {
      state.activeStepIndex = explicitIndex;
    } else if (state.steps[beforeActiveStepIndex] && stepMissingFields(state.steps[beforeActiveStepIndex]).length) {
      state.activeStepIndex = beforeActiveStepIndex;
    } else if (lastTouchedIndex >= 0) {
      state.activeStepIndex = lastTouchedIndex;
    }
    const cluster = currentDrilldownCluster(getCurrentStep());
    state.drilldown.currentClusterId = cluster?.id || "";
    state.currentQuestionOverride = stepInterviewQuestion();
    state.currentQuestionSource = "Guided step drill-down";
    state.drilldown.lastPrompt = state.currentQuestionOverride;
  }
  return touched;
}

function mergeCurrentStepDetailHintsFromAnswer(answer, options = {}) {
  if (!state.steps.length) return 0;
  const hints = inferStepDetailHintsFromAnswer(answer);
  if (!Object.keys(hints).length) return 0;
  const explicitIndex = explicitStepIndexFromAnswer(answer);
  const beforeActiveStepIndex = Number.isFinite(options.beforeActiveStepIndex) ? options.beforeActiveStepIndex : getCurrentStepIndex();
  const targetIndex = explicitIndex >= 0 ? explicitIndex : beforeActiveStepIndex;
  const step = state.steps[targetIndex];
  if (!step) return 0;

  let touched = 0;
  for (const [key, value] of Object.entries(hints)) {
    if (!isCapturedValue(value) || !(key in step)) continue;
    const current = step[key];
    if (shouldReplaceStepDetailValue(current)) {
      step[key] = value;
      touched += 1;
    } else if (["tool", "accessMode"].includes(key)) {
      const delimiter = key === "tool" ? ", " : "; ";
      const merged = mergeSignalList(current, value, delimiter);
      if (merged !== current) {
        step[key] = merged;
        touched += 1;
      }
    }
  }

  if (!touched) return 0;
  state.activeSection = "workflow";
  state.activeStepIndex = targetIndex;
  ensureDrilldownState();
  state.drilldown.skeletonConfirmed = true;
  state.drilldown.status = "active";
  state.drilldown.manualStepFocus = false;
  lockWorkflowStepList();
  if (!isCapturedValue(step.evidenceConfidence)) step.evidenceConfidence = "Medium";
  const cluster = currentDrilldownCluster(step);
  state.drilldown.currentClusterId = cluster?.id || "";
  state.currentQuestionOverride = stepInterviewQuestion();
  state.currentQuestionSource = "Guided step drill-down";
  state.drilldown.lastPrompt = state.currentQuestionOverride;
  return touched;
}

function mergeOverviewSignalsFromAnswer(answer = "", askedQuestion = "") {
  const raw = String(answer || "");
  if (!raw.trim()) return 0;
  const question = String(askedQuestion || "");
  const isOverviewPrompt = [
    WORKFLOW_FRAME_QUESTION,
    WORKFLOW_COMPONENT_OVERVIEW_QUESTION,
    WORKFLOW_DATA_TOOLS_OVERVIEW_QUESTION,
    PROCESS_MAP_QUESTION
  ].some((item) => isSameQuestion(question, item));
  if (!isOverviewPrompt && !hasToolSignals(raw) && !hasDataSignals(raw) && !hasOutputSignals(raw)) return 0;

  let touched = 0;
  const summary = raw.replace(/\s+/g, " ").trim();
  if (summary && !String(state.fields.currentStateSummary || "").includes(summary.slice(0, 80))) {
    state.fields.currentStateSummary = [state.fields.currentStateSummary, summary].filter(Boolean).join("\n\n");
    touched += 1;
  }

  if (isSameQuestion(question, WORKFLOW_FRAME_QUESTION)) {
    if (!isCapturedValue(state.fields.workflowName)) {
      state.fields.workflowName = inferWorkflowNameFromOverview(raw) || state.fields.submittedWorkflowTask || state.fields.submittedIdea || "";
      if (state.fields.workflowName) touched += 1;
    }
    if (!isCapturedValue(state.fields.startPoint)) {
      const start = inferStartPointFromOverview(raw);
      if (start) {
        state.fields.startPoint = start;
        touched += 1;
      }
    }
    if (!isCapturedValue(state.fields.endPoint)) {
      const end = inferEndPointFromOverview(raw);
      if (end) {
        state.fields.endPoint = end;
        touched += 1;
      }
    }
  }

  const tools = inferToolsFromAnswer(raw);
  tools.forEach((tool) => {
    const before = state.systems.length;
    mergeCollectionRecord("systems", {
      ...newRecord("systems"),
      name: tool,
      purpose: "Mentioned in the top-level workflow overview.",
      access: inferOverviewAccessMode(raw)
    });
    if (state.systems.length > before) touched += 1;
  });

  inferDataCategoriesFromOverview(raw).forEach((category) => {
    const before = state.data.length;
    mergeCollectionRecord("data", {
      ...newRecord("data"),
      category,
      source: inferOverviewDataSource(raw),
      sensitivity: inferOverviewSensitivity(raw),
      usageMode: "Top-level workflow input or in-process data",
      processing: "Mentioned in the broad workflow overview."
    });
    if (state.data.length > before) touched += 1;
  });

  const outputs = inferOverviewOutputs(raw);
  if (outputs.length && !isCapturedValue(state.fields.expectedWorkshopOutput) && /\bworkshop|agenda|facilitator|pre[- ]?read|deck|mural|miro\b/i.test(raw)) {
    state.fields.expectedWorkshopOutput = outputs.join(", ");
    touched += 1;
  }
  if (outputs.length && !isCapturedValue(state.fields.businessOutcome)) {
    state.fields.businessOutcome = `Produces ${outputs.join(", ")}.`;
    touched += 1;
  }

  if (touched && !state.currentQuestionSource) {
    state.currentQuestionSource = "Workflow overview";
  }
  return touched;
}

function inferWorkflowNameFromOverview(text = "") {
  const compact = String(text || "").replace(/\s+/g, " ").trim();
  const named = compact.match(/\b(?:called|workflow is|workflow called|task is)\s+["']?([^"'.;,]+)["']?/i)?.[1];
  if (named) return truncateUi(named.trim(), 72);
  const submitted = state.fields.submittedWorkflowTask || state.fields.submittedIdea || "";
  return submitted ? truncateUi(submitted, 72) : truncateUi(compact.split(/\b(?:starts?|begins?|ends?|produces?|outputs?)\b/i)[0], 72);
}

function inferStartPointFromOverview(text = "") {
  return String(text || "").match(/\b(?:starts?|begins?|triggered|kicks off)\s+(?:when|with|from)?\s*([^.;]+)/i)?.[1]?.trim() || "";
}

function inferEndPointFromOverview(text = "") {
  return String(text || "").match(/\b(?:ends?|finishes?|wraps up|final output is|produces?|creates?)\s+(?:with|when|as)?\s*([^.;]+)/i)?.[1]?.trim() || "";
}

function inferOverviewAccessMode(text = "") {
  const hints = inferStepDetailHintsFromAnswer(text);
  return hints.accessMode || "";
}

function inferOverviewDataSource(text = "") {
  const tools = inferToolsFromAnswer(text);
  return tools.length ? tools.join(", ") : "";
}

function inferOverviewSensitivity(text = "") {
  const raw = String(text || "");
  if (/\bpii|personal data|regulated|mnpi|pci|phi\b/i.test(raw)) return "Regulated or personal data may be involved";
  if (/\bclient confidential|client data|client files?|customer|financial|legal\b/i.test(raw)) return "Client confidential or sensitive";
  if (/\binternal\b/i.test(raw)) return "Internal";
  return "";
}

function inferDataCategoriesFromOverview(text = "") {
  const raw = String(text || "");
  const matches = [
    [/client (?:objectives|goals|request|problem|context)/i, "Client objectives / request context"],
    [/\battendee|participant|stakeholder|decision[- ]maker/i, "Participants / stakeholders"],
    [/\bprior decks?|powerpoint|presentation|slide/i, "Prior decks / presentation materials"],
    [/\bword documents?|documents?|docs?|notes|meeting notes|transcripts?/i, "Documents / notes / transcripts"],
    [/\btracker|spreadsheet|excel|status report|reporting/i, "Trackers / spreadsheets / reports"],
    [/\brequirements?|user stories|acceptance criteria/i, "Requirements / acceptance criteria"],
    [/\bfinancial targets?|commercial|budget|revenue|margin|cost/i, "Financial or commercial context"],
    [/\brisk|issue|exception|defect|control/i, "Risks / issues / exceptions"],
    [/\bresearch|market|benchmark|competitive|industry/i, "Research / benchmark inputs"],
    [/\bemail|teams|chat|planning conversation/i, "Messages / planning conversations"],
    [/\bscreenshot|export/i, "Screenshots / exports"]
  ];
  return uniqueSignals(matches.filter(([pattern]) => pattern.test(raw)).map(([, label]) => label));
}

function inferOverviewOutputs(text = "") {
  const raw = String(text || "");
  const matches = [
    [/\bagenda\b/i, "agenda"],
    [/\bpre[- ]?read\b/i, "pre-read"],
    [/\bdeck|slides?|powerpoint|presentation\b/i, "deck"],
    [/\bfacilitator guide|guide\b/i, "facilitator guide"],
    [/\bresearch pack|research summary|market research\b/i, "research pack"],
    [/\bmiro|mural|board\b/i, "collaboration board"],
    [/\bstatus pack|status report|report\b/i, "status report"],
    [/\baction list|next steps|actions\b/i, "action list"],
    [/\brecommendation|decision\b/i, "recommendation or decision"],
    [/\bworkshop materials?|workshop package|materials\b/i, "workshop materials"]
  ];
  return uniqueSignals(matches.filter(([pattern]) => pattern.test(raw)).map(([, label]) => label));
}

function inferStepDetailHintsFromAnswer(answer = "") {
  const raw = String(answer || "");
  const text = raw.toLowerCase();
  if (!text.trim()) return {};
  const hints = {};
  const tools = inferToolsFromAnswer(text);
  if (tools.length) hints.tool = tools.join(", ");

  const accessModes = [];
  const hasMicrosoftFiles = /\b(microsoft\s*365|m365|office\s*365|sharepoint|teams|powerpoint|word|deck|decks|document|documents|folder|folders|file|files|link|links|template|templates|email|outlook)\b/i.test(raw);
  const hasFileLanguage = /\b(file|files|folder|folders|document|documents|deck|decks|link|links|template|templates|sharepoint|word|powerpoint|email|teams)\b/i.test(raw);
  if (hasMicrosoftFiles && hasFileLanguage) accessModes.push("Microsoft 365 file-based / approved file links");
  if (/\b(export|exports|exported|screenshot|screenshots|screen shot|screen shots)\b/i.test(raw)) accessModes.push("exports/screenshots");
  if (/\b(transcript|transcripts|notes|meeting notes|planning notes)\b/i.test(raw)) accessModes.push("transcripts/notes");
  if (/\b(user[- ]provided|provided by the user|approved files?|approved links?|provided links?|uploaded|attachments?)\b/i.test(raw)) accessModes.push("user-provided approved inputs");
  if (/\b(no|not|without)\s+(?:direct\s+)?(?:system\s+)?access\b/i.test(raw) || /\bno direct system access\b/i.test(raw)) {
    accessModes.push("no direct system access for MVP");
  } else if (/\bdirect\s+(?:system\s+)?access\b/i.test(raw)) {
    accessModes.push("direct system access");
  }
  if (accessModes.length) hints.accessMode = uniqueSignals(accessModes).join("; ");

  if (/\b(strategy manager|engagement lead)\b/i.test(raw)) {
    hints.actor = "Strategy manager or engagement lead";
  } else if (/\b(manager|senior consultant|analyst|workshop lead|consultant)\b/i.test(raw) && /\b(does|owns|handles|identifies|team|usually)\b/i.test(raw)) {
    hints.actor = "Manager, consultant, or analyst";
  }

  const inputParts = [];
  if (/\b(approved files?|approved links?|provided links?|user[- ]provided links?)\b/i.test(raw)) inputParts.push("approved files or links");
  if (/\b(exported notes?|screenshots?|transcripts?)\b/i.test(raw)) inputParts.push("exported notes, screenshots, or transcripts");
  if (inputParts.length && /\b(work from|input|source|provided|approved|uploaded)\b/i.test(raw)) {
    hints.input = uniqueSignals(inputParts).join("; ");
  }

  if (/\b(client confidential|client data|confidential|regulated|personal data|financial data|sensitive)\b/i.test(raw)) {
    hints.dataSensitivity = "Client confidential or sensitive data may be involved";
  }

  return hints;
}

function inferToolsFromAnswer(text = "") {
  const matches = [
    [/sharepoint/i, "SharePoint"],
    [/\bteams\b|microsoft teams/i, "Microsoft Teams"],
    [/\boutlook\b|\bemail\b/i, "Outlook/email"],
    [/powerpoint|\bppt\b|\bdeck\b|\bdecks\b/i, "PowerPoint"],
    [/\bword\b|\bword notes\b/i, "Word"],
    [/\bmiro\b/i, "Miro"],
    [/\bmural\b/i, "Mural"],
    [/project tracker|\btracker\b/i, "project tracker"],
    [/planning notes/i, "planning notes"],
    [/confluence/i, "Confluence"],
    [/\bjira\b/i, "Jira"],
    [/github/i, "GitHub"],
    [/bitbucket/i, "Bitbucket"]
  ];
  return uniqueSignals(matches.filter(([pattern]) => pattern.test(text)).map(([, label]) => label));
}

function hasToolSignals(text = "") {
  return inferToolsFromAnswer(String(text || "")).length > 0
    || /\b(system|systems|tool|tools|platform|application|repository|database|tracker|spreadsheet|folder|folders)\b/i.test(String(text || ""));
}

function hasDataSignals(text = "") {
  return /\b(data|input|inputs|client data|file|files|document|documents|deck|decks|tracker|spreadsheet|report|reports|screenshot|screenshots|transcript|notes|requirements|objectives|financial|customer|participant|attendee|risk|issue|exception)\b/i.test(String(text || ""));
}

function hasOutputSignals(text = "") {
  return /\b(output|outputs|deliverable|deliverables|deck|agenda|pre-read|preread|guide|packet|pack|report|summary|status|decision|recommendation|action list|workshop materials|client-ready|final)\b/i.test(String(text || ""));
}

function shouldReplaceStepDetailValue(value) {
  const normalized = String(value || "").replace(/\s+/g, " ").trim().toLowerCase();
  if (!isCapturedValue(normalized)) return true;
  return /^unknown\b/.test(normalized)
    || /^tbd\b/.test(normalized)
    || /^not asked\b/.test(normalized)
    || /\bunknown\b.*\blikely\b/.test(normalized)
    || /\bexact (?:mode|tool|access).*unknown\b/.test(normalized);
}

function mergeSignalList(currentValue, incomingValue, delimiter = "; ") {
  const current = String(currentValue || "").replace(/\s+/g, " ").trim();
  const incomingParts = String(incomingValue || "")
    .split(delimiter.trim() === "," ? /\s*,\s*/ : /\s*;\s*/)
    .map((part) => part.trim())
    .filter(isCapturedValue);
  if (!current) return incomingParts.join(delimiter);
  const merged = [current];
  const lowered = current.toLowerCase();
  incomingParts.forEach((part) => {
    const normalized = part.toLowerCase();
    if (!lowered.includes(normalized)) merged.push(part);
  });
  return merged.join(delimiter);
}

function uniqueSignals(values = []) {
  const seen = new Set();
  return values
    .map((value) => String(value || "").replace(/\s+/g, " ").trim())
    .filter((value) => {
      const key = value.toLowerCase();
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    });
}

function extractStepAnchorsFromText(answer) {
  const text = String(answer || "").replace(/\r/g, "\n");
  if (!text.trim()) return [];
  const wordNumbers = {
    one: 1,
    two: 2,
    three: 3,
    four: 4,
    five: 5,
    six: 6,
    seven: 7,
    eight: 8,
    nine: 9,
    ten: 10
  };
  const ordinals = {
    first: 1,
    second: 2,
    third: 3,
    fourth: 4,
    fifth: 5,
    sixth: 6,
    seventh: 7,
    eighth: 8,
    ninth: 9,
    tenth: 10
  };
  const markerPattern = /(?:^|[\n;]|(?:\.\s+)|\b)\s*(?:(?:step\s+(\d{1,2}|one|two|three|four|five|six|seven|eight|nine|ten))|(?:(first|second|third|fourth|fifth|sixth|seventh|eighth|ninth|tenth)(?:\s+step)?)|(\d{1,2})[.)])\s*(?:is|are|then|:|-|,)?\s*/gi;
  const markers = [];
  let match;
  while ((match = markerPattern.exec(text))) {
    const raw = (match[1] || match[2] || match[3] || "").toLowerCase();
    const number = Number(raw) || wordNumbers[raw] || ordinals[raw] || markers.length + 1;
    markers.push({
      number,
      markerStart: match.index,
      contentStart: markerPattern.lastIndex
    });
  }
  if (markers.length < 2 && !/\bstep\s+(?:\d|one|two|three|four|five|six|seven|eight|nine|ten)\b/i.test(text)) {
    return [];
  }

  return markers
    .map((marker, index) => {
      const next = markers[index + 1];
      const rawAction = text.slice(marker.contentStart, next ? next.markerStart : text.length);
      const action = cleanStepAction(rawAction);
      if (!action || action.length < 4) return null;
      const name = stepNameFromAction(action);
      return {
        ...newRecord("steps"),
        name: `Step ${marker.number}: ${name}`,
        action,
        evidenceConfidence: "Medium",
        interviewNotes: "Captured from spoken step marker such as Step 1, first step, or numbered list."
      };
    })
    .filter(Boolean);
}

function cleanStepAction(value) {
  return String(value || "")
    .replace(/\s+/g, " ")
    .replace(/^[,:\-\s]+/, "")
    .replace(/[.;,\s]+$/, "")
    .trim();
}

function stepNameFromAction(action) {
  const sentence = String(action || "").split(/[.!?]/)[0] || action;
  const words = sentence.split(/\s+/).filter(Boolean);
  return truncateUi(words.slice(0, 9).join(" "), 72);
}

function mergeCollectionRecord(collection, record) {
  const keyField = { data: "category", systems: "name", decisions: "decision", patterns: "step" }[collection];
  const key = normalizeStepKey(record?.[keyField]);
  const existing = state[collection].find((item) => key && normalizeStepKey(item?.[keyField]) === key);
  if (!existing) {
    state[collection].push(record);
    return;
  }
  for (const [field, value] of Object.entries(record)) {
    if (String(value || "").trim() && !String(existing[field] || "").trim()) {
      existing[field] = value;
    }
  }
}

function normalizeStepKey(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/^\s*(step\s*)?\d+[\).:-]?\s*/i, "")
    .replace(/[^a-z0-9]+/g, " ")
    .trim();
}

function latestTranscriptBlock() {
  const chatText = (state.aiChat || [])
    .slice(-8)
    .map((message) => `${message.role === "user" ? "User" : "AI"}: ${message.text}`)
    .join("\n");
  const conversationText = (state.conversation || [])
    .slice(-8)
    .map((message) => `${message.role === "user" ? "User" : "AI"}: ${message.text}`)
    .join("\n");
  return [chatText, conversationText].filter(Boolean).join("\n\n").trim();
}

function syncCurrentQuestionFromText(text, source) {
  const cleaned = String(text || "").trim();
  const question = extractQuestionFromText(cleaned) || (source === "AI extraction" && cleaned.length <= 220 ? cleaned : "");
  if (!question) return;
  if (state.steps.length && isProceedPermissionQuestion(question)) return;
  state.currentQuestionOverride = question;
  state.currentQuestionSource = source ? `From ${source}` : "From latest AI message";
}

function inferSectionFromQuestion(question) {
  const text = String(question || "").toLowerCase();
  const matches = [
    ["idea", ["submitted idea", "original ask", "domain team", "workflow category", "category"]],
    ["validate", ["validation status", "build readiness", "commercial", "paid", "unpaid", "pursuit"]],
    ["workflow", ["trigger", "start", "initiate", "event", "frequency", "step", "walk me", "process", "sequence", "first action", "final output", "data", "file", "document", "source", "sensitive", "client data", "system", "tool", "application", "repository", "database"]],
    ["evidence", ["evidence", "artifact", "screenshot", "upload", "deck", "transcript"]],
    ["value", ["how often", "how long", "duration", "volume", "pain", "friction", "capacity", "margin"]],
    ["aiFit", ["ai pattern", "automate", "summarize", "classify", "extract", "candidate ai", "copilot", "chatgpt"]],
    ["blueprint", ["decision", "approve", "approval", "human", "escalation", "map", "blueprint"]],
    ["review", ["correctly", "confirm", "play this back", "missing", "pdr", "handoff", "open question", "engineering"]]
  ];
  return matches.find(([, terms]) => terms.some((term) => text.includes(term)))?.[0] || "";
}

function intakeSnapshot() {
  return {
    fields: Object.values(state.fields || {}).filter(isCapturedValue).length,
    steps: state.steps?.length || 0,
    data: state.data?.length || 0,
    systems: state.systems?.length || 0,
    decisions: state.decisions?.length || 0,
    ideas: state.ideas?.length || 0,
    evidenceArtifacts: state.evidenceArtifacts?.filter((artifact) => artifact.applied || artifact.status === "reviewed").length || 0,
    mapReviews: state.mapReviews?.length || 0
  };
}

function addIntakeDelta(source, before, after, note) {
  const delta = {
    source,
    note,
    time: new Date().toISOString(),
    fields: Math.max(0, after.fields - before.fields),
    steps: Math.max(0, after.steps - before.steps),
    data: Math.max(0, after.data - before.data),
    systems: Math.max(0, after.systems - before.systems),
    decisions: Math.max(0, after.decisions - before.decisions),
    ideas: Math.max(0, after.ideas - before.ideas),
    evidenceArtifacts: Math.max(0, after.evidenceArtifacts - before.evidenceArtifacts),
    mapReviews: Math.max(0, after.mapReviews - before.mapReviews)
  };
  const changed = ["fields", "steps", "data", "systems", "decisions", "ideas", "evidenceArtifacts", "mapReviews"].some((key) => delta[key] > 0);
  if (!changed && !note) return null;
  state.intakeDeltas = [delta, ...(state.intakeDeltas || [])].slice(0, 12);
  return delta;
}

function addConversationMessage(role, text, section = getActiveSection().label) {
  const messageText = normalizeLiveAssistantReply(role, text);
  if (!messageText) return;
  state.conversation = state.conversation || [];
  state.conversation.push({
    role,
    section,
    text: messageText,
    time: new Date().toISOString()
  });
  if (role === "assistant" && section !== "AI Summary" && !/\bis that correct\?\s*$/i.test(messageText.trim())) {
    syncCurrentQuestionFromText(messageText, section);
    renderCurrentQuestion();
  }
  persistState();
  renderConversation();
}

function lastConversationTextIs(role, text) {
  const last = state.conversation?.[state.conversation.length - 1];
  return last?.role === role && last?.text === text;
}

function lastAssistantAskedConfirmation() {
  const lastAssistant = [...(state.conversation || [])].reverse().find((message) => message.role === "assistant");
  return /\bis that correct\?\s*$/i.test(lastAssistant?.text || "");
}

function isConfirmationAnswer(text) {
  return /^(yes|yeah|yep|correct|that's correct|that is correct|right|looks right|sounds right|confirmed|confirm|exactly|good|yes that's right|yes that is right)[.! ]*$/i.test(String(text || "").trim());
}

function isCorrectionAnswer(text) {
  return /^(no|nope|not quite|not really|needs changes|needs correction|change it|revise|revise it|not correct)[.! ]*$/i.test(String(text || "").trim());
}

function isProceedPermissionQuestion(text = "") {
  const normalized = String(text || "").toLowerCase().replace(/\s+/g, " ").trim();
  if (!normalized) return false;
  const asksPermission = /\b(should we|do you want|would you like|ready to|shall we|can we|before we)\b/.test(normalized)
    || /\b(move on|move to|move into|move forward|proceed|continue)\b/.test(normalized)
    || /\bdo these look right\b/.test(normalized);
  const stepContext = /\b(step|steps|skeleton|workflow|process map|drill|drill-down|detail|details|review)\b/.test(normalized);
  return asksPermission && stepContext;
}

function wordCount(text = "") {
  return String(text || "").trim().split(/\s+/).filter(Boolean).length;
}

function isSameQuestion(a = "", b = "") {
  const normalize = (value) => cleanQuestionLabel(value)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  const left = normalize(a);
  const right = normalize(b);
  if (!left || !right) return false;
  if (left === right) return true;
  if (Math.min(left.length, right.length) < 28) return false;
  return left.includes(right) || right.includes(left);
}

function isThinOpeningAnswer(answer = "", askedQuestion = "") {
  const text = String(answer || "").trim();
  if (!text || state.steps.length || explicitStepIndexFromAnswer(text) >= 0) return false;
  const question = String(askedQuestion || state.currentQuestionOverride || "").toLowerCase();
  if (question && !/task|workflow|idea|use case|talk about|explore/i.test(question)) return false;
  if (wordCount(text) > 12) return false;
  if (/\b(first|second|third|fourth|fifth|step|then|after|finally|trigger|start|end|output|input|system|tool|sharepoint|powerpoint|excel|email|teams|client request)\b/i.test(text)) {
    return false;
  }
  return /\b(use case|workflow|task|process|workshop|testing|qa|research|governance|analytics|document|legal|crm|uat|requirement|risk)\b/i.test(text);
}

function compactStartingTopic(answer = "") {
  return String(answer || "")
    .replace(/^\s*(let'?s|let us)\s+(explore|talk about|discuss|look at|start with)\b[\s,.:;-]*/i, "")
    .replace(/^\s*(sure|yeah|yes|ok|okay|so|it'?s|it is|about|this is|the)\b[\s,.:;-]*/gi, "")
    .replace(/\b(it'?s|it is|about|the)\b/gi, "")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/[.;,\s]+$/, "")
    .replace(/^./, (char) => char.toUpperCase())
    .slice(0, 90);
}

function isGenericStartingTopic(value = "") {
  const normalized = String(value || "")
    .toLowerCase()
    .replace(/[^a-z0-9 ]+/g, " ")
    .replace(/\b(the|a|an|this|that|new|another|some|something|generic|sample|example)\b/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  if (!normalized) return true;
  return /^(use case|workflow|task|process|idea|opportunity|workstream|project|case)$/.test(normalized);
}

function isSpecificSubmittedTopic(value = "") {
  return isCapturedValue(value) && !isGenericStartingTopic(value);
}

function questionAsksDataBoundary(question = "") {
  const text = String(question || "").toLowerCase();
  return /\b(data boundary|msa|client[- ]approved|sanitized artifacts|client data approval|internal only|deployment environment|where would the solution run)\b/.test(text);
}

function answerLooksLikeDataBoundary(answer = "") {
  return /\b(client[- ]approved|client environment|approved environment|internal data|internal only|sanitized|exported|msa|client data|no production data|approved to use|client tenant|client vdi|sandbox)\b/i.test(String(answer || ""));
}

function isSubmittedTopicCaptured(candidateState = state) {
  const fields = candidateState.fields || {};
  return isSpecificSubmittedTopic(fields.submittedIdea) || isSpecificSubmittedTopic(fields.submittedWorkflowTask);
}

function workflowInterviewStage() {
  const signals = workflowOverviewSignals();
  const overview = workflowOverviewQuestion([]);
  const hasProcessSkeleton = state.steps.length > 0;
  return {
    submittedCaptured: isSubmittedTopicCaptured(),
    signals,
    overview,
    hasProcessSkeleton,
    isWorkshop: state.fields.workflowCategory === "Pre-delivery / workshop prep",
    shouldShowHandoffGaps: hasProcessSkeleton
  };
}

function isPrematureSupplementalQuestion(question = "", candidateState = state) {
  if (candidateState.steps?.length) return false;
  const submittedCaptured = isSubmittedTopicCaptured(candidateState);
  if (!submittedCaptured) return false;
  const text = String(question || "").toLowerCase();
  return questionAsksDataBoundary(text)
    || /\b(commercial context|value path|hours saved|dollars|capacity|staffing|margin|frequency|time baseline|kpi|pilot worked|success metric|governance path|post-build review|deployment environment)\b/.test(text);
}

function applyCurrentQuestionAnswer(answer = "", askedQuestion = "") {
  const text = String(answer || "");
  if (!text.trim()) return;
  if (isThinOpeningAnswer(text, askedQuestion) && !isCapturedValue(state.fields.submittedIdea)) {
    const topic = compactStartingTopic(text) || text.trim();
    if (!isGenericStartingTopic(topic)) {
      state.fields.submittedIdea = topic;
    }
  }
  if (!questionAsksDataBoundary(askedQuestion) || !answerLooksLikeDataBoundary(text)) return;

  const lower = text.toLowerCase();
  if (/\binternal only\b|no client data/.test(lower)) {
    state.fields.msaBoundary = "Internal delivery only; no client data";
  } else if (/sanitized|export/.test(lower)) {
    state.fields.msaBoundary = "Uses sanitized/exported artifacts";
  } else if (/msa|contract/.test(lower)) {
    state.fields.msaBoundary = "Likely MSA review needed";
  } else if (/client data|client approval/.test(lower)) {
    state.fields.msaBoundary = "Requires client data access approval";
  } else if (/client[- ]approved|approved environment|approved to use|sandbox/.test(lower)) {
    state.fields.msaBoundary = "Client-approved environment; no production data";
  }

  if (/client[- ]approved|approved environment|sandbox/.test(lower)) {
    state.fields.deploymentEnvironment = "Client-approved sandbox";
  } else if (/client tenant/.test(lower)) {
    state.fields.deploymentEnvironment = "Client cloud tenant";
  } else if (/client vdi/.test(lower)) {
    state.fields.deploymentEnvironment = "Client VDI";
  } else if (/\binternal\b/.test(lower) && state.fields.deploymentEnvironment === "Unknown") {
    state.fields.deploymentEnvironment = "Company internal";
  }

  if (/client/.test(lower) && !/no client data/.test(lower)) {
    state.fields.dataSensitivity = "Client Confidential";
  } else if (/\binternal data\b|\binternal\b/.test(lower) && state.fields.dataSensitivity === "Unknown") {
    state.fields.dataSensitivity = "Internal";
  }
}

function isLegacyDiscoveryQuestion(text = "") {
  const normalized = String(text || "").toLowerCase().replace(/\s+/g, " ").trim();
  return /validated workflow name, finance domain/.test(normalized)
    || /commercial context paid, unpaid investment/.test(normalized)
    || /prepare final workshop readiness/.test(normalized)
    || /personell mix|personnel mix|fixed-fee|margin\/capacity/.test(normalized);
}

function manualCaptureReply(section) {
  return `Captured that under ${section.label}. The current question is now: ${getActiveSection().question}`;
}

function buildAiReply(result, answer = result._answer || "", routedNextQuestion = "") {
  const nextQuestion = routedNextQuestion || nextQuestionAfterCapture(result);
  if (questionAsksDataBoundary(result._askedQuestion) && answerLooksLikeDataBoundary(answer)) {
    return intakeCaptureAcknowledgement(result, nextQuestion, answer);
  }
  if (state.steps.length && state.drilldown?.status === "active") {
    return stepCaptureAcknowledgement(nextQuestion);
  }
  return intakeCaptureAcknowledgement(result, nextQuestion, answer);
}

function normalizeLiveAssistantReply(role, text) {
  const raw = String(text || "").trim();
  if (role !== "assistant" || !raw) return raw;
  if (/^here is what i heard:/i.test(raw) || /^captured additional step/i.test(raw) || /\bis that correct\?\s*$/i.test(raw)) {
    const extractedQuestion = extractQuestionFromText(raw);
    const nextQuestion = nextQuestionAfterCapture({ nextQuestion: extractedQuestion });
    if (!state.steps.length || state.drilldown?.status !== "active") {
      return intakeCaptureAcknowledgement({}, nextQuestion);
    }
    return stepCaptureAcknowledgement(stepInterviewQuestion());
  }
  return raw;
}

function intakeCaptureAcknowledgement(result = {}, nextQuestion = nextQuestionAfterCapture(result), answer = result._answer || "") {
  const captured = capturedIntakeLabels(result);
  const prefix = conciseAnswerSummary(answer, result);
  const capturedText = captured.length ? ` I captured this as ${captured.join(", ")}.` : " I captured that.";
  const nextText = nextQuestion ? ` Next: ${nextQuestion}` : "";
  const playback = shouldIncludeWorkflowPlayback() ? `${workflowPlaybackSummary()} ` : "";
  if (isThinOpeningAnswer(answer, result._askedQuestion)) return `${prefix}${nextText}`;
  return `${playback}${prefix}${capturedText}${nextText}`;
}

function shouldIncludeWorkflowPlayback() {
  const userTurns = (state.conversation || []).filter((message) => message.role === "user").length;
  if (userTurns < 3 || userTurns % 3 !== 0) return false;
  const recentAssistantText = [...(state.conversation || [])].reverse().find((message) => message.role === "assistant")?.text || "";
  if (/quick playback:/i.test(recentAssistantText)) return false;
  const signals = workflowOverviewSignals();
  return Boolean(state.steps.length || signals.componentOverviewCaptured || isCapturedValue(state.fields.workflowName));
}

function workflowPlaybackSummary() {
  const pieces = [];
  const workflow = state.fields.workflowName || state.fields.submittedWorkflowTask || state.fields.submittedIdea;
  if (isCapturedValue(workflow)) pieces.push(`workflow: ${truncateUi(workflow, 56)}`);
  if (state.steps.length) pieces.push(`${state.steps.length} step${state.steps.length === 1 ? "" : "s"}`);
  const tools = uniqueSignals([
    ...(state.systems || []).map((system) => system.name),
    ...(state.steps || []).map((step) => step.tool)
  ].filter(isCapturedValue)).slice(0, 3);
  if (tools.length) pieces.push(`tools: ${tools.join(", ")}`);
  const data = uniqueSignals([
    ...(state.data || []).map((item) => item.category),
    ...(state.steps || []).map((step) => step.input || step.dataHandling)
  ].filter(isCapturedValue)).slice(0, 3);
  if (data.length) pieces.push(`data: ${data.join(", ")}`);
  const output = state.fields.expectedWorkshopOutput || state.fields.businessOutcome || state.fields.endPoint || state.steps.find((step) => isCapturedValue(step.output))?.output;
  if (isCapturedValue(output)) pieces.push(`output: ${truncateUi(output, 56)}`);
  if (!pieces.length) return "";
  return `Quick playback: I have ${pieces.join("; ")}. Correct anything that is off.`;
}

function capturedIntakeLabels(result = {}) {
  if (isThinOpeningAnswer(result._answer, result._askedQuestion)) {
    return isGenericStartingTopic(compactStartingTopic(result._answer)) ? [] : ["starting topic"];
  }
  const labels = [];
  if (questionAsksDataBoundary(result._askedQuestion) && answerLooksLikeDataBoundary(result._answer)) {
    labels.push("data boundary");
  }
  const fields = result.fields || {};
  const records = result.newRecords || {};
  const fieldLabels = [
    ["submittedIdea", "submitted idea"],
    ["submittedWorkflowTask", "submitted workflow"],
    ["workflowName", "workflow name"],
    ["workflowCategory", "workflow category"],
    ["domain", "domain"],
    ["commercialContext", "commercial context"],
    ["commercialValuePath", "value path"],
    ["businessOutcome", "business outcome"],
    ["expectedWorkshopOutput", "output"],
    ["submittedWhereToday", "where it happens today"],
    ["candidateAiAssistValidation", "candidate AI assist"],
    ["msaBoundary", "MSA/client boundary"],
    ["deploymentEnvironment", "deployment environment"],
    ["dataSensitivity", "data sensitivity"],
    ["availableTooling", "available tooling"]
  ];
  fieldLabels.forEach(([key, label]) => {
    if (isCapturedValue(fields[key]) && !labels.includes(label)) labels.push(label);
  });
  if (records.steps?.length) labels.push(`${records.steps.length} workflow step${records.steps.length === 1 ? "" : "s"}`);
  if (records.data?.length) labels.push(`${records.data.length} data signal${records.data.length === 1 ? "" : "s"}`);
  if (records.systems?.length) labels.push(`${records.systems.length} system/tool signal${records.systems.length === 1 ? "" : "s"}`);
  if (records.decisions?.length) labels.push(`${records.decisions.length} decision signal${records.decisions.length === 1 ? "" : "s"}`);
  return labels.slice(0, 3);
}

function conciseAnswerSummary(answer = "", result = {}) {
  const text = String(answer || "").replace(/\s+/g, " ").trim();
  if (!text) return "I reviewed that answer.";
  if (isThinOpeningAnswer(text, result._askedQuestion)) {
    if (isGenericStartingTopic(compactStartingTopic(text))) {
      return "I need the actual workflow or use-case name before we frame it.";
    }
    return `I heard this is about ${compactStartingTopic(text) || "an early use-case idea"}.`;
  }
  if (questionAsksDataBoundary(result._askedQuestion) && answerLooksLikeDataBoundary(text)) {
    return `I heard the boundary as ${truncateUi(text, 130)}.`;
  }
  return `I heard: ${truncateUi(text, 130)}.`;
}

function stepCaptureAcknowledgement(nextQuestion = stepInterviewQuestion()) {
  const fields = capturedFieldsForReply();
  const captured = fields.length ? `I captured ${fields.join(", ")}.` : `I captured that detail.`;
  return `${captured} ${nextQuestion}`;
}

function capturedFieldsForReply() {
  const current = getCurrentStep();
  const captured = current
    ? stepFieldStatusList(current)
        .filter((item) => item.status === "captured")
        .map((item) => item.label.toLowerCase())
    : [];
  return captured.filter((label) => !["action", "confidence"].includes(label)).slice(0, 3);
}

function nextQuestionAfterCapture(result = {}) {
  const route = nextQuestionRouteAfterExtraction(result);
  if (route?.text && !isProceedPermissionQuestion(route.text)) return route.text;
  if (state.steps.length) return stepInterviewQuestion();
  const checklistQuestion = topHandoffChecklistQuestions(3)
    .find((question) => !isSameQuestion(question, result._askedQuestion) && !isSameQuestion(question, result.nextQuestion));
  if (checklistQuestion && !isProceedPermissionQuestion(checklistQuestion)) return checklistQuestion;
  if (result.nextQuestion && !isProceedPermissionQuestion(result.nextQuestion) && !isSameQuestion(result.nextQuestion, result._askedQuestion)) return result.nextQuestion;
  return currentValidationStage().question;
}

function latestDeltaSummary() {
  const latest = state.intakeDeltas?.[0];
  if (!latest) return "";
  const labels = [
    ["fields", "field"],
    ["steps", "step"],
    ["data", "data item"],
    ["systems", "tool/system"],
    ["decisions", "decision"],
    ["ideas", "parked idea"],
    ["evidenceArtifacts", "evidence artifact"],
    ["mapReviews", "map checkpoint"]
  ];
  const changes = labels
    .map(([key, label]) => {
      const count = latest[key] || 0;
      if (!count) return "";
      return `${count} ${label}${count === 1 ? "" : "s"}`;
    })
    .filter(Boolean);
  if (!changes.length) return "I checked the answer against the intake matrix and kept the existing structure.";
  return `I updated ${changes.join(", ")} in the intake.`;
}

async function maybeSpeak(text) {
  // Skip when the toggle is off, or when a live realtime call owns the audio.
  if (!state.voiceReplyEnabled || realtimeConnection) return;
  const clean = normalizeLiveAssistantReply("assistant", text);
  if (!clean) return;
  // Interrupt anything already playing so replies never overlap.
  stopSpeaking();
  if (ttsAvailable) {
    try {
      ttsAbortController = new AbortController();
      const response = await fetch("/api/tts/speak", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text: clean }),
        signal: ttsAbortController.signal
      });
      if (!response.ok) {
        const payload = await response.json().catch(() => ({}));
        throw new Error(payload.error || `TTS request failed with status ${response.status}`);
      }
      const blob = await response.blob();
      const url = URL.createObjectURL(blob);
      const audio = new Audio(url);
      ttsAudioElement = audio;
      setSpeakingUi(true);
      const release = () => {
        URL.revokeObjectURL(url);
        if (ttsAudioElement === audio) {
          ttsAudioElement = null;
          setSpeakingUi(false);
        }
      };
      audio.addEventListener("ended", release, { once: true });
      audio.addEventListener("error", release, { once: true });
      await audio.play();
      return;
    } catch (error) {
      // AbortError means the user/UI intentionally stopped playback; stay silent.
      if (error?.name === "AbortError") return;
      // Any other failure (offline, quota, etc.) falls back to the browser voice.
      ttsAbortController = null;
    }
  }
  speakWithBrowser(clean);
}

function speakWithBrowser(text) {
  if (!("speechSynthesis" in window)) return;
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(text);
  const voice = selectNaturalBrowserVoice();
  if (voice) utterance.voice = voice;
  utterance.rate = 0.94;
  utterance.pitch = 1.04;
  utterance.volume = 0.95;
  utterance.addEventListener("end", () => setSpeakingUi(false), { once: true });
  setSpeakingUi(true);
  window.speechSynthesis.speak(utterance);
}

function stopSpeaking() {
  if (ttsAbortController) {
    ttsAbortController.abort();
    ttsAbortController = null;
  }
  if (ttsAudioElement) {
    ttsAudioElement.pause();
    ttsAudioElement.src = "";
    ttsAudioElement = null;
  }
  if ("speechSynthesis" in window) {
    window.speechSynthesis.cancel();
  }
  setSpeakingUi(false);
}

// Keep the Stop button live while the AI is speaking so it can interrupt
// playback, without clobbering the recording state that owns it otherwise.
function setSpeakingUi(speaking) {
  const stopButton = document.getElementById("endRecordingButton");
  if (!stopButton) return;
  if (speaking) {
    stopButton.disabled = false;
  } else if (!postTurnRecorder && !isListening) {
    stopButton.disabled = true;
  }
}

function selectNaturalBrowserVoice() {
  const voices = browserVoices.length ? browserVoices : window.speechSynthesis.getVoices();
  const preferred = [
    "Samantha",
    "Victoria",
    "Karen",
    "Moira",
    "Tessa",
    "Serena",
    "Microsoft Jenny",
    "Microsoft Aria",
    "Google UK English Female",
    "Google US English",
    "Natural",
    "Enhanced",
    "Premium"
  ];
  return (
    preferred.map((name) => voices.find((voice) => voice.name.includes(name) && voice.lang.startsWith("en"))).find(Boolean) ||
    voices.find((voice) => voice.lang === "en-US") ||
    voices.find((voice) => voice.lang.startsWith("en")) ||
    null
  );
}

function maybePromptMapCheckpoint(sectionId) {
  if (sectionId === "workflow" && state.steps.length >= 3) {
    toast("Map checkpoint: review the process map and confirm the sequence.");
  }
}

function goToNextSection() {
  const visible = getVisibleSections();
  const index = visible.findIndex((section) => section.id === state.activeSection);
  state.activeSection = visible[Math.min(index + 1, visible.length - 1)].id;
  state.currentQuestionOverride = "";
  state.currentQuestionSource = "Intake guide";
  persistState();
  render();
}

function addIdea(existingText) {
  const text = typeof existingText === "string" ? existingText : els.ideaInput.value.trim();
  if (!text) return;
  state.ideas.push({ idea: text, source: getActiveSection().label, notes: "" });
  els.ideaInput.value = "";
  persistState();
  renderIdeas();
  toast("Idea parked for later.");
}

function addMapFeedback() {
  const feedback = els.mapFeedbackInput.value.trim();
  if (!feedback) return;
  state.mapReviews.push({
    checkpoint: "User feedback",
    status: "needs update",
    feedback,
    changes: ""
  });
  els.mapFeedbackInput.value = "";
  persistState();
  render();
  toast("Map feedback logged.");
}

function addMapStepFromFeedback() {
  const text = els.mapFeedbackInput.value.trim();
  if (!text) {
    toast("Type the missing step or correction first.");
    return;
  }
  const step = { ...newRecord("steps"), name: text, action: text, evidenceConfidence: "Low", interviewNotes: "Added from map checkpoint" };
  state.steps.push(step);
  state.activeStepIndex = state.steps.length - 1;
  state.activeSection = "workflow";
  state.mapReviews.push({
    checkpoint: "Map step added",
    status: "needs review",
    feedback: text,
    changes: `Added Step ${state.steps.length}`
  });
  els.mapFeedbackInput.value = "";
  persistState();
  render();
  toast("Missing step added to the process map.");
}

function renderSummary() {
  if (!els.captureSummary) return;
  const progress = calculateProgress();
  const readiness = calculateReadiness(progress.percent);
  const dataDepth = Math.min(100, Math.round((state.data.length / 4) * 100));
  const decisionDepth = Math.min(100, Math.round((state.decisions.length / 3) * 100));
  const systemsCount = uniqueCount(state.systems, "name");
  const riskSignal = riskSignalLabel();
  const dataSignal = dataSignalLabel();
  const mapStatus = state.mapReviews.some((item) => item.status === "confirmed") ? "Confirmed" : state.mapReviews.length ? "Needs review" : "Not reviewed";
  els.captureSummary.innerHTML = `
    <div class="insights-heading">
      <p class="eyebrow">Session Insights</p>
      <h3>Discovery readiness</h3>
    </div>
    <div class="readiness-card">
      <div class="ring-metric" style="--ring-value:${readiness}; --ring-color: var(--pink);">
        <span>${readiness}%</span>
      </div>
      <div>
        <strong>${escapeHtml(state.fields.workflowName || "Workflow not named")}</strong>
        <p>${progress.completed} of ${progress.total} intake areas complete</p>
      </div>
    </div>
    <div class="metric-grid">
      ${metricCard("Process", state.steps.length, "steps", "list-ordered", Math.min(100, state.steps.length * 20), "var(--blue)")}
      ${metricCard("Data", state.data.length, "categories", "database", dataDepth, "var(--cyan)")}
      ${metricCard("Human", state.decisions.length, "decisions", "git-branch", decisionDepth, "var(--amber)")}
      ${metricCard("Tools", systemsCount, "systems", "blocks", Math.min(100, systemsCount * 25), "var(--green)")}
    </div>
    <div class="signal-list">
      ${signalItem("Trigger", state.fields.triggerSource || "Not captured", "radio-tower")}
      ${signalItem("Data signal", dataSignal, "shield-check")}
      ${signalItem("Risk signal", riskSignal, "triangle-alert")}
      ${signalItem("Process map", mapStatus, "map")}
      ${signalItem("AI patterns", "Post-intake enrichment", "sparkles")}
    </div>
    ${productReadinessCard()}
    ${completionQuestionsCard()}
    ${changeChart()}
  `;
  refreshIcons();
}

function renderDemoConsole() {
  if (!els.demoCaseSummaryMetrics) return;
  if (els.demoCaseSelect) {
    const configured = demoCaseConfigs.some((item) => item.id === state.demoCaseId);
    els.demoCaseSelect.innerHTML = demoCaseConfigs
      .map((item) => `<option value="${escapeHtml(item.id)}">${escapeHtml(item.label)}</option>`)
      .join("");
    els.demoCaseSelect.value = configured ? state.demoCaseId : demoCaseConfigs[0].id;
  }
  els.demoCaseSummaryMetrics.className = "analysis-command-dashboard";
  els.demoCaseSummaryMetrics.innerHTML = analysisDashboardCards()
    .map((card, index) => analysisDashboardCard(card, index))
    .join("");
  refreshIcons();
}

function analysisDashboardCards() {
  const progress = calculateProgress();
  const review = buildReviewGate();
  const productBrief = deriveProductBrief();
  const engineeringBrief = deriveEngineeringBrief();
  const businessBrief = deriveBusinessBrief();
  const combined = deriveCombinedHandoff(productBrief, engineeringBrief, businessBrief);
  const checklist = handoffChecklistSections();
  const checklistScore = handoffChecklistScore(checklist);
  const lowestDoc = [
    ["Product", productBrief.readiness],
    ["Engineering", engineeringBrief.readiness],
    ["Business", businessBrief.readiness]
  ].sort((a, b) => a[1] - b[1])[0];
  const nextGap = nextHandoffChecklistGap();
  return [
    {
      tab: "library",
      label: "Live Session + Library",
      icon: "folder-clock",
      score: progress.percent,
      status: `${state.steps.length} steps / ${state.data.length} data / ${state.systems.length} systems`,
      detail: "Current captured facts, session metadata, evidence, saved intakes, and package history.",
      next: topCompletionQuestions(1)[0] || "Save the session after the next meaningful answer."
    },
    {
      tab: "handoff",
      label: "Handoff Builder",
      icon: "list-checks",
      score: checklistScore,
      status: `${review.completionQuestions.length} completion question${review.completionQuestions.length === 1 ? "" : "s"}`,
      detail: "Converts captured facts into PDR-ready fields and preserves assumptions separately from validated facts.",
      next: nextGap ? `${nextGap.section}: ${nextGap.item.label}` : "Review and confirm the handoff checklist."
    },
    {
      tab: "inspector",
      label: "Readiness Inspector",
      icon: "panel-right",
      score: handoffReadinessScore(),
      status: `${lowestDoc[0]} is lowest at ${lowestDoc[1]}%`,
      detail: "Document readiness, missing fields, routed owner questions, and the next action to improve completeness.",
      next: review.followUps[0] || "Route the next open item to the right owner lane."
    },
    {
      tab: "blueprint",
      label: "Outputs",
      icon: "files",
      score: combined.readiness,
      status: combined.readinessLabel,
      detail: "Download current Product, Engineering, Business, governance-input, and combined packet drafts.",
      next: state.sessionMeta?.lastPackagePath ? "Package exists; create a fresh one after the next pilot test." : "Create a package after output review."
    }
  ];
}

function analysisDashboardCard(card, index) {
  const score = Math.max(4, Math.min(100, Number(card.score) || 0));
  return `
    <article class="analysis-dashboard-card" style="--dashboard-score:${score}%;">
      <div class="analysis-dashboard-head">
        <span>${String(index + 1).padStart(2, "0")}</span>
        <i data-lucide="${escapeHtml(card.icon)}"></i>
      </div>
      <strong>${escapeHtml(card.label)}</strong>
      <p>${escapeHtml(card.detail)}</p>
      <div class="readiness-meter"><i></i></div>
      <small>${score}% · ${escapeHtml(card.status)}</small>
      <em>${escapeHtml(card.next)}</em>
      <button class="secondary-button compact" data-dashboard-tab="${escapeHtml(card.tab)}" type="button">
        Open
        <i data-lucide="arrow-right"></i>
      </button>
    </article>
  `;
}

function handleAnalysisDashboardClick(event) {
  const button = event.target.closest("[data-dashboard-tab]");
  if (!button) return;
  activateWorkbenchTab(button.dataset.dashboardTab);
}

function activateWorkbenchTab(tab) {
  state.activeWorkbenchTab = normalizeWorkbenchTab(tab);
  persistState();
  renderWorkbenchTabs();
  refreshIcons();
}

function analysisReadinessMetrics() {
  const gateRows = gateDimensionRows();
  const reviewItems = reviewCompletenessItems();
  const archetype = activeUseCaseArchetype();
  const byLabel = (items, label) => items.find((item) => item.label === label);
  const average = (...values) => Math.round(values.filter((value) => Number.isFinite(value)).reduce((sum, value) => sum + value, 0) / Math.max(1, values.filter((value) => Number.isFinite(value)).length));
  const aToZ = byLabel(reviewItems, "A-Z Process")?.score ?? matrixCompletionScore();
  const data = byLabel(reviewItems, "Data Handling")?.score ?? 0;
  const tools = byLabel(reviewItems, "Tools & Systems")?.score ?? 0;
  const pdr = byLabel(reviewItems, "PDR Inputs")?.score ?? 0;
  const engineering = average(data, tools, state.steps.some((step) => isCapturedValue(step.accessMode)) ? 80 : 35, state.fields.deploymentEnvironment !== "Unknown" ? 80 : 35);
  return [
    {
      label: "Submitted context",
      score: scoreBySignals(`${state.fields.submittedIdea} ${state.fields.submittedWorkflowTask} ${state.fields.submittedWhereToday} ${state.fields.submittedCurrentEffort}`, [state.fields.submittedIdea || state.fields.submittedWorkflowTask, state.fields.submittedWhereToday, state.fields.submittedCurrentEffort], 18),
      detail: "Original ask, where work happens, current effort, expected impact, and notes.",
      icon: "clipboard-list"
    },
    {
      label: "Use-case lens",
      score: archetypeReadinessScore(archetype),
      detail: archetype.id === "unknown" ? "Classify the submitted idea into a discovery pattern." : `${archetype.label}: ${archetype.pdrFocus}`,
      icon: archetype.icon
    },
    {
      label: "Workflow steps",
      score: aToZ,
      detail: `${state.steps.length || 0} mapped step${state.steps.length === 1 ? "" : "s"} with A-Z structure.`,
      icon: "list-ordered"
    },
    {
      label: "Process matrix",
      score: matrixCompletionScore(),
      detail: "Actors, tools, data, handoffs, decisions, and timing by step.",
      icon: "table-2"
    },
    {
      label: "Data & tools",
      score: average(data, tools),
      detail: "Source systems, sensitivity, access mode, and output contract.",
      icon: "database"
    },
    {
      label: "Human decisions",
      score: byLabel(reviewItems, "Human Controls")?.score ?? 0,
      detail: "Judgment, approval, escalation, exceptions, and quality gates.",
      icon: "git-branch"
    },
    {
      label: "Business value",
      score: byLabel(gateRows, "Business value")?.score ?? 0,
      detail: "Capacity, dollars, quality, reuse, frequency, and KPI proof.",
      icon: "badge-dollar-sign"
    },
    {
      label: "Product handoff",
      score: pdr,
      detail: "Problem, users, MVP slice, metrics, acceptance criteria, and PDR inputs.",
      icon: "package-check"
    },
    {
      label: "Engineering handoff",
      score: engineering,
      detail: "Data boundary, systems, access, integration, logging, and controls.",
      icon: "wrench"
    }
  ];
}

function readinessMetricCard(metric, index) {
  const status = metric.score >= 75 ? "Ready" : metric.score >= 45 ? "Partial" : "Needs discovery";
  return `
    <article class="readiness-metric-card" style="--metric-score:${Math.max(4, Math.min(100, Number(metric.score) || 0))}%;">
      <div>
        <span>${String(index + 1).padStart(2, "0")}</span>
        <i data-lucide="${metric.icon}"></i>
      </div>
      <strong>${escapeHtml(metric.label)}</strong>
      <p>${escapeHtml(metric.detail)}</p>
      <div class="readiness-meter"><i></i></div>
      <small>${metric.score}% ${escapeHtml(status)}</small>
    </article>
  `;
}

function renderAnalysisMatrixMap() {
  if (!els.analysisMatrixMap) return;
  const rows = analysisMatrixRows();
  const stepCount = Math.max(0, rows[0].length - 1);
  els.analysisMatrixMap.innerHTML = `
    <div class="analysis-matrix-heading">
      <div>
        <p class="eyebrow">Dynamic Intake Matrix</p>
        <h3>Coverage by workflow step and handoff field</h3>
      </div>
      <div class="matrix-legend compact">
        <span><i class="legend-dot captured"></i>Captured</span>
        <span><i class="legend-dot inferred"></i>Inferred</span>
        <span><i class="legend-dot review"></i>Review</span>
        <span><i class="legend-dot missing"></i>Missing</span>
      </div>
    </div>
    <div class="analysis-matrix-scroll">
      <table class="confidence-matrix-table">
        <tbody>
          ${rows.map((row, rowIndex) => `
            <tr>
              ${row.map((cell, cellIndex) => {
                const tag = rowIndex === 0 || cellIndex === 0 ? "th" : "td";
                const step = state.steps[cellIndex - 1] || {};
                const meta = tag === "td" ? matrixCellMeta(rows[rowIndex][0], cell, step) : null;
                const attrs = meta ? ` class="${meta.className}" title="${escapeHtml(meta.title)}"` : "";
                const label = tag === "td" ? matrixCellLabel(cell, meta) : cell;
                return `<${tag}${attrs}>${escapeHtml(label || "")}</${tag}>`;
              }).join("")}
            </tr>
          `).join("")}
        </tbody>
      </table>
    </div>
    <p class="matrix-footnote">${stepCount ? `Showing ${stepCount} workflow step${stepCount === 1 ? "" : "s"} against the intake rows Product and Engineering need.` : "Waiting for a rough A-to-Z process list before the matrix can shade by step."}</p>
  `;
}

function analysisMatrixRows() {
  const rows = stepMatrixRows();
  const desiredLabels = [
    "Workflow Steps",
    "Persona(s) / Actor(s)",
    "Systems/Tools Involved",
    "Input",
    "In Process Data Handling",
    "Output",
    "Handoffs",
    "Triggers",
    "Time Taken (Mins/Hrs.)",
    "AI Pattern"
  ];
  if (!state.steps.length) {
    return [
      ["", "Step 1", "Step 2", "Step 3"],
      ...desiredLabels.map((label) => [label, "", "", ""])
    ];
  }
  return [
    ["", ...state.steps.slice(0, 6).map((_, index) => `Step ${index + 1}`)],
    ...rows.filter((row) => desiredLabels.includes(row[0])).map((row) => [row[0], ...row.slice(1, 7)])
  ];
}

function matrixCellLabel(cell, meta) {
  if (!cell) return "";
  const text = String(cell);
  if (meta?.className === "matrix-missing") return "";
  return text.length > 42 ? `${text.slice(0, 39)}...` : text;
}

