// "Saved Sessions" list shown inside the top-nav "Open" dropdown (the
// #savedSessionsPanel container now lives in that <details> menu). Lists
// disk-persisted sessions (and any local-only ones) from
// getCombinedSessionLibrary(); clicking a row loads it into state via the
// existing loadSessionFromLibrary(), which fetches GET /api/sessions/:id for
// server-only sessions, then closes the dropdown.
// === Workflow naming + engagement context (PR 10) ==========================
// Lets users name the workflow and tag an engagement before/during discovery.
// Stored on state.sessionMeta (the canonical source), persisted locally and,
// best-effort, to the server via PATCH /api/sessions/:id/metadata.

// True once the user has engaged (a step exists or they have sent a message),
// which is when the start-of-discovery naming prompt auto-dismisses.
function discoveryHasStarted() {
  const conversation = state.conversation || [];
  const aiChat = state.aiChat || [];
  // #1 (interim canonical rule — revisit PR 30): treat a populated workflowGrid
  // as "started" too, so a loaded grid session doesn't re-show the naming prompt.
  return (state.steps?.length || 0) > 0
    || (state.workflowGrid?.steps?.length || 0) > 0
    || conversation.some((message) => message.role === "user")
    || aiChat.some((message) => message.role === "user");
}

function setWorkflowMetadata(patch = {}) {
  ensureSessionMeta();
  if (typeof patch.workflowName === "string") {
    state.sessionMeta.workflowName = patch.workflowName.trim();
    if (state.sessionMeta.workflowName) state.sessionMeta.name = state.sessionMeta.workflowName;
  }
  if (typeof patch.engagementContext === "string") {
    state.sessionMeta.engagementContext = patch.engagementContext.trim();
  }
  if (typeof patch.userRole === "string") {
    state.sessionMeta.userRole = patch.userRole.trim().toLowerCase();
  }
  state.sessionMeta.updatedAt = new Date().toISOString();
  persistState();
  patchSessionMetadata();
  renderWorkflowHeaderName();
  renderSavedSessionsPanel();
}

// Sets the user's self-identified level, persists it, and re-renders so the new
// blended rate shows immediately in the business case (PR 12a). The naming-
// prompt chips are restyled in place by the click handler, not here.
function setUserRole(role) {
  setWorkflowMetadata({ userRole: role });
  render();
}

// Best-effort server sync. If the session isn't saved server-side yet, the
// values still persist on the next full save (sessionMeta travels with state).
function patchSessionMetadata() {
  const id = state.sessionMeta?.id;
  if (!id) return;
  requestJson(`/api/sessions/${encodeURIComponent(id)}/metadata`, {
    method: "PATCH",
    body: {
      workflowName: state.sessionMeta.workflowName || "",
      engagementContext: state.sessionMeta.engagementContext || "",
      userRole: state.sessionMeta.userRole || ""
    }
  }).catch(() => {});
}

// Editable inline workflow title in the Discovery header. Always shows an input
// (styled as a label); blur / Enter saves. Skips re-render while focused so it
// never disrupts typing.
let lastHeaderSessionId = null;

function renderWorkflowHeaderName() {
  const host = document.getElementById("workflowHeaderName");
  if (!host) return;
  // #1 (interim canonical rule — revisit PR 30): prefer the explicit workflow
  // name, but fall back to the grid's name so a loaded session shows its title
  // even when sessionMeta.workflowName is unset.
  const name = (state.sessionMeta?.workflowName || state.workflowGrid?.workflowName || "").trim();
  // Detect a session switch (e.g. opening a saved session from the Open menu) so
  // we refresh the field even if it still holds focus from the previous session.
  const sessionId = state.sessionMeta?.id || "";
  const sessionChanged = sessionId !== lastHeaderSessionId;
  lastHeaderSessionId = sessionId;
  const existing = host.querySelector("#workflowNameInput");
  if (existing) {
    // Don't clobber the field mid-edit — unless the session itself just changed.
    if (document.activeElement === existing && !sessionChanged) return;
    existing.value = name;
    existing.style.color = name ? "#e8f4ff" : "#8899aa";
    return;
  }
  host.innerHTML = `
    <input id="workflowNameInput" type="text" value="${escapeHtml(name)}" placeholder="Unnamed workflow" aria-label="Workflow name"
      title="Click to name this workflow"
      style="background:transparent;border:none;border-bottom:1px dashed #1e3350;color:${name ? "#e8f4ff" : "#8899aa"};font-size:15px;font-weight:700;padding:3px 0;min-width:220px;max-width:100%;outline:none;" />`;
  const input = host.querySelector("#workflowNameInput");
  const save = () => {
    const value = input.value.trim();
    if (value === (state.sessionMeta?.workflowName || "").trim()) return;
    setWorkflowMetadata({ workflowName: value });
  };
  input.addEventListener("blur", save);
  input.addEventListener("keydown", (event) => {
    if (event.key === "Enter") { event.preventDefault(); input.blur(); }
  });
}

// Compact inline name prompt shown at the start of a fresh discovery session.
// Two optional fields + "Save & start"; auto-dismisses once discovery begins.
function renderWorkflowNamingPrompt() {
  const host = document.getElementById("workflowNamingPrompt");
  if (!host) return;
  const show = !state.sessionMeta?.namingPromptDone && !discoveryHasStarted();
  if (!show) {
    if (host.innerHTML) host.innerHTML = "";
    return;
  }
  // Only skip a rebuild while a text field is being typed in — not when a chip
  // holds focus (chips need their highlight refreshed).
  const active = document.activeElement;
  if (active && (active.id === "namingWorkflowInput" || active.id === "namingEngagementInput")) return;
  const inputStyle = "display:block;width:100%;margin-top:3px;background:#0d1b2e;border:1px solid #1e3350;border-radius:6px;color:#e8f4ff;font-size:13px;padding:6px 8px;outline:none;box-sizing:border-box;";
  const currentRole = (state.sessionMeta?.userRole || "").toLowerCase();
  const roleChip = ([key, label]) => {
    const on = currentRole ? currentRole === key : key === "consultant";
    return `<button type="button" data-role-chip="${key}" style="border:1px solid ${on ? "#00d4b4" : "#1e3350"};background:${on ? "rgba(0,212,180,0.15)" : "#0d1b2e"};color:${on ? "#00d4b4" : "#8899aa"};border-radius:99px;font-size:12px;font-weight:600;padding:5px 12px;cursor:pointer;">${label}</button>`;
  };
  const chips = [["analyst", "Analyst"], ["consultant", "Consultant"], ["manager", "Manager"], ["principal", "Principal+"]].map(roleChip).join("");
  host.innerHTML = `
    <div class="ds-panel" style="padding:10px 14px;margin-bottom:10px;display:flex;gap:10px;align-items:flex-end;flex-wrap:wrap;">
      <label style="flex:1;min-width:170px;font-size:11px;color:#8899aa;">Workflow name
        <input id="namingWorkflowInput" type="text" placeholder="e.g. Month-end close reporting" value="${escapeHtml(state.sessionMeta?.workflowName || "")}" style="${inputStyle}" />
      </label>
      <label style="flex:1;min-width:170px;font-size:11px;color:#8899aa;">Engagement / project
        <input id="namingEngagementInput" type="text" placeholder="e.g. Q3 finance transformation" value="${escapeHtml(state.sessionMeta?.engagementContext || "")}" style="${inputStyle}" />
      </label>
      <button class="primary-button compact" id="namingSaveBtn" type="button">Save &amp; start</button>
      <div style="flex-basis:100%;display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-top:4px;">
        <span style="font-size:11px;color:#8899aa;">Your level</span>
        ${chips}
      </div>
    </div>`;
  host.querySelectorAll("[data-role-chip]").forEach((btn) => {
    btn.addEventListener("click", () => {
      const key = btn.dataset.roleChip;
      host.querySelectorAll("[data-role-chip]").forEach((b) => {
        const on = b.dataset.roleChip === key;
        b.style.borderColor = on ? "#00d4b4" : "#1e3350";
        b.style.background = on ? "rgba(0,212,180,0.15)" : "#0d1b2e";
        b.style.color = on ? "#00d4b4" : "#8899aa";
      });
      setUserRole(key);
    });
  });
  host.querySelector("#namingSaveBtn")?.addEventListener("click", () => {
    const workflowName = host.querySelector("#namingWorkflowInput")?.value || "";
    const engagementContext = host.querySelector("#namingEngagementInput")?.value || "";
    ensureSessionMeta();
    state.sessionMeta.namingPromptDone = true;
    setWorkflowMetadata({ workflowName, engagementContext });
    renderWorkflowNamingPrompt();
    document.getElementById("aiChatInput")?.focus();
    toast("Workflow named — start describing it whenever you're ready.");
  });
}

// Tier + business-case metrics for a saved-session library entry. Local entries
// carry full state (grid with opportunity, conversation, level); remote-only
// summaries don't — those return null bc and "" tier, rendered as "—".
function sessionCardMetrics(entry) {
  const sessionState = entry?.state;
  const steps = sessionState?.workflowGrid?.steps;
  if (!Array.isArray(steps) || !steps.length) return { tier: "", bc: null };
  let tier = "";
  try { tier = getStepOpportunityMeta(steps[0]).tier || ""; } catch { tier = ""; }
  const convText = [
    (sessionState.conversation || []).map((m) => m?.text || "").join("\n"),
    sessionState.transcript || ""
  ].filter(Boolean).join("\n");
  let bc = null;
  try { bc = computeBusinessCase(steps, convText, sessionState.sessionMeta?.userRole || ""); } catch { bc = null; }
  return { tier, bc };
}

const SESSION_TIER_ORDER = { "quick-win": 0, strategic: 1, compliance: 2, speculative: 3 };

function renderSavedSessionsPanel() {
  const container = document.getElementById("savedSessionsPanel");
  if (!container) return;
  const sessions = getCombinedSessionLibrary().map((entry) => ({ entry, ...sessionCardMetrics(entry) }));
  const countBadge = document.getElementById("openSessionsCount");
  if (countBadge) {
    countBadge.textContent = String(sessions.length);
    countBadge.style.display = sessions.length ? "" : "none";
  }
  const currentId = state.sessionMeta?.id;
  const head = `
    <div class="saved-sessions-head" style="display:flex;align-items:center;gap:8px;margin-bottom:8px;">
      <i data-lucide="folder-clock" style="width:14px;height:14px;color:#7a93b4;"></i>
      <strong style="font-size:12px;letter-spacing:0.04em;text-transform:uppercase;color:#7a93b4;">Saved Sessions</strong>
      <span style="font-size:11px;color:#5b7186;margin-left:auto;">${sessions.length} saved</span>
    </div>`;
  if (!sessions.length) {
    container.innerHTML = head + `<p style="font-size:12px;color:#5b7186;margin:0;">No saved sessions yet. Click <strong>Save</strong> to keep this workflow on disk.</p>`;
    refreshIcons();
    return;
  }

  // Sort: Quick Win → Strategic → Compliance → Speculative (then untiered);
  // most recent first within a tier.
  sessions.sort((a, b) => {
    const ta = a.tier in SESSION_TIER_ORDER ? SESSION_TIER_ORDER[a.tier] : 4;
    const tb = b.tier in SESSION_TIER_ORDER ? SESSION_TIER_ORDER[b.tier] : 4;
    if (ta !== tb) return ta - tb;
    return String(b.entry.updatedAt || b.entry.savedAt || "").localeCompare(String(a.entry.updatedAt || a.entry.savedAt || ""));
  });

  // Portfolio summary across all sessions.
  const num = (n) => Math.round(n).toLocaleString("en-US");
  let quickWins = 0;
  let totalAnnualHours = 0;
  let totalValue = 0;
  sessions.forEach(({ tier, bc }) => {
    if (tier === "quick-win") quickWins += 1;
    if (bc) {
      totalAnnualHours += bc.results.annualHours || 0;
      totalValue += (bc.results.annualValue || 0) + (bc.results.projectValue || 0);
    }
  });
  const summaryCell = (value, label, color) =>
    `<div style="flex:1;text-align:center;"><div class="${color}" style="font-size:1.1rem;font-weight:800;">${value}</div><div style="font-size:10px;color:#5b7186;text-transform:uppercase;letter-spacing:0.05em;margin-top:2px;">${label}</div></div>`;
  const summaryStrip = `
    <div class="ds-panel" style="display:flex;gap:8px;padding:10px 12px;margin-bottom:8px;">
      ${summaryCell(num(quickWins), "Quick Wins", "ds-num-teal")}
      ${summaryCell(`${num(totalAnnualHours)} hrs/yr`, "Total time", "ds-num-teal")}
      ${summaryCell(`$${num(totalValue)}`, "Total value", "ds-num-amber")}
    </div>
    <div style="font-size:10px;color:#5b7186;margin-bottom:6px;">Sorted by opportunity tier</div>`;

  const rows = sessions.map(({ entry, tier, bc }) => {
    const id = entry.sessionId || entry.id;
    const when = formatSavedSessionDate(entry.savedAt || entry.updatedAt);
    const name = entry.workflowName || entry.name || when || "Untitled workflow";
    const engagement = (entry.engagementContext || "").trim();
    const stepCount = Number.isFinite(entry.stepCount) ? entry.stepCount : 0;
    const active = id === currentId;
    const meta = `${stepCount} step${stepCount === 1 ? "" : "s"}${when ? ` · ${escapeHtml(when)}` : ""}${entry.remoteOnly ? " · on disk" : ""}`;
    const badge = tier && tier in SESSION_TIER_ORDER ? scoringTierBadge(tier) : null;

    // Value footer: hours (teal) on the left, dollars (amber) on the right.
    let hoursHtml = `<span style="color:#445566;">—</span>`;
    let valueHtml = `<span style="color:#445566;">—</span>`;
    if (bc) {
      const hrs = (n) => n.toLocaleString("en-US", { minimumFractionDigits: 1, maximumFractionDigits: 1 });
      const tealNum = (n) => `<span class="ds-num-teal" style="font-size:13px;font-weight:700;">${n}</span>`;
      const amberNum = (n) => `<span class="ds-num-amber" style="font-size:13px;font-weight:700;">$${num(n)}</span>`;
      if (bc.workflowMode === "role") {
        hoursHtml = `${tealNum(hrs(bc.results.hoursPerWeek))} hrs/wk · ${tealNum(num(bc.results.annualHours))} hrs/yr saved`;
        valueHtml = `${amberNum(bc.results.annualValue)}/year`;
      } else {
        hoursHtml = `${tealNum(hrs(bc.results.totalHours))} total hrs saved`;
        valueHtml = `${amberNum(bc.results.projectValue)} project value`;
      }
    }

    return `
      <button type="button" data-load-session="${escapeHtml(id)}" ${active ? 'aria-current="true"' : ""} style="display:flex;flex-direction:column;align-items:stretch;gap:2px;width:100%;text-align:left;background:${active ? "#102338" : "#0d1b2a"};border:1px solid ${active ? "#00d4b4" : "#1a2a3a"};border-radius:8px;padding:8px 10px;color:#dde8f5;cursor:pointer;">
        <div style="display:flex;align-items:center;justify-content:space-between;gap:8px;">
          <strong style="font-size:13px;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${escapeHtml(name)}</strong>
          ${badge ? `<span class="ds-badge ${badge.cls}" style="flex-shrink:0;">${badge.label}</span>` : ""}
        </div>
        ${engagement ? `<span style="font-size:11px;color:#5b7186;">${escapeHtml(engagement)}</span>` : ""}
        <span style="font-size:11px;color:#7a93b4;">${meta}</span>
        <div style="display:flex;align-items:baseline;justify-content:space-between;gap:10px;margin-top:8px;padding-top:8px;border-top:1px solid #1a2a3a;font-size:11px;color:#7a93b4;">
          <span>${hoursHtml}</span>
          <span style="text-align:right;">${valueHtml}</span>
        </div>
      </button>`;
  }).join("");

  container.innerHTML = head + summaryStrip + `<div style="display:flex;flex-direction:column;gap:6px;max-height:320px;overflow:auto;">${rows}</div>`;
  container.querySelectorAll("[data-load-session]").forEach((button) => {
    button.addEventListener("click", () => {
      button.closest("details")?.removeAttribute("open");
      loadSessionFromLibrary(button.dataset.loadSession);
    });
  });
  refreshIcons();
}

// Phase 5a auth controls: when the Azure AD gate is enabled and a user is
// signed in, show their name + a POST logout button in the top nav. Renders
// nothing when AUTH_ENABLED is false (the gate is a no-op), so the un-gated app
// is visually unchanged. /api/me is a public endpoint.
async function hydrateAuthControls() {
  const host = document.getElementById("authControls");
  if (!host) return;
  let data;
  try {
    data = await requestJson("/api/me");
  } catch {
    return;
  }
  if (!data || !data.authEnabled || !data.user) {
    host.innerHTML = "";
    return;
  }
  const label = escapeHtml(data.user.name || data.user.email || "Signed in");
  host.innerHTML = `
    <span style="font-size:0.78rem;color:#8899aa;margin-right:8px;" title="${escapeHtml(data.user.email || "")}">${label}</span>
    <button type="button" id="logoutButton" class="topbar-trio-button" title="Sign out">Log out</button>`;
  document.getElementById("logoutButton")?.addEventListener("click", async () => {
    try {
      await requestJson("/auth/logout", { method: "POST" });
    } catch {
      // fall through to the redirect regardless — the gate will re-challenge
    }
    window.location.href = "/login.html";
  });
}

function formatSavedSessionDate(value) {
  if (!value) return "";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "";
  return date.toLocaleString(undefined, { month: "short", day: "numeric", hour: "2-digit", minute: "2-digit" });
}

function renderSessionLibrary() {
  if (!els.sessionLibraryList) return;
  ensureSessionMeta();
  renderSessionControls();
  const library = getCombinedSessionLibrary();
  if (!library.length) {
    els.sessionLibraryList.innerHTML = `
      <div class="session-empty-state">
        <i data-lucide="folder-clock"></i>
        <strong>No saved intakes yet</strong>
        <p>Use Save Session to keep this intake in the local browser library. Sample cases can also be loaded and duplicated into working sessions.</p>
      </div>
    `;
    refreshIcons();
    return;
  }
  els.sessionLibraryList.innerHTML = library.map(sessionLibraryCard).join("");
  els.sessionLibraryList.querySelectorAll("[data-session-action]").forEach((button) => {
    button.addEventListener("click", () => {
      const id = button.dataset.sessionId;
      const action = button.dataset.sessionAction;
      if (action === "load") loadSessionFromLibrary(id);
      if (action === "duplicate") duplicateSavedSession(id);
      if (action === "delete") deleteSessionFromLibrary(id);
    });
  });
  refreshIcons();
}

function renderSessionControls() {
  const meta = ensureSessionMeta();
  if (els.sessionNameInput && document.activeElement !== els.sessionNameInput) {
    els.sessionNameInput.value = meta.name || "";
  }
  if (els.sessionOwnerInput && document.activeElement !== els.sessionOwnerInput) {
    els.sessionOwnerInput.value = meta.owner || "";
  }
  if (els.sessionDataClassificationSelect) {
    els.sessionDataClassificationSelect.value = meta.dataClassification || "Unknown";
  }
  if (els.sessionStatusSelect) {
    els.sessionStatusSelect.value = meta.status || "Discovery";
  }
  if (!els.sessionMetaSummary) return;
  const summary = sessionSummaryMeta(state);
  els.sessionMetaSummary.innerHTML = `
    <div>
      <span>Current session</span>
      <strong>${escapeHtml(summary.name)}</strong>
      <p>${escapeHtml(summary.workflowName || "Workflow not named yet")} · ${escapeHtml(summary.category)}</p>
    </div>
    <div>
      <span>Data classification</span>
      <strong>${escapeHtml(summary.dataClassification)}</strong>
      <p>${escapeHtml(summary.status)} · ${escapeHtml(summary.source)}</p>
    </div>
    <div>
      <span>Coverage</span>
      <strong>${summary.stepCount} steps</strong>
      <p>${summary.dataCount} data · ${summary.systemCount} systems · ${summary.decisionCount} decisions</p>
    </div>
    <div>
      <span>Updated</span>
      <strong>${escapeHtml(formatDateTime(summary.updatedAt))}</strong>
      <p>${summary.lastPackagePath ? `Package ${escapeHtml(summary.lastPackagePath)}` : `ID ${escapeHtml(summary.id.slice(-8))}`}</p>
    </div>
  `;
}

