function changeChart() {
  const totals = intakeSnapshot();
  const latest = state.intakeDeltas?.[0];
  const bars = [
    ["Fields", totals.fields, 32, "var(--pink)"],
    ["Steps", totals.steps, 8, "var(--blue)"],
    ["Data", totals.data, 5, "var(--cyan)"],
    ["Tools", totals.systems, 5, "var(--green)"],
    ["Decisions", totals.decisions, 4, "var(--amber)"],
    ["Evidence", totals.evidenceArtifacts, 3, "var(--violet)"]
  ];
  return `
    <div class="change-card">
      <div class="change-heading">
        <div>
          <p class="eyebrow">Context Change Chart</p>
          <h3>What changed from the conversation</h3>
        </div>
        <span>${latest ? new Date(latest.time).toLocaleTimeString([], { hour: "numeric", minute: "2-digit" }) : "Waiting"}</span>
      </div>
      <div class="change-bars">
        ${bars.map(([label, value, target, color]) => changeBar(label, value, target, color)).join("")}
      </div>
      <p class="change-note">${escapeHtml(latest?.note || "As the AI analyzes new answers, this chart shows which intake areas gained new context.")}</p>
    </div>
  `;
}

function productReadinessCard() {
  const scores = productReadinessScores();
  const overall = Math.round(scores.reduce((sum, item) => sum + item.score, 0) / scores.length);
  return `
    <div class="product-fit-card">
      <div class="change-heading">
        <div>
          <p class="eyebrow">Product Readiness</p>
          <h3>${overall}% PDR handoff signal</h3>
        </div>
        <span>${escapeHtml(productReadinessLabel(overall))}</span>
      </div>
      <div class="fit-grid">
        ${scores.map((item) => fitSignal(item)).join("")}
      </div>
      <p class="change-note">${escapeHtml(productReadinessNote(scores))}</p>
    </div>
  `;
}

function fitSignal(item) {
  return `
    <div class="fit-signal" style="--fit-score:${item.score}; --fit-color:${item.color};">
      <div>
        <strong>${escapeHtml(item.label)}</strong>
        <span>${item.score}%</span>
      </div>
      <p>${escapeHtml(item.detail)}</p>
      <div class="change-track"><span></span></div>
    </div>
  `;
}

function productReadinessScores() {
  const toolFitText = `${state.fields.availableTooling} ${state.fields.toolFitRecommendation} ${state.steps.map((step) => step.toolFit || inferToolFit(step).label).join(" ")}`.toLowerCase();
  const valueText = `${state.fields.hoursSavedHypothesis} ${state.fields.marginImpactHypothesis} ${state.fields.qualityImpactHypothesis} ${state.fields.businessImpact} ${state.fields.biggestPain} ${state.fields.submittedExpectedImpact}`;
  const dataText = `${state.data.map((item) => `${item.category} ${item.sensitivity} ${item.avoidRaw} ${item.splitNotes}`).join(" ")} ${state.steps.map((step) => step.dataSensitivity).join(" ")} ${state.fields.availableTooling}`;
  const mvpText = `${state.fields.solutionHypothesis} ${state.fields.mvpScope} ${state.fields.userStories} ${state.fields.acceptanceCriteria}`;
  const riskText = `${riskSignalLabel()} ${state.decisions.map((item) => `${item.risk} ${item.approval}`).join(" ")} ${state.steps.map((step) => `${step.risk} ${step.decision}`).join(" ")}`;
  const gate = gateAssessment();
  const governance = governanceRoute();
  return [
    {
      label: "Value",
      score: scoreBySignals(valueText, [state.fields.hoursSavedHypothesis, state.fields.businessImpact, state.fields.biggestPain, state.fields.kpiTypes, state.fields.commercialValuePath, state.fields.submittedExpectedImpact], 24),
      detail: "Commercial path, KPI type, hours, margin, quality, speed, or capacity signal.",
      color: "var(--pink)"
    },
    {
      label: "Repeatability",
      score: Math.min(100, state.steps.length * 12 + (isCapturedValue(state.fields.runsPerPeriod) ? 25 : 0) + (isCapturedValue(state.fields.reusePotential) ? 25 : 0)),
      detail: "Frequency, stable steps, and reuse across domains.",
      color: "var(--blue)"
    },
    {
      label: "Data Feasibility",
      score: scoreBySignals(dataText, [state.data.length, state.fields.availableTooling], 30),
      detail: "Data categories, sensitivity, and raw-data avoidance.",
      color: "var(--cyan)"
    },
    {
      label: "Tool Fit",
      score: toolFitText.includes("chatgpt") || toolFitText.includes("copilot") ? Math.min(100, 55 + state.steps.length * 8 + state.systems.length * 6) : 35,
      detail: "Fit against ChatGPT Enterprise and Microsoft 365 Copilot.",
      color: "var(--green)"
    },
    {
      label: "Risk Clarity",
      score: scoreBySignals(riskText, [state.decisions.length, riskSignalLabel() !== "Not captured"], 30),
      detail: "Human review, approvals, and failure impact.",
      color: "var(--amber)"
    },
    {
      label: "MVP Clarity",
      score: scoreBySignals(mvpText, [state.fields.solutionHypothesis, state.fields.mvpScope, state.fields.userStories, state.fields.acceptanceCriteria], 22),
      detail: "Product scope, stories, and acceptance criteria.",
      color: "var(--violet)"
    },
    {
      label: "Gov Inputs",
      score: Math.max(25, 100 - governance.flags.length * 14 - (governance.path === "Multiple / TBD" ? 14 : 0)),
      detail: `Later review inputs: ${governance.path}; ${governance.sensitivity}; ${governance.environment}.`,
      color: "var(--cyan)"
    },
    {
      label: "Gate A",
      score: gate.overall,
      detail: `${gate.decision}: ${gate.rationale}`,
      color: "var(--blue)"
    }
  ];
}

function scoreBySignals(text, signals, unit = 25) {
  const textScore = String(text || "").trim().length > 40 ? 35 : String(text || "").trim().length > 10 ? 20 : 0;
  const signalScore = signals.filter((value) => {
    if (typeof value === "number") return value > 0;
    return isCapturedValue(value);
  }).length * unit;
  return Math.min(100, textScore + signalScore);
}

function productReadinessLabel(score) {
  if (score >= 75) return "Pilot ready";
  if (score >= 55) return "Needs light follow-up";
  if (score >= 35) return "Discovery in progress";
  return "Early signal";
}

function productReadinessNote(scores) {
  const weakest = [...scores].sort((a, b) => a.score - b.score)[0];
  return weakest ? `Next best Product/Engineering question: strengthen ${weakest.label.toLowerCase()} by capturing ${weakest.detail.toLowerCase()}` : "Capture workflow details to calculate product readiness.";
}

function changeBar(label, value, target, color) {
  const percent = Math.min(100, Math.round((value / target) * 100));
  return `
    <div class="change-bar" style="--bar-color:${color}; --bar-fill:${percent};">
      <div>
        <strong>${escapeHtml(label)}</strong>
        <span>${value}</span>
      </div>
      <div class="change-track"><span></span></div>
    </div>
  `;
}

function uniqueCount(records, key) {
  const values = records.map((record) => String(record?.[key] || "").trim().toLowerCase()).filter(Boolean);
  return new Set(values).size;
}

function calculateReadiness(progressPercent) {
  const detailScore = Math.min(25, state.steps.length * 5 + state.data.length * 4 + state.systems.length * 3);
  const decisionScore = Math.min(10, state.decisions.length * 4);
  const mapScore = state.mapReviews.some((item) => item.status === "confirmed") ? 10 : state.mapReviews.length ? 5 : 0;
  const pdrScore = String(state.fields.businessOutcome || state.fields.openQuestions || "").trim() ? 10 : 0;
  return Math.min(100, Math.round(progressPercent * 0.45 + detailScore + decisionScore + mapScore + pdrScore));
}

function dataSignalLabel() {
  const text = state.data
    .map((item) => `${item.category} ${item.sensitivity} ${item.avoidRaw} ${item.splitNotes}`)
    .concat(state.steps.map((step) => `${step.dataSensitivity} ${step.input} ${step.dataHandling} ${step.output}`))
    .join(" ")
    .toLowerCase();
  if (!state.data.length && !state.steps.some((step) => isCapturedValue(step.dataSensitivity))) return "Not captured";
  if (text.includes("client") || text.includes("confidential") || text.includes("sensitive") || text.includes("restricted")) {
    return "Sensitive data present";
  }
  if (text.includes("avoid") || text.includes("anonym") || text.includes("metadata")) return "Raw data may be avoidable";
  return "Needs classification";
}

function riskSignalLabel() {
  const text = [
    ...state.steps.map((step) => `${step.risk} ${step.pain} ${step.exceptions} ${step.dataSensitivity}`),
    ...state.decisions.map((decision) => `${decision.risk} ${decision.approval}`),
    state.fields.qualityVariability,
    state.fields.reworkNotes
  ]
    .join(" ")
    .toLowerCase();
  if (!text.trim()) return "Not captured";
  if (text.includes("high") || text.includes("approval") || text.includes("compliance") || text.includes("error")) return "Human review likely";
  if (text.includes("low") || text.includes("minor")) return "Low risk noted";
  return "Needs review";
}

async function renderMap() {
  if (!els.mapCanvas) return;
  if (!state.steps.length) {
    els.mapCanvas.innerHTML = `
      <div class="empty-map">
        <i data-lucide="list-ordered"></i>
        <strong>Waiting for the rough A-to-Z process list</strong>
        <p>Once steps are captured, the map will show actor, tool, data, decision, pain/risk, and inferred AI pattern overlays.</p>
      </div>
    `;
    refreshIcons();
    return;
  }

  els.mapCanvas.innerHTML = `
    <div class="process-map-visual">
      ${state.steps.map((step, index) => processStepCard(step, index)).join("")}
    </div>
  `;
  refreshIcons();
}

function renderMapStepEditor() {
  if (!els.mapStepEditor) return;
  if (!state.steps.length) {
    els.mapStepEditor.innerHTML = "";
    return;
  }
  els.mapStepEditor.innerHTML = `
    <div class="map-editor-heading">
      <p class="eyebrow">Map Checkpoint Editor</p>
      <span>${state.steps.length} steps</span>
    </div>
    <div class="map-step-list">
      ${state.steps.map((step, index) => mapStepEditorRow(step, index)).join("")}
    </div>
  `;
  els.mapStepEditor.querySelectorAll("[data-map-action]").forEach((button) => {
    button.addEventListener("click", () => {
      const index = Number(button.dataset.stepIndex);
      const action = button.dataset.mapAction;
      if (action === "up") moveMapStep(index, -1);
      if (action === "down") moveMapStep(index, 1);
      if (action === "focus") setCurrentStepIndex(index);
      if (action === "remove") removeMapStep(index);
    });
  });
  els.mapStepEditor.querySelectorAll("[data-map-step-name]").forEach((input) => {
    input.addEventListener("change", () => {
      const index = Number(input.dataset.mapStepName);
      if (!state.steps[index]) return;
      state.steps[index].name = input.value.trim() || state.steps[index].name;
      state.steps[index].evidenceConfidence = state.steps[index].evidenceConfidence || "Medium";
      persistState();
      render();
    });
  });
  refreshIcons();
}

function mapStepEditorRow(step, index) {
  const isCurrent = index === getCurrentStepIndex();
  return `
    <div class="map-step-row ${isCurrent ? "active" : ""}">
      <span>${index + 1}</span>
      <input data-map-step-name="${index}" value="${escapeHtml(step.name || step.action || `Step ${index + 1}`)}" aria-label="Step ${index + 1} name" />
      <button class="mini-button" data-map-action="focus" data-step-index="${index}" type="button" title="Interview this step">
        <i data-lucide="message-circle-question"></i>
      </button>
      <button class="mini-button" data-map-action="up" data-step-index="${index}" type="button" title="Move step up" ${index === 0 ? "disabled" : ""}>
        <i data-lucide="arrow-up"></i>
      </button>
      <button class="mini-button" data-map-action="down" data-step-index="${index}" type="button" title="Move step down" ${index === state.steps.length - 1 ? "disabled" : ""}>
        <i data-lucide="arrow-down"></i>
      </button>
      <button class="mini-button" data-map-action="remove" data-step-index="${index}" type="button" title="Remove step">
        <i data-lucide="x"></i>
      </button>
    </div>
  `;
}

function moveMapStep(index, direction, options = {}) {
  const target = index + direction;
  if (!state.steps[index] || target < 0 || target >= state.steps.length) return;
  const [step] = state.steps.splice(index, 1);
  state.steps.splice(target, 0, step);
  state.activeStepIndex = target;
  if (!options.silent) {
    state.mapReviews.push({
      checkpoint: "Map order updated",
      status: "needs review",
      feedback: `Moved step ${index + 1} to position ${target + 1}`,
      changes: state.steps.map((item, stepIndex) => `${stepIndex + 1}. ${item.name || item.action || "Untitled step"}`).join(" | ")
    });
  }
  persistState();
  render();
}

function removeMapStep(index, options = {}) {
  const step = state.steps[index];
  if (!step) return;
  if (options.confirmRemoval !== false && !confirm(`Remove "${step.name || step.action || `Step ${index + 1}`}" from the map?`)) return;
  state.steps.splice(index, 1);
  state.activeStepIndex = Math.max(0, Math.min(index, state.steps.length - 1));
  if (!options.silent) {
    state.mapReviews.push({
      checkpoint: "Map step removed",
      status: "needs review",
      feedback: step.name || step.action || `Step ${index + 1}`,
      changes: "Removed from process map"
    });
  }
  if (!state.steps.length) {
    ensureDrilldownState();
    state.drilldown.status = "waitingForSteps";
    state.drilldown.skeletonConfirmed = false;
    state.currentQuestionOverride = "";
    state.currentQuestionSource = "Intake guide";
  }
  persistState();
  render();
}

function processStepCard(step, index) {
  const pattern = inferAiPattern(step);
  const painRisk = inferPainRisk(step);
  const hasNext = index < state.steps.length - 1;
  const completion = stepCompletion(step);
  const missing = stepMissingFields(step).slice(0, 3);
  const isCurrent = index === getCurrentStepIndex();
  return `
    <article class="process-step-card ${hasNext ? "has-next" : ""} ${isCurrent ? "current" : ""}" style="--step-completion:${completion}%;">
      <div class="step-card-header">
        <span class="step-number">${index + 1}</span>
        <div>
          <strong>${escapeHtml(step.name || step.action || `Step ${index + 1}`)}</strong>
          <p>${escapeHtml(step.action || "Action not captured yet")}</p>
        </div>
      </div>
      <div class="step-map-status">
        <span><i data-lucide="${isCurrent ? "message-circle-question" : "check-circle-2"}"></i>${completion}% captured</span>
        <div><i></i></div>
        <small>${missing.length ? `Missing ${escapeHtml(missing.map((item) => item.label).join(", "))}` : "Ready for first-pass review"}</small>
      </div>
      <div class="step-chip-grid">
        ${stepChip("user-round", "Actor", step.actor || "TBD")}
        ${stepChip("monitor-cog", "Tool", step.tool || "TBD")}
        ${stepChip("key-round", "Access", step.accessMode || "TBD")}
        ${stepChip("database", "Data", step.dataHandling || step.input || "TBD")}
        ${stepChip("corner-down-right", "Output", step.output || "TBD")}
        ${stepChip("git-branch", "Decision", step.decision || "None captured")}
        ${stepChip("shield-check", "Sensitivity", step.dataSensitivity || "TBD")}
        ${stepChip("split", "Variations", step.exceptions || "None captured")}
        ${stepChip(pattern.icon, "AI Pattern", pattern.label, "pattern")}
        ${stepChip("triangle-alert", "Pain/Risk", painRisk.label, painRisk.level)}
      </div>
      <div class="step-flow-footer">
        <span><i data-lucide="radio-tower"></i>${escapeHtml(step.trigger || "Trigger TBD")}</span>
        <span><i data-lucide="timer"></i>${escapeHtml(step.time || "Time TBD")}</span>
        <span><i data-lucide="send"></i>${escapeHtml(step.handoff || "Handoff TBD")}</span>
      </div>
    </article>
  `;
}

function stepChip(icon, label, value, tone = "") {
  const captured = isCapturedValue(value) && value !== "TBD" && value !== "None captured";
  return `
    <div class="step-chip ${tone} ${captured ? "captured" : "missing"}">
      <i data-lucide="${icon}"></i>
      <span>${escapeHtml(label)}</span>
      <strong>${escapeHtml(value)}</strong>
    </div>
  `;
}

function buildMermaidGraph() {
  const trigger = safeMermaidLabel(state.fields.triggerSource || "Trigger unknown");
  const lines = ["flowchart LR", `  T1["Trigger: ${trigger}"]`];
  if (!state.steps.length) {
    lines.push(`  T1 --> O1["Output: ${safeMermaidLabel(state.fields.definitionOfDone || "Output unknown")}"]`);
    return lines.join("\n");
  }
  state.steps.forEach((step, index) => {
    const id = `S${index + 1}`;
    const label = safeMermaidLabel(step.name || step.action || `Step ${index + 1}`);
    lines.push(`  ${id}["${index + 1}. ${label}"]`);
    if (step.decision) {
      lines.push(`  D${index + 1}{"Decision: ${safeMermaidLabel(step.decision)}"}`);
    }
  });
  lines.push(`  T1 --> S1`);
  state.steps.forEach((step, index) => {
    const current = `S${index + 1}`;
    const next = index === state.steps.length - 1 ? "O1" : `S${index + 2}`;
    if (step.decision) {
      lines.push(`  ${current} --> D${index + 1}`);
      lines.push(`  D${index + 1} --> ${next}`);
    } else {
      lines.push(`  ${current} --> ${next}`);
    }
  });
  lines.push(`  O1["Output: ${safeMermaidLabel(state.fields.definitionOfDone || "Final output")}"]`);
  return lines.join("\n");
}

function deriveWorkflowMapStudio() {
  const workflow = state.fields.workflowName || state.fields.submittedWorkflowTask || state.sessionMeta?.name || "Unnamed workflow";
  const triggerLabel = state.fields.triggerSource || state.fields.triggerType || state.fields.startPoint || "Trigger / starting event TBD";
  const outputLabel = state.fields.definitionOfDone || state.fields.endPoint || summarizedOutputs() || "Final output TBD";
  const nodes = [
    workflowMapNode("trigger", "Trigger", triggerLabel, {
      lane: "Start",
      detail: state.fields.entryConditions || state.fields.triggerFrequency || "Entry conditions not fully captured.",
      status: isCapturedValue(triggerLabel) ? "captured" : "missing"
    })
  ];
  const edges = [];
  const steps = state.steps.length ? state.steps : [{
    name: "Capture the rough A-to-Z process",
    actor: state.fields.intervieweeRole || "Workflow owner",
    tool: state.fields.availableTooling || "Current tools TBD",
    input: state.fields.submittedWorkflowTask || state.fields.submittedIdea || "Workflow description",
    output: "Numbered process map",
    decision: "",
    dataSensitivity: inferOverallDataSensitivity(),
    handoff: "Discovery follow-up"
  }];

  steps.forEach((step, index) => {
    const stepId = `step-${index + 1}`;
    nodes.push(workflowMapNode(stepId, `Step ${index + 1}`, step.name || step.action || `Step ${index + 1}`, {
      lane: "Activity",
      actor: step.actor || "Actor TBD",
      tool: step.tool || step.accessMode || "Tool TBD",
      data: step.input || step.dataHandling || "Input data TBD",
      output: step.output || "Output TBD",
      detail: step.action || step.interviewNotes || "Step details need follow-up.",
      status: stepMapStatus(step)
    }));
    edges.push(workflowMapEdge(index === 0 ? "trigger" : `step-${index}`, stepId, index === 0 ? "starts" : "next"));
    if (isCapturedValue(step.decision)) {
      const decisionId = `decision-${index + 1}`;
      nodes.push(workflowMapNode(decisionId, "Decision", step.decision, {
        lane: "Human review",
        actor: step.actor || "Reviewer TBD",
        detail: step.risk || step.openQuestions || "Decision criteria need validation.",
        status: "review"
      }));
      edges.push(workflowMapEdge(stepId, decisionId, "review"));
      if (index < steps.length - 1) edges.push(workflowMapEdge(decisionId, `step-${index + 2}`, "approved"));
    }
  });

  nodes.push(workflowMapNode("output", "Output", outputLabel, {
    lane: "Finish",
    actor: state.fields.outputConsumer || "Output consumer TBD",
    tool: state.fields.deliverableType || "Deliverable TBD",
    detail: state.fields.acceptanceCriteria || state.fields.successMetrics || "Acceptance criteria need confirmation.",
    status: isCapturedValue(outputLabel) ? "captured" : "missing"
  }));
  const finalStep = steps.length ? `step-${steps.length}` : "trigger";
  const finalDecision = state.steps[steps.length - 1]?.decision ? `decision-${steps.length}` : "";
  edges.push(workflowMapEdge(finalDecision || finalStep, "output", "produces"));

  state.data.slice(0, 8).forEach((item, index) => {
    const dataId = `data-${index + 1}`;
    nodes.push(workflowMapNode(dataId, "Data", item.category || item.source || `Data ${index + 1}`, {
      lane: "Data",
      tool: item.source || item.format || "Source TBD",
      data: item.sensitivity || "Sensitivity TBD",
      detail: item.processing || item.usageMode || item.splitNotes || "Data usage needs validation.",
      status: /unknown|tbd/i.test(item.sensitivity || "") ? "review" : "captured"
    }));
    edges.push(workflowMapEdge(dataId, bestWorkflowStepMatch(item, steps), "used by"));
  });

  state.systems.slice(0, 8).forEach((item, index) => {
    const systemId = `system-${index + 1}`;
    nodes.push(workflowMapNode(systemId, "System", item.name || `System ${index + 1}`, {
      lane: "Systems",
      actor: item.owner || "Owner TBD",
      tool: item.access || "Access TBD",
      detail: item.purpose || item.integration || "System purpose needs validation.",
      status: isCapturedValue(item.access) ? "captured" : "review"
    }));
    edges.push(workflowMapEdge(systemId, bestWorkflowStepMatch(item, steps), "supports"));
  });

  const openQuestions = dedupeQuestions([
    ...reviewFollowUps(),
    state.fields.openQuestions,
    state.fields.engineeringUnknowns
  ]).slice(0, 6);
  const map = {
    version: 1,
    generatedAt: new Date().toISOString(),
    workflow,
    summary: {
      nodeCount: nodes.length,
      edgeCount: edges.length,
      stepCount: state.steps.length,
      dataCount: state.data.length,
      systemCount: state.systems.length,
      decisionCount: state.decisions.length + state.steps.filter((step) => isCapturedValue(step.decision)).length,
      dataSensitivity: inferOverallDataSensitivity(),
      route: solutionBuildRoute().label
    },
    lanes: ["Start", "Activity", "Data", "Systems", "Human review", "Finish"],
    nodes,
    edges,
    openQuestions,
    reviewerNotes: [
      "Confirm the A-to-Z activity order with the workflow owner.",
      "Validate data sensitivity and source-system access before connector work.",
      "Keep writeback/actions out of scope until human approval gates are named."
    ]
  };
  map.mermaid = workflowMapMermaid(map);
  return map;
}

function workflowMapNode(id, type, label, details = {}) {
  return {
    id,
    type,
    label: String(label || type || id),
    lane: details.lane || "Activity",
    actor: details.actor || "",
    tool: details.tool || "",
    data: details.data || "",
    output: details.output || "",
    detail: details.detail || "",
    status: details.status || "review"
  };
}

function workflowMapEdge(from, to, label = "") {
  return { from, to, label };
}

function stepMapStatus(step = {}) {
  const captured = ["name", "actor", "tool", "input", "output"].filter((key) => isCapturedValue(step[key])).length;
  if (captured >= 4) return "captured";
  if (captured >= 2) return "review";
  return "missing";
}

function bestWorkflowStepMatch(item = {}, steps = state.steps) {
  if (!steps.length) return "step-1";
  const sourceText = Object.values(item).join(" ").toLowerCase();
  let bestIndex = 0;
  let bestScore = -1;
  steps.forEach((step, index) => {
    const tokens = [step.name, step.action, step.tool, step.input, step.output, step.dataHandling]
      .join(" ")
      .toLowerCase()
      .split(/[^a-z0-9]+/)
      .filter((token) => token.length > 3);
    const score = tokens.filter((token) => sourceText.includes(token)).length;
    if (score > bestScore) {
      bestScore = score;
      bestIndex = index;
    }
  });
  return `step-${bestIndex + 1}`;
}

function workflowMapMermaid(map = deriveWorkflowMapStudio()) {
  const lines = ["flowchart LR"];
  const byLane = new Map();
  map.nodes.forEach((node) => {
    if (!byLane.has(node.lane)) byLane.set(node.lane, []);
    byLane.get(node.lane).push(node);
  });
  map.lanes.forEach((lane, laneIndex) => {
    const nodes = byLane.get(lane) || [];
    if (!nodes.length) return;
    lines.push(`  subgraph L${laneIndex + 1}["${safeMermaidLabel(lane)}"]`);
    nodes.forEach((node) => {
      const shape = node.type === "Decision" ? `{` : `[`;
      const endShape = node.type === "Decision" ? `}` : `]`;
      const label = `${node.type}: ${node.label}`;
      lines.push(`    ${workflowMapMermaidId(node.id)}${shape}"${safeMermaidLabel(label)}"${endShape}`);
    });
    lines.push("  end");
  });
  map.edges.forEach((edge) => {
    const label = edge.label ? `|${safeMermaidLabel(edge.label)}|` : "";
    lines.push(`  ${workflowMapMermaidId(edge.from)} -->${label} ${workflowMapMermaidId(edge.to)}`);
  });
  return lines.join("\n");
}

function workflowMapMermaidId(id) {
  return String(id || "node").replace(/[^a-zA-Z0-9_]/g, "_");
}

function workflowMapStudioRows(map = deriveWorkflowMapStudio()) {
  return [
    ["Record Type", "ID", "Type", "Lane", "Label", "From", "To", "Edge Label", "Actor", "Tool / Source", "Data / Sensitivity", "Output", "Status", "Detail"],
    ...map.nodes.map((node) => [
      "Node",
      node.id,
      node.type,
      node.lane,
      node.label,
      "",
      "",
      "",
      node.actor,
      node.tool,
      node.data,
      node.output,
      node.status,
      node.detail
    ]),
    ...map.edges.map((edge) => [
      "Edge",
      `${edge.from}->${edge.to}`,
      "",
      "",
      "",
      edge.from,
      edge.to,
      edge.label,
      "",
      "",
      "",
      "",
      "",
      ""
    ])
  ];
}

function workflowMapStudioMarkdown(map = deriveWorkflowMapStudio()) {
  return [
    `# ${map.workflow} Workflow Map Studio`,
    "",
    "## Summary",
    `- Steps: ${map.summary.stepCount}`,
    `- Data sources: ${map.summary.dataCount}`,
    `- Systems: ${map.summary.systemCount}`,
    `- Decisions: ${map.summary.decisionCount}`,
    `- Data sensitivity: ${map.summary.dataSensitivity}`,
    `- Recommended build route: ${map.summary.route}`,
    "",
    "## Visual Map",
    "```mermaid",
    map.mermaid,
    "```",
    "",
    "## Nodes",
    ...map.nodes.map((node) => `- ${node.type}: ${node.label} (${node.lane}) - ${node.detail || node.status}`),
    "",
    "## Open Questions",
    ...(map.openQuestions.length ? map.openQuestions.map((question, index) => `${index + 1}. ${question}`) : ["No major map questions captured."]),
    "",
    "## Reviewer Notes",
    ...map.reviewerNotes.map((note) => `- ${note}`)
  ].join("\n");
}

