function renderIdeas() {
  if (!els.ideasList) return;
  els.ideasList.innerHTML = "";
  if (!state.ideas.length) {
    els.ideasList.innerHTML = `<div class="summary-item">No future-state ideas parked yet.</div>`;
    return;
  }
  state.ideas.forEach((idea, index) => {
    const item = document.createElement("div");
    item.className = "list-item";
    item.innerHTML = `<span>${escapeHtml(idea.idea)}</span><button class="mini-button" type="button" title="Remove"><i data-lucide="x"></i></button>`;
    item.querySelector("button").addEventListener("click", () => {
      state.ideas.splice(index, 1);
      persistState();
      renderIdeas();
    });
    els.ideasList.appendChild(item);
  });
  refreshIcons();
}

