function connectorBoundarySummary() {
  const sensitivity = inferOverallDataSensitivity();
  const boundary = state.fields.msaBoundary;
  const environment = state.fields.deploymentEnvironment;
  return [
    sensitivity !== "Unknown" ? sensitivity : "",
    isCapturedValue(boundary) ? boundary : "",
    isCapturedValue(environment) ? environment : ""
  ].filter(Boolean).join(" / ") || "Unknown boundary; avoid raw client data until approved.";
}

function hasMicrosoft365SourceSignal() {
  const text = [
    state.fields.availableTooling,
    state.fields.submittedWhereToday,
    state.fields.reusableCollateralSource,
    state.fields.prepArtifactsNeeded,
    state.fields.deploymentEnvironment,
    state.fields.expectedWorkshopOutput,
    ...state.systems.flatMap((item) => [item.name, item.purpose, item.access, item.integration]),
    ...state.steps.flatMap((step) => [step.tool, step.accessMode, step.input, step.output, step.handoff])
  ].join(" ");
  return /\b(sharepoint|one\s*drive|onedrive|teams|outlook|email|word|powerpoint|excel|microsoft|m365|office|copilot|transcript)\b/i.test(text);
}

