function solutionConnectorModel(route = solutionBuildRoute()) {
  if (/Microsoft|Hybrid/i.test(route.routeType)) {
    return "Microsoft 365 Copilot connectors for enterprise content; Graph/custom connector only if no prebuilt connector covers the source; MCP/API plugin path only after security review.";
  }
  if (/agent/i.test(route.routeType)) return "OpenAI function/MCP tool contracts for approved sources; optional Microsoft connector later if outputs move to Microsoft 365.";
  return "Manual upload or approved file set first; connector request is a later enterprise-hardening step.";
}

function solutionWritebackBoundary(route = solutionBuildRoute()) {
  if (/hybrid|agent/i.test(route.routeType)) return "Read-only first. Add create/update/delete actions only after owner approval, authentication, logging, and confirmation prompts are defined.";
  return "No writeback in the first MVP; users copy or export reviewed outputs manually.";
}

function solutionRoleInstruction() {
  return `You are building an AI assistant for ${state.fields.workflowName || state.fields.submittedWorkflowTask || "this workflow"}. Help the user complete the workflow using approved context, ask for missing inputs, produce the agreed output, and clearly separate facts, assumptions, and items needing human review.`;
}

function solutionRunPrompt() {
  return `Use the approved inputs for ${state.fields.workflowName || state.fields.submittedWorkflowTask || "this workflow"}. Follow the captured workflow steps, produce ${templateValue(state.fields.definitionOfDone || summarizedOutputs(), "the agreed output")}, cite or name the source material used, list assumptions, and mark anything requiring reviewer approval.`;
}

function solutionReviewerPrompt() {
  return "Review the AI output against the source material, accepted output format, client/data sensitivity rules, and definition of done. Return approve, approve with edits, or reject with the reason and the exact correction needed.";
}

function solutionEscalationPrompt() {
  return "Stop and escalate to the human owner when source material is missing, data sensitivity is unclear, the output would be client-facing, or the model needs to write/update an enterprise system.";
}

function solutionDataMinimizationControl() {
  const sensitivity = inferOverallDataSensitivity();
  if (/sensitive|client|confidential|regulated|personal|pii|mnpi|pci|phi/i.test(sensitivity)) {
    return "Use sanitized or minimum necessary inputs, avoid raw regulated/client data until approved, and keep examples separate from production records.";
  }
  return "Use only the approved files and fields needed for the MVP, and remove unused source material from the pilot package.";
}

function solutionAuditTrailControl() {
  return "Log source files or evidence used, prompt/version notes, output timestamp, reviewer decision, corrections, and any open assumptions before pilot signoff.";
}

function solutionMvpBuildSteps(route = solutionBuildRoute()) {
  return [
    "1. Confirm the MVP input, output, user, and reviewer from the Product and Engineering briefs.",
    "2. Create the ChatGPT instruction pack and run it on one safe sample.",
    /Microsoft|Hybrid/i.test(route.routeType)
      ? "3. Map the same workflow to the Microsoft 365 surfaces and confirm approved SharePoint/OneDrive/Teams/Office paths."
      : "3. Keep Microsoft 365 integration optional until the sample proves useful.",
    "4. Add source/evidence traceability and a human review checklist.",
    "5. Run 3-5 pilot examples, collect reviewer decisions, and update prompts/actions from failures.",
    "6. Only then request enterprise connectors, Copilot agent/actions, or API tool hardening."
  ];
}

function solutionTestScript(route = solutionBuildRoute()) {
  return [
    "1. Run the recipe on one safe sample input.",
    "2. Check whether the output matches the definition of done.",
    "3. Verify facts against source material and mark unsupported claims.",
    /Microsoft|Hybrid/i.test(route.routeType)
      ? "4. Confirm the Copilot/Microsoft 365 path can find the needed source content without permission leakage."
      : "4. Confirm the ChatGPT workflow works without enterprise connectors.",
    "5. Capture reviewer decision, corrections, time saved, and next backlog item."
  ];
}

function solutionAcceptanceCriteria(route = solutionBuildRoute()) {
  return [
    "The builder can run the workflow from approved inputs.",
    "The output is useful enough for human review.",
    "Assumptions and missing inputs are visible.",
    "Reviewer approval or rejection is captured.",
    /Microsoft|Hybrid/i.test(route.routeType) ? "Microsoft 365 source and permission assumptions are documented." : "Connector needs are explicitly deferred or justified."
  ].join("\n");
}

function solutionBuildOpenQuestions(review = buildReviewGate()) {
  return dedupeQuestions([
    ...(review.handoff.engineering || []),
    ...(review.handoff.product || []),
    ...(review.handoff.governance || []),
    "Which parts should be built in ChatGPT versus Microsoft Copilot for the first pilot?",
    "Which data sources are approved for the first MVP?"
  ]).slice(0, 6);
}

function deriveSolutionBuildSpec(solutionBuildRecipe = deriveSolutionBuildRecipe()) {
  const route = solutionBuildRoute();
  const workflow = state.fields.workflowName || state.fields.submittedWorkflowTask || state.sessionMeta?.name || "Unnamed workflow";
  const chatGptPlatform = {
    id: "chatgpt",
    label: "ChatGPT / OpenAI",
    implementationSurface: chatGptImplementationSurface(route),
    responsibilities: [
      route.chatgptMode,
      "Reusable instructions, prompt pack, file/source reasoning, structured outputs, and review rubrics."
    ],
    knowledgePlan: chatGptKnowledgePlan(),
    toolPlan: chatGptToolPlan(route),
    instructionPack: {
      roleInstruction: solutionRoleInstruction(),
      runPrompt: solutionRunPrompt(),
      reviewerPrompt: solutionReviewerPrompt(),
      escalationPrompt: solutionEscalationPrompt()
    },
    outputContract: mvpOutputContractSummary()
  };
  const copilotPlatform = {
    id: "microsoft-copilot",
    label: "Microsoft 365 Copilot / Copilot Studio",
    implementationSurface: copilotImplementationSurface(route),
    responsibilities: [
      route.copilotMode,
      "Microsoft 365 execution surface, enterprise content context, collaboration, and approved agent/action paths."
    ],
    m365Surfaces: microsoft365SurfaceSummary(),
    knowledgePlan: copilotKnowledgePlan(route),
    actionPlan: copilotActionPlan(route),
    outputDestination: summarizedOutputs()
  };
  const spec = {
    version: 1,
    generatedAt: new Date().toISOString(),
    workflow,
    readiness: solutionBuildRecipe.readiness,
    route,
    platforms: [chatGptPlatform, copilotPlatform],
    connectors: solutionBuildConnectorContracts(route),
    controls: solutionBuildControlContracts(route),
    mvp: {
      buildSteps: solutionMvpBuildSteps(route),
      testScript: solutionTestScript(route),
      acceptanceCriteria: solutionAcceptanceCriteria(route).split(/\n+/).filter(Boolean),
      pilotUsers: templateValue(state.fields.pilotCandidate || state.fields.outputConsumer || state.fields.peopleInvolved, "Pilot users TBD"),
      successMetrics: templateValue(state.fields.successMetrics || state.fields.kpiTypes, "Success metrics TBD")
    },
    openQuestions: solutionBuildOpenQuestions(),
    sourceSignals: {
      stepCount: state.steps.length,
      systemCount: state.systems.length,
      dataCount: state.data.length,
      decisionCount: state.decisions.length,
      dataSensitivity: inferOverallDataSensitivity(),
      m365Surfaces: microsoft365SurfaceSummary(),
      accessModel: accessModelSummary(),
      outputContract: mvpOutputContractSummary()
    },
    capabilityPlan: deriveSolutionCapabilityPlan({ workflow, readiness: solutionBuildRecipe.readiness, route })
  };
  spec.executionPlan = deriveSolutionExecutionPlan(spec);
  spec.workflowMapStudio = deriveWorkflowMapStudio();
  spec.addOnProviderPlan = deriveAddOnProviderPlan();
  spec.agentBuildPack = deriveAgentBuildPack(spec);
  return spec;
}

function solutionBuildConnectorContracts(route = solutionBuildRoute()) {
  const needsMicrosoft = /Microsoft|Hybrid/i.test(route.routeType);
  const needsActions = /Hybrid|agent/i.test(route.routeType);
  return [
    {
      id: "manual-evidence-files",
      platform: "Shared MVP",
      connectorType: "Manual upload or approved file set",
      readWriteMode: "Read-only",
      status: "MVP-ready",
      authModel: "User-provided approved files",
      source: dataSourcesSummary(),
      nextAction: "Use safe samples first; attach only artifacts needed for the MVP."
    },
    {
      id: "chatgpt-tools",
      platform: "ChatGPT / OpenAI",
      connectorType: needsActions ? "Function or MCP tool contract" : "Structured prompt/file workflow",
      readWriteMode: needsActions ? "Read first; write only after approval" : "No writeback",
      status: needsActions ? "Candidate after pilot proof" : "Later hardening",
      authModel: "Approved enterprise OpenAI/ChatGPT access",
      source: chatGptKnowledgePlan(),
      nextAction: chatGptToolPlan(route)
    },
    {
      id: "microsoft-365-copilot",
      platform: "Microsoft 365 Copilot / Copilot Studio",
      connectorType: needsMicrosoft ? "Microsoft 365 content connector or Copilot agent/action" : "Optional Office collaboration surface",
      readWriteMode: needsActions ? "Read-first, human-confirmed write/actions later" : "Read-only or manual output copy",
      status: needsMicrosoft ? "Enterprise candidate" : "Optional later",
      authModel: "Microsoft tenant approval, Entra identity, and approved content permissions",
      source: microsoft365SurfaceSummary(),
      nextAction: copilotKnowledgePlan(route)
    }
  ];
}

function solutionBuildControlContracts(route = solutionBuildRoute()) {
  return [
    {
      id: "human-review",
      owner: "Product / Domain Sponsor",
      control: humanReviewGateSummary(),
      requiredBefore: "Pilot reliance or client-facing use"
    },
    {
      id: "data-minimization",
      owner: "Governance / Security",
      control: solutionDataMinimizationControl(),
      requiredBefore: "Adding real enterprise or client context"
    },
    {
      id: "audit-trail",
      owner: "Engineering / Solution Owner",
      control: solutionAuditTrailControl(),
      requiredBefore: "Enterprise pilot"
    },
    {
      id: "writeback-boundary",
      owner: "Engineering / Platform Owner",
      control: solutionWritebackBoundary(route),
      requiredBefore: "Copilot actions, API writes, or system updates"
    }
  ];
}

function deriveEnterpriseConnectorContracts(solutionBuildSpec = deriveSolutionBuildSpec()) {
  const registry = deriveConnectorRegistry();
  const contracts = solutionBuildSpec.connectors.map((connector) => {
    const registryMatch = enterpriseConnectorRegistryMatch(connector, registry);
    const writeSensitive = /write|action|update|create|delete/i.test(`${connector.readWriteMode} ${connector.connectorType}`);
    const enterpriseCandidate = /enterprise|candidate|microsoft|mcp|function|copilot/i.test(`${connector.status} ${connector.platform} ${connector.connectorType}`);
    return {
      id: connector.id,
      name: enterpriseConnectorName(connector.id),
      platform: connector.platform,
      sourceSystem: registryMatch?.name || connector.source || "Approved source TBD",
      sourceLocations: enterpriseConnectorSourceLocations(connector, registryMatch),
      connectorType: connector.connectorType,
      status: connector.status,
      authModel: connector.authModel,
      readWriteMode: connector.readWriteMode,
      dataBoundary: registryMatch?.dataBoundary || connectorBoundarySummary(),
      owner: registryMatch?.owner || enterpriseConnectorOwner(connector),
      storageTarget: registryMatch?.storageTarget || currentPilotControls().storageTarget || "Approved storage TBD",
      linkedRegistryId: registryMatch?.id || "",
      linkedBuildSpecId: connector.id,
      permissionScope: enterpriseConnectorPermissionScope(connector),
      allowedOperations: enterpriseConnectorAllowedOperations(connector),
      blockedOperations: enterpriseConnectorBlockedOperations(connector),
      permissions: enterpriseConnectorPermissions(connector),
      requiredApprovals: enterpriseConnectorApprovals(connector, { writeSensitive, enterpriseCandidate }),
      approvalGate: enterpriseConnectorApprovalGate(connector, { writeSensitive, enterpriseCandidate }),
      pilotDataPolicy: enterpriseConnectorPilotDataPolicy(connector),
      fallbackMode: enterpriseConnectorFallbackMode(connector),
      setupSteps: enterpriseConnectorSetupSteps(connector),
      testCriteria: enterpriseConnectorTestCriteria(connector),
      openQuestions: enterpriseConnectorOpenQuestions(connector),
      nextAction: connector.nextAction
    };
  });
  const readiness = enterpriseConnectorReadiness(contracts);
  return {
    version: 1,
    generatedAt: new Date().toISOString(),
    workflow: solutionBuildSpec.workflow,
    routeType: solutionBuildSpec.route.routeType,
    routeLabel: solutionBuildSpec.route.label,
    readiness,
    readinessLabel: templateReadinessLabel(readiness),
    dataBoundary: connectorBoundarySummary(),
    nextAction: enterpriseConnectorNextAction(contracts, solutionBuildSpec.route),
    contracts,
    controls: solutionBuildSpec.controls
  };
}

function enterpriseConnectorRegistryMatch(connector = {}, registry = deriveConnectorRegistry()) {
  const text = `${connector.id} ${connector.platform} ${connector.connectorType}`.toLowerCase();
  if (/manual|evidence|file/.test(text)) return registry.find((item) => item.id === "evidence-files") || registry.find((item) => item.id === "live-intake");
  if (/microsoft|copilot|sharepoint|teams|outlook|onedrive|office/.test(text)) return registry.find((item) => item.id === "microsoft-365");
  if (/chatgpt|openai|mcp|function/.test(text)) return registry.find((item) => item.id === "live-intake");
  return registry.find((item) => item.id === "handoff-package") || registry[0];
}

function enterpriseConnectorName(id) {
  const names = {
    "manual-evidence-files": "Manual evidence/file source contract",
    "chatgpt-tools": "ChatGPT/OpenAI tool contract",
    "microsoft-365-copilot": "Microsoft 365 Copilot connector/action contract"
  };
  return names[id] || String(id || "Connector contract");
}

function enterpriseConnectorOwner(connector = {}) {
  if (/microsoft|copilot/i.test(`${connector.platform} ${connector.connectorType}`)) return "Microsoft tenant admin / Enterprise app owner";
  if (/chatgpt|openai/i.test(`${connector.platform} ${connector.connectorType}`)) return "AI Engineering / OpenAI platform owner";
  return "Session owner / AI Infusion";
}

function enterpriseConnectorSourceLocations(connector = {}, registryMatch = null) {
  const text = `${connector.id} ${connector.platform} ${connector.connectorType}`;
  if (/microsoft|copilot/i.test(text)) {
    return microsoft365SourceLocationSummary() || currentPilotControls().sharepointPath || currentPilotControls().storageTarget || "Approved SharePoint, OneDrive, Teams, Outlook, Word, PowerPoint, or Excel locations TBD.";
  }
  if (/chatgpt|openai|mcp|function/i.test(text)) {
    return chatGptKnowledgePlan();
  }
  if (/manual|evidence|file/i.test(text)) {
    const artifacts = (state.evidenceArtifacts || []).map((artifact) => artifact.fileName).filter(Boolean);
    return artifacts.length ? artifacts.slice(0, 8).join("\n") : "User-provided safe sample files, screenshots, transcripts, templates, or package exports.";
  }
  return [registryMatch?.storageTarget, registryMatch?.sourceType, connector.source]
    .map((item) => String(item || "").trim())
    .filter(isCapturedValue)
    .join("\n") || "Approved source locations TBD.";
}

function microsoft365SourceLocationSummary() {
  const values = [
    currentPilotControls().sharepointPath,
    ...state.systems
      .filter((item) => /sharepoint|one\s*drive|onedrive|teams|outlook|word|powerpoint|excel|microsoft|m365|office/i.test(`${item.name} ${item.purpose} ${item.access} ${item.integration}`))
      .map((item) => `${item.name || "Microsoft 365 source"}${item.purpose ? ` - ${item.purpose}` : ""}${item.access ? ` (${item.access})` : ""}`),
    ...state.steps
      .filter((step) => /sharepoint|one\s*drive|onedrive|teams|outlook|word|powerpoint|excel|microsoft|m365|office/i.test(`${step.tool} ${step.accessMode} ${step.input} ${step.output} ${step.handoff}`))
      .map((step) => `${step.name || step.action || "Workflow step"} - ${templateValue(step.tool || step.accessMode || step.input || step.output, "Microsoft 365 context")}`),
    ...state.data
      .filter((item) => /sharepoint|one\s*drive|onedrive|teams|outlook|word|powerpoint|excel|microsoft|m365|office/i.test(`${item.source} ${item.format} ${item.usage}`))
      .map((item) => `${item.category || "Data source"} - ${templateValue(item.source || item.format, "Microsoft 365 source")}`)
  ].filter(isCapturedValue);
  return [...new Set(values)].slice(0, 10).join("\n");
}

function enterpriseConnectorPermissionScope(connector = {}) {
  const text = `${connector.platform} ${connector.connectorType} ${connector.readWriteMode}`;
  if (/write|action|update|create|delete/i.test(text)) {
    return "Separate read scope from write/action scope; start read-only, then require explicit owner approval, confirmation prompt, logging, and rollback expectation before writes.";
  }
  if (/microsoft|copilot/i.test(text)) {
    return "Use inherited user permissions or tenant-approved read permissions for named Microsoft 365 locations only; avoid broad tenant search until the platform owner approves it.";
  }
  if (/chatgpt|openai|mcp|function/i.test(text)) {
    return "Limit ChatGPT/OpenAI access to the approved workspace, approved files, and reviewed tool schemas; each tool gets its own auth and logging review.";
  }
  return "Use user-provided or approved read-only source material; no background system access in the local MVP.";
}

function enterpriseConnectorAllowedOperations(connector = {}) {
  const text = `${connector.id} ${connector.platform} ${connector.connectorType} ${connector.readWriteMode}`;
  if (/microsoft|copilot/i.test(text)) return "Read approved Microsoft 365 content, ground responses, draft Office artifacts, and route outputs for human review.";
  if (/chatgpt|openai|mcp|function/i.test(text)) return "Analyze approved sources, transform or summarize content, generate structured outputs, and prepare review handoffs.";
  if (/manual|evidence|file/i.test(text)) return "Upload or reference approved files, extract metadata, summarize evidence, and link suggestions to fields or workflow records.";
  return "Read approved inputs and generate reviewable outputs inside the documented MVP boundary.";
}

function enterpriseConnectorBlockedOperations(connector = {}) {
  const blocked = [
    "No raw client, regulated, PII, MNPI, PHI, PCI, or confidential data unless the boundary is explicitly approved.",
    "No broad tenant crawl, cross-client search, silent external sharing, deletion, or background sync.",
    "No writeback, update, notification, ticket creation, or system action without a separate human-confirmed write/action gate."
  ];
  if (/manual|evidence|file/i.test(`${connector.id} ${connector.connectorType}`)) blocked.push("No mandatory evidence upload for the basic interview flow.");
  return blocked.join("\n");
}

function enterpriseConnectorPermissions(connector = {}) {
  if (/write|action|update|create|delete/i.test(`${connector.readWriteMode} ${connector.connectorType}`)) {
    return "Least-privilege read first; write/action permissions require separate approval, confirmation prompt, logging, and rollback expectation.";
  }
  if (/microsoft|copilot/i.test(`${connector.platform} ${connector.connectorType}`)) {
    return "Read access only to approved Microsoft 365 content locations with inherited user permissions or tenant-approved connector permissions.";
  }
  return "User-provided or approved read-only source material for the MVP.";
}

function enterpriseConnectorApprovals(connector = {}, flags = {}) {
  const approvals = [];
  if (flags.enterpriseCandidate || /microsoft|copilot/i.test(`${connector.platform} ${connector.connectorType}`)) approvals.push("Enterprise platform owner");
  if (/openai|chatgpt|mcp|function/i.test(`${connector.platform} ${connector.connectorType}`)) approvals.push("AI Engineering / OpenAI platform owner");
  if (flags.writeSensitive) approvals.push("Workflow owner approval for write/actions");
  approvals.push("Governance/Security review before real client or regulated data");
  return [...new Set(approvals)].join("; ");
}

function enterpriseConnectorApprovalGate(connector = {}, flags = {}) {
  if (flags.writeSensitive) return "Workflow owner and platform owner must approve the exact write/action behavior before any non-read operation is enabled.";
  if (flags.enterpriseCandidate || /microsoft|copilot/i.test(`${connector.platform} ${connector.connectorType}`)) return "Enterprise platform owner confirms source locations, inherited permissions, retention, and audit evidence before connector build.";
  if (/openai|chatgpt|mcp|function/i.test(`${connector.platform} ${connector.connectorType}`)) return "AI Engineering confirms tool schema, auth path, logging, and data boundary before function/MCP tooling is enabled.";
  return "Session owner confirms the safe-sample source set before local MVP testing.";
}

function enterpriseConnectorPilotDataPolicy(connector = {}) {
  const controls = currentPilotControls();
  const policy = controls.clientDataPolicy || "Use synthetic, sanitized, metadata-only, or explicitly approved sample data.";
  if (/microsoft|copilot/i.test(`${connector.platform} ${connector.connectorType}`)) {
    return `${policy} Start from a named SharePoint/OneDrive/Teams/Office location and verify permissions with a test user before broader access.`;
  }
  if (/chatgpt|openai/i.test(`${connector.platform} ${connector.connectorType}`)) {
    return `${policy} Keep uploaded files or prompts inside the approved ChatGPT/OpenAI workspace and record source assumptions.`;
  }
  return policy;
}

function enterpriseConnectorFallbackMode(connector = {}) {
  if (/microsoft|copilot/i.test(`${connector.platform} ${connector.connectorType}`)) return "If tenant or source approval is not ready, use manual export/upload plus reviewed Office copy-paste for the pilot.";
  if (/chatgpt|openai|mcp|function/i.test(`${connector.platform} ${connector.connectorType}`)) return "If tools are not approved, run the instruction pack manually with structured output templates and no live system calls.";
  return "Use conversation-only intake and local package exports; evidence remains optional.";
}

function enterpriseConnectorSetupSteps(connector = {}) {
  return [
    "Confirm source owner and approved data boundary.",
    `Document source locations: ${enterpriseConnectorSourceLocations(connector).replace(/\n+/g, "; ")}`,
    `Document permission scope: ${enterpriseConnectorPermissionScope(connector)}`,
    "Confirm auth model, permission scope, retention, and logging expectation.",
    /write|action|update|create|delete/i.test(`${connector.readWriteMode} ${connector.connectorType}`)
      ? "Split read and write/action tools; require human confirmation before writeback."
      : "Keep the first pilot read-only or manual-output-copy.",
    "Run one safe sample and compare output against source evidence.",
    "Record reviewer decision and unresolved connector risks before enterprise pilot."
  ];
}

function enterpriseConnectorTestCriteria(connector = {}) {
  return [
    "Only approved source content is reachable.",
    `Allowed operations are limited to: ${enterpriseConnectorAllowedOperations(connector)}`,
    `Blocked operations remain blocked: ${enterpriseConnectorBlockedOperations(connector).split("\n")[0]}`,
    "The output identifies source assumptions or missing inputs.",
    "Human review is required before reliance.",
    /write|action|update|create|delete/i.test(`${connector.readWriteMode} ${connector.connectorType}`)
      ? "No write/action occurs without explicit confirmation and logged reviewer intent."
      : "No writeback occurs in the MVP path."
  ];
}

function enterpriseConnectorOpenQuestions(connector = {}) {
  return dedupeQuestions([
    `Who owns approval for ${enterpriseConnectorName(connector.id)}?`,
    `Which exact source locations or APIs should ${connector.platform} access?`,
    "What retention, logging, and audit evidence is required for the pilot?",
    /write|action|update|create|delete/i.test(`${connector.readWriteMode} ${connector.connectorType}`)
      ? "What rollback or exception path is required for write/actions?"
      : "When, if ever, should this connector move beyond read-only?"
  ]);
}

function enterpriseConnectorReadiness(contracts = []) {
  if (!contracts.length) return 0;
  const scores = contracts.map((contract) => {
    let score = 35;
    if (isCapturedValue(contract.sourceSystem)) score += 12;
    if (isCapturedValue(contract.sourceLocations)) score += 6;
    if (isCapturedValue(contract.authModel)) score += 12;
    if (isCapturedValue(contract.readWriteMode)) score += 10;
    if (isCapturedValue(contract.permissionScope)) score += 6;
    if (isCapturedValue(contract.requiredApprovals)) score += 12;
    if (isCapturedValue(contract.approvalGate)) score += 6;
    if ((contract.setupSteps || []).length >= 3) score += 10;
    if ((contract.testCriteria || []).length >= 3) score += 9;
    return Math.min(100, score);
  });
  return Math.round(scores.reduce((sum, score) => sum + score, 0) / scores.length);
}

function enterpriseConnectorNextAction(contracts = [], route = solutionBuildRoute()) {
  const microsoft = contracts.find((contract) => /microsoft|copilot/i.test(`${contract.platform} ${contract.connectorType}`));
  if (microsoft && /Enterprise candidate/i.test(microsoft.status)) {
    return "Confirm Microsoft 365 content locations, permission model, and tenant owner before any Copilot connector/action build.";
  }
  const writeAction = contracts.find((contract) => /write|action|update|create|delete/i.test(`${contract.readWriteMode} ${contract.connectorType}`));
  if (writeAction) return "Keep connector read-only until the workflow owner approves write/action behavior and logging.";
  return route.nextAction || "Use safe samples first, then review connector contracts with Engineering and platform owners.";
}

function enterpriseConnectorContractRows(contractPack = deriveEnterpriseConnectorContracts()) {
  return [
    ["ID", "Name", "Platform", "Source System", "Source Locations", "Connector Type", "Status", "Auth Model", "Read/Write Mode", "Data Boundary", "Owner", "Storage Target", "Linked Registry ID", "Linked Build Spec ID", "Permission Scope", "Allowed Operations", "Blocked Operations", "Permissions", "Required Approvals", "Approval Gate", "Pilot Data Policy", "Fallback Mode", "Setup Steps", "Test Criteria", "Open Questions", "Next Action"],
    ...contractPack.contracts.map((contract) => [
      contract.id,
      contract.name,
      contract.platform,
      contract.sourceSystem,
      contract.sourceLocations,
      contract.connectorType,
      contract.status,
      contract.authModel,
      contract.readWriteMode,
      contract.dataBoundary,
      contract.owner,
      contract.storageTarget,
      contract.linkedRegistryId,
      contract.linkedBuildSpecId,
      contract.permissionScope,
      contract.allowedOperations,
      contract.blockedOperations,
      contract.permissions,
      contract.requiredApprovals,
      contract.approvalGate,
      contract.pilotDataPolicy,
      contract.fallbackMode,
      (contract.setupSteps || []).join("\n"),
      (contract.testCriteria || []).join("\n"),
      (contract.openQuestions || []).join("\n"),
      contract.nextAction
    ])
  ];
}

function enterpriseConnectorContractsMarkdown(contractPack = deriveEnterpriseConnectorContracts()) {
  const workflow = templateValue(contractPack.workflow || state.fields.workflowName || state.fields.submittedWorkflowTask || state.sessionMeta?.name, "Workflow TBD");
  const contracts = contractPack.contracts || [];
  return [
    `# Enterprise Connector Contracts - ${workflow}`,
    "",
    `Generated: ${new Date().toLocaleString()}`,
    `Readiness: ${Number(contractPack.readiness || 0)}% - ${contractPack.readinessLabel || templateReadinessLabel(contractPack.readiness || 0)}`,
    `Route: ${formatMarkdownValue(contractPack.routeLabel || contractPack.routeType || "TBD")}`,
    `Data boundary: ${formatMarkdownValue(contractPack.dataBoundary || "Unknown boundary; avoid raw client data until approved.")}`,
    "",
    "Use this as the practical source, permission, approval, and fallback review pack before any Microsoft 365, OpenAI tool, MCP, API, or write/action connector work is requested.",
    "",
    "## Reviewer Summary",
    "",
    `- Connector contracts: ${contracts.length}`,
    `- Next action: ${formatMarkdownValue(contractPack.nextAction || "Review connector contracts with Engineering and platform owners.")}`,
    "",
    "## Required Controls",
    "",
    ...(contractPack.controls || []).map((control) => `- ${formatMarkdownValue(control.control)} (${formatMarkdownValue(control.owner)}; before ${formatMarkdownValue(control.requiredBefore)})`),
    ...((contractPack.controls || []).length ? [""] : ["- No connector-level controls generated yet.", ""]),
    ...contracts.flatMap((contract) => enterpriseConnectorContractMarkdownSection(contract))
  ].join("\n");
}

function enterpriseConnectorContractMarkdownSection(contract = {}) {
  return [
    `## ${formatMarkdownValue(contract.name || contract.id || "Connector Contract")}`,
    "",
    markdownValueList("Platform", contract.platform),
    markdownValueList("Connector type", contract.connectorType),
    markdownValueList("Status", contract.status),
    markdownValueList("Owner", contract.owner),
    markdownValueList("Source system", contract.sourceSystem),
    markdownValueList("Source locations", contract.sourceLocations),
    markdownValueList("Auth model", contract.authModel),
    markdownValueList("Permission scope", contract.permissionScope),
    markdownValueList("Read/write mode", contract.readWriteMode),
    markdownValueList("Allowed operations", contract.allowedOperations),
    markdownValueList("Blocked operations", contract.blockedOperations),
    "",
    "### Approval Gate",
    "",
    markdownValueList("Required approvals", contract.requiredApprovals),
    markdownValueList("Approval gate", contract.approvalGate),
    markdownValueList("Pilot data policy", contract.pilotDataPolicy),
    markdownValueList("Fallback mode", contract.fallbackMode),
    "",
    "### Setup Steps",
    "",
    markdownOrderedList(contract.setupSteps, "No setup steps generated yet."),
    "",
    "### Test Criteria",
    "",
    markdownOrderedList(contract.testCriteria, "No test criteria generated yet."),
    "",
    "### Open Questions",
    "",
    markdownQuestionList(contract.openQuestions || [], "No connector questions generated yet."),
    "",
    `Next action: ${formatMarkdownValue(contract.nextAction || "Review this connector with the source owner.")}`,
    ""
  ];
}

function markdownValueList(label, value) {
  const lines = markdownValueLines(value);
  if (!lines.length) return `- ${label}: TBD`;
  if (lines.length === 1) return `- ${label}: ${lines[0]}`;
  return [`- ${label}:`, ...lines.map((line) => `  - ${line}`)].join("\n");
}

function markdownValueLines(value) {
  if (Array.isArray(value)) return value.map(formatMarkdownValue).filter(isCapturedValue);
  return String(value ?? "")
    .split(/\n+/)
    .map(formatMarkdownValue)
    .filter(isCapturedValue);
}

function markdownOrderedList(items = [], emptyText = "No items generated yet.") {
  const values = markdownValueLines(items);
  if (!values.length) return `- ${emptyText}`;
  return values.map((item, index) => `${index + 1}. ${item}`).join("\n");
}

function deriveConnectorApprovalChecklist(contractPack = deriveEnterpriseConnectorContracts()) {
  const workflow = templateValue(contractPack.workflow || state.fields.workflowName || state.fields.submittedWorkflowTask || state.sessionMeta?.name, "Workflow TBD");
  const items = (contractPack.contracts || []).map((contract) => connectorApprovalChecklistItem(contract));
  const readyCount = items.filter((item) => item.status === "Ready for local safe sample").length;
  const readiness = items.length ? Math.round((items.reduce((sum, item) => sum + item.score, 0) / items.length)) : 0;
  return {
    version: 1,
    generatedAt: new Date().toISOString(),
    workflow,
    routeType: contractPack.routeType || "",
    routeLabel: contractPack.routeLabel || "",
    readiness,
    readinessLabel: templateReadinessLabel(readiness),
    readyCount,
    totalCount: items.length,
    decisionRule: "Treat a connector as enterprise-build-ready only after source locations, permission scope, data boundary, approval owner, audit evidence, safe sample test, and fallback path are confirmed.",
    nextAction: connectorApprovalNextAction(items, contractPack),
    items
  };
}

function connectorApprovalChecklistItem(contract = {}) {
  const writeOrAction = /write|action|update|create|delete/i.test(`${contract.readWriteMode} ${contract.connectorType}`);
  const evidence = connectorApprovalEvidence(contract, { writeOrAction });
  const openQuestions = connectorApprovalOpenQuestions(contract, { writeOrAction });
  const missing = evidence.filter((item) => item.status !== "Ready").length + openQuestions.length;
  const score = Math.max(25, Math.min(100, 100 - (missing * 7) - (writeOrAction ? 8 : 0)));
  const status = score >= 82 && !writeOrAction ? "Ready for local safe sample" : score >= 70 ? "Needs owner review" : "Needs approval detail";
  return {
    id: contract.id,
    connectorName: contract.name || enterpriseConnectorName(contract.id),
    platform: contract.platform,
    connectorType: contract.connectorType,
    owner: contract.owner,
    status,
    score,
    sourceLocations: contract.sourceLocations,
    permissionScope: contract.permissionScope,
    requiredApprovals: contract.requiredApprovals,
    approvalGate: contract.approvalGate,
    pilotDataPolicy: contract.pilotDataPolicy,
    fallbackMode: contract.fallbackMode,
    allowedOperations: contract.allowedOperations,
    blockedOperations: contract.blockedOperations,
    requiredEvidence: evidence,
    decisionOptions: connectorApprovalDecisionOptions(contract, { writeOrAction }),
    openQuestions,
    nextAction: connectorApprovalItemNextAction(contract, status, { writeOrAction })
  };
}

function connectorApprovalEvidence(contract = {}, options = {}) {
  return [
    connectorApprovalEvidenceItem("Source owner", contract.owner, "Confirm who can approve this source/connector boundary."),
    connectorApprovalEvidenceItem("Named source locations", contract.sourceLocations, "Name the SharePoint, OneDrive, Teams, Outlook, Office, OpenAI workspace, file set, or API boundary."),
    connectorApprovalEvidenceItem("Permission scope", contract.permissionScope, "Confirm least-privilege read scope and whether inherited user permissions are enough."),
    connectorApprovalEvidenceItem("Data boundary", contract.dataBoundary || connectorBoundarySummary(), "Confirm whether safe samples, sanitized exports, client approval, or regulated-data review is required."),
    connectorApprovalEvidenceItem("Approval gate", contract.approvalGate, "Confirm who signs off and what must be true before build work starts."),
    connectorApprovalEvidenceItem("Audit / retention evidence", contract.requiredApprovals, "Confirm logging, retention, and review evidence expectations."),
    connectorApprovalEvidenceItem("Fallback path", contract.fallbackMode, "Keep a no-connector path for local/coworker pilot if enterprise approval is not ready."),
    connectorApprovalEvidenceItem(
      options.writeOrAction ? "Write/action rollback path" : "Read-only confirmation",
      options.writeOrAction ? contract.blockedOperations : contract.readWriteMode,
      options.writeOrAction ? "Write/action tools need rollback, confirmation, and logging before enablement." : "First pilot should stay read-only or manual-output-copy."
    )
  ];
}

function connectorApprovalEvidenceItem(label, value, needed) {
  return {
    label,
    status: isCapturedValue(value) ? "Ready" : "Needs confirmation",
    value: templateValue(value, "TBD"),
    needed
  };
}

function connectorApprovalDecisionOptions(contract = {}, options = {}) {
  return [
    "Approve for local safe-sample review only.",
    "Approve read-only enterprise source validation with named locations and test users.",
    options.writeOrAction
      ? "Defer write/action behavior until rollback, confirmation, logging, and workflow-owner signoff are documented."
      : "Defer write/action behavior; continue with manual output copy.",
    "Block connector work until source owner, permission scope, or data boundary is clarified."
  ];
}

function connectorApprovalOpenQuestions(contract = {}, options = {}) {
  return dedupeQuestions([
    isCapturedValue(contract.owner) ? "" : `Who owns approval for ${contract.name || contract.id}?`,
    isCapturedValue(contract.sourceLocations) ? "" : "Which exact source locations, APIs, folders, workspaces, or files are in scope?",
    isCapturedValue(contract.permissionScope) ? "" : "What least-privilege permission scope should the connector use?",
    "What audit, logging, retention, and source-citation evidence must be retained for the pilot?",
    options.writeOrAction ? "What rollback path and human confirmation language are required before writes/actions are enabled?" : ""
  ]);
}

function connectorApprovalItemNextAction(contract = {}, status = "", options = {}) {
  if (/Needs approval detail/i.test(status)) return `Resolve source owner, source locations, and permission scope for ${contract.name || contract.id}.`;
  if (options.writeOrAction) return `Keep ${contract.name || contract.id} read-only until write/action approval and rollback evidence are documented.`;
  if (/microsoft|copilot/i.test(`${contract.platform} ${contract.connectorType}`)) return "Ask the Microsoft tenant/source owner to confirm named locations, inherited permissions, test user, and audit evidence.";
  if (/openai|chatgpt|mcp|function/i.test(`${contract.platform} ${contract.connectorType}`)) return "Ask AI Engineering to confirm tool schema, auth path, logging, data boundary, and fallback mode.";
  return "Confirm the safe-sample source set and run one local review before promoting this connector.";
}

function connectorApprovalNextAction(items = [], contractPack = deriveEnterpriseConnectorContracts()) {
  const needsDetail = items.find((item) => /Needs approval detail/i.test(item.status));
  if (needsDetail) return needsDetail.nextAction;
  const needsOwnerReview = items.find((item) => /Needs owner review/i.test(item.status));
  if (needsOwnerReview) return needsOwnerReview.nextAction;
  return contractPack.nextAction || "Review the checklist with platform, source, governance, and workflow owners before connector build.";
}

function connectorApprovalChecklistRows(checklist = deriveConnectorApprovalChecklist()) {
  return [
    ["ID", "Connector", "Platform", "Owner", "Status", "Score", "Source Locations", "Permission Scope", "Required Approvals", "Approval Gate", "Pilot Data Policy", "Fallback Mode", "Required Evidence", "Decision Options", "Open Questions", "Next Action"],
    ...checklist.items.map((item) => [
      item.id,
      item.connectorName,
      item.platform,
      item.owner,
      item.status,
      item.score,
      item.sourceLocations,
      item.permissionScope,
      item.requiredApprovals,
      item.approvalGate,
      item.pilotDataPolicy,
      item.fallbackMode,
      item.requiredEvidence.map((evidence) => `${evidence.label}: ${evidence.status} - ${evidence.value}`).join("\n"),
      item.decisionOptions.join("\n"),
      item.openQuestions.join("\n"),
      item.nextAction
    ])
  ];
}

function connectorApprovalChecklistMarkdown(checklist = deriveConnectorApprovalChecklist()) {
  return [
    `# Connector Approval Checklist - ${checklist.workflow}`,
    "",
    `Generated: ${new Date().toLocaleString()}`,
    `Readiness: ${checklist.readiness}% - ${checklist.readinessLabel}`,
    `Ready for local safe sample: ${checklist.readyCount}/${checklist.totalCount}`,
    "",
    checklist.decisionRule,
    "",
    "## Next Action",
    "",
    checklist.nextAction,
    "",
    ...checklist.items.flatMap((item) => connectorApprovalChecklistMarkdownSection(item))
  ].join("\n");
}

function connectorApprovalChecklistMarkdownSection(item = {}) {
  return [
    `## ${formatMarkdownValue(item.connectorName || item.id)}`,
    "",
    markdownValueList("Status", `${item.status} (${item.score}/100)`),
    markdownValueList("Platform", item.platform),
    markdownValueList("Owner", item.owner),
    markdownValueList("Source locations", item.sourceLocations),
    markdownValueList("Permission scope", item.permissionScope),
    markdownValueList("Required approvals", item.requiredApprovals),
    markdownValueList("Approval gate", item.approvalGate),
    markdownValueList("Pilot data policy", item.pilotDataPolicy),
    markdownValueList("Fallback mode", item.fallbackMode),
    "",
    "### Required Evidence",
    "",
    markdownOrderedList((item.requiredEvidence || []).map((evidence) => `${evidence.label}: ${evidence.status} - ${evidence.value}; needed: ${evidence.needed}`), "No required evidence generated."),
    "",
    "### Decision Options",
    "",
    markdownOrderedList(item.decisionOptions || [], "No decision options generated."),
    "",
    "### Open Questions",
    "",
    markdownQuestionList(item.openQuestions || [], "No open connector approval questions generated."),
    "",
    `Next action: ${formatMarkdownValue(item.nextAction || "Review with the connector owner.")}`,
    ""
  ];
}

function deriveConnectorValidationPlan(contractPack = deriveEnterpriseConnectorContracts(), approvalChecklist = deriveConnectorApprovalChecklist(contractPack)) {
  const workflow = templateValue(contractPack.workflow || state.fields.workflowName || state.fields.submittedWorkflowTask || state.sessionMeta?.name, "Workflow TBD");
  const tests = (contractPack.contracts || []).flatMap((contract) => connectorValidationTestsForContract(contract, connectorValidationApprovalItem(contract, approvalChecklist)));
  const readiness = connectorValidationReadiness(tests);
  const readyCount = tests.filter((test) => test.status === "Ready to test").length;
  const needsApprovalCount = tests.filter((test) => test.status === "Needs approval detail").length;
  const blockedCount = tests.filter((test) => test.status === "Blocked").length;
  return {
    version: 1,
    generatedAt: new Date().toISOString(),
    workflow,
    routeType: contractPack.routeType || "",
    routeLabel: contractPack.routeLabel || "",
    readiness,
    readinessLabel: templateReadinessLabel(readiness),
    totalCount: tests.length,
    readyCount,
    needsApprovalCount,
    blockedCount,
    decisionRule: "Treat a connector as validated only after source reachability, least-privilege permissions, blocked-operation tests, safe pilot data, audit evidence, human review, fallback behavior, and write/action safeguards are evidenced.",
    nextAction: connectorValidationNextAction(tests, contractPack),
    tests
  };
}

function connectorValidationApprovalItem(contract = {}, checklist = {}) {
  return (checklist.items || []).find((item) => item.id === contract.id) || {};
}

function connectorValidationTestsForContract(contract = {}, checklistItem = {}) {
  const writeOrAction = /write|action|update|create|delete/i.test(`${contract.readWriteMode} ${contract.connectorType}`);
  const source = "Enterprise Connector Contracts; Connector Approval Checklist";
  const tests = [
    connectorValidationTest(contract, {
      key: "source-reachability",
      testArea: "Source reachability",
      test: "Run one safe sample query, upload, or connector read against the named source locations.",
      expectedEvidence: `Named source locations, source owner confirmation, and test-user access result: ${templateValue(contract.sourceLocations, "Source locations TBD")}`,
      statusInputs: [contract.sourceLocations, contract.owner],
      passCriteria: "Only approved source content is reachable; no broad tenant, cross-client, or background crawl is possible.",
      fallbackIfFailed: contract.fallbackMode || "Use conversation-only intake or manual safe-sample export until source access is approved.",
      source
    }),
    connectorValidationTest(contract, {
      key: "permission-boundary",
      testArea: "Permission boundary",
      test: "Confirm least-privilege auth, inherited permission behavior, and read/write mode with a test user or approved local sample.",
      expectedEvidence: `Auth model, permission scope, and read/write mode: ${templateValue([contract.authModel, contract.permissionScope, contract.readWriteMode], "Permission detail TBD")}`,
      statusInputs: [contract.authModel, contract.permissionScope, contract.readWriteMode],
      passCriteria: "The connector cannot see data outside the approved source boundary and uses read-only or manual-output-copy first.",
      fallbackIfFailed: "Limit the pilot to manual exports or local package review until the permission model is approved.",
      source
    }),
    connectorValidationTest(contract, {
      key: "blocked-operations",
      testArea: "Blocked operations",
      test: "Negative-test prohibited behaviors such as raw client-data access, broad search, external sharing, deletion, sync, writeback, and silent notifications.",
      expectedEvidence: `Blocked operations list and negative-test result: ${templateValue(contract.blockedOperations, "Blocked operations TBD")}`,
      statusInputs: [contract.blockedOperations],
      passCriteria: "Every blocked operation is unavailable, denied, or routed to a documented human approval gate.",
      fallbackIfFailed: "Disable the connector path and continue with local package output until prohibited operations are blocked.",
      source
    }),
    connectorValidationTest(contract, {
      key: "pilot-data-policy",
      testArea: "Pilot data policy",
      test: "Verify the sample data used for validation is synthetic, sanitized, metadata-only, or explicitly approved for the current environment.",
      expectedEvidence: `Pilot data policy and sample classification: ${templateValue(contract.pilotDataPolicy, "Pilot data policy TBD")}`,
      statusInputs: [contract.pilotDataPolicy],
      passCriteria: "The validation run uses only approved safe sample data and records any source assumptions.",
      fallbackIfFailed: "Replace the sample set with synthetic or sanitized data before running connector validation.",
      source
    }),
    connectorValidationTest(contract, {
      key: "audit-evidence",
      testArea: "Audit evidence",
      test: "Capture the evidence needed for logging, retention, source citation, test output, reviewer decision, and owner approval.",
      expectedEvidence: `Audit and retention evidence expectation: ${templateValue(connectorValidationChecklistEvidence(checklistItem, "Audit / retention evidence") || contract.requiredApprovals, "Audit evidence TBD")}`,
      statusInputs: [contract.requiredApprovals],
      passCriteria: "The package or enterprise logging path preserves who tested, what source was used, what output was produced, and what decision was made.",
      fallbackIfFailed: "Keep the connector out of enterprise pilot and preserve reviewer evidence in the local package only.",
      source
    }),
    connectorValidationTest(contract, {
      key: "human-review",
      testArea: "Human review gate",
      test: "Confirm the human checkpoint before reliance, sharing, enterprise release, or any non-read operation.",
      expectedEvidence: `Approval gate and owner decision path: ${templateValue(contract.approvalGate, "Approval gate TBD")}`,
      statusInputs: [contract.approvalGate],
      passCriteria: "A named human owner can approve, defer, or block the connector before it is used with real work data.",
      fallbackIfFailed: "Use the build recipe and package exports for review without live connector access.",
      source
    }),
    connectorValidationTest(contract, {
      key: "fallback-mode",
      testArea: "Fallback mode",
      test: "Run or rehearse the no-connector fallback path so the pilot can continue if enterprise source approval is not ready.",
      expectedEvidence: `Fallback path and manual review route: ${templateValue(contract.fallbackMode, "Fallback mode TBD")}`,
      statusInputs: [contract.fallbackMode],
      passCriteria: "The workflow can still be reviewed through conversation-only intake, manual export/upload, or package review.",
      fallbackIfFailed: "Do not promote this connector until a manual or local fallback path is documented.",
      source
    })
  ];
  if (writeOrAction) {
    tests.push(connectorValidationTest(contract, {
      key: "write-action-safeguard",
      testArea: "Write/action safeguard",
      test: "Validate separate write/action approval, confirmation language, logging, rollback expectation, and no automatic action on draft outputs.",
      expectedEvidence: "Workflow owner approval, explicit confirmation prompt, audit log, rollback or exception path, and a disabled-by-default action setting.",
      statusInputs: [],
      blocked: true,
      passCriteria: "No write, update, delete, notification, ticket, or workflow action can occur without explicit human confirmation and logged intent.",
      fallbackIfFailed: "Keep the connector read-only and use manual output copy until write/action safeguards are approved.",
      source
    }));
  }
  return tests;
}

function connectorValidationChecklistEvidence(checklistItem = {}, label = "") {
  const evidence = (checklistItem.requiredEvidence || []).find((item) => item.label === label);
  if (!evidence) return "";
  return `${evidence.status}: ${evidence.value}; needed: ${evidence.needed}`;
}

function connectorValidationTest(contract = {}, details = {}) {
  return {
    id: `${contract.id || "connector"}-${details.key || "test"}`,
    connectorId: contract.id || "",
    connectorName: contract.name || enterpriseConnectorName(contract.id),
    platform: contract.platform || "",
    owner: contract.owner || enterpriseConnectorOwner(contract),
    testArea: details.testArea,
    test: details.test,
    expectedEvidence: details.expectedEvidence,
    status: connectorValidationStatus(details.statusInputs || [], { blocked: details.blocked }),
    passCriteria: details.passCriteria,
    fallbackIfFailed: details.fallbackIfFailed,
    source: details.source || "Connector validation plan"
  };
}

function connectorValidationStatus(inputs = [], options = {}) {
  if (options.blocked) return "Blocked";
  return inputs.every(isCapturedValue) ? "Ready to test" : "Needs approval detail";
}

function connectorValidationReadiness(tests = []) {
  if (!tests.length) return 0;
  const weights = {
    "Ready to test": 100,
    "Needs approval detail": 58,
    "Blocked": 18
  };
  const score = tests.reduce((sum, test) => sum + (weights[test.status] || 0), 0) / tests.length;
  return Math.round(score);
}

function connectorValidationNextAction(tests = [], contractPack = deriveEnterpriseConnectorContracts()) {
  const blocked = tests.find((test) => test.status === "Blocked");
  if (blocked) return `Keep ${blocked.connectorName || blocked.connectorId} read-only until write/action safeguards, rollback expectations, and logging evidence are approved.`;
  const needsDetail = tests.find((test) => test.status === "Needs approval detail");
  if (needsDetail) return `Resolve ${needsDetail.testArea.toLowerCase()} evidence for ${needsDetail.connectorName || needsDetail.connectorId} before connector validation.`;
  return contractPack.nextAction || "Run safe sample connector validation with the source owner and record evidence in the handoff package.";
}

function connectorValidationPlanRows(plan = deriveConnectorValidationPlan()) {
  return [
    ["Connector ID", "Connector", "Platform", "Test Area", "Test", "Expected Evidence", "Owner", "Status", "Pass Criteria", "Fallback If Failed", "Source"],
    ...(plan.tests || []).map((test) => [
      test.connectorId,
      test.connectorName,
      test.platform,
      test.testArea,
      test.test,
      test.expectedEvidence,
      test.owner,
      test.status,
      test.passCriteria,
      test.fallbackIfFailed,
      test.source
    ])
  ];
}

function connectorValidationPlanMarkdown(plan = deriveConnectorValidationPlan()) {
  const tests = plan.tests || [];
  const connectorIds = [...new Set(tests.map((test) => test.connectorId || test.connectorName).filter(Boolean))];
  return [
    `# Connector Validation Plan - ${plan.workflow}`,
    "",
    `Generated: ${new Date().toLocaleString()}`,
    `Readiness: ${Number(plan.readiness || 0)}% - ${plan.readinessLabel || templateReadinessLabel(plan.readiness || 0)}`,
    `Route: ${formatMarkdownValue(plan.routeLabel || plan.routeType || "TBD")}`,
    "",
    plan.decisionRule,
    "",
    "## Test Summary",
    "",
    `- Total tests: ${plan.totalCount || tests.length}`,
    `- Ready to test: ${plan.readyCount || 0}`,
    `- Needs approval detail: ${plan.needsApprovalCount || 0}`,
    `- Blocked: ${plan.blockedCount || 0}`,
    `- Next action: ${formatMarkdownValue(plan.nextAction || "Run safe sample validation with the source owner.")}`,
    "",
    ...connectorIds.flatMap((id) => connectorValidationMarkdownSection(id, tests.filter((test) => (test.connectorId || test.connectorName) === id)))
  ].join("\n");
}

function connectorValidationMarkdownSection(id = "", tests = []) {
  const name = tests[0]?.connectorName || id || "Connector";
  return [
    `## ${formatMarkdownValue(name)}`,
    "",
    ...tests.flatMap((test) => [
      `### ${formatMarkdownValue(test.testArea)}`,
      "",
      markdownValueList("Status", test.status),
      markdownValueList("Test", test.test),
      markdownValueList("Expected evidence", test.expectedEvidence),
      markdownValueList("Owner", test.owner),
      markdownValueList("Pass criteria", test.passCriteria),
      markdownValueList("Fallback if failed", test.fallbackIfFailed),
      markdownValueList("Source", test.source),
      ""
    ])
  ];
}

function deriveConnectorValidationEvidenceLog(plan = deriveConnectorValidationPlan()) {
  const entries = (plan.tests || []).map((test) => connectorValidationEvidenceEntry(test));
  const readiness = connectorValidationEvidenceReadiness(entries);
  const readyCount = entries.filter((entry) => entry.evidenceStatus === "Ready to capture").length;
  const needsOwnerInputCount = entries.filter((entry) => entry.evidenceStatus === "Needs owner input").length;
  const blockedCount = entries.filter((entry) => entry.evidenceStatus === "Blocked by safeguard").length;
  return {
    version: 1,
    generatedAt: new Date().toISOString(),
    workflow: plan.workflow || "Workflow TBD",
    routeType: plan.routeType || "",
    routeLabel: plan.routeLabel || "",
    readiness,
    readinessLabel: templateReadinessLabel(readiness),
    totalCount: entries.length,
    readyCount,
    needsOwnerInputCount,
    blockedCount,
    decisionRule: "Do not treat connector validation as complete until each required proof item has an owner, a safe sample result, a reviewer decision, and a fallback or blocker path.",
    nextAction: connectorValidationEvidenceNextAction(entries, plan),
    entries
  };
}

function connectorValidationEvidenceEntry(test = {}) {
  const evidenceStatus = connectorValidationEvidenceStatus(test);
  return {
    id: `${test.id || "connector-test"}-evidence`,
    testId: test.id || "",
    connectorId: test.connectorId || "",
    connectorName: test.connectorName || "Connector",
    platform: test.platform || "",
    testArea: test.testArea || "",
    validationStatus: test.status || "",
    evidenceStatus,
    evidenceOwner: test.owner || "Source owner / reviewer",
    proofToCapture: connectorValidationProofForTest(test),
    expectedEvidence: test.expectedEvidence || "",
    captureMethod: connectorValidationCaptureMethod(test),
    reviewerPrompt: connectorValidationReviewerPrompt(test),
    resultOptions: connectorValidationEvidenceResultOptions(test),
    decisionImpact: connectorValidationDecisionImpact(test),
    fallbackIfMissing: test.fallbackIfFailed || "Keep connector validation open until evidence is captured.",
    packageTarget: `connector-validation/${test.id || "test"}`,
    source: "Connector Validation Plan"
  };
}

function connectorValidationEvidenceStatus(test = {}) {
  if (test.status === "Blocked") return "Blocked by safeguard";
  if (test.status === "Needs approval detail") return "Needs owner input";
  return "Ready to capture";
}

function connectorValidationProofForTest(test = {}) {
  const area = String(test.testArea || "");
  if (/source reachability/i.test(area)) return "Screenshot, log, or reviewer note showing a safe sample/test user can reach only the named approved source locations.";
  if (/permission boundary/i.test(area)) return "Permission-scope evidence showing inherited access, least-privilege scope, and read/write mode for the safe sample or test user.";
  if (/blocked operations/i.test(area)) return "Negative-test evidence showing prohibited operations are denied, disabled, or routed to an explicit human approval gate.";
  if (/pilot data policy/i.test(area)) return "Safe-data confirmation showing the validation sample is synthetic, sanitized, metadata-only, or explicitly approved.";
  if (/audit evidence/i.test(area)) return "Log, citation, package record, or reviewer note showing who tested, what source was used, what output was produced, and what decision was made.";
  if (/human review/i.test(area)) return "Named approver decision, reviewer note, or signoff artifact that records approve, defer, or block.";
  if (/fallback mode/i.test(area)) return "Manual fallback rehearsal output, local package path, or reviewed copy-paste result showing the pilot can continue without the connector.";
  if (/write|action/i.test(area)) return "Disabled-by-default write/action setting, confirmation prompt text, audit log sample, rollback expectation, and workflow-owner approval.";
  return "Reviewer evidence that proves the validation test passed, failed, or was deferred with a named fallback.";
}

function connectorValidationCaptureMethod(test = {}) {
  const area = String(test.testArea || "");
  if (/source|permission/i.test(area)) return "Capture source-owner note plus screenshot or access test output.";
  if (/blocked|write|action/i.test(area)) return "Capture negative-test result plus the blocked action or approval-gate behavior.";
  if (/audit|human/i.test(area)) return "Capture reviewer decision, owner signoff, and retained package/log reference.";
  if (/fallback/i.test(area)) return "Capture fallback run output and where the local package or manual export is stored.";
  return "Capture reviewer note, sample output, and any package evidence path.";
}

function connectorValidationReviewerPrompt(test = {}) {
  return `Does the evidence prove that ${test.connectorName || "this connector"} passed the ${String(test.testArea || "validation").toLowerCase()} test without expanding access beyond the approved pilot boundary?`;
}

function connectorValidationEvidenceResultOptions(test = {}) {
  const options = [
    "Pass - evidence captured",
    "Pass with limitation - capture follow-up",
    "Needs more detail - owner input required",
    "Defer to fallback mode"
  ];
  if (test.status === "Blocked" || /write|action/i.test(test.testArea || "")) {
    options.push("Block connector write/action until safeguards are approved");
  } else {
    options.push("Block connector promotion until evidence is captured");
  }
  return options;
}

function connectorValidationDecisionImpact(test = {}) {
  const area = String(test.testArea || "");
  if (/source reachability/i.test(area)) return "Determines whether the connector can access the approved source boundary at all.";
  if (/permission boundary/i.test(area)) return "Determines whether the connector can be tested with least-privilege or inherited permissions.";
  if (/blocked operations/i.test(area)) return "Determines whether prohibited behavior is safely prevented before pilot use.";
  if (/pilot data policy/i.test(area)) return "Determines whether validation can proceed without client, regulated, or unapproved data.";
  if (/audit evidence/i.test(area)) return "Determines whether the pilot can retain enough evidence for governance and enterprise review.";
  if (/human review/i.test(area)) return "Determines who can approve, defer, or block connector promotion.";
  if (/fallback mode/i.test(area)) return "Determines whether the pilot can continue if enterprise connector approval is delayed.";
  if (/write|action/i.test(area)) return "Determines whether non-read behavior stays disabled until explicit approval, logging, and rollback expectations exist.";
  return "Determines whether the connector can move beyond local/coworker review.";
}

function connectorValidationEvidenceReadiness(entries = []) {
  if (!entries.length) return 0;
  const weights = {
    "Ready to capture": 88,
    "Needs owner input": 55,
    "Blocked by safeguard": 22
  };
  return Math.round(entries.reduce((sum, entry) => sum + (weights[entry.evidenceStatus] || 0), 0) / entries.length);
}

function connectorValidationEvidenceNextAction(entries = [], plan = deriveConnectorValidationPlan()) {
  const blocked = entries.find((entry) => entry.evidenceStatus === "Blocked by safeguard");
  if (blocked) return `Keep ${blocked.connectorName || blocked.connectorId} in fallback/read-only mode until ${blocked.testArea.toLowerCase()} evidence is approved.`;
  const needsOwnerInput = entries.find((entry) => entry.evidenceStatus === "Needs owner input");
  if (needsOwnerInput) return `Ask ${needsOwnerInput.evidenceOwner || "the source owner"} to provide ${needsOwnerInput.testArea.toLowerCase()} evidence before connector validation.`;
  return plan.nextAction || "Run the safe sample validation tests and attach or record evidence for each connector.";
}

function connectorValidationEvidenceLogRows(log = deriveConnectorValidationEvidenceLog()) {
  return [
    ["Evidence ID", "Test ID", "Connector ID", "Connector", "Platform", "Test Area", "Validation Status", "Evidence Status", "Evidence Owner", "Proof To Capture", "Expected Evidence", "Capture Method", "Reviewer Prompt", "Result Options", "Decision Impact", "Fallback If Missing", "Package Target", "Source"],
    ...(log.entries || []).map((entry) => [
      entry.id,
      entry.testId,
      entry.connectorId,
      entry.connectorName,
      entry.platform,
      entry.testArea,
      entry.validationStatus,
      entry.evidenceStatus,
      entry.evidenceOwner,
      entry.proofToCapture,
      entry.expectedEvidence,
      entry.captureMethod,
      entry.reviewerPrompt,
      (entry.resultOptions || []).join("\n"),
      entry.decisionImpact,
      entry.fallbackIfMissing,
      entry.packageTarget,
      entry.source
    ])
  ];
}

function connectorValidationEvidenceLogMarkdown(log = deriveConnectorValidationEvidenceLog()) {
  const entries = log.entries || [];
  const connectorIds = [...new Set(entries.map((entry) => entry.connectorId || entry.connectorName).filter(Boolean))];
  return [
    `# Connector Validation Evidence Log - ${log.workflow}`,
    "",
    `Generated: ${new Date().toLocaleString()}`,
    `Readiness: ${Number(log.readiness || 0)}% - ${log.readinessLabel || templateReadinessLabel(log.readiness || 0)}`,
    `Route: ${formatMarkdownValue(log.routeLabel || log.routeType || "TBD")}`,
    "",
    log.decisionRule,
    "",
    "## Evidence Summary",
    "",
    `- Evidence items: ${log.totalCount || entries.length}`,
    `- Ready to capture: ${log.readyCount || 0}`,
    `- Needs owner input: ${log.needsOwnerInputCount || 0}`,
    `- Blocked by safeguard: ${log.blockedCount || 0}`,
    `- Next action: ${formatMarkdownValue(log.nextAction || "Capture validation evidence with the source owner.")}`,
    "",
    ...connectorIds.flatMap((id) => connectorValidationEvidenceMarkdownSection(id, entries.filter((entry) => (entry.connectorId || entry.connectorName) === id)))
  ].join("\n");
}

function connectorValidationEvidenceMarkdownSection(id = "", entries = []) {
  const name = entries[0]?.connectorName || id || "Connector";
  return [
    `## ${formatMarkdownValue(name)}`,
    "",
    ...entries.flatMap((entry) => [
      `### ${formatMarkdownValue(entry.testArea)}`,
      "",
      markdownValueList("Evidence status", entry.evidenceStatus),
      markdownValueList("Validation status", entry.validationStatus),
      markdownValueList("Evidence owner", entry.evidenceOwner),
      markdownValueList("Proof to capture", entry.proofToCapture),
      markdownValueList("Expected evidence", entry.expectedEvidence),
      markdownValueList("Capture method", entry.captureMethod),
      markdownValueList("Reviewer prompt", entry.reviewerPrompt),
      markdownValueList("Result options", entry.resultOptions || []),
      markdownValueList("Decision impact", entry.decisionImpact),
      markdownValueList("Fallback if missing", entry.fallbackIfMissing),
      markdownValueList("Package target", entry.packageTarget),
      ""
    ])
  ];
}

function deriveConnectorBuildRequestPack(contractPack = deriveEnterpriseConnectorContracts(), approvalChecklist = deriveConnectorApprovalChecklist(contractPack), validationPlan = deriveConnectorValidationPlan(contractPack, approvalChecklist), evidenceLog = deriveConnectorValidationEvidenceLog(validationPlan)) {
  const workflow = templateValue(contractPack.workflow || validationPlan.workflow || state.fields.workflowName || state.fields.submittedWorkflowTask || state.sessionMeta?.name, "Workflow TBD");
  const requests = (contractPack.contracts || []).map((contract) => connectorBuildRequest(contract, approvalChecklist, validationPlan, evidenceLog));
  const readiness = connectorBuildRequestReadiness(requests);
  const blockedCount = requests.filter((request) => /block|defer/i.test(request.requestStatus)).length;
  const readyCount = requests.filter((request) => /ready/i.test(request.requestStatus)).length;
  return {
    version: 1,
    generatedAt: new Date().toISOString(),
    workflow,
    routeType: contractPack.routeType || "",
    routeLabel: contractPack.routeLabel || "",
    readiness,
    readinessLabel: templateReadinessLabel(readiness),
    totalCount: requests.length,
    readyCount,
    blockedCount,
    decisionRule: "Submit a connector build request only when the request names the source boundary, minimum build scope, approval owner, validation evidence, blocked operations, and fallback path.",
    nextAction: connectorBuildRequestNextAction(requests, contractPack),
    requests
  };
}

function connectorBuildRequest(contract = {}, approvalChecklist = {}, validationPlan = {}, evidenceLog = {}) {
  const checklistItem = (approvalChecklist.items || []).find((item) => item.id === contract.id) || {};
  const tests = (validationPlan.tests || []).filter((test) => test.connectorId === contract.id);
  const evidenceEntries = (evidenceLog.entries || []).filter((entry) => entry.connectorId === contract.id);
  const writeOrAction = /write|action|update|create|delete/i.test(`${contract.readWriteMode} ${contract.connectorType}`);
  const status = connectorBuildRequestStatus(contract, checklistItem, tests, evidenceEntries, { writeOrAction });
  return {
    id: `${contract.id || "connector"}-build-request`,
    connectorId: contract.id || "",
    connectorName: contract.name || enterpriseConnectorName(contract.id),
    platform: contract.platform || "",
    requestType: connectorBuildRequestType(contract),
    requestStatus: status,
    requestedDecision: connectorBuildRequestedDecision(contract, checklistItem, tests, evidenceEntries, { writeOrAction }),
    approvalOwner: contract.owner || checklistItem.owner || enterpriseConnectorOwner(contract),
    sourceSystem: contract.sourceSystem || "",
    sourceLocations: contract.sourceLocations || "",
    authModel: contract.authModel || "",
    permissionScope: contract.permissionScope || "",
    readWriteMode: contract.readWriteMode || "",
    minimumBuildScope: connectorBuildMinimumScope(contract, { writeOrAction }),
    outOfScope: contract.blockedOperations || enterpriseConnectorBlockedOperations(contract),
    allowedOperations: contract.allowedOperations || "",
    dataBoundary: contract.dataBoundary || connectorBoundarySummary(),
    pilotDataPolicy: contract.pilotDataPolicy || "",
    requiredApprovals: contract.requiredApprovals || checklistItem.requiredApprovals || "",
    approvalGate: contract.approvalGate || checklistItem.approvalGate || "",
    validationSummary: connectorBuildValidationSummary(tests),
    evidenceSummary: connectorBuildEvidenceSummary(evidenceEntries),
    humanCheckpoints: connectorBuildHumanCheckpoints(contract, checklistItem),
    enterpriseControls: connectorBuildEnterpriseControls(contract),
    evidencePackage: connectorBuildEvidencePackage(contract),
    fallbackMode: contract.fallbackMode || checklistItem.fallbackMode || "",
    reviewerQuestions: connectorBuildReviewerQuestions(contract, checklistItem, tests, evidenceEntries, { writeOrAction }),
    nextAction: connectorBuildRequestItemNextAction(contract, status, { writeOrAction })
  };
}

function connectorBuildRequestType(contract = {}) {
  const text = `${contract.platform} ${contract.connectorType} ${contract.id}`;
  if (/microsoft|copilot|sharepoint|teams|outlook|onedrive|office/i.test(text)) return "Microsoft 365 / Copilot source validation request";
  if (/openai|chatgpt|mcp|function|api/i.test(text)) return "OpenAI tool / MCP contract review request";
  if (/manual|evidence|file/i.test(text)) return "Manual evidence source promotion request";
  return "Enterprise connector review request";
}

function connectorBuildRequestStatus(contract = {}, checklistItem = {}, tests = [], evidenceEntries = [], options = {}) {
  if (options.writeOrAction) return "Defer write/action";
  if (/Needs approval detail/i.test(checklistItem.status || "")) return "Needs owner detail";
  if (tests.some((test) => test.status === "Blocked") || evidenceEntries.some((entry) => entry.evidenceStatus === "Blocked by safeguard")) return "Blocked by safeguard";
  if (tests.some((test) => test.status === "Needs approval detail") || evidenceEntries.some((entry) => entry.evidenceStatus === "Needs owner input")) return "Needs validation evidence";
  return "Ready for owner review";
}

function connectorBuildRequestedDecision(contract = {}, checklistItem = {}, tests = [], evidenceEntries = [], options = {}) {
  if (options.writeOrAction) return "Approve read-only validation only; defer write/action build until safeguards, logging, and rollback evidence are approved.";
  if (/microsoft|copilot/i.test(`${contract.platform} ${contract.connectorType}`)) return "Approve read-only Microsoft 365 source validation for named locations and test users.";
  if (/openai|chatgpt|mcp|function/i.test(`${contract.platform} ${contract.connectorType}`)) return "Approve OpenAI tool/MCP schema review using safe samples and no live writeback.";
  if (/Needs approval detail/i.test(checklistItem.status || "") || tests.some((test) => test.status === "Needs approval detail") || evidenceEntries.some((entry) => entry.evidenceStatus === "Needs owner input")) return "Resolve source owner, permission boundary, and validation evidence before connector build.";
  return "Approve local safe-sample source validation and keep fallback mode available.";
}

function connectorBuildMinimumScope(contract = {}, options = {}) {
  if (options.writeOrAction) return "Read-only validation first; no write/action tool until separate workflow-owner approval.";
  if (/microsoft|copilot/i.test(`${contract.platform} ${contract.connectorType}`)) return "Read only the named SharePoint, OneDrive, Teams, Outlook, Word, PowerPoint, or Excel locations with inherited or approved permissions.";
  if (/openai|chatgpt|mcp|function/i.test(`${contract.platform} ${contract.connectorType}`)) return "Review tool schema, approved files/workspace, auth path, logging, and safe-sample execution only.";
  return "Use approved safe-sample files or manual exports with no mandatory evidence upload and no live system access.";
}

function connectorBuildValidationSummary(tests = []) {
  if (!tests.length) return "No validation tests generated yet.";
  const counts = tests.reduce((acc, test) => {
    acc[test.status] = (acc[test.status] || 0) + 1;
    return acc;
  }, {});
  return Object.entries(counts).map(([status, count]) => `${status}: ${count}`).join("; ");
}

function connectorBuildEvidenceSummary(entries = []) {
  if (!entries.length) return "No evidence capture items generated yet.";
  const counts = entries.reduce((acc, entry) => {
    acc[entry.evidenceStatus] = (acc[entry.evidenceStatus] || 0) + 1;
    return acc;
  }, {});
  return Object.entries(counts).map(([status, count]) => `${status}: ${count}`).join("; ");
}

function connectorBuildHumanCheckpoints(contract = {}, checklistItem = {}) {
  return [
    contract.approvalGate || checklistItem.approvalGate || "Source owner approves the connector boundary.",
    "Reviewer confirms safe sample data and source assumptions before reliance.",
    /write|action|update|create|delete/i.test(`${contract.readWriteMode} ${contract.connectorType}`)
      ? "Workflow owner confirms every write/action with logging and rollback expectations."
      : "Human reviews generated output before sharing or enterprise use."
  ].filter(isCapturedValue);
}

function connectorBuildEnterpriseControls(contract = {}) {
  return [
    contract.permissionScope || "Least-privilege source boundary.",
    contract.pilotDataPolicy || "Synthetic, sanitized, metadata-only, or explicitly approved sample data.",
    "Audit evidence records source, reviewer, test result, and decision.",
    contract.blockedOperations || enterpriseConnectorBlockedOperations(contract)
  ].filter(isCapturedValue);
}

function connectorBuildEvidencePackage(contract = {}) {
  return [
    "enterprise-connector-contracts.json",
    "connector-approval-checklist.json",
    "connector-validation-plan.json",
    "connector-validation-evidence-log.json",
    `connector-validation/${contract.id || "connector"}-*`
  ].join("; ");
}

function connectorBuildReviewerQuestions(contract = {}, checklistItem = {}, tests = [], evidenceEntries = [], options = {}) {
  return dedupeQuestions([
    `Who is the accountable approver for ${contract.name || contract.id}?`,
    isCapturedValue(contract.sourceLocations) ? "" : "Which exact source locations or APIs are in scope?",
    isCapturedValue(contract.permissionScope) ? "" : "What least-privilege scope should be requested?",
    tests.some((test) => test.status === "Needs approval detail") || evidenceEntries.some((entry) => entry.evidenceStatus === "Needs owner input")
      ? "What evidence is still needed before this request can be submitted?"
      : "",
    options.writeOrAction ? "What confirmation language, audit log, and rollback path are required before any write/action is enabled?" : "",
    checklistItem.nextAction || contract.nextAction || ""
  ]);
}

function connectorBuildRequestItemNextAction(contract = {}, status = "", options = {}) {
  if (/Defer write\/action/i.test(status) || options.writeOrAction) return `Submit only a read-only validation request for ${contract.name || contract.id}; defer write/action scope.`;
  if (/Needs owner detail/i.test(status)) return `Resolve source owner, source locations, and permission scope before submitting ${contract.name || contract.id}.`;
  if (/Needs validation evidence/i.test(status)) return `Capture validation evidence for ${contract.name || contract.id} before requesting enterprise build.`;
  if (/microsoft|copilot/i.test(`${contract.platform} ${contract.connectorType}`)) return "Route this request to the Microsoft tenant/source owner for read-only named-location validation.";
  if (/openai|chatgpt|mcp|function/i.test(`${contract.platform} ${contract.connectorType}`)) return "Route this request to AI Engineering/OpenAI platform owner for tool schema and safe-sample review.";
  return "Review this request with the session owner before promoting beyond local package review.";
}

function connectorBuildRequestReadiness(requests = []) {
  if (!requests.length) return 0;
  const weights = {
    "Ready for owner review": 88,
    "Needs validation evidence": 62,
    "Needs owner detail": 48,
    "Defer write/action": 42,
    "Blocked by safeguard": 25
  };
  return Math.round(requests.reduce((sum, request) => sum + (weights[request.requestStatus] || 45), 0) / requests.length);
}

function connectorBuildRequestNextAction(requests = [], contractPack = deriveEnterpriseConnectorContracts()) {
  const needsDetail = requests.find((request) => /Needs owner detail/i.test(request.requestStatus));
  if (needsDetail) return needsDetail.nextAction;
  const needsEvidence = requests.find((request) => /Needs validation evidence/i.test(request.requestStatus));
  if (needsEvidence) return needsEvidence.nextAction;
  const writeAction = requests.find((request) => /Defer write\/action/i.test(request.requestStatus));
  if (writeAction) return writeAction.nextAction;
  return contractPack.nextAction || "Review connector build requests with enterprise platform and source owners.";
}

function connectorBuildRequestRows(pack = deriveConnectorBuildRequestPack()) {
  return [
    ["Request ID", "Connector ID", "Connector", "Platform", "Request Type", "Request Status", "Requested Decision", "Approval Owner", "Source System", "Source Locations", "Auth Model", "Permission Scope", "Read/Write Mode", "Minimum Build Scope", "Out Of Scope", "Allowed Operations", "Data Boundary", "Pilot Data Policy", "Required Approvals", "Approval Gate", "Validation Summary", "Evidence Summary", "Human Checkpoints", "Enterprise Controls", "Evidence Package", "Fallback Mode", "Reviewer Questions", "Next Action"],
    ...(pack.requests || []).map((request) => [
      request.id,
      request.connectorId,
      request.connectorName,
      request.platform,
      request.requestType,
      request.requestStatus,
      request.requestedDecision,
      request.approvalOwner,
      request.sourceSystem,
      request.sourceLocations,
      request.authModel,
      request.permissionScope,
      request.readWriteMode,
      request.minimumBuildScope,
      request.outOfScope,
      request.allowedOperations,
      request.dataBoundary,
      request.pilotDataPolicy,
      request.requiredApprovals,
      request.approvalGate,
      request.validationSummary,
      request.evidenceSummary,
      (request.humanCheckpoints || []).join("\n"),
      (request.enterpriseControls || []).join("\n"),
      request.evidencePackage,
      request.fallbackMode,
      (request.reviewerQuestions || []).join("\n"),
      request.nextAction
    ])
  ];
}

function connectorBuildRequestMarkdown(pack = deriveConnectorBuildRequestPack()) {
  const requests = pack.requests || [];
  return [
    `# Connector Build Request Pack - ${pack.workflow}`,
    "",
    `Generated: ${new Date().toLocaleString()}`,
    `Readiness: ${Number(pack.readiness || 0)}% - ${pack.readinessLabel || templateReadinessLabel(pack.readiness || 0)}`,
    `Route: ${formatMarkdownValue(pack.routeLabel || pack.routeType || "TBD")}`,
    "",
    pack.decisionRule,
    "",
    "## Request Summary",
    "",
    `- Requests: ${pack.totalCount || requests.length}`,
    `- Ready for owner review: ${pack.readyCount || 0}`,
    `- Blocked/deferred: ${pack.blockedCount || 0}`,
    `- Next action: ${formatMarkdownValue(pack.nextAction || "Review connector requests with platform owners.")}`,
    "",
    ...requests.flatMap((request) => connectorBuildRequestMarkdownSection(request))
  ].join("\n");
}

function connectorBuildRequestMarkdownSection(request = {}) {
  return [
    `## ${formatMarkdownValue(request.connectorName || request.connectorId || "Connector Request")}`,
    "",
    markdownValueList("Request status", request.requestStatus),
    markdownValueList("Request type", request.requestType),
    markdownValueList("Requested decision", request.requestedDecision),
    markdownValueList("Approval owner", request.approvalOwner),
    markdownValueList("Source system", request.sourceSystem),
    markdownValueList("Source locations", request.sourceLocations),
    markdownValueList("Auth model", request.authModel),
    markdownValueList("Permission scope", request.permissionScope),
    markdownValueList("Read/write mode", request.readWriteMode),
    markdownValueList("Minimum build scope", request.minimumBuildScope),
    markdownValueList("Out of scope", request.outOfScope),
    markdownValueList("Allowed operations", request.allowedOperations),
    markdownValueList("Pilot data policy", request.pilotDataPolicy),
    markdownValueList("Required approvals", request.requiredApprovals),
    markdownValueList("Approval gate", request.approvalGate),
    markdownValueList("Validation summary", request.validationSummary),
    markdownValueList("Evidence summary", request.evidenceSummary),
    markdownValueList("Evidence package", request.evidencePackage),
    markdownValueList("Fallback mode", request.fallbackMode),
    "",
    "### Human Checkpoints",
    "",
    markdownOrderedList(request.humanCheckpoints || [], "No human checkpoints generated."),
    "",
    "### Enterprise Controls",
    "",
    markdownOrderedList(request.enterpriseControls || [], "No enterprise controls generated."),
    "",
    "### Reviewer Questions",
    "",
    markdownQuestionList(request.reviewerQuestions || [], "No connector build request questions generated."),
    "",
    `Next action: ${formatMarkdownValue(request.nextAction || "Review this request with the connector owner.")}`,
    ""
  ];
}

function deriveConnectorPilotRunbook(buildRequestPack = deriveConnectorBuildRequestPack(), validationPlan = deriveConnectorValidationPlan(), evidenceLog = deriveConnectorValidationEvidenceLog(validationPlan)) {
  const requests = buildRequestPack.requests || [];
  const steps = requests.flatMap((request) => connectorPilotStepsForRequest(request, validationPlan, evidenceLog));
  const readiness = connectorPilotRunbookReadiness(steps);
  const blockedCount = steps.filter((step) => /blocked|stop/i.test(step.status)).length;
  const readyCount = steps.filter((step) => step.status === "Ready").length;
  return {
    version: 1,
    generatedAt: new Date().toISOString(),
    workflow: buildRequestPack.workflow || "Workflow TBD",
    routeType: buildRequestPack.routeType || "",
    routeLabel: buildRequestPack.routeLabel || "",
    readiness,
    readinessLabel: templateReadinessLabel(readiness),
    totalCount: steps.length,
    readyCount,
    blockedCount,
    decisionRule: "Run connector pilots only with safe sample data, named source scope, human review, recorded evidence, fallback path, and stop triggers.",
    nextAction: connectorPilotRunbookNextAction(steps, buildRequestPack),
    steps
  };
}

function connectorPilotStepsForRequest(request = {}, validationPlan = {}, evidenceLog = {}) {
  const tests = (validationPlan.tests || []).filter((test) => test.connectorId === request.connectorId);
  const evidenceEntries = (evidenceLog.entries || []).filter((entry) => entry.connectorId === request.connectorId);
  const validationAreas = tests.map((test) => test.testArea).filter(Boolean).join("; ") || request.validationSummary || "Connector validation tests";
  const evidenceTargets = evidenceEntries.map((entry) => entry.packageTarget).filter(Boolean).join("; ") || "connector-validation-evidence-log.json";
  const base = {
    connectorId: request.connectorId,
    connectorName: request.connectorName,
    platform: request.platform,
    requestStatus: request.requestStatus,
    owner: request.approvalOwner || "Pilot owner",
    fallbackAction: request.fallbackMode || "Use local package review or conversation-only intake.",
    source: "Connector Build Request Pack; Connector Validation Plan; Connector Validation Evidence Log"
  };
  return [
    connectorPilotStep(base, request, {
      key: "preflight",
      sequence: 1,
      phase: "Pilot preflight",
      action: "Confirm request status, owner, and source boundary.",
      entryCriteria: "Connector build request exists and the requested decision, owner, source system, and out-of-scope behavior are named.",
      evidenceToCapture: "Request status, approval owner, source locations, read/write mode, data boundary, and blocked operations.",
      passCriteria: "Pilot owner confirms the connector can be tested only inside the named safe-sample boundary.",
      stopTrigger: "Request status, source owner, permission scope, or data boundary is unclear.",
      packageEvidence: "connector-build-request-pack.json; enterprise-connector-contracts.json; connector-approval-checklist.json"
    }),
    connectorPilotStep(base, request, {
      key: "safe-sample-setup",
      sequence: 2,
      phase: "Safe sample setup",
      action: "Prepare safe sample data and a named test location.",
      entryCriteria: "Pilot preflight passed and no real client, regulated, or unapproved data is needed.",
      evidenceToCapture: "Synthetic, sanitized, metadata-only, or explicitly approved sample name, owner, storage location, and source boundary.",
      passCriteria: "The sample can test the workflow without exposing raw client data or broad enterprise search.",
      stopTrigger: "Sample includes sensitive, client, or unapproved data, or the sample location is not explicitly named.",
      packageEvidence: "connector-approval-checklist.json; connector-validation-plan.json"
    }),
    connectorPilotStep(base, request, {
      key: "access-setup",
      sequence: 3,
      phase: "Access setup",
      action: "Configure least-privilege test access.",
      entryCriteria: "Safe sample is ready and the source boundary is approved for a controlled pilot.",
      evidenceToCapture: "Test user or inherited-permission model, auth model, permission scope, approved source locations, and setup timestamp.",
      passCriteria: "Access is read-only or explicitly approved, least-privilege, and limited to the named source boundary.",
      stopTrigger: "Connector can reach sources beyond the approved boundary or write/action behavior is enabled without approval.",
      packageEvidence: "enterprise-connector-contracts.json; connector-approval-checklist.json"
    }),
    connectorPilotStep(base, request, {
      key: "validation-run",
      sequence: 4,
      phase: "Validation run",
      action: "Run the connector validation tests.",
      entryCriteria: "Approved safe sample or test user is ready.",
      evidenceToCapture: `Validation result for: ${validationAreas}.`,
      passCriteria: "Source reachability, permission boundary, blocked-operation, safe-data, audit, human review, fallback, and write/action safeguards pass or are explicitly deferred.",
      stopTrigger: "Output uses unapproved content, sensitive data, unsupported assumptions, or an unapproved operation path.",
      packageEvidence: "connector-validation-plan.json; connector-validation-plan-rows.json"
    }),
    connectorPilotStep(base, request, {
      key: "evidence-capture",
      sequence: 5,
      phase: "Evidence capture",
      action: "Record validation proof in the package.",
      entryCriteria: "Validation run has a pass, limited pass, defer, or block result for each required test.",
      evidenceToCapture: `Proof items and reviewer notes linked to ${evidenceTargets}.`,
      passCriteria: "Every required proof item has an owner, result option, decision impact, package evidence location, and fallback if missing.",
      stopTrigger: "Evidence is missing for source reachability, permission boundary, blocked operations, or human review.",
      packageEvidence: "connector-validation-evidence-log.json; connector-validation-evidence-log-rows.json"
    }),
    connectorPilotStep(base, request, {
      key: "human-signoff",
      sequence: 6,
      phase: "Human signoff",
      action: "Capture approve, defer, or block signoff.",
      entryCriteria: "Validation output and control evidence are available.",
      evidenceToCapture: "Reviewer decision, approval owner note, issues, accepted limitations, and next action.",
      passCriteria: "A named owner approves, defers, or blocks promotion with rationale.",
      stopTrigger: "No accountable owner will sign off on the pilot result.",
      packageEvidence: "connector-validation-evidence-log.json; connector-build-request-pack.json"
    }),
    connectorPilotStep(base, request, {
      key: "fallback-drill",
      sequence: 7,
      phase: "Fallback drill",
      action: "Rehearse the manual or package fallback.",
      entryCriteria: "A connector result or blocker has been observed.",
      evidenceToCapture: "Manual export/upload result, local package path, or conversation-only replacement path.",
      passCriteria: "The team can continue review without live connector access.",
      stopTrigger: "No working fallback exists for the pilot workflow.",
      packageEvidence: "connector-pilot-runbook.md; local package ZIP or manual export evidence"
    }),
    connectorPilotStep(base, request, {
      key: "promotion-decision",
      sequence: 8,
      phase: "Promotion decision",
      action: "Record local-only, enterprise-validation, promote, defer, or block decision.",
      entryCriteria: "Owner signoff and fallback evidence are complete.",
      evidenceToCapture: "Approve/defer/block decision, evidence package path, remaining risks, and enterprise owner handoff.",
      passCriteria: "Decision is recorded before any broader rollout or real-data use.",
      stopTrigger: "Evidence package is incomplete or decision owner is unresolved.",
      packageEvidence: "connector-pilot-runbook.json; connector-pilot-runbook.md; output-manifest.json"
    })
  ];
}

function connectorPilotStep(base = {}, request = {}, details = {}) {
  const writeOrAction = /write|action|update|delete|create/i.test(`${request.readWriteMode} ${request.requestStatus} ${request.requestedDecision}`);
  const status = connectorPilotStepStatus(request, details, { writeOrAction });
  const packageEvidence = details.packageEvidence || connectorPilotPackageEvidence(base, details);
  return {
    id: `${base.connectorId || "connector"}-pilot-${details.key}`,
    connectorId: base.connectorId || "",
    connectorName: base.connectorName || "Connector",
    platform: base.platform || "",
    sequence: details.sequence,
    phase: details.phase,
    action: details.action,
    owner: connectorPilotStepOwner(request, details),
    status,
    stepStatus: status,
    entryCriteria: details.entryCriteria,
    evidenceToCapture: details.evidenceToCapture,
    passCriteria: details.passCriteria,
    stopTrigger: details.stopTrigger,
    fallbackAction: connectorPilotFallbackAction(base, request, details),
    decisionGate: connectorPilotDecisionGate(request, details),
    packageEvidence,
    packageTarget: packageEvidence,
    source: base.source || "Connector Build Request Pack; Connector Validation Plan"
  };
}

function connectorPilotStepStatus(request = {}, details = {}, options = {}) {
  if (/Blocked by safeguard/i.test(request.requestStatus || "")) return "Blocked by safeguard";
  if (/Needs owner detail/i.test(request.requestStatus || "")) return "Needs owner detail";
  if (options.writeOrAction && /access-setup|validation-run|promotion-decision/i.test(details.key || "")) return "Stop - write/action approval required";
  if (/Needs validation evidence/i.test(request.requestStatus || "") && /validation-run|evidence-capture|human-signoff|promotion-decision/i.test(details.key || "")) return "Needs validation evidence";
  return "Ready";
}

function connectorPilotStepOwner(request = {}, details = {}) {
  if (/access-setup/i.test(details.key || "")) return request.approvalOwner || "Platform owner";
  if (/safe-sample/i.test(details.key || "")) return request.approvalOwner || "Source owner";
  if (/human-signoff|promotion-decision/i.test(details.key || "")) return request.approvalOwner || "Pilot owner";
  if (/fallback/i.test(details.key || "")) return "AI Infusion / Pilot owner";
  return request.approvalOwner || "Pilot owner";
}

function connectorPilotFallbackAction(base = {}, request = {}, details = {}) {
  if (/fallback/i.test(details.key || "")) return request.fallbackMode || base.fallbackAction || "Use local package review.";
  if (/access|validation|evidence/i.test(details.key || "")) return request.fallbackMode || "Use approved manual export/upload while access or validation is unresolved.";
  if (/safe-sample/i.test(details.key || "")) return request.fallbackMode || "Use synthetic sample files or conversation-only intake until sample approval is clear.";
  return request.fallbackMode || base.fallbackAction || "Use the no-connector fallback path.";
}

function connectorPilotDecisionGate(request = {}, details = {}) {
  if (/pilot|safe-sample|access/i.test(details.key || "")) return "Proceed only when the named owner confirms the sample and access boundary.";
  if (/validation-run|evidence-capture/i.test(details.key || "")) return "Continue only if validation evidence is captured or the fallback path is activated.";
  if (/promotion-decision/i.test(details.key || "")) return "Approve for next controlled pilot, defer pending evidence, or block connector promotion.";
  if (/human-signoff/i.test(details.key || "")) return "Named owner accepts, defers, or blocks the pilot result.";
  return request.requestedDecision || "Proceed only after owner review.";
}

function connectorPilotPackageEvidence(base = {}, details = {}) {
  return `connector-pilot/${base.connectorId || "connector"}-${details.key || "step"}`;
}

function connectorPilotRunbookReadiness(steps = []) {
  if (!steps.length) return 0;
  const weights = {
    "Ready": 88,
    "Needs validation evidence": 62,
    "Needs owner detail": 48,
    "Stop - write/action approval required": 35,
    "Blocked by safeguard": 25
  };
  return Math.round(steps.reduce((sum, step) => sum + (weights[step.status] || 45), 0) / steps.length);
}

function connectorPilotRunbookNextAction(steps = [], buildRequestPack = deriveConnectorBuildRequestPack()) {
  const needsOwner = steps.find((step) => step.status === "Needs owner detail");
  if (needsOwner) return `Resolve pilot owner and source boundary for ${needsOwner.connectorName || needsOwner.connectorId}.`;
  const needsEvidence = steps.find((step) => step.status === "Needs validation evidence");
  if (needsEvidence) return `Capture validation evidence before running ${needsEvidence.connectorName || needsEvidence.connectorId} pilot steps.`;
  const stopped = steps.find((step) => /Stop|Blocked/i.test(step.status || ""));
  if (stopped) return `Keep ${stopped.connectorName || stopped.connectorId} in fallback/read-only mode until stop-trigger evidence is resolved.`;
  return buildRequestPack.nextAction || "Run the connector pilot with safe samples and record evidence before promotion.";
}

function connectorPilotRunbookRows(runbook = deriveConnectorPilotRunbook()) {
  return [
    ["Step ID", "Connector ID", "Connector", "Platform", "Sequence", "Phase", "Action", "Owner", "Status", "Entry Criteria", "Evidence To Capture", "Pass Criteria", "Stop Trigger", "Fallback Action", "Decision Gate", "Package Evidence", "Source"],
    ...(runbook.steps || []).map((step) => [
      step.id,
      step.connectorId,
      step.connectorName,
      step.platform,
      step.sequence,
      step.phase,
      step.action,
      step.owner,
      step.status,
      step.entryCriteria,
      step.evidenceToCapture,
      step.passCriteria,
      step.stopTrigger,
      step.fallbackAction,
      step.decisionGate,
      step.packageEvidence,
      step.source
    ])
  ];
}

function connectorPilotRunbookMarkdown(runbook = deriveConnectorPilotRunbook()) {
  const steps = runbook.steps || [];
  const connectorIds = [...new Set(steps.map((step) => step.connectorId || step.connectorName).filter(Boolean))];
  return [
    `# Connector Pilot Runbook - ${runbook.workflow}`,
    "",
    `Generated: ${new Date().toLocaleString()}`,
    `Readiness: ${Number(runbook.readiness || 0)}% - ${runbook.readinessLabel || templateReadinessLabel(runbook.readiness || 0)}`,
    `Route: ${formatMarkdownValue(runbook.routeLabel || runbook.routeType || "TBD")}`,
    "",
    runbook.decisionRule,
    "",
    "## Pilot Summary",
    "",
    `- Pilot steps: ${runbook.totalCount || steps.length}`,
    `- Ready to run: ${runbook.readyCount || 0}`,
    `- Blocked/deferred: ${runbook.blockedCount || 0}`,
    `- Next action: ${formatMarkdownValue(runbook.nextAction || "Run the connector pilot with safe samples.")}`,
    "",
    ...connectorIds.flatMap((id) => connectorPilotRunbookMarkdownSection(id, steps.filter((step) => (step.connectorId || step.connectorName) === id)))
  ].join("\n");
}

function connectorPilotRunbookMarkdownSection(id = "", steps = []) {
  const name = steps[0]?.connectorName || id || "Connector";
  return [
    `## ${formatMarkdownValue(name)}`,
    "",
    ...steps.flatMap((step) => [
      `### ${step.sequence}. ${formatMarkdownValue(step.phase)}`,
      "",
      markdownValueList("Action", step.action),
      markdownValueList("Phase", step.phase),
      markdownValueList("Status", step.status),
      markdownValueList("Owner", step.owner),
      markdownValueList("Entry criteria", step.entryCriteria),
      markdownValueList("Evidence to capture", step.evidenceToCapture),
      markdownValueList("Pass criteria", step.passCriteria),
      markdownValueList("Stop trigger", step.stopTrigger),
      markdownValueList("Fallback action", step.fallbackAction),
      markdownValueList("Decision gate", step.decisionGate),
      markdownValueList("Package evidence", step.packageEvidence),
      ""
    ])
  ];
}

function deriveConnectorPromotionDecisionPacket(runbook = deriveConnectorPilotRunbook(), buildRequestPack = deriveConnectorBuildRequestPack(), evidenceLog = deriveConnectorValidationEvidenceLog()) {
  const requests = buildRequestPack.requests || [];
  const decisions = requests.map((request) => {
    const steps = (runbook.steps || []).filter((step) => step.connectorId === request.connectorId);
    const evidenceEntries = (evidenceLog.entries || []).filter((entry) => entry.connectorId === request.connectorId);
    return connectorPromotionDecision(request, steps, evidenceEntries);
  });
  const readiness = connectorPromotionDecisionReadiness(decisions);
  const readyCount = decisions.filter((decision) => /ready/i.test(decision.decisionStatus)).length;
  const deferCount = decisions.filter((decision) => /defer/i.test(decision.decisionStatus)).length;
  const blockCount = decisions.filter((decision) => /block/i.test(decision.decisionStatus)).length;
  return {
    version: 1,
    generatedAt: new Date().toISOString(),
    workflow: runbook.workflow || buildRequestPack.workflow || "Workflow TBD",
    routeType: runbook.routeType || buildRequestPack.routeType || "",
    routeLabel: runbook.routeLabel || buildRequestPack.routeLabel || "",
    readiness,
    readinessLabel: templateReadinessLabel(readiness),
    totalCount: decisions.length,
    readyCount,
    deferCount,
    blockCount,
    decisionRule: "Treat promotion as a reviewer decision, not automatic approval: promote only when pilot evidence, owner signoff, fallback posture, stop criteria, and enterprise handoff are recorded.",
    nextAction: connectorPromotionDecisionNextAction(decisions, runbook),
    decisions
  };
}

function connectorPromotionDecision(request = {}, steps = [], evidenceEntries = []) {
  const recommendedDecision = connectorPromotionRecommendedDecision(request, steps);
  const decisionStatus = connectorPromotionDecisionStatus(recommendedDecision);
  return {
    id: `${request.connectorId || "connector"}-promotion-decision`,
    connectorId: request.connectorId || "",
    connectorName: request.connectorName || "Connector",
    platform: request.platform || "",
    recommendedDecision,
    decisionStatus,
    owner: request.approvalOwner || "Pilot owner / source owner",
    requestedDecision: request.requestedDecision || "",
    pilotReadiness: connectorPromotionPilotReadiness(steps),
    evidenceStatus: connectorPromotionEvidenceStatus(evidenceEntries, steps),
    promotionScope: connectorPromotionScope(request, recommendedDecision),
    conditions: connectorPromotionConditions(request, steps, evidenceEntries, recommendedDecision),
    openGaps: connectorPromotionOpenGaps(request, steps, evidenceEntries, recommendedDecision),
    fallbackPosture: connectorPromotionFallbackPosture(request, steps),
    enterpriseHandoff: connectorPromotionEnterpriseHandoff(request, recommendedDecision),
    stopCriteria: connectorPromotionStopCriteria(request, steps),
    nextAction: connectorPromotionDecisionItemNextAction(request, recommendedDecision, steps),
    packageEvidence: connectorPromotionPackageEvidence(request),
    source: "Connector Pilot Runbook; Connector Build Request Pack; Connector Validation Evidence Log"
  };
}

function connectorPromotionRecommendedDecision(request = {}, steps = []) {
  const statusText = steps.map((step) => step.status).join(" ");
  const requestText = `${request.requestStatus} ${request.readWriteMode} ${request.requestedDecision}`;
  if (/Blocked|Stop/i.test(statusText) || /Blocked by safeguard/i.test(requestText)) return "Block promotion until stop trigger is resolved";
  if (/Needs owner detail/i.test(statusText) || /Needs owner detail/i.test(requestText)) return "Defer pending owner signoff";
  if (/Needs validation evidence/i.test(statusText) || /Needs validation evidence/i.test(requestText)) return "Defer pending validation evidence";
  if (/write|action|update|delete|create/i.test(requestText)) return "Promote read-only pilot only; defer write/action";
  if (steps.length && steps.every((step) => step.status === "Ready")) return "Promote to next controlled safe-sample pilot";
  return "Keep in local-only pilot review";
}

function connectorPromotionDecisionStatus(recommendedDecision = "") {
  if (/block/i.test(recommendedDecision)) return "Block promotion";
  if (/defer/i.test(recommendedDecision)) return "Defer";
  if (/promote/i.test(recommendedDecision)) return "Ready for owner decision";
  return "Local review only";
}

function connectorPromotionPilotReadiness(steps = []) {
  if (!steps.length) return "No pilot steps generated";
  const ready = steps.filter((step) => step.status === "Ready").length;
  const stopped = steps.filter((step) => /Blocked|Stop/i.test(step.status || "")).length;
  const deferred = steps.filter((step) => /Needs|Defer/i.test(step.status || "")).length;
  return `${ready}/${steps.length} ready; ${deferred} deferred; ${stopped} stop/block`;
}

function connectorPromotionEvidenceStatus(evidenceEntries = [], steps = []) {
  const readyEvidence = evidenceEntries.filter((entry) => /ready|pass/i.test(entry.evidenceStatus || "")).length;
  const requiredEvidenceSteps = steps.filter((step) => /evidence|validation|human|promotion/i.test(`${step.phase} ${step.action}`)).length;
  if (!evidenceEntries.length) return `No validation evidence entries captured; ${requiredEvidenceSteps} pilot evidence steps require review.`;
  return `${readyEvidence}/${evidenceEntries.length} validation evidence entries ready to capture; ${requiredEvidenceSteps} pilot evidence steps require reviewer decision.`;
}

function connectorPromotionScope(request = {}, recommendedDecision = "") {
  if (/block/i.test(recommendedDecision)) return "No promotion beyond fallback/local package review.";
  if (/read-only/i.test(recommendedDecision)) return "Read-only controlled pilot only; write/action behavior remains out of scope.";
  if (/defer/i.test(recommendedDecision)) return "Keep connector in local-only or safe-sample review until missing evidence or owner decision is resolved.";
  return request.minimumBuildScope || "Next controlled safe-sample pilot with named source boundary and no broader rollout.";
}

function connectorPromotionConditions(request = {}, steps = [], evidenceEntries = [], recommendedDecision = "") {
  const conditions = [
    "Named owner records approve, defer, or block decision.",
    "Safe-sample or sanitized data boundary remains documented.",
    "Fallback path remains available until enterprise handoff is accepted."
  ];
  if (!evidenceEntries.length) conditions.push("Attach validation evidence log before any promotion beyond review.");
  if (/read-only/i.test(recommendedDecision) || /write|action/i.test(`${request.readWriteMode} ${request.requestedDecision}`)) conditions.push("Keep write/action behavior disabled until separate approval, logging, and rollback expectations are recorded.");
  if (steps.some((step) => /Stop|Blocked/i.test(step.status || ""))) conditions.push("Resolve every stop trigger before connector promotion.");
  return conditions;
}

function connectorPromotionOpenGaps(request = {}, steps = [], evidenceEntries = [], recommendedDecision = "") {
  const gaps = [];
  if (/owner/i.test(recommendedDecision)) gaps.push("Owner signoff is missing or unresolved.");
  if (/validation evidence/i.test(recommendedDecision) || !evidenceEntries.length) gaps.push("Validation evidence package needs reviewer proof.");
  if (steps.some((step) => /Stop|Blocked/i.test(step.status || ""))) gaps.push("Stop trigger or blocked safeguard must be resolved.");
  if (request.reviewerQuestions?.length) gaps.push(...request.reviewerQuestions.slice(0, 2));
  return gaps.length ? gaps : ["No critical promotion gaps generated; confirm with the named owner before broader use."];
}

function connectorPromotionFallbackPosture(request = {}, steps = []) {
  const fallbackStep = steps.find((step) => /Fallback drill/i.test(step.phase || ""));
  const fallback = fallbackStep?.fallbackAction || request.fallbackMode || "Use local package review or conversation-only intake.";
  return `${fallback} Keep this fallback active until the promotion decision is accepted.`;
}

function connectorPromotionEnterpriseHandoff(request = {}, recommendedDecision = "") {
  if (/block/i.test(recommendedDecision)) return "Send blocker, stop trigger, and fallback evidence to the source/platform owner before re-opening promotion.";
  if (/defer/i.test(recommendedDecision)) return "Send open gaps, required evidence, and owner decision request to the source/platform owner.";
  if (/read-only/i.test(recommendedDecision)) return "Hand off read-only pilot boundary, evidence package, and explicit write/action exclusion to enterprise reviewers.";
  return "Hand off connector build request, pilot runbook, validation evidence, fallback drill, and owner decision to enterprise reviewers.";
}

function connectorPromotionStopCriteria(request = {}, steps = []) {
  const stopTriggers = steps.map((step) => step.stopTrigger).filter(Boolean);
  const uniqueTriggers = [...new Set(stopTriggers)];
  const requestStop = request.outOfScope || "No broader rollout, real-data use, broad search, writeback, deletion, external sharing, or silent notification without explicit approval.";
  return [...uniqueTriggers.slice(0, 4), requestStop].join(" ");
}

function connectorPromotionDecisionItemNextAction(request = {}, recommendedDecision = "", steps = []) {
  if (/block/i.test(recommendedDecision)) return `Keep ${request.connectorName || request.connectorId || "the connector"} in fallback mode and resolve stop triggers before another pilot.`;
  if (/defer/i.test(recommendedDecision)) return `Assign ${request.approvalOwner || "the pilot owner"} to close evidence and signoff gaps before promotion review.`;
  if (/read-only/i.test(recommendedDecision)) return `Record read-only pilot approval scope and keep write/action behavior out of scope.`;
  const decisionStep = steps.find((step) => /Promotion decision/i.test(step.phase || ""));
  return decisionStep?.decisionGate || "Review the promotion recommendation with the named owner before broader use.";
}

function connectorPromotionPackageEvidence(request = {}) {
  return [
    "connector-build-request-pack.json",
    "connector-validation-evidence-log.json",
    "connector-pilot-runbook.json",
    "connector-pilot-runbook.md",
    `connector-promotion/${request.connectorId || "connector"}-decision`
  ].join("; ");
}

function connectorPromotionDecisionReadiness(decisions = []) {
  if (!decisions.length) return 0;
  const weights = {
    "Ready for owner decision": 88,
    "Local review only": 68,
    "Defer": 52,
    "Block promotion": 25
  };
  return Math.round(decisions.reduce((sum, decision) => sum + (weights[decision.decisionStatus] || 45), 0) / decisions.length);
}

function connectorPromotionDecisionNextAction(decisions = [], runbook = deriveConnectorPilotRunbook()) {
  const blocked = decisions.find((decision) => decision.decisionStatus === "Block promotion");
  if (blocked) return blocked.nextAction;
  const deferred = decisions.find((decision) => decision.decisionStatus === "Defer");
  if (deferred) return deferred.nextAction;
  const ready = decisions.find((decision) => decision.decisionStatus === "Ready for owner decision");
  if (ready) return `Review ${ready.connectorName || ready.connectorId} promotion recommendation with the named owner.`;
  return runbook.nextAction || "Review promotion decisions with pilot and source owners.";
}

function connectorPromotionDecisionRows(packet = deriveConnectorPromotionDecisionPacket()) {
  return [
    ["Decision ID", "Connector ID", "Connector", "Platform", "Recommended Decision", "Decision Status", "Owner", "Requested Decision", "Pilot Readiness", "Evidence Status", "Promotion Scope", "Conditions", "Open Gaps", "Fallback Posture", "Enterprise Handoff", "Stop Criteria", "Next Action", "Package Evidence", "Source"],
    ...(packet.decisions || []).map((decision) => [
      decision.id,
      decision.connectorId,
      decision.connectorName,
      decision.platform,
      decision.recommendedDecision,
      decision.decisionStatus,
      decision.owner,
      decision.requestedDecision,
      decision.pilotReadiness,
      decision.evidenceStatus,
      decision.promotionScope,
      (decision.conditions || []).join("\n"),
      (decision.openGaps || []).join("\n"),
      decision.fallbackPosture,
      decision.enterpriseHandoff,
      decision.stopCriteria,
      decision.nextAction,
      decision.packageEvidence,
      decision.source
    ])
  ];
}

function connectorPromotionDecisionMarkdown(packet = deriveConnectorPromotionDecisionPacket()) {
  const decisions = packet.decisions || [];
  return [
    `# Connector Promotion Decision Packet - ${packet.workflow}`,
    "",
    `Generated: ${new Date().toLocaleString()}`,
    `Readiness: ${Number(packet.readiness || 0)}% - ${packet.readinessLabel || templateReadinessLabel(packet.readiness || 0)}`,
    `Route: ${formatMarkdownValue(packet.routeLabel || packet.routeType || "TBD")}`,
    "",
    packet.decisionRule,
    "",
    "## Decision Summary",
    "",
    `- Decisions: ${packet.totalCount || decisions.length}`,
    `- Ready for owner decision: ${packet.readyCount || 0}`,
    `- Deferred: ${packet.deferCount || 0}`,
    `- Blocked: ${packet.blockCount || 0}`,
    `- Next action: ${formatMarkdownValue(packet.nextAction || "Review promotion decisions with pilot owners.")}`,
    "",
    ...decisions.flatMap((decision) => connectorPromotionDecisionMarkdownSection(decision))
  ].join("\n");
}

function connectorPromotionDecisionMarkdownSection(decision = {}) {
  return [
    `## ${formatMarkdownValue(decision.connectorName || decision.connectorId || "Connector Decision")}`,
    "",
    markdownValueList("Recommended decision", decision.recommendedDecision),
    markdownValueList("Decision status", decision.decisionStatus),
    markdownValueList("Owner", decision.owner),
    markdownValueList("Requested decision", decision.requestedDecision),
    markdownValueList("Pilot readiness", decision.pilotReadiness),
    markdownValueList("Evidence status", decision.evidenceStatus),
    markdownValueList("Promotion scope", decision.promotionScope),
    "",
    "### Conditions",
    "",
    markdownOrderedList(decision.conditions || [], "No promotion conditions generated."),
    "",
    "### Open gaps",
    "",
    markdownOrderedList(decision.openGaps || [], "No open gaps generated."),
    "",
    markdownValueList("Fallback posture", decision.fallbackPosture),
    markdownValueList("Enterprise handoff", decision.enterpriseHandoff),
    markdownValueList("Stop criteria", decision.stopCriteria),
    markdownValueList("Package evidence", decision.packageEvidence),
    "",
    `Next action: ${formatMarkdownValue(decision.nextAction || "Review with the named owner.")}`,
    ""
  ];
}

function deriveCombinedHandoff(productBrief = deriveProductBrief(), engineeringBrief = deriveEngineeringBrief(), businessBrief = deriveBusinessBrief(), solutionBuildRecipe = null, solutionExecutionBrief = null, enterpriseReadinessTemplateBrief = null) {
  const review = buildReviewGate();
  const workflowTitle = state.fields.workflowName || state.fields.submittedWorkflowTask || "Unnamed workflow";
  const buildRecipeForPacket = solutionBuildRecipe || solutionBuildPacketPlaceholder();
  const executionBriefForPacket = solutionExecutionBrief || solutionExecutionPacketPlaceholder(buildRecipeForPacket);
  const enterpriseReadinessForPacket = enterpriseReadinessTemplateBrief || enterpriseReadinessPacketPlaceholder();
  const readinessInputs = [
    productBrief.readiness,
    engineeringBrief.readiness,
    businessBrief.readiness,
    buildRecipeForPacket.readiness,
    executionBriefForPacket.readiness,
    enterpriseReadinessForPacket.readiness,
    review.overall
  ].map(Number).filter(Number.isFinite);
  const readiness = Math.round(readinessInputs.reduce((sum, score) => sum + score, 0) / Math.max(1, readinessInputs.length));
  const sections = [
    templateSection("Packet Summary", [
      templateField("Workflow", workflowTitle),
      templateField("Readiness", `${readiness}% - ${templateReadinessLabel(readiness)}`),
      templateField("Product PDR readiness", `${productBrief.readiness}% - ${productBrief.readinessLabel}`),
      templateField("Engineering brief readiness", `${engineeringBrief.readiness}% - ${engineeringBrief.readinessLabel}`),
      templateField("Business value readiness", `${businessBrief.readiness}% - ${businessBrief.readinessLabel}`),
      templateField("Build recipe readiness", `${buildRecipeForPacket.readiness}% - ${buildRecipeForPacket.readinessLabel}`),
      templateField("Execution plan readiness", `${executionBriefForPacket.readiness}% - ${executionBriefForPacket.readinessLabel}`),
      templateField("Enterprise readiness", enterpriseReadinessForPacket.enterpriseReadiness?.decision || `${enterpriseReadinessForPacket.readiness}% - ${enterpriseReadinessForPacket.readinessLabel}`, "", { ownerRoute: "Governance Inputs", treatment: "Use as release posture" }),
      ...(workshopUseCaseContext() ? [templateField("Use-case context", "", workshopUseCaseContext(), { inferred: true })] : []),
      templateField("Top completion questions", review.completionQuestions.join("\n")),
      templateField("Decision posture", gateAssessment().decision)
    ]),
    templateSection("Included Artifacts", [
      templateField("Product PDR handoff", "Included"),
      templateField("Engineering / Solution Architecture brief", "Included"),
      templateField("Business Value brief", "Included"),
      templateField("Governance input checklist", "Included for later review"),
      templateField("Solution Build Recipe", "Included"),
      templateField("Solution Execution Plan", "Included"),
      templateField("Enterprise Readiness Brief", "Included"),
      templateField("Process matrix", state.steps.length ? `${state.steps.length} captured step(s)` : ""),
      templateField("Open question routing", `${questionRoutingRows().length - 1} routed question(s)`)
    ]),
    templateSection("Build and Readiness Artifacts", [
      templateField("Recommended build route", solutionBuildRoute().label, "", { inferred: true, ownerRoute: "Solution Build", treatment: "Use as builder route" }),
      templateField("Build recipe summary", buildRecipeForPacket.shortSummary, "", { inferred: true, ownerRoute: "Solution Build", treatment: "Use as build handoff" }),
      templateField("Execution runbook summary", executionBriefForPacket.shortSummary, "", { inferred: true, ownerRoute: "Solution Build", treatment: "Use as builder runbook" }),
      templateField("Enterprise release posture", enterpriseReadinessForPacket.shortSummary, "", { inferred: true, ownerRoute: "Governance Inputs", treatment: "Use as release posture" }),
      templateField("Package evidence", "solution-build-recipe.docx; solution-execution-plan.docx; enterprise-readiness-brief.docx; template-alignment-contract.json", "", { inferred: true, ownerRoute: "Engineering", treatment: "Use as package review evidence" })
    ]),
    templateSection("Recommended Operator Actions", [
      templateField("Next intake action", review.completionQuestions[0] || state.fields.recommendedNextStep || "Review packet with Product, Engineering, and Business owners.", "", { inferred: true }),
      templateField("Build review action", solutionBuildRoute().nextAction, "", { inferred: true, ownerRoute: "Solution Build", treatment: "Use as next builder action" }),
      templateField("Enterprise review action", enterpriseReadinessForPacket.enterpriseReadiness?.nextActions?.[0] || "Review enterprise gates with the platform, security, and pilot owners.", "", { inferred: true, ownerRoute: "Governance Inputs", treatment: "Track before enterprise review" }),
      templateField("Packaging note", "Export Excel or create the local package when the owner lanes agree the remaining questions are acceptable.", "", { inferred: true })
    ])
  ];
  const packet = buildTemplateBrief({
    id: "combined-handoff",
    label: "Combined Packet",
    title: `${workflowTitle} Combined Handoff Packet`,
    shortSummary: `${readiness}% packet readiness across Product, Engineering, Business, Build Recipe, Execution Plan, Enterprise Readiness, and open question routing.`,
    sections
  });
  packet.readiness = readiness;
  packet.readinessLabel = templateReadinessLabel(readiness);
  packet.questionRouting = questionRoutingRows();
  packet.markdown = combinedHandoffMarkdown(packet, productBrief, engineeringBrief, businessBrief, buildRecipeForPacket, executionBriefForPacket, enterpriseReadinessForPacket);
  return packet;
}

function packetPlaceholderBrief({ id, label, title, shortSummary, readiness = 0, markdown = "", sections = [], extra = {} }) {
  return {
    id,
    label,
    title,
    shortSummary,
    readiness,
    readinessLabel: templateReadinessLabel(readiness),
    sections,
    markdown: markdown || [`# ${title}`, "", shortSummary].join("\n"),
    ...extra
  };
}

function solutionBuildPacketPlaceholder() {
  const route = solutionBuildRoute();
  const readiness = Math.round((buildSolutionBlueprint().readiness + gateAssessment().overall) / 2);
  return packetPlaceholderBrief({
    id: "solution-build-recipe",
    label: "Solution Build Recipe",
    title: "Solution Build Recipe",
    readiness,
    shortSummary: `${route.label}. ${route.nextAction}`,
    markdown: [
      "# Solution Build Recipe",
      "",
      `Route: ${route.label}`,
      `Next action: ${route.nextAction}`
    ].join("\n")
  });
}

function solutionExecutionPacketPlaceholder(solutionBuildRecipe = solutionBuildPacketPlaceholder()) {
  return packetPlaceholderBrief({
    id: "solution-execution-plan",
    label: "Solution Execution Plan",
    title: "Solution Execution Plan",
    readiness: solutionBuildRecipe.readiness,
    shortSummary: "Builder runbook will be included when the full Outputs package is generated.",
    markdown: [
      "# Solution Execution Plan",
      "",
      "Builder actions, data inputs, permissions, controls, human gates, package evidence, and expected outputs are generated in the full Outputs package."
    ].join("\n")
  });
}

function enterpriseReadinessPacketPlaceholder() {
  const readiness = governanceReadinessScore();
  const governance = governanceRoute();
  return packetPlaceholderBrief({
    id: "enterprise-readiness-brief",
    label: "Enterprise Readiness Brief",
    title: "Enterprise Readiness Brief",
    readiness,
    shortSummary: `${governance.path}. Enterprise gates are generated in the full Outputs package.`,
    markdown: [
      "# Enterprise Readiness Brief",
      "",
      `Review path: ${governance.path}`,
      `Data boundary: ${governance.boundary}`,
      "Full source setup, connector approval, human checkpoint, evidence, and next-action gates are generated in the Outputs package."
    ].join("\n"),
    extra: {
      enterpriseReadiness: {
        decision: governance.path,
        nextActions: ["Create the handoff package and review enterprise gates with the platform, security, and pilot owners."]
      }
    }
  });
}

function buildTemplateBrief({ id, label, title, shortSummary, sections }) {
  const brief = {
    id,
    label,
    title,
    shortSummary,
    sections,
    readiness: templateReadinessScore(sections)
  };
  brief.readinessLabel = templateReadinessLabel(brief.readiness);
  brief.markdown = templateBriefMarkdown(brief);
  return brief;
}

function templateSection(title, fields = []) {
  return { title, fields };
}

function templateField(label, value, fallback = "TBD", options = {}) {
  const captured = Array.isArray(value) ? value.some(isCapturedValue) : isCapturedValue(value);
  const fallbackText = formatTemplateValue(fallback);
  const valueText = captured ? templateValue(value, fallbackText || "TBD") : (fallbackText || "TBD");
  const status = captured ? "Captured" : options.inferred && isCapturedValue(fallbackText) ? "Inferred" : "Missing";
  const supplementLater = Boolean(options.supplementLater);
  return {
    label,
    value: valueText,
    status,
    ownerRoute: options.ownerRoute || inferTemplateOwnerRoute(label),
    sourceType: options.sourceType || templateSourceType(status, supplementLater),
    treatment: options.treatment || templateTreatment(status, supplementLater),
    supplementLater: supplementLater ? "Yes" : "No"
  };
}

function templateSourceType(status, supplementLater = false) {
  if (supplementLater) return "Trusted supplement";
  if (status === "Captured") return "Discovery capture";
  if (status === "Inferred") return "AI inference from current state";
  return "Open discovery gap";
}

function templateTreatment(status, supplementLater = false) {
  if (supplementLater) return "Supplement later";
  if (status === "Captured") return "Use as captured";
  if (status === "Inferred") return "Review inference";
  return "Ask before handoff";
}

function inferTemplateOwnerRoute(label) {
  const text = String(label || "");
  if (/cost|margin|commercial|capacity|annual|baseline|metric|kpi|hours saved|volume|occurrence|value|portfolio/i.test(text)) return "Finance/Ops";
  if (/governance|security|privacy|msa|data sensitivity|deployment|human review|retention|logging|traceability|approval/i.test(text)) return "Governance Inputs";
  if (/architecture|integration|system|tool|access|source|technical|functional|non-functional|platform|mvp input|mvp output|engineering|connector/i.test(text)) return "Engineering";
  if (/owner|scope|user|beneficiar|pilot|acceptance|definition|problem|priority|recommendation|product/i.test(text)) return "Product";
  return "Product";
}

function templateFieldMetaSummary(field = {}) {
  return [field.ownerRoute, field.sourceType, field.treatment]
    .map((item) => String(item || "").trim())
    .filter(Boolean)
    .join(" / ");
}

function templateAlignmentTreatmentSummary(document = {}) {
  const parts = [
    `${Number(document.capturedFields || 0)} captured`,
    `${Number(document.inferredFields || 0)} inferred`,
    `${Number(document.missingFields || 0)} missing`
  ];
  if (Number(document.supplementFieldCount || 0)) parts.push(`${document.supplementFieldCount} supplement`);
  return parts.join(" / ");
}

function templateValue(value, fallback = "TBD") {
  if (Array.isArray(value)) {
    const values = value.map(formatTemplateValue).filter(isCapturedValue);
    return values.length ? values.join("; ") : fallback;
  }
  const text = formatTemplateValue(value);
  return isCapturedValue(text) ? text : fallback;
}

function formatTemplateValue(value) {
  if (Array.isArray(value)) return value.map(formatTemplateValue).filter(Boolean).join("; ");
  if (value && typeof value === "object") return JSON.stringify(value);
  return String(value ?? "").trim();
}

function templateReadinessScore(sections = []) {
  const weights = { Captured: 1, Inferred: 0.68, Missing: 0.08 };
  const fields = sections.flatMap((section) => section.fields || []);
  if (!fields.length) return 0;
  return Math.round((fields.reduce((sum, field) => sum + (weights[field.status] || 0), 0) / fields.length) * 100);
}

function templateReadinessLabel(score) {
  if (score >= 78) return "Template ready";
  if (score >= 58) return "Light follow-up";
  if (score >= 38) return "Discovery gaps";
  return "Early draft";
}

function templateStatusClass(status) {
  return String(status || "missing").toLowerCase().replace(/\s+/g, "-");
}

function templateBriefMarkdown(brief) {
  const counts = templateBriefStatusCounts(brief);
  const captured = templateBriefFieldsByStatus(brief, "Captured", 8);
  const inferred = templateBriefFieldsByStatus(brief, "Inferred", 6);
  const missing = templateBriefFieldsByStatus(brief, "Missing", 8);
  const routedQuestions = routedQuestionsForBrief(brief).slice(0, 6);
  return [
    `# ${brief.title}`,
    "",
    `Document: ${brief.label}`,
    `Generated: ${new Date().toLocaleString()}`,
    "",
    "## Executive Snapshot",
    "",
    `- Readiness: ${brief.readiness}% - ${brief.readinessLabel}`,
    `- Workflow: ${templateValue(state.fields.workflowName || state.fields.submittedWorkflowTask || state.sessionMeta?.name, "Workflow TBD")}`,
    `- Practice / domain: ${templateValue(state.fields.practice || state.fields.domain, "TBD")}`,
    `- Use-case pattern: ${activeUseCaseArchetype().label}`,
    `- Gate posture: ${gateAssessment().decision}`,
    `- Data sensitivity: ${inferOverallDataSensitivity()}`,
    `- Governance note: ${governanceRoute().path} (later review input, not primary early-readiness driver)`,
    ...(workshopUseCaseContext() ? [`- Workshop context: ${workshopUseCaseContext()}`] : []),
    "",
    "## Handoff Summary",
    "",
    brief.shortSummary || "Summary still needs discovery.",
    "",
    "## Recommended Next Action",
    "",
    outputRecommendedNextAction(brief, missing, routedQuestions),
    "",
    "## Readiness Signals",
    "",
    "| Captured | Inferred | Missing |",
    "| ---: | ---: | ---: |",
    `| ${counts.Captured} | ${counts.Inferred} | ${counts.Missing} |`,
    "",
    "## Strongest Current Inputs",
    "",
    markdownFieldList(captured, "No strong captured inputs yet."),
    "",
    "## Important Assumptions / Inferences",
    "",
    markdownFieldList(inferred, "No major inferred inputs yet."),
    "",
    "## Needs Confirmation Before Handoff",
    "",
    markdownFieldList(missing, "No major missing fields detected."),
    "",
    "## Routed Questions",
    "",
    markdownQuestionList(routedQuestions, "No major routed questions detected."),
    "",
    "## Full Field Detail",
    "",
    ...brief.sections.flatMap((section) => [
      `## ${section.title}`,
      "",
      ...(section.fields || []).map((field) => `- [${field.status} | ${templateFieldMetaSummary(field)}] ${field.label}: ${formatMarkdownValue(field.value)}`),
      ""
    ])
  ].join("\n");
}

function templateBriefStatusCounts(brief) {
  return (brief.sections || [])
    .flatMap((section) => section.fields || [])
    .reduce((counts, field) => {
      const key = field.status || "Missing";
      counts[key] = (counts[key] || 0) + 1;
      return counts;
    }, { Captured: 0, Inferred: 0, Missing: 0 });
}

function templateBriefTreatmentCounts(brief) {
  return (brief.sections || [])
    .flatMap((section) => section.fields || [])
    .reduce((counts, field) => {
      const key = field.treatment || "Ask before handoff";
      counts[key] = (counts[key] || 0) + 1;
      return counts;
    }, {});
}

function templateBriefFieldsByStatus(brief, status, limit = 6) {
  return (brief.sections || [])
    .flatMap((section) => (section.fields || []).map((field) => ({ ...field, section: section.title })))
    .filter((field) => field.status === status)
    .slice(0, limit);
}

function markdownFieldList(fields, emptyText) {
  if (!fields.length) return `- ${emptyText}`;
  return fields.map((field) => `- ${field.label} (${templateFieldMetaSummary(field)}): ${formatMarkdownValue(field.value)}`).join("\n");
}

function markdownQuestionList(questions, emptyText) {
  const values = questions.map((question) => String(question || "").trim()).filter(Boolean);
  if (!values.length) return `- ${emptyText}`;
  return values.map((question) => `- ${formatMarkdownValue(question)}`).join("\n");
}

function formatMarkdownValue(value) {
  return String(value ?? "TBD").replace(/\s*\n+\s*/g, "; ").trim() || "TBD";
}

function routedQuestionsForBrief(brief) {
  const review = buildReviewGate();
  if (brief.id === "product-pdr") return review.handoff.product;
  if (brief.id === "engineering-brief") return review.handoff.engineering;
  if (brief.id === "business-value") return review.handoff.business;
  if (brief.id === "governance-inputs") return review.handoff.governance;
  if (brief.id === "solution-build-recipe") return solutionBuildOpenQuestions(review);
  return [
    ...review.completionQuestions,
    ...questionRoutingRows().slice(1, 6).map((row) => `${row[0]} / ${row[2]}: ${row[3]}`)
  ];
}

function outputRecommendedNextAction(brief, missingFields = [], routedQuestions = []) {
  const firstQuestion = routedQuestions[0] || topCompletionQuestions(1)[0] || "";
  if (brief.id === "product-pdr") {
    return firstQuestion
      ? `Confirm the Product lane first: ${firstQuestion}`
      : "Review Product scope, MVP slice, users, and success metrics with the Product owner.";
  }
  if (brief.id === "engineering-brief") {
    return firstQuestion
      ? `Confirm the Engineering lane first: ${firstQuestion}`
      : "Review process, data access, systems, output contract, logging, and controls with Engineering.";
  }
  if (brief.id === "business-value") {
    return firstQuestion
      ? `Confirm the Business lane first: ${firstQuestion}`
      : "Review baseline volume, time saved, KPI proof, and sponsor ownership with the business owner.";
  }
  if (brief.id === "governance-inputs") {
    return firstQuestion
      ? `Capture the minimum later-review input: ${firstQuestion}`
      : "Keep governance as a later review lane; confirm data boundary, environment, human review, and evidence trail before build approval.";
  }
  if (brief.id === "solution-build-recipe") {
    return solutionBuildRoute().nextAction;
  }
  if (missingFields.length) {
    return `Resolve the top packet gap before sharing broadly: ${missingFields[0].label}.`;
  }
  return "Review the combined packet with Product, Engineering, and Business owners, then create the package for pilot testing.";
}

function combinedHandoffMarkdown(packet, productBrief, engineeringBrief, businessBrief, solutionBuildRecipe = solutionBuildPacketPlaceholder(), solutionExecutionBrief = solutionExecutionPacketPlaceholder(solutionBuildRecipe), enterpriseReadinessTemplateBrief = enterpriseReadinessPacketPlaceholder()) {
  const routing = questionRoutingRows();
  const governanceBrief = deriveGovernanceBrief();
  return [
    templateBriefMarkdown(packet),
    "## Product PDR",
    "",
    productBrief.markdown,
    "",
    "## Engineering / Solution Architecture Brief",
    "",
    engineeringBrief.markdown,
    "",
    "## Business Value Brief",
    "",
    businessBrief.markdown,
    "",
    "## Governance Inputs",
    "",
    governanceBrief.markdown,
    "",
    "## Solution Build Recipe",
    "",
    solutionBuildRecipe.markdown,
    "",
    "## Solution Execution Plan",
    "",
    solutionExecutionBrief.markdown,
    "",
    "## Enterprise Readiness Brief",
    "",
    enterpriseReadinessTemplateBrief.markdown,
    "",
    "## Open Question Routing",
    "",
    routing.slice(1).map((row) => `- ${row[0]} / ${row[2]} / P${row[1]}: ${row[3]}`).join("\n") || "No routed questions."
  ].join("\n");
}

function templateBriefRows(brief) {
  return [
    ["Template", "Section", "Field", "Value", "Status", "Owner Route", "Source Type", "Treatment", "Supplement Later?"],
    ...brief.sections.flatMap((section) =>
      (section.fields || []).map((field) => [
        brief.label,
        section.title,
        field.label,
        field.value,
        field.status,
        field.ownerRoute,
        field.sourceType,
        field.treatment,
        field.supplementLater
      ])
    )
  ];
}

function combinedHandoffRows(combinedHandoff = deriveCombinedHandoff()) {
  return [
    ...templateBriefRows(combinedHandoff),
    [],
    ["Open Question Routing", "Priority", "Owner", "Question", "Why It Matters"],
    ...questionRoutingRows().slice(1).map((row) => [row[0], row[1], row[2], row[3], row[4]])
  ];
}

function solutionBuildRecipeRows(solutionBuildRecipe = deriveSolutionBuildRecipe()) {
  return templateBriefRows(solutionBuildRecipe);
}

function solutionBuildSpecRows(solutionBuildSpec = deriveSolutionBuildSpec()) {
  const capabilityPlan = solutionBuildSpec.capabilityPlan || deriveSolutionCapabilityPlan(solutionBuildSpec);
  const executionPlan = solutionBuildSpec.executionPlan || deriveSolutionExecutionPlan(solutionBuildSpec);
  return [
    ["Area", "Item", "Value", "Owner / Platform", "Status / Mode"],
    ["Route", "Recommended route", solutionBuildSpec.route.label, "Solution Builder / AI Engineering", solutionBuildSpec.route.routeType],
    ["Route", "Why this route", solutionBuildSpec.route.why, "Solution Builder / AI Engineering", solutionBuildSpec.route.confidence],
    ["Route", "Next action", solutionBuildSpec.route.nextAction, "Solution Builder / AI Engineering", "Next"],
    ...((solutionBuildSpec.agentBuildPack?.buildOptions || []).map((option) => [
      "Agent Build Option",
      option.id,
      `${option.label}\nSurface: ${option.buildSurface}\nWhen to use: ${option.whenToUse}`,
      "Solution Builder / AI Engineering",
      option.fit
    ])),
    ...solutionBuildSpec.platforms.flatMap((platform) => [
      ["Platform", `${platform.label} surface`, platform.implementationSurface, platform.label, "Implementation surface"],
      ["Platform", `${platform.label} responsibilities`, platform.responsibilities.join("\n"), platform.label, "Responsibilities"],
      ["Platform", `${platform.label} knowledge plan`, platform.knowledgePlan, platform.label, "Knowledge"],
      ["Platform", `${platform.label} tool/action plan`, platform.toolPlan || platform.actionPlan, platform.label, "Tool/action"]
    ]),
    ...solutionBuildSpec.connectors.map((connector) => [
      "Connector",
      connector.id,
      `${connector.connectorType}\nSource: ${connector.source}\nNext: ${connector.nextAction}`,
      connector.platform,
      `${connector.status}; ${connector.readWriteMode}`
    ]),
    ...solutionBuildSpec.controls.map((control) => [
      "Control",
      control.id,
      `${control.control}\nRequired before: ${control.requiredBefore}`,
      control.owner,
      "Required"
    ]),
    ...capabilityPlan.chatgptCapabilities.map((capability) => [
      "Capability",
      capability.id,
      `${capability.capability}\n${capability.buildUse}\nSetup: ${capability.setup}`,
      "ChatGPT / OpenAI",
      capability.useWhen
    ]),
    ...capabilityPlan.microsoftCopilotCapabilities.map((capability) => [
      "Capability",
      capability.id,
      `${capability.capability}\n${capability.buildUse}\nSetup: ${capability.setup}`,
      "Microsoft 365 Copilot",
      capability.useWhen
    ]),
    ...executionPlan.items.map((item) => [
      "Execution Plan",
      item.id,
      `${item.builderAction}\nInputs: ${item.dataInputs}\nPermissions: ${item.permissionsNeeded}\nControl: ${item.enterpriseControls}\nGate: ${item.humanCheckpoint}\nOutput: ${item.expectedOutput}`,
      item.platform,
      item.status
    ]),
    ...solutionBuildSpec.mvp.buildSteps.map((step, index) => [
      "MVP Build Step",
      `Step ${index + 1}`,
      step,
      "Solution Builder",
      "MVP"
    ]),
    ...solutionBuildSpec.mvp.testScript.map((step, index) => [
      "Test Script",
      `Test ${index + 1}`,
      step,
      "Reviewer",
      "Pilot"
    ]),
    ...solutionBuildSpec.openQuestions.map((question, index) => [
      "Open Question",
      `Question ${index + 1}`,
      question,
      "Solution Builder",
      "Open"
    ])
  ];
}

function questionRoutingGroups() {
  const review = buildReviewGate();
  const archetype = activeUseCaseArchetype();
  return [
    {
      route: "Use-Case Lens",
      owner: state.fields.businessOwner || state.sessionMeta?.owner || "AI Infusion / submitting SME",
      icon: archetype.icon,
      reason: "Classifies the submitted idea into the right discovery pattern before Product and Engineering overfit to the first solution idea.",
      questions: dedupeQuestions([archetypeFollowUpQuestion(archetype)])
    },
    {
      route: "Product",
      owner: state.fields.followUpOwner || "Product owner / AI Infusion",
      icon: "package-check",
      reason: "Scope, PDR, user workflow, prioritization, and pilot definition.",
      questions: dedupeQuestions(review.handoff.product)
    },
    {
      route: "Engineering",
      owner: "AI Engineer / Solution Architect",
      icon: "wrench",
      reason: "Technical inputs, data access, integrations, requirements, and feasibility.",
      questions: dedupeQuestions(review.handoff.engineering)
    },
    {
      route: "Business",
      owner: state.fields.businessOwner || "Business sponsor",
      icon: "badge-dollar-sign",
      reason: "Value hypothesis, owner commitment, adoption, and decision rights.",
      questions: dedupeQuestions(review.handoff.business)
    },
    {
      route: "Governance Inputs",
      owner: "Governance, Security, Legal/MSA, or Privacy",
      icon: "shield-check",
      reason: "Basic inputs for the later governance/security review: data sensitivity, approval path, human review, and audit trail.",
      questions: dedupeQuestions(review.handoff.governance)
    },
    {
      route: "Finance/Ops",
      owner: "Finance / Operations partner",
      icon: "calculator",
      reason: "Baseline, capacity value, fixed-fee impact, and portfolio economics.",
      questions: dedupeQuestions(financeOpsQuestions())
    },
    {
      route: "Domain Sponsor",
      owner: state.fields.businessOwner || state.fields.pilotCandidate || "Submitting leader / domain sponsor",
      icon: "user-round-check",
      reason: "Workflow truth, sponsor signoff, pilot users, and acceptable change management.",
      questions: dedupeQuestions(domainSponsorQuestions())
    }
  ];
}

function questionRoutingRows() {
  return [
    ["Route", "Priority", "Suggested Owner", "Question", "Why It Matters", "Status"],
    ...questionRoutingGroups().flatMap((group) =>
      group.questions.map((question, index) => [
        group.route,
        index + 1,
        group.owner,
        question,
        group.reason,
        "Open"
      ])
    )
  ];
}

function questionRoutingMarkdown(groups = questionRoutingGroups()) {
  const workflow = templateValue(state.fields.workflowName || state.fields.submittedWorkflowTask || state.sessionMeta?.name, "Workflow TBD");
  const routedCount = groups.reduce((sum, group) => sum + (group.questions || []).length, 0);
  return [
    `# Open Question Routing - ${workflow}`,
    "",
    `Generated: ${new Date().toLocaleString()}`,
    `Routed questions: ${routedCount}`,
    "",
    "Use this as the owner-routed follow-up list before Product, Engineering, Business, and governance input owners treat the discovery package as build-ready.",
    "",
    ...groups.flatMap((group) => [
      `## ${group.route}`,
      "",
      `Owner: ${group.owner}`,
      `Why it matters: ${group.reason}`,
      "",
      ...(group.questions || []).map((question, index) => `${index + 1}. ${formatMarkdownValue(question)}`),
      ""
    ])
  ].join("\n");
}

function dedupeQuestions(questions = []) {
  const values = questions.map((question) => String(question || "").trim()).filter(Boolean);
  return [...new Set(values)].slice(0, 5);
}

function financeOpsQuestions() {
  const questions = [
    isCapturedValue(state.fields.runsPerPeriod) && isCapturedValue(state.fields.averageDuration) ? "" : "What baseline volume and time assumptions should Finance/Ops use for the current manual workflow?",
    isCapturedValue(state.fields.hoursSavedHypothesis) ? "" : "What first-pass time-saved assumption per occurrence is credible enough for a pilot value case?",
    isCapturedValue(state.fields.marginImpactHypothesis) ? "" : "Is there a fixed-fee margin, staffing flexibility, or cost-to-serve impact Finance should estimate?",
    "What blended cost rate or role-cost band should be used for sensitivity analysis?",
    isCapturedValue(state.fields.reusePotential) ? "" : "Should reuse across projects or practices count as a portfolio value lever?"
  ].filter(Boolean);
  return questions.length ? questions : ["Validate the baseline, savings assumption, cost band, and portfolio priority before funding or build prioritization."];
}

function domainSponsorQuestions() {
  const questions = [
    state.fields.playbackConfirmed === "yes" ? "" : "Can the domain sponsor confirm the A-to-Z workflow playback and identify any missing steps or exceptions?",
    isCapturedValue(state.fields.businessOwner) ? "" : "Who is the business sponsor accountable for adoption, signoff, and workflow change?",
    isCapturedValue(state.fields.pilotCandidate) ? "" : "Which pilot team, SME, or engagement should test the first version?",
    isCapturedValue(state.fields.outputConsumer) ? "" : "Who consumes the final output, and what would make it trusted enough to use?",
    isCapturedValue(state.fields.successMetrics) ? "" : "What success threshold would convince the sponsor to expand, backlog, or stop the use case?"
  ].filter(Boolean);
  return questions.length ? questions : ["Confirm sponsor signoff, pilot users, and success threshold before packaging the use case as ready."];
}

function currentWorkflowSummary() {
  if (state.fields.currentStateSummary) return state.fields.currentStateSummary;
  const boundary = workflowBoundarySummary();
  const steps = state.steps.length ? `${state.steps.length} captured steps` : "steps not captured yet";
  return `${boundary}; ${steps}; ${summarizedSystems()}`;
}

function workflowBoundarySummary() {
  const start = templateValue(state.fields.startPoint, "start TBD");
  const end = templateValue(state.fields.endPoint || state.fields.definitionOfDone, "end TBD");
  return `${start} -> ${end}`;
}

function stepDetailsForTemplate() {
  if (!state.steps.length) return "";
  return state.steps.map((step, index) => {
    return `Step ${index + 1}: ${step.name || step.action || "Untitled"} | Actor: ${templateValue(step.actor)} | Tool: ${templateValue(step.tool)} | Input: ${templateValue(step.input)} | Output: ${templateValue(step.output)} | Handoff: ${templateValue(step.handoff)} | Time: ${templateValue(step.time)} | Pattern: ${step.pattern || inferAiPattern(step).label}`;
  }).join("\n");
}

function engineeringStepDetailsForTemplate() {
  if (!state.steps.length) return "";
  return state.steps.map((step, index) => {
    return `Step ${index + 1}: ${step.name || step.action || "Untitled"} | Actor: ${templateValue(step.actor)} | System: ${templateValue(step.tool)} | Access: ${templateValue(step.accessMode)} | Input: ${templateValue(step.input)} | Output: ${templateValue(step.output)} | AI pattern: ${step.pattern || inferAiPattern(step).label} | Human review: ${templateValue(step.decision)}`;
  }).join("\n");
}

function stepActorsSummary() {
  const actors = state.steps.map((step) => step.actor).filter(isCapturedValue);
  return [...new Set(actors)].slice(0, 6).join(", ");
}

function stepPainSummary() {
  return state.steps.map((step) => [step.pain, step.risk].filter(isCapturedValue).join(" / ")).filter(isCapturedValue).slice(0, 5).join("; ");
}

function aiPatternSummary() {
  const patterns = [
    ...state.patterns.map((item) => item.pattern || item.name || item.capability),
    ...state.steps.map((step) => step.pattern || inferAiPattern(step).label)
  ].filter(isCapturedValue);
  return [...new Set(patterns)].slice(0, 8).join(", ");
}

function productAssumptionsSummary() {
  return [
    state.fields.availableTooling ? `Build path assumes ${state.fields.availableTooling}.` : "",
    state.fields.msaBoundary && state.fields.msaBoundary !== "Unknown" ? `Data boundary: ${state.fields.msaBoundary}.` : "",
    state.fields.deploymentEnvironment && state.fields.deploymentEnvironment !== "Unknown" ? `Deployment: ${state.fields.deploymentEnvironment}.` : "",
    "Conversation-derived fields require human confirmation before final handoff."
  ].filter(Boolean).join(" ");
}

function recommendedProductNextStep(review, blueprint) {
  if (review.completionQuestions.length) return `Answer the top completion question: ${review.completionQuestions[0]}`;
  if (state.fields.mvpScope) return "Review PDR scope with Product, Engineering, Business, and governance input owners.";
  return `Define MVP around ${blueprint.mvpSlice}`;
}

function productDecisionNeeded(review, gate) {
  if (review.overall < 58) return "Continue discovery before Product accepts this as handoff-ready.";
  if (gate.decision === "Build now" || gate.decision === "Approved") return "Approve pilot scope and assign Product owner.";
  return `Decide whether to ${String(gate.decision || "prioritize, backlog, or continue discovery").toLowerCase()}.`;
}

function dataSourcesSummary() {
  const sources = [
    ...state.data.map((item) => item.source || item.category),
    ...state.systems.map((item) => item.name),
    ...state.steps.map((step) => step.tool)
  ].filter(isCapturedValue);
  return [...new Set(sources)].slice(0, 8).join(", ");
}

function dataTypesSummary() {
  const types = [
    ...state.data.map((item) => [item.category, item.format, item.sensitivity].filter(isCapturedValue).join(" / ")),
    ...state.steps.map((step) => step.dataSensitivity)
  ].filter(isCapturedValue);
  return [...new Set(types)].slice(0, 8).join("; ");
}

function clientDataInvolvedSummary() {
  const sensitivity = inferOverallDataSensitivity();
  if (sensitivity === "Public" || sensitivity === "Internal") return "No client-sensitive data indicated yet; confirm during governance review.";
  if (sensitivity === "Unknown") return "";
  return `${sensitivity}; ${state.fields.msaBoundary || "MSA boundary TBD"}`;
}

function accessModelSummary() {
  const access = [
    ...state.steps.map((step) => step.accessMode),
    ...state.systems.map((system) => system.access)
  ].filter(isCapturedValue);
  return [...new Set(access)].slice(0, 6).join("; ");
}

function retentionLoggingSummary() {
  const controls = currentPilotControls();
  return `${controls.retentionNote || "Retention TBD"} Logging/audit: ${controls.auditStatus || "local package manifest"}.`;
}

function functionalRequirementsDraft() {
  if (!state.steps.length) return "";
  return state.steps.slice(0, 8).map((step, index) => {
    return `FR${index + 1}: Support ${step.name || step.action || `step ${index + 1}`} from ${templateValue(step.input)} to ${templateValue(step.output)} with ${step.decision ? "human review" : "appropriate reviewer confirmation"}.`;
  }).join("\n");
}

function nonFunctionalRequirementsDraft() {
  return [
    "Preserve human review for client-facing, sensitive, or judgment-heavy outputs.",
    "Minimize raw client data and prefer approved, sanitized, or metadata-only inputs where possible.",
    "Log assumptions, source references, and reviewer corrections during pilot.",
    "Fit primarily within ChatGPT Enterprise, Microsoft 365 Copilot, Copilot Studio, or approved agentic workflows."
  ].join("\n");
}

function traceabilitySummary() {
  return (state.evidenceArtifacts || []).length
    ? "Use uploaded/applied evidence summaries plus source notes and reviewer corrections."
    : "Use conversation transcript, process matrix, source references, and reviewer corrections as the trace path.";
}

function architectureComponentsDraft(blueprint) {
  return [
    "Intake/orchestration experience",
    "Approved source retrieval or user-provided file intake",
    "Extraction and synthesis layer",
    "Human review checkpoint",
    "Export/output packaging",
    blueprint.pattern
  ].join("; ");
}

function integrationSummary() {
  const systems = summarizedSystems();
  return systems === "Source systems and access modes need confirmation." ? "" : systems;
}

function risksMitigationsSummary() {
  const flags = inspectorRiskFlags();
  const controls = recommendedControls();
  return `${flags.length ? flags.slice(0, 4).join("; ") : riskSignalLabel()}. Mitigation: ${controls}`;
}

function technicalFeasibilityLabel() {
  const blueprint = buildSolutionBlueprint();
  if (blueprint.readiness >= 75) return "High";
  if (blueprint.readiness >= 50) return "Medium";
  return "Low / needs discovery";
}

function dataReadinessLabel() {
  if (state.data.length && inferOverallDataSensitivity() !== "Unknown") return "Medium";
  if (state.steps.some((step) => isCapturedValue(step.dataSensitivity))) return "Partial";
  return "";
}

function integrationComplexityLabel() {
  const count = uniqueCount(state.systems, "name") || uniqueStepToolCount();
  if (count >= 4) return "High";
  if (count >= 2) return "Medium";
  if (count === 1) return "Low";
  return "";
}

function mvpInputOutputSummary() {
  const first = state.steps.find((step) => isCapturedValue(step.input) || isCapturedValue(step.output)) || state.steps[0];
  if (!first) return "";
  return `Input: ${templateValue(first.input)}. Output: ${templateValue(first.output)}. Candidate slice: ${recommendedMvpSlice()}`;
}

function mvpInputContractSummary() {
  const inputs = state.steps.map((step) => step.input).filter(isCapturedValue).slice(0, 5);
  const sources = dataSourcesSummary();
  if (!inputs.length && !isCapturedValue(sources)) return "";
  return [
    inputs.length ? `Inputs: ${inputs.join("; ")}` : "",
    isCapturedValue(sources) ? `Sources: ${sources}` : "",
    accessModelSummary() ? `Access: ${accessModelSummary()}` : ""
  ].filter(Boolean).join(". ");
}

function mvpOutputContractSummary() {
  const outputs = state.steps.map((step) => step.output).filter(isCapturedValue).slice(0, 5);
  const done = state.fields.definitionOfDone;
  if (!outputs.length && !isCapturedValue(done)) return "";
  return [
    outputs.length ? `Outputs: ${outputs.join("; ")}` : "",
    isCapturedValue(done) ? `Definition of done: ${done}` : "",
    state.fields.outputConsumer ? `Consumer: ${state.fields.outputConsumer}` : ""
  ].filter(Boolean).join(". ");
}

function humanReviewGateSummary() {
  const decisions = summarizedDecisions();
  if (isOutputLaneCapturedValue(decisions)) return decisions;
  return state.fields.submittedHumanReviewNeeded || state.fields.humanJudgmentArea || "";
}

function acceptanceCriteriaSummary() {
  if (isCapturedValue(state.fields.acceptanceCriteria)) return state.fields.acceptanceCriteria;
  const pieces = [
    state.fields.successMetrics ? `Meet success metric: ${state.fields.successMetrics}` : "",
    state.fields.definitionOfDone ? `Produce accepted output: ${state.fields.definitionOfDone}` : "",
    humanReviewGateSummary() ? `Pass human review gate: ${humanReviewGateSummary()}` : "",
    traceabilitySummary() ? `Maintain traceability: ${traceabilitySummary()}` : ""
  ].filter(Boolean);
  return pieces.join("\n");
}

function connectorAssumptionsSummary() {
  const registry = deriveConnectorRegistry();
  const m365 = registry.find((item) => item.id === "microsoft-365");
  const packageEndpoint = registry.find((item) => item.id === "handoff-package");
  return [
    m365 ? `Microsoft 365: ${m365.status}; ${m365.nextAction}` : "",
    packageEndpoint ? `Package endpoint: ${packageEndpoint.status}; ${packageEndpoint.nextAction}` : "",
    "Direct enterprise connectors remain a later contract until approved folders, identity, retention, and permissions are confirmed."
  ].filter(Boolean).join(" ");
}

function governanceEvidenceNeedSummary() {
  const evidenceCount = (state.evidenceArtifacts || []).length;
  return [
    evidenceCount ? `${evidenceCount} optional evidence artifact(s) available.` : "No optional evidence uploaded yet.",
    "For later review, preserve source notes, reviewer corrections, package manifest, and any approved evidence references."
  ].join(" ");
}

function businessDecisionNeeded(review, gate) {
  if (review.overall < 58) return "Decide whether enough value signal exists to finish discovery.";
  return `Decide whether to ${String(gate.decision || "prioritize this opportunity").toLowerCase()} and assign a business owner.`;
}

function annualProjectsSummary() {
  const text = `${state.fields.runsPerPeriod} ${state.fields.submittedFrequency}`.toLowerCase();
  const match = text.match(/(\d+)\s*(?:to|-)?\s*(\d+)?\s*(?:projects|engagements|clients)/i);
  if (match) return match[2] ? `${match[1]}-${match[2]}` : match[1];
  return "";
}

function totalBaselineHoursSummary() {
  if (!isCapturedValue(state.fields.runsPerPeriod) || !isCapturedValue(state.fields.averageDuration)) return "";
  return "Calculate from occurrences x baseline time after Finance validates the period and unit.";
}

function valueLeversSummary() {
  return [
    state.fields.commercialValuePath,
    state.fields.hoursSavedHypothesis ? "Time saved" : "",
    state.fields.capacityTeamCompositionImpact ? "Capacity / team mix" : "",
    state.fields.marginImpactHypothesis ? "Margin" : "",
    state.fields.qualityImpactHypothesis ? "Quality / rework" : "",
    state.fields.reusePotential ? "Reuse" : ""
  ].filter(isCapturedValue).join(", ");
}

function baselineSourceSummary() {
  return [
    state.fields.submittedCurrentEffort ? "Submitted current effort" : "",
    state.fields.averageDuration ? "Interview baseline duration" : "",
    state.fields.runsPerPeriod ? "Interview run frequency" : "",
    state.evidenceArtifacts?.length ? "Optional evidence artifact(s)" : ""
  ].filter(Boolean).join(", ");
}

function validationMethodSummary() {
  return "Pilot on representative examples, compare against current manual baseline, capture reviewer corrections, and validate time, quality, and adoption signals.";
}

function businessEvidenceNeeded(review) {
  const items = [
    !isCapturedValue(state.fields.averageDuration) ? "baseline duration" : "",
    !isCapturedValue(state.fields.runsPerPeriod) ? "run frequency" : "",
    !isCapturedValue(state.fields.hoursSavedHypothesis) ? "savings assumption" : "",
    !isCapturedValue(state.fields.successMetrics) ? "success metric threshold" : "",
    review.completionQuestions[0] || ""
  ].filter(Boolean);
  return items.join("; ") || "Evidence is sufficient for a first business review; validate numbers before funding.";
}

function annualOccurrencesSummary() {
  return state.fields.runsPerPeriod || state.fields.submittedFrequency || "";
}

function annualHoursSavedSummary() {
  if (!isCapturedValue(state.fields.runsPerPeriod) || !isCapturedValue(state.fields.hoursSavedHypothesis)) return "";
  return "Calculate from annual occurrences x time saved per occurrence after baseline normalization.";
}

function sensitivityRangeSummary() {
  return "Model low/base/high using conservative, expected, and stretch time-saved assumptions once volume and cost rate are confirmed.";
}

function handoffChecklistSections() {
  const handoff = buildHandoffQuestions();
  const sensitivity = inferOverallDataSensitivity();
  const governance = governanceRoute();
  const hasAnyTiming = isCapturedValue(state.fields.averageDuration) || isCapturedValue(state.fields.runsPerPeriod);
  const hasTools = state.systems.length || state.steps.some((step) => isCapturedValue(step.tool));
  const hasAccess = state.steps.some((step) => isCapturedValue(step.accessMode));
  const hasStepOutputs = state.steps.some((step) => isCapturedValue(step.output));
  const hasStepData = state.data.length || state.steps.some((step) => isCapturedValue(step.dataSensitivity) || isCapturedValue(step.input));
  const hasHumanReview = state.decisions.length || state.steps.some((step) => isCapturedValue(step.decision));
  const hasEvidence = (state.evidenceArtifacts || []).some((item) => item.status === "analyzed" || item.applied);
  return [
    {
      title: "Product",
      icon: "package-check",
      accent: "cyan",
      items: [
        handoffChecklistItem("Problem / workflow boundary", state.fields.workflowName && (state.fields.startPoint || state.fields.endPoint), state.fields.workflowName || state.fields.submittedWorkflowTask || "Workflow name and boundary still need confirmation."),
        handoffChecklistItem("Submitted ask preserved", state.fields.submittedIdea || state.fields.submittedWorkflowTask, state.fields.submittedIdea || state.fields.submittedWorkflowTask || "Original submitted idea not captured."),
        handoffChecklistItem("Validated facts separated", state.fields.ideaValidationStatus !== "unknown", state.fields.ideaValidationStatus === "unknown" ? "Need to validate, split, merge, or reject the submitted idea." : `Idea status: ${state.fields.ideaValidationStatus}.`),
        handoffChecklistItem("Users and output consumers", state.fields.personas || state.fields.outputConsumer, state.fields.personas || state.fields.outputConsumer || "Persona, actors, or output consumer still missing."),
        handoffChecklistItem("MVP slice", state.fields.mvpScope, state.fields.mvpScope || "Product still needs the smallest credible pilot slice."),
        handoffChecklistItem("PDR success metrics", state.fields.successMetrics || state.fields.kpiTypes, state.fields.successMetrics || state.fields.kpiTypes || "Metrics should cover time, capacity, quality, reuse, adoption, or economics."),
        handoffChecklistItem("Product open questions", handoff.product.length <= 2, `${handoff.product.length} product question${handoff.product.length === 1 ? "" : "s"} remain.`)
      ]
    },
    {
      title: "Engineering",
      icon: "wrench",
      accent: "blue",
      items: [
        handoffChecklistItem("A-Z process skeleton", state.steps.length >= 3, state.steps.length ? `${state.steps.length} step${state.steps.length === 1 ? "" : "s"} captured.` : "Need rough numbered workflow steps."),
        handoffChecklistItem("Step-level matrix", matrixCompletionScore() >= 65, `${matrixCompletionScore()}% step matrix coverage.`),
        handoffChecklistItem("Systems and tools", hasTools, summarizedSystems()),
        handoffChecklistItem("Access mode", hasAccess, hasAccess ? "At least one source access mode captured." : "Need direct access, file/export, screenshot, transcript, or manual-input path."),
        handoffChecklistItem("Data boundary", sensitivity !== "Unknown", sensitivity === "Unknown" ? "Data sensitivity is still unknown." : sensitivity),
        handoffChecklistItem("Output contract", hasStepOutputs || state.fields.definitionOfDone, summarizedOutputs()),
        handoffChecklistItem("Engineering open questions", handoff.engineering.length <= 2, `${handoff.engineering.length} engineering question${handoff.engineering.length === 1 ? "" : "s"} remain.`)
      ]
    },
    {
      title: "Business",
      icon: "badge-dollar-sign",
      accent: "pink",
      items: [
        handoffChecklistItem("Commercial context", state.fields.commercialContext !== "unknown", state.fields.commercialContext === "unknown" ? "Commercial context still unknown." : state.fields.commercialContext),
        handoffChecklistItem("Value path", state.fields.commercialValuePath !== "unknown", state.fields.commercialValuePath === "unknown" ? "Need value path: capacity, margin, speed, quality, reuse, or pursuit conversion." : state.fields.commercialValuePath),
        handoffChecklistItem("Frequency and time baseline", hasAnyTiming, [state.fields.runsPerPeriod, state.fields.averageDuration].filter(isCapturedValue).join(" | ") || "Need run frequency and current duration."),
        handoffChecklistItem("Hours saved / dollars", state.fields.hoursSavedHypothesis || state.fields.marginImpactHypothesis, state.fields.hoursSavedHypothesis || state.fields.marginImpactHypothesis || "Need initial value hypothesis."),
        handoffChecklistItem("Capacity / team mix", state.fields.capacityTeamCompositionImpact || state.fields.roleMix, state.fields.capacityTeamCompositionImpact || state.fields.roleMix || "Need staffing flexibility or role-mix impact."),
        handoffChecklistItem("Reusable asset signal", state.fields.reusePotential, state.fields.reusePotential || "Need reuse potential across clients, practices, or delivery teams."),
        handoffChecklistItem("Business open questions", handoff.business.length <= 2, `${handoff.business.length} business question${handoff.business.length === 1 ? "" : "s"} remain.`)
      ]
    },
    {
      title: "Governance Inputs",
      icon: "shield-check",
      accent: "violet",
      items: [
        handoffChecklistItem("MSA boundary", state.fields.msaBoundary !== "Unknown", state.fields.msaBoundary),
        handoffChecklistItem("Deployment environment", state.fields.deploymentEnvironment !== "Unknown", state.fields.deploymentEnvironment),
        handoffChecklistItem("Post-build review route", governance.path !== "Multiple / TBD", governance.path),
        handoffChecklistItem("Human review gates", hasHumanReview, summarizedDecisions()),
        handoffChecklistItem("Evidence trace", hasEvidence || state.steps.length, hasEvidence ? "Evidence artifacts analyzed or applied." : "No optional evidence uploaded; conversation-derived trace is available."),
        handoffChecklistItem("Risk flags", inspectorRiskFlags().length <= 2, inspectorRiskFlags().slice(0, 2).join(" | ") || "No major risk flag captured."),
        handoffChecklistItem("Governance input questions", handoff.governance.length <= 2, `${handoff.governance.length} governance input question${handoff.governance.length === 1 ? "" : "s"} remain.`)
      ]
    }
  ];
}

function handoffChecklistItem(label, captured, detail) {
  const hasDetail = isCapturedValue(detail);
  let status = "missing";
  if (captured && hasDetail) status = "captured";
  else if (captured || hasDetail) status = "inferred";
  else if (String(detail || "").toLowerCase().includes("question")) status = "review";
  return { label, status, detail: hasDetail ? String(detail) : "Missing" };
}

function handoffChecklistScore(sections = handoffChecklistSections()) {
  const weights = { captured: 1, inferred: 0.68, review: 0.42, missing: 0.08 };
  const items = sections.flatMap((section) => section.items || []);
  if (!items.length) return 0;
  return Math.round((items.reduce((sum, item) => sum + (weights[item.status] || 0), 0) / items.length) * 100);
}

function handoffChecklistColumn(section) {
  const captured = section.items.filter((item) => item.status === "captured").length;
  const sectionScore = Math.round((captured / Math.max(section.items.length, 1)) * 100);
  return `
    <section class="handoff-checklist-column accent-${escapeHtml(section.accent)}">
      <div class="handoff-checklist-column-head">
        <span><i data-lucide="${escapeHtml(section.icon)}"></i></span>
        <div>
          <strong>${escapeHtml(section.title)}</strong>
          <small>${sectionScore}% captured</small>
        </div>
      </div>
      <div class="handoff-checklist-items">
        ${section.items.map((item) => handoffChecklistRow(item)).join("")}
      </div>
    </section>
  `;
}

function handoffChecklistRow(item) {
  return `
    <article class="handoff-checklist-row status-${escapeHtml(item.status)}">
      <div>
        <strong>${escapeHtml(item.label)}</strong>
        <span>${escapeHtml(item.detail)}</span>
      </div>
      <em>${escapeHtml(statusLabel(item.status))}</em>
    </article>
  `;
}

function handoffMiniCard(icon, label, title, detail) {
  return `
    <article class="handoff-mini-card">
      <span><i data-lucide="${escapeHtml(icon)}"></i></span>
      <div>
        <small>${escapeHtml(label)}</small>
        <strong>${escapeHtml(title)}</strong>
        <p>${escapeHtml(detail)}</p>
      </div>
    </article>
  `;
}

function statusLabel(status) {
  if (status === "captured") return "Captured";
  if (status === "inferred") return "Inferred";
  if (status === "review") return "Review";
  return "Missing";
}

function handoffChecklistRows() {
  return [
    ["Audience", "Checklist Item", "Status", "Current Detail"],
    ...handoffChecklistSections().flatMap((section) =>
      section.items.map((item) => [section.title, item.label, statusLabel(item.status), item.detail])
    )
  ];
}

function nextHandoffChecklistGap(focus = state.questionFocus) {
  return rankedHandoffChecklistGaps(focus)[0] || null;
}

function rankedHandoffChecklistGaps(focus = state.questionFocus) {
  const statusWeight = { missing: 0, review: 1, inferred: 2, captured: 9 };
  const sectionWeight = { Engineering: 0, Product: 1, Business: 2, "Governance Inputs": 3 };
  const focusSection = questionFocusSection(focus);
  const itemWeight = {
    "A-Z process skeleton": -5,
    "Step-level matrix": -4,
    "Problem / workflow boundary": -3,
    "Data boundary": -2,
    "Access mode": -2,
    "Commercial context": -1,
    "Frequency and time baseline": -1,
    "Human review gates": -1
  };
  return handoffChecklistSections()
    .flatMap((section) =>
      section.items
        .filter((item) => item.status !== "captured")
        .filter(() => !focusSection || section.title === focusSection)
        .map((item, itemIndex) => ({
          section: section.title,
          item,
          itemIndex,
          rank: (statusWeight[item.status] ?? 5) * 100 + (sectionWeight[section.title] ?? 5) * 10 + (itemWeight[item.label] ?? itemIndex)
        }))
    )
    .sort((a, b) => a.rank - b.rank);
}

function questionFocusSection(focus = state.questionFocus) {
  const lookup = {
    product: "Product",
    engineering: "Engineering",
    business: "Business",
    governance: "Governance Inputs"
  };
  return lookup[validQuestionFocus(focus)] || "";
}

function topHandoffChecklistQuestions(limit = 3, focus = state.questionFocus) {
  const questions = [];
  rankedHandoffChecklistGaps(focus).forEach((gap) => {
    const question = questionForHandoffChecklistGap(gap);
    if (question && !questions.includes(question)) questions.push(question);
  });
  return questions.slice(0, limit);
}

function handoffChecklistQuestionForSection(sectionId) {
  const matches = rankedHandoffChecklistGaps().filter((gap) => sectionForHandoffGap(gap) === sectionId);
  return questionForHandoffChecklistGap(matches[0] || null);
}

function sectionForHandoffGap(gap) {
  if (!gap) return "";
  if (gap.section === "Engineering") return "workflow";
  if (gap.section === "Business") return "value";
  if (gap.section === "Governance Inputs") return "review";
  if (gap.section === "Product") {
    if (/submitted|validated|problem|boundary/i.test(gap.item.label)) return "validate";
    return "blueprint";
  }
  return "review";
}

function questionForHandoffChecklistGap(gap) {
  if (!gap) return "";
  const handoff = buildHandoffQuestions();
  const label = gap.item.label;
  const lookup = {
    Product: {
      "Problem / workflow boundary": "Can you confirm the workflow boundary: what starts it, what final output ends it, and who uses that output?",
      "Submitted ask preserved": "What was the original domain-submitted idea, in the submitter's own words, before we validate or reshape it?",
      "Validated facts separated": "Should we treat the submitted idea as accurate, needing clarification, split across workflows, or not enough evidence yet?",
      "Users and output consumers": "Who performs the work today, who consumes the final output, and what do they need from the experience?",
      "MVP slice": "What is the smallest credible pilot slice Product should define first, before attempting the full workflow?",
      "PDR success metrics": "Which success metrics should go in the PDR: hours saved, cycle time, quality, rework, margin/capacity, reuse, adoption, or client experience?",
      "Product open questions": handoff.product[0]
    },
    Engineering: {
      "A-Z process skeleton": "Can you give the rough numbered A-to-Z process from trigger to final output?",
      "Step-level matrix": firstMatrixGap() ? `For "${firstMatrixGap().stepName}", ${firstMatrixGap().prompt}?` : "Which step still needs actor, tool, data, handoff, timing, or decision detail?",
      "Systems and tools": "Which systems, tools, repositories, templates, trackers, folders, or databases are used in the major steps?",
      "Access mode": "How would an AI solution access the work today: Microsoft 365 files, exports, screenshots, transcripts, direct system access, or user-provided inputs?",
      "Data boundary": "What data is handled at each major step, and is it public, internal, client confidential, regulated, PII, financial, legal, or unknown?",
      "Output contract": "What structured output should the solution produce, and what format or handoff does the downstream reviewer need?",
      "Engineering open questions": handoff.engineering[0]
    },
    Business: {
      "Commercial context": "If you know it, what commercial context should downstream reviewers use; otherwise we can ask Finance, Ops, Account Reporting, PMO, or Product later?",
      "Value path": "Which value signal seems most relevant: speed, quality, rework reduction, risk reduction, reuse, client experience, capacity, or economics?",
      "Frequency and time baseline": "If you know it, how often does this workflow happen, how long does it take today, and where is most of the time spent?",
      "Hours saved / dollars": "If known, what is the first-pass time-saved hypothesis; otherwise Finance or Ops can supplement the value model later?",
      "Capacity / team mix": "Should staffing mix and capacity impact be left for the business or Finance/Ops to estimate later?",
      "Reusable asset signal": "Could the output become a reusable delivery asset across practices, clients, or similar engagements?",
      "Business open questions": handoff.business[0]
    },
    "Governance Inputs": {
      "MSA boundary": "What data boundary applies: internal only, client-approved environment, sanitized artifacts, client data approval, likely MSA review, or unknown?",
      "Deployment environment": "Where would the solution run: company internal, client VDI, client tenant, approved sandbox, on-prem/restricted, SaaS approved tool, or unknown?",
      "Post-build review route": "Which later review path is likely needed: standard AI, privacy, model risk, cyber, legal/MSA, client approval, or multiple?",
      "Human review gates": "Where must accountable human review, approval, escalation, or quality control remain in the workflow?",
      "Evidence trace": "What evidence, citations, source notes, or review trail would Product and Engineering need before piloting this?",
      "Risk flags": "What is the biggest risk or exception that could make this workflow unsafe, unreliable, or poor fit for AI?",
      "Governance input questions": handoff.governance[0]
    }
  };
  return lookup[gap.section]?.[label] || `${gap.section} handoff gap: can you clarify ${label.toLowerCase()}?`;
}

function renderHandoffSnapshot() {
  if (!els.handoffSnapshot) return;
  const snapshot = buildHandoffSnapshot();
  els.handoffSnapshot.innerHTML = `
    <section class="handoff-snapshot-hero">
      <div>
        <p class="eyebrow">Product / Engineering Snapshot</p>
        <h3>${escapeHtml(snapshot.title)}</h3>
        <p>${escapeHtml(snapshot.summary)}</p>
      </div>
      <div class="handoff-status-stack">
        <span>${escapeHtml(snapshot.category)}</span>
        <strong>${snapshot.readiness}%</strong>
        <small>${escapeHtml(snapshot.label)}</small>
      </div>
    </section>
    <div class="handoff-snapshot-grid">
      ${handoffSnapshotColumn("Product", "package-check", snapshot.product)}
      ${handoffSnapshotColumn("Engineering", "wrench", snapshot.engineering)}
      ${handoffSnapshotColumn("Governance Inputs", "shield-check", snapshot.governance)}
    </div>
    <section class="handoff-completion-strip">
      <div>
        <p class="eyebrow">Finish The Intake</p>
        <h3>Questions before Product/Engineering handoff</h3>
      </div>
      <ol>${snapshot.completionQuestions.map((question) => `<li>${escapeHtml(question)}</li>`).join("")}</ol>
    </section>
  `;
  refreshIcons();
}

function handoffSnapshotColumn(title, icon, rows) {
  return `
    <article class="handoff-snapshot-column">
      <h4><i data-lucide="${icon}"></i>${escapeHtml(title)}</h4>
      <dl>
        ${rows.map(([label, value]) => `
          <div>
            <dt>${escapeHtml(label)}</dt>
            <dd>${escapeHtml(value || "TBD")}</dd>
          </div>
        `).join("")}
      </dl>
    </article>
  `;
}

function buildHandoffSnapshot() {
  const review = buildReviewGate();
  const blueprint = buildSolutionBlueprint();
  const systems = summarizedSystems();
  const outputs = summarizedOutputs();
  const title = state.fields.workflowName || state.fields.submittedWorkflowTask || "Workflow not named";
  const summary = `${state.fields.businessOutcome || "A time-heavy workflow"} in ${state.fields.workflowCategory || "an unclassified category"} with value path ${state.fields.commercialValuePath || "TBD"}.${workshopUseCaseContext() ? ` ${workshopUseCaseContext()}` : ""}`;
  return {
    title,
    summary,
    category: state.fields.workflowCategory || "unknown",
    readiness: review.overall,
    label: review.label,
    completionQuestions: review.completionQuestions.length ? review.completionQuestions : ["No major completion questions captured."],
    product: [
      ["Problem", state.fields.businessOutcome || state.fields.valueHypothesis || "Define the business outcome and value hypothesis."],
      ["MVP slice", state.fields.mvpScope || blueprint.mvpSlice],
      ["Value path", state.fields.commercialValuePath || "TBD"],
      ["Success proof", state.fields.successMetrics || "Hours saved, cycle time, quality, margin/capacity, reuse, and adoption."]
    ],
    engineering: [
      ["Data boundary", dataSignalLabel()],
      ["Systems/access", systems],
      ["Output contract", outputs],
      ["Tool path", state.fields.toolFitRecommendation || blueprint.toolStack]
    ],
    governance: [
      ["Controls", recommendedControls()],
      ["Human review", state.fields.humanJudgmentArea || summarizedDecisions()],
      ["Post-build review input", state.fields.engineeringUnknowns || review.handoff.governance[0] || "Confirm data policy and evidence trail."],
      ["Evidence status", (state.evidenceArtifacts || []).length ? `${state.evidenceArtifacts.length} optional artifact(s) uploaded` : "No optional evidence uploaded."]
    ]
  };
}

function summarizedSystems() {
  const systems = [
    ...state.systems.map((item) => item.name),
    ...state.steps.map((step) => step.tool)
  ]
    .flatMap((value) => String(value || "").split(/[,;/]/))
    .map((value) => value.trim())
    .filter(Boolean);
  const unique = [...new Set(systems.map((item) => item.toLowerCase()))]
    .map((key) => systems.find((item) => item.toLowerCase() === key))
    .slice(0, 6);
  return unique.length ? unique.join(", ") : "Source systems and access modes need confirmation.";
}

function summarizedOutputs() {
  const outputs = state.steps.map((step) => step.output).filter(isCapturedValue).slice(0, 4);
  return state.fields.definitionOfDone || outputs.join("; ") || "Final output / definition of done needs confirmation.";
}

function summarizedDecisions() {
  const decisions = [
    ...state.decisions.map((item) => item.decision || item.approval),
    ...state.steps.map((step) => step.decision)
  ].filter(isCapturedValue);
  return decisions.length ? decisions.slice(0, 3).join("; ") : "Human review and approval path needs confirmation.";
}

function handoffSnapshotRows() {
  const snapshot = buildHandoffSnapshot();
  return [
    ["Area", "Field", "Content"],
    ["Summary", "Workflow", snapshot.title],
    ["Summary", "Category", snapshot.category],
    ["Summary", "Readiness", `${snapshot.readiness}% - ${snapshot.label}`],
    ...snapshot.product.map(([label, value]) => ["Product", label, value]),
    ...snapshot.engineering.map(([label, value]) => ["Engineering", label, value]),
    ...snapshot.governance.map(([label, value]) => ["Governance Inputs", label, value]),
    ...snapshot.completionQuestions.map((question, index) => ["Completion Questions", `Question ${index + 1}`, question])
  ];
}

