function buildPilotRoundTracker(options = {}) {
  const currentSessionId = state.sessionMeta?.id || "";
  const currentSessionPackages = serverPackages.filter((item) => item.summary?.id === currentSessionId);
  const currentSessionPackageCount = currentSessionPackages.length + (options.packagePending ? 1 : 0);
  const feedbackCount = (state.pilotFeedbackLog || []).length;
  const packageRunCount = Math.min(currentSessionPackageCount, 4);
  const feedbackRunCount = Math.min(feedbackCount, 4);
  const totalPackageCount = serverPackages.length + (options.packagePending ? 1 : 0);
  const runs = [
    {
      label: "Run 1 - Dry benchmark",
      owner: "Facilitator + AI Infusion reviewer",
      pattern: "Strategy/workshop prep or other low-technical-density workflow",
      evidenceTarget: "Question behavior, transcript clarity, package completeness, and no confirmation loops.",
      passSignal: "Tester can follow the current question and outputs show useful Product, Engineering, and Business gaps."
    },
    {
      label: "Run 2 - Technical delivery",
      owner: "Tech/Engineering, QA, or delivery SME",
      pattern: "UAT, test generation, CI triage, requirements traceability, or architecture/risk assessment.",
      evidenceTarget: "Systems/tools, access mode, data boundary, step matrix, and Engineering Brief quality.",
      passSignal: "Engineering output names source access, constraints, logs/audit needs, and a realistic MVP path."
    },
    {
      label: "Run 3 - Data/document-heavy work",
      owner: "Data, risk, operations, FRRF, or delivery-management SME",
      pattern: "Tracker review, document extraction, CRM upload, analytics synthesis, or governance summaries.",
      evidenceTarget: "Input/output contract, data sensitivity, evidence trace, human review, and value baseline.",
      passSignal: "Business Value and governance-input sections identify baseline, sensitivity, review, and reusable asset signal."
    },
    {
      label: "Run 4 - Real colleague use case",
      owner: "Practice/domain SME + Product or AI Infusion reviewer",
      pattern: "Sanitized real workflow from a colleague outside the build team.",
      evidenceTarget: "Real-world usability, missing-question quality, package shareability, and reviewer confidence.",
      passSignal: "At least one reviewer says the package is a credible starting point for Product/Engineering discussion."
    }
  ].map((run, index) => ({
    ...run,
    status: pilotRunStatus(index, packageRunCount, feedbackRunCount, options.packagePending)
  }));
  const readyRuns = runs.filter((run) => run.status === "Evidence captured").length;
  return {
    runs,
    feedbackCount,
    feedbackRunCount,
    currentSessionPackageCount,
    packageRunCount,
    totalPackageCount,
    recentPackages: serverPackages.slice(0, 5),
    nextAction: pilotRoundNextAction(runs, feedbackCount, currentSessionPackageCount),
    decisionRule: `${readyRuns}/4 runs have both a package and feedback. Move beyond the MVP pilot only when at least 3 of 4 runs produce useful packages, feedback is saved, and no restricted client data was used.`
  };
}

function pilotRunStatus(index, packageRunCount, feedbackRunCount, packagePending) {
  const furthestStartedRun = Math.max(packageRunCount, feedbackRunCount);
  if (index < packageRunCount && index < feedbackRunCount) return "Evidence captured";
  if (index < packageRunCount && index >= feedbackRunCount) return "Needs feedback";
  if (index < feedbackRunCount && index >= packageRunCount) return "Needs package";
  if (index === furthestStartedRun && packagePending) return "Package being created";
  if (index === furthestStartedRun) return "Next run";
  return "Planned";
}

function pilotRoundNextAction(runs, feedbackCount, currentSessionPackageCount) {
  const nextRun = runs.find((run) => run.status === "Next run" || run.status === "Package being created");
  if (currentSessionPackageCount > feedbackCount) return "Save feedback for the latest packaged run before starting another session.";
  if (!feedbackCount) return "Run the dry benchmark, save one feedback snapshot, then create a package.";
  if (currentSessionPackageCount < feedbackCount) return "Create a package for the latest feedback snapshot before starting another session.";
  if (nextRun) return `Prepare ${nextRun.label.toLowerCase()} and invite the matching SME.`;
  return "Review the four-run evidence set with Product, Engineering, and Business reviewers.";
}

function renderPilotRoundTrackerCard() {
  const tracker = buildPilotRoundTracker();
  return `
    <section class="pilot-round-tracker">
      <div class="pilot-round-head">
        <div>
          <p class="eyebrow">Pilot Round Tracker</p>
          <h3>Track the first four MVP tests</h3>
          <p>${escapeHtml(tracker.nextAction)}</p>
        </div>
        <div class="pilot-round-stats">
          <span>${tracker.feedbackRunCount}/4 feedback</span>
          <span>${tracker.packageRunCount}/4 packages</span>
        </div>
      </div>
      <div class="pilot-round-grid">
        ${tracker.runs.map((run) => `
          <article class="${escapeHtml(fileSafe(run.status))}">
            <div>
              <strong>${escapeHtml(run.label)}</strong>
              <span>${escapeHtml(run.status)}</span>
            </div>
            <p>${escapeHtml(run.pattern)}</p>
            <small>${escapeHtml(run.passSignal)}</small>
          </article>
        `).join("")}
      </div>
      <div class="pilot-round-footer">
        <span><i data-lucide="folder-clock"></i> ${tracker.totalPackageCount} local package${tracker.totalPackageCount === 1 ? "" : "s"} indexed</span>
        <small>${escapeHtml(tracker.decisionRule)}</small>
      </div>
    </section>
  `;
}

