function buildLiveTestScriptSections() {
  const workflowName = state.fields.workflowName || state.fields.submittedWorkflowTask || "this workflow";
  const category = state.fields.workflowCategory && state.fields.workflowCategory !== "unknown" ? state.fields.workflowCategory : "the workflow category";
  const topQuestion = topCompletionQuestions(1)[0] || "What is the most important missing detail before handoff?";
  const context = workshopUseCaseContext();
  return [
    {
      title: "Opening Script",
      icon: "messages-square",
      summary: "Use this language to set expectations before the colleague starts answering.",
      items: [
        {
          prompt: "Thanks for helping test this discovery flow. We are testing whether the app can capture a real workflow and turn it into Product, Engineering, and Business handoff outputs.",
          observe: "The tester understands this is a usability test and not a commitment to build a solution.",
          pass: "Tester can restate the goal in plain language."
        },
        {
          prompt: `Today we will use ${workflowName}. I will avoid raw client data and use categories, sanitized examples, or synthetic details where needed.`,
          observe: "The data boundary feels clear and not intimidating.",
          pass: "Tester knows what details are safe to share."
        },
        {
          prompt: context || `The current category is ${category}. We want to see whether the app can handle this category without forcing it into a generic client-delivery shape.`,
          observe: "The tester sees the use case in the right business context.",
          pass: "Tester agrees the app's category framing is reasonable."
        }
      ]
    },
    {
      title: "Discovery Tasks",
      icon: "mic-2",
      summary: "Run these tasks while watching whether the participant knows what to say next.",
      items: [
        {
          prompt: "Ask the tester for the rough A-to-Z workflow in numbered steps before drilling into tools or AI ideas.",
          observe: "The app keeps the conversation anchored on the current-state workflow.",
          pass: "At least three steps appear with useful names."
        },
        {
          prompt: "For one important step, ask who does it, what tools or files they use, what input/output exists, how long it takes, and where human judgment happens.",
          observe: "The app captures matrix detail without making the tester feel like they are filling a form.",
          pass: "Actor, system/tool, input/output, time, and decision detail are visible or clearly requested."
        },
        {
          prompt: topQuestion,
          observe: "The next-best question is specific enough to answer and relevant to the handoff.",
          pass: "Tester answers without needing the facilitator to translate the question."
        }
      ]
    },
    {
      title: "Output Review",
      icon: "files",
      summary: "Use this after Discovery to inspect whether the app produced useful handoff material.",
      items: [
        {
          prompt: "Open Outputs and review Product PDR, Engineering Brief, Business Value, and governance inputs.",
          observe: "Tester can tell which output goes to which owner lane.",
          pass: "Tester identifies at least one useful Product point and one useful Engineering point."
        },
        {
          prompt: "Ask what is inferred versus actually validated by the tester.",
          observe: "The app makes assumptions visible enough to challenge.",
          pass: "Tester can name one assumption to confirm or correct."
        },
        {
          prompt: "Create the package and confirm the live-test plan, feedback, and handoff outputs are included.",
          observe: "The package feels like something an AI Infusion operator could share internally.",
          pass: "Package includes live-test plan, Product PDR, Engineering Brief, Business Value, and question routing."
        }
      ]
    },
    {
      title: "Feedback Rubric",
      icon: "clipboard-check",
      summary: "Score immediately after the session, then save one feedback snapshot.",
      items: [
        {
          prompt: "Interview flow: 1 = confusing, 3 = usable with guidance, 5 = natural enough for another colleague test.",
          observe: "Whether the tester always knew the current question and what to answer.",
          pass: "Score 3 or higher with concrete notes."
        },
        {
          prompt: "Output usefulness: 1 = not useful, 3 = partial draft, 5 = credible handoff starting point.",
          observe: "Whether Product, Engineering, and Business outputs reduce manual synthesis work.",
          pass: "Tester finds at least two outputs worth keeping."
        },
        {
          prompt: "Enterprise readiness: 1 = unclear data/control path, 3 = local test only, 5 = clear enough to plan controlled company pilot.",
          observe: "Whether storage, data classification, permissions, and governance input capture are understandable.",
          pass: "Tester can name the next control or approval needed without over-weighting governance."
        }
      ]
    }
  ];
}

