function buildPilotInsights() {
  const signals = pilotFeedbackSignals();
  const feedbackCount = signals.length;
  const ratings = signals.map((item) => ratingToNumber(item.experienceRating)).filter((value) => value > 0);
  const averageRating = ratings.length ? ratings.reduce((sum, value) => sum + value, 0) / ratings.length : 0;
  const decisions = countValues(signals.map((item) => item.decision).filter(isCapturedValue));
  const primaryDecision = Object.entries(decisions).sort((a, b) => b[1] - a[1])[0]?.[0] || "Needs iteration";
  const themes = buildPilotInsightThemes(signals);
  const actions = buildPilotImprovementActions(signals, themes, primaryDecision);
  return {
    feedbackCount,
    averageRating,
    averageRatingLabel: ratings.length ? `${averageRating.toFixed(1)} / 5` : "Not rated",
    ratingSummary: ratingSummary(averageRating, feedbackCount),
    primaryDecision,
    decisionSummary: decisionSummary(primaryDecision, feedbackCount),
    nextExperiment: nextPilotExperiment(primaryDecision, themes),
    themes,
    actions
  };
}

function pilotFeedbackSignals() {
  const draft = currentPilotFeedback();
  const log = state.pilotFeedbackLog || [];
  const draftHasContent = pilotFeedbackFields.some(([key]) => isCapturedValue(draft[key]));
  return [
    ...log,
    ...(draftHasContent ? [{ ...draft, savedAt: draft.updatedAt || "Draft" }] : [])
  ];
}

function ratingToNumber(value) {
  const match = String(value || "").match(/^([1-5])/);
  return match ? Number(match[1]) : 0;
}

function countValues(values) {
  return values.reduce((counts, value) => {
    counts[value] = (counts[value] || 0) + 1;
    return counts;
  }, {});
}

function ratingSummary(averageRating, count) {
  if (!count) return "No feedback snapshots yet. Save feedback after the next pilot test.";
  if (!averageRating) return "Feedback exists, but no experience rating has been selected yet.";
  if (averageRating >= 4) return "Early experience signal is strong. Focus next on output polish and enterprise readiness.";
  if (averageRating >= 3) return "The app is usable, but the next phase should reduce friction before broader testing.";
  return "The app needs another usability pass before a broader colleague pilot.";
}

function decisionSummary(primaryDecision, count) {
  if (!count) return "No pilot decision captured yet.";
  if (primaryDecision.includes("Ready")) return "Feedback suggests this can move toward a handoff review, with caveats captured below.";
  if (primaryDecision.includes("Run another")) return "Feedback suggests another controlled test is the right next move.";
  if (primaryDecision.includes("Pause")) return "Feedback suggests the use case or experience needs rethinking before continuing.";
  return "Feedback suggests focused iteration before expanding the pilot.";
}

function buildPilotInsightThemes(signals) {
  const themeConfig = [
    ["Interview Flow", "interviewFlow", "workflow"],
    ["Voice Experience", "voiceExperience", "mic-2"],
    ["Question Quality", "questionQuality", "message-circle-question"],
    ["Output Usefulness", "outputUsefulness", "file-check-2"],
    ["Confusing Moments", "confusingMoments", "circle-help"],
    ["Missing Questions", "missingQuestions", "list-plus"],
    ["Product / Engineering Gaps", "productEngineeringGaps", "wrench"],
    ["Enterprise Concerns", "enterpriseConcerns", "shield-alert"]
  ];
  return themeConfig.map(([label, key, icon]) => {
    const notes = signals.map((item) => item[key]).filter(isCapturedValue);
    const latest = notes[0] || "";
    const concernTheme = ["confusingMoments", "missingQuestions", "productEngineeringGaps", "enterpriseConcerns"].includes(key);
    const level = !signals.length ? "empty" : notes.length && concernTheme ? "risk" : notes.length ? "signal" : "quiet";
    const status = !signals.length ? "No feedback yet" : notes.length ? `${notes.length} signal${notes.length === 1 ? "" : "s"}` : "No issue captured";
    return {
      label,
      key,
      icon,
      status,
      level,
      signal: latest ? truncateUi(latest, 150) : "No feedback captured for this area yet."
    };
  });
}

function buildPilotImprovementActions(signals, themes, primaryDecision) {
  if (!signals.length) {
    return [
      {
        title: "Run one structured colleague pilot",
        detail: "Use Banking, Insurance, or the cross-practice workshop prep case as the walkthrough and save feedback immediately after the test."
      },
      {
        title: "Capture one feedback snapshot per session",
        detail: "Use Review to log what was confusing, what worked, and what Product/Engineering still needed."
      }
    ];
  }
  const hasTheme = (key) => themes.some((theme) => theme.key === key && theme.level === "risk");
  const actions = [];
  if (hasTheme("confusingMoments") || hasTheme("questionQuality")) {
    actions.push({
      title: "Simplify the discovery conversation prompts",
      detail: "Reduce ambiguity in the current question, answer summary, and next best question so the user always knows what they are answering."
    });
  }
  if (hasTheme("voiceExperience")) {
    actions.push({
      title: "Tune the voice turn-taking experience",
      detail: "Refine start/stop cues, AI acknowledgement, and spoken summary timing so voice mode feels calmer and more natural."
    });
  }
  if (hasTheme("outputUsefulness") || hasTheme("productEngineeringGaps")) {
    actions.push({
      title: "Tighten Product and Engineering handoff translation",
      detail: "Make inferred facts, validated facts, open questions, and build assumptions easier to inspect before export."
    });
  }
  if (hasTheme("missingQuestions")) {
    actions.push({
      title: "Add missing-question patterns to the interview logic",
      detail: "Convert recurring missing questions into guided follow-ups for workflow steps, value metrics, data policy, and human review."
    });
  }
  if (hasTheme("enterpriseConcerns")) {
    actions.push({
      title: "Strengthen enterprise readiness controls",
      detail: "Clarify data classification, evidence policy, storage target, auth path, retention, and audit expectations before broader rollout."
    });
  }
  if (primaryDecision.includes("Run another")) {
    actions.push({
      title: "Run the next pilot on a different workflow category",
      detail: "Use one client delivery case and one pre-delivery/workshop case to confirm the app is not overfit to one workflow type."
    });
  }
  if (!actions.length) {
    actions.push({
      title: "Prepare Product review package",
      detail: "Feedback does not show a major blocker. Review completion questions, Pilot Controls, and the PDR draft before sharing."
    });
  }
  return actions.slice(0, 5);
}

function nextPilotExperiment(primaryDecision, themes) {
  if (themes.some((theme) => theme.key === "voiceExperience" && theme.level === "risk")) return "Voice-only pilot";
  if (themes.some((theme) => theme.key === "productEngineeringGaps" && theme.level === "risk")) return "Handoff review pilot";
  if (themes.some((theme) => theme.key === "enterpriseConcerns" && theme.level === "risk")) return "Governance review pilot";
  if (primaryDecision.includes("Ready")) return "Product review";
  if (primaryDecision.includes("Run another")) return "Cross-domain pilot";
  return "Focused usability pilot";
}

