function currentPilotFeedbackTarget() {
  const tracker = buildPilotRoundTracker();
  const targetRun =
    tracker.runs.find((run) => run.status === "Needs feedback") ||
    tracker.runs.find((run) => run.status === "Next run" || run.status === "Needs package") ||
    tracker.runs[0];
  const currentSessionId = state.sessionMeta?.id || "";
  const packageItem = currentSessionId ? serverPackages.find((item) => item.summary?.id === currentSessionId) : null;
  const packagePath = state.sessionMeta?.lastPackagePath || packageItem?.relativePath || "";
  const needsFeedback = targetRun?.status === "Needs feedback";
  const hasTestActivity = hasFeedbackEligibleTestActivity();
  if (!hasTestActivity && !packagePath) {
    return {
      runLabel: "No self-test yet",
      status: "Waiting",
      packagePath: "",
      packageName: "",
      needsFeedback: false,
      notStarted: true,
      summary: "Run a self-test first. This panel is only for saving what you noticed after using Discovery, Outputs, downloads, or package creation.",
      questions: [
        "After the self-test, could you follow the current question and know what to answer next?",
        "After reviewing Outputs, what was useful, missing, repetitive, or confusing?",
        "What should change before the next self-test or colleague share test?"
      ]
    };
  }
  return {
    runLabel: targetRun?.label || "Next pilot run",
    status: targetRun?.status || "Planned",
    packagePath,
    packageName: packageItem?.packageName || "",
    needsFeedback,
    summary: needsFeedback
      ? "A package exists for this run. Save feedback before starting another session."
      : packagePath
        ? "Package is available; save feedback after reviewing it."
        : "Create a package after the next test, then save feedback against it.",
    questions: [
      "Could you follow the current question and know what to answer next?",
      "Did Product, Engineering, and Business outputs contain useful draft material or clear gaps?",
      "What was confusing, missing, repetitive, or over-weighted?",
      "Should the next move be another pilot, Product review, Engineering review, or app iteration?"
    ]
  };
}

function hasFeedbackEligibleTestActivity() {
  const live = currentPilotLiveTest();
  return Boolean(
    live.startedAt ||
    live.completedAt ||
    state.sessionMeta?.lastPackagePath ||
    (isCapturedValue(state.fields.submittedIdea) || isCapturedValue(state.fields.submittedWorkflowTask)) ||
    state.steps.length ||
    (state.conversation || []).some((message) => message.role === "user") ||
    (state.aiChat || []).some((message) => message.role === "user")
  );
}

function renderPilotFeedbackRequest(target) {
  const level = target.notStarted ? "not-started" : target.needsFeedback ? "needs-feedback" : "ready";
  return `
    <article class="pilot-feedback-request ${level}">
      <div class="pilot-feedback-request-head">
        <span><i data-lucide="${target.notStarted ? "play-circle" : target.needsFeedback ? "message-square-warning" : "message-square-check"}"></i></span>
        <div>
          <p class="eyebrow">Feedback Target</p>
          <h3>${escapeHtml(target.notStarted ? "Nothing to score yet" : target.needsFeedback ? "Review the latest package before the next run" : "Use this after the next self-test")}</h3>
          <p>${escapeHtml(target.summary)}</p>
        </div>
      </div>
      <div class="pilot-feedback-target-meta">
        <span>${escapeHtml(target.runLabel)}</span>
        <span>${escapeHtml(target.packagePath || "No package yet")}</span>
      </div>
      <ol>
        ${target.questions.map((question) => `<li>${escapeHtml(question)}</li>`).join("")}
      </ol>
    </article>
  `;
}

function feedbackSummaryText(feedback = {}) {
  const worked = truncateUi(feedback.questionsThatWorked || "", 80);
  const confusing = truncateUi(feedback.confusingMoments || "", 80);
  if (worked && confusing) return `Worked: ${worked} | Confusing: ${confusing}`;
  if (worked) return `Worked: ${worked}`;
  if (confusing) return `Confusing: ${confusing}`;
  return "Capture what felt smooth, what confused the tester, and what Product/Engineering still needed.";
}

function pilotFeedbackInput([key, label, type = "input", options = []], feedback) {
  const value = feedback[key] || "";
  if (type === "select") {
    return `
      <label class="pilot-feedback-field">
        <span>${escapeHtml(label)}</span>
        <select data-pilot-feedback="${escapeHtml(key)}">
          ${options.map((option) => `<option value="${escapeHtml(option)}"${option === value ? " selected" : ""}>${escapeHtml(option)}</option>`).join("")}
        </select>
      </label>
    `;
  }
  if (type === "textarea") {
    return `
      <label class="pilot-feedback-field wide">
        <span>${escapeHtml(label)}</span>
        <textarea rows="3" data-pilot-feedback="${escapeHtml(key)}">${escapeHtml(value)}</textarea>
      </label>
    `;
  }
  return `
    <label class="pilot-feedback-field">
      <span>${escapeHtml(label)}</span>
      <input type="text" value="${escapeHtml(value)}" data-pilot-feedback="${escapeHtml(key)}" />
    </label>
  `;
}

function pilotFeedbackLogCard(item = {}) {
  return `
    <article class="feedback-log-card">
      <div>
        <strong>${escapeHtml(item.decision || "Decision TBD")}</strong>
        <span>${escapeHtml(item.experienceRating || "Not rated")} | ${escapeHtml(item.reviewerName || "Unnamed reviewer")}</span>
      </div>
      <p>${escapeHtml(feedbackSummaryText(item))}</p>
      <small>${escapeHtml(formatDateTime(item.savedAt))} | ${escapeHtml(item.pilotRunLabel || item.pilotScenario || "Pilot scenario TBD")}${item.packagePath ? ` | ${escapeHtml(item.packagePath)}` : ""}</small>
    </article>
  `;
}

function updatePilotFeedbackFromEvent(event) {
  const key = event.target?.dataset?.pilotFeedback;
  if (!key) return;
  const feedback = currentPilotFeedback();
  feedback[key] = event.target.value;
  feedback.updatedAt = new Date().toISOString();
  persistState();
}

function handlePilotFeedbackClick(event) {
  const button = event.target.closest("[data-feedback-action]");
  if (!button) return;
  if (button.dataset.feedbackAction === "save") {
    savePilotFeedbackSnapshot();
    return;
  }
  if (button.dataset.feedbackAction === "clear") {
    state.pilotFeedback = structuredClone(defaultState.pilotFeedback);
    persistState();
    renderPilotFeedback();
    toast("Pilot feedback draft cleared.");
  }
}

function savePilotFeedbackSnapshot() {
  const feedback = currentPilotFeedback();
  const hasContent = hasSubstantivePilotFeedback(feedback);
  if (!hasContent) {
    toast("Add a rating, reviewer note, or decision change before saving feedback.");
    return false;
  }
  const target = currentPilotFeedbackTarget();
  const snapshot = {
    ...structuredClone(defaultState.pilotFeedback),
    ...feedback,
    id: makeId("feedback"),
    pilotRunLabel: target.runLabel,
    packagePath: target.packagePath,
    savedAt: new Date().toISOString()
  };
  state.pilotFeedbackLog = [snapshot, ...(state.pilotFeedbackLog || [])].slice(0, 25);
  state.pilotFeedback.updatedAt = snapshot.savedAt;
  persistState();
  renderPilotFeedback();
  renderPilotInsights();
  renderLiveTestCommandCenter();
  toast("Pilot feedback snapshot saved.");
  return true;
}

function hasSubstantivePilotFeedback(feedback = {}) {
  const textKeys = [
    "reviewerName",
    "reviewerRole",
    "interviewFlow",
    "voiceExperience",
    "questionQuality",
    "outputUsefulness",
    "confusingMoments",
    "questionsThatWorked",
    "missingQuestions",
    "productEngineeringGaps",
    "enterpriseConcerns",
    "recommendedChanges"
  ];
  const hasText = textKeys.some((key) => isCapturedValue(feedback[key]));
  const hasRating = ratingToNumber(feedback.experienceRating) > 0;
  const decisionChanged = isCapturedValue(feedback.decision) && feedback.decision !== defaultState.pilotFeedback.decision;
  return hasText || hasRating || decisionChanged;
}

