function addonCopyText(kind) {
  const runbook = deriveAddOnSetupRunbook();
  if (kind === "restart") return runbook.restartCommand;
  return runbook.envPlaceholderBlock;
}

function addOnStatusTone(provider) {
  if (provider.configured) return "configured";
  if (provider.status === "included" || provider.defaultUse === "native") return "included";
  return "needs-setup";
}

function addOnStatusLabel(provider) {
  if (provider.configured) return "Configured";
  if (provider.status === "included") return "Included";
  if (provider.defaultUse === "native") return "Native";
  return "Needs setup";
}

function recommendedAddOnRolloutPath(status = getAddOnProviderStatus()) {
  const providers = status.providers || [];
  const hasOpenAi = providers.some((provider) => provider.id === "openai-responses" && provider.configured);
  const hasDocIntel = providers.some((provider) => ["azure-document-intelligence", "llamaparse", "mistral-ocr"].includes(provider.id) && provider.configured);
  const hasPrivacy = providers.some((provider) => ["presidio-pii", "azure-ai-language-pii"].includes(provider.id) && provider.configured);
  return [
    {
      phase: "1",
      action: hasOpenAi ? "Use current OpenAI intake and extraction as the default path." : "Finish OpenAI API setup before enabling AI extraction.",
      reason: "OpenAI-native capture, transcription, and workflow reasoning keep the MVP small and controllable."
    },
    {
      phase: "2",
      action: hasDocIntel ? "Benchmark document extraction against uploaded PDFs, DOCX, XLSX, and screenshots." : "Add enterprise document intelligence after the work tenant approves it.",
      reason: "Consulting workflows often arrive as decks, trackers, SOPs, and screenshots; better extraction improves the recipe and workflow map."
    },
    {
      phase: "3",
      action: hasPrivacy ? "Run evidence through PII/privacy checks before package export." : "Choose a PII review path before using client-sensitive artifacts.",
      reason: "The app should make evidence useful while keeping client, employee, and regulated data reviewable."
    },
    {
      phase: "4",
      action: "Add evals/tracing only after pilot criteria are stable.",
      reason: "Observability is most useful once there are repeatable test transcripts and reviewer scoring rubrics."
    }
  ];
}

async function handleAddOnTestAction(event) {
  const copyButton = event.target.closest("[data-addon-copy]");
  if (copyButton) {
    await copyAddOnSetupText(copyButton.dataset.addonCopy || "env");
    return;
  }

  const runButton = event.target.closest("[data-addon-test-run]");
  const providerButton = event.target.closest("[data-addon-test-provider]");
  if (!runButton && !providerButton) return;

  const providerId = providerButton?.dataset.addonTestProvider || "";
  const mode = runButton?.dataset.addonTestRun || providerButton?.dataset.addonTestMode || "config";
  const allowLiveChecks = mode === "live";
  if (allowLiveChecks) {
    const proceed = confirm("Run safe live provider checks? This will ping configured external provider APIs, but it will not send workflow content, files, screenshots, or secrets to the browser.");
    if (!proceed) return;
  }
  await runAddOnProviderTests({ providerId, allowLiveChecks });
}

async function runAddOnProviderTests({ providerId = "", allowLiveChecks = false } = {}) {
  const existingResults = addOnTestRun.results || [];
  addOnTestRun = {
    status: "running",
    allowLiveChecks,
    summary: null,
    results: existingResults,
    checkedAt: new Date().toISOString()
  };
  renderOperatorAddOnsPanel();
  try {
    const payload = await requestJson("/api/add-ons/test", {
      method: "POST",
      body: {
        providerId,
        allowLiveChecks
      }
    });
    const incomingResults = Array.isArray(payload.results) ? payload.results : [];
    const previous = providerId
      ? existingResults.filter((result) => result.id !== providerId)
      : [];
    addOnTestRun = {
      status: "complete",
      allowLiveChecks: Boolean(payload.allowLiveChecks),
      summary: providerId ? summarizeClientAddOnTestResults([...previous, ...incomingResults]) : payload.summary,
      results: providerId ? [...previous, ...incomingResults] : incomingResults,
      checkedAt: payload.checkedAt || new Date().toISOString()
    };
    toast(allowLiveChecks ? "Safe live add-on checks complete." : "Add-on configuration checks complete.");
  } catch (error) {
    addOnTestRun = {
      status: "error",
      allowLiveChecks,
      summary: null,
      results: [],
      checkedAt: new Date().toISOString()
    };
    toast(`Add-on check failed: ${error.message}`);
  }
  renderOperatorAddOnsPanel();
}

async function copyAddOnSetupText(kind) {
  const text = addonCopyText(kind);
  try {
    await navigator.clipboard.writeText(text);
    toast(kind === "restart" ? "Restart command copied." : "Add-on env placeholder block copied.");
  } catch {
    const textarea = document.createElement("textarea");
    textarea.value = text;
    textarea.setAttribute("readonly", "true");
    textarea.style.position = "fixed";
    textarea.style.left = "-9999px";
    document.body.appendChild(textarea);
    textarea.select();
    document.execCommand("copy");
    textarea.remove();
    toast(kind === "restart" ? "Restart command copied." : "Add-on env placeholder block copied.");
  }
}

function summarizeClientAddOnTestResults(results = []) {
  return {
    total: results.length,
    passed: results.filter((result) => result.testStatus === "passed").length,
    configured: results.filter((result) => result.testStatus === "configured").length,
    missingConfig: results.filter((result) => result.testStatus === "missing-config").length,
    failed: results.filter((result) => result.testStatus === "failed").length,
    skipped: results.filter((result) => result.testStatus === "skipped").length
  };
}

function renderEvidenceWorkbench() {
  ensureEvidenceWorkbenchState();
  const artifacts = state.evidenceArtifacts || [];
  if (els.evidenceNoteInput && document.activeElement !== els.evidenceNoteInput) {
    els.evidenceNoteInput.value = state.evidenceWorkbench.draftText || "";
  }
  if (els.evidenceWorkbenchMetrics) {
    els.evidenceWorkbenchMetrics.innerHTML = evidenceWorkbenchMetricsHtml(artifacts);
  }
  if (!els.evidenceWorkbench && !els.evidenceWorkbenchFull) return;
  if (!artifacts.length) {
    const empty = `
      <div class="evidence-empty compact-evidence-empty">
        <i data-lucide="paperclip"></i>
        <div>
          <strong>No evidence uploaded yet</strong>
          <span>Optional add-on only. Use evidence when a screenshot, tracker, process doc, or note would improve confidence.</span>
        </div>
      </div>
    `;
    if (els.evidenceWorkbench) els.evidenceWorkbench.innerHTML = empty;
    if (els.evidenceWorkbenchFull) els.evidenceWorkbenchFull.innerHTML = empty;
    refreshIcons();
    return;
  }
  if (els.evidenceWorkbench) {
    els.evidenceWorkbench.innerHTML = `
    <div class="evidence-workbench-grid compact-evidence-grid">
      ${artifacts.map((artifact) => evidenceArtifactCard(artifact, "compact")).join("")}
    </div>
  `;
    bindEvidenceActions(els.evidenceWorkbench);
  }
  if (els.evidenceWorkbenchFull) {
    els.evidenceWorkbenchFull.innerHTML = `
      <div class="evidence-workbench-grid full-evidence-grid">
        ${artifacts.map((artifact) => evidenceArtifactCard(artifact, "full")).join("")}
      </div>
    `;
    bindEvidenceActions(els.evidenceWorkbenchFull);
  }
  refreshIcons();
}

function evidenceWorkbenchMetricsHtml(artifacts = state.evidenceArtifacts || []) {
  const stats = evidenceWorkbenchStats(artifacts);
  return `
    <div class="evidence-metric-strip">
      ${evidenceMetricCard("Artifacts", stats.total, "paperclip", `${stats.reviewed} reviewed`)}
      ${evidenceMetricCard("Apply queue", stats.readyToApply, "search-check", `${stats.suggestions} suggestions`)}
      ${evidenceMetricCard("Applied", stats.applied, "check-circle-2", `${stats.appliedRecords} records fed`)}
      ${evidenceMetricCard("Risks & approvals", stats.riskSignals, "shield-alert", `${stats.followUps} follow-ups`)}
    </div>
    <div class="evidence-output-feed">
      ${evidenceOutputFeedCards().map((item) => `
        <article class="${item.ready ? "ready" : item.pending ? "pending" : "open"}">
          <span><i data-lucide="${escapeHtml(item.icon)}"></i></span>
          <div>
            <strong>${escapeHtml(item.label)}</strong>
            <small>${escapeHtml(item.detail)}</small>
          </div>
        </article>
      `).join("")}
    </div>
  `;
}

function evidenceMetricCard(label, value, icon, detail) {
  return `
    <article class="evidence-metric-card">
      <span><i data-lucide="${escapeHtml(icon)}"></i></span>
      <div>
        <strong>${escapeHtml(value)}</strong>
        <small>${escapeHtml(label)}</small>
      </div>
      <em>${escapeHtml(detail)}</em>
    </article>
  `;
}

function evidenceWorkbenchStats(artifacts = []) {
  const reviewed = artifacts.filter((artifact) => evidenceArtifactStatus(artifact) === "reviewed").length;
  const applied = artifacts.filter((artifact) => artifact.applied || evidenceArtifactStatus(artifact) === "applied").length;
  const readyToApply = artifacts.filter((artifact) => !artifact.applied && evidenceArtifactStatus(artifact) === "reviewed").length;
  const suggestions = artifacts.reduce((sum, artifact) => sum + evidenceSuggestionCount(artifact), 0);
  const records = artifacts.reduce((sum, artifact) => {
    const suggested = normalizeSuggestedRecords(artifact.suggestedRecords);
    return sum + Object.values(suggested).reduce((recordSum, items) => recordSum + items.length, 0);
  }, 0);
  const appliedRecords = state.steps.length + state.data.length + state.systems.length + state.decisions.length + state.patterns.length;
  const riskSignals = artifacts.reduce((sum, artifact) => {
    const text = [
      artifact.summary,
      ...(artifact.warnings || []),
      stringifyRecords(normalizeSuggestedRecords(artifact.suggestedRecords).steps),
      stringifyRecords(normalizeSuggestedRecords(artifact.suggestedRecords).decisions)
    ].join(" ").toLowerCase();
    return sum + (/\brisk|approval|review gate|control|exception|sensitive|confidential|regulated|pii\b/.test(text) ? 1 : 0);
  }, 0);
  const followUps = artifacts.reduce((sum, artifact) => sum + (artifact.followUpQuestions || []).length, 0);
  return { total: artifacts.length, reviewed, applied, readyToApply, suggestions, records, appliedRecords, riskSignals, followUps };
}

function evidenceOutputFeedCards() {
  const reviewedArtifacts = (state.evidenceArtifacts || []).filter((artifact) => artifact.status === "reviewed" && !artifact.applied).length;
  const pendingDetail = reviewedArtifacts ? `${reviewedArtifacts} evidence review${reviewedArtifacts === 1 ? "" : "s"} waiting` : "No pending evidence";
  const hasEvidence = (state.evidenceArtifacts || []).some((artifact) => artifact.applied || artifact.status === "reviewed");
  const cards = [
    ["Solution Build Recipe", "sparkles", state.steps.length || state.systems.length || state.patterns.length, "steps, systems, and AI patterns"],
    ["Workflow Map Studio", "map", state.steps.length, `${state.steps.length} step${state.steps.length === 1 ? "" : "s"}`],
    ["Product PDR", "file-check-2", state.fields.workflowName || state.fields.submittedIdea || hasEvidence, "problem, users, outputs, and evidence"],
    ["Engineering Brief", "file-code-2", state.steps.length || state.systems.length || state.data.length, "data, tools, access, and handoffs"],
    ["Business Value", "chart-no-axes-column-increasing", state.fields.businessOutcome || state.fields.valueHypothesis || state.fields.biggestPain, "pain, value, effort, and KPI signals"],
    ["Governance Inputs", "shield-check", inferOverallDataSensitivity() !== "Unknown" || state.decisions.length || hasEvidence, "data boundary, review, and controls"],
    ["Enterprise Readiness Brief", "building-2", currentPilotControls().controlsConfirmed === "Yes" || hasEvidence, "testing evidence and approval gates"],
    ["Combined Packet", "package-check", hasEvidence || state.steps.length, pendingDetail]
  ];
  return cards.map(([label, icon, ready, detail]) => ({
    label,
    icon,
    ready: Boolean(ready),
    pending: !ready && reviewedArtifacts > 0,
    detail: ready ? detail : pendingDetail
  }));
}

function renderTestLab() {
  if (!els.testScenarioSelect || !els.testTranscriptInput || !els.testResults) return;
  state.testLab = state.testLab || structuredClone(defaultState.testLab);
  const selectedId = state.testLab.scenarioId || testScenarios[0].id;
  els.testScenarioSelect.innerHTML = testScenarios
    .map((scenario) => `<option value="${escapeHtml(scenario.id)}" ${scenario.id === selectedId ? "selected" : ""}>${escapeHtml(scenario.title)}</option>`)
    .join("");
  if (document.activeElement !== els.testTranscriptInput) {
    els.testTranscriptInput.value = state.testLab.transcript || "";
  }
  els.testResults.innerHTML = testLabResultHtml(state.testLab.result);
  refreshIcons();
}

function testLabResultHtml(result) {
  if (!result) {
    return `
      <div class="test-empty">
        <i data-lucide="flask-conical"></i>
        <strong>No test run yet</strong>
        <p>Load a scenario or paste a conversation, then run the extraction test. This will not modify the live intake.</p>
      </div>
      <div class="test-principles">
        <div><i data-lucide="message-square-text"></i><span>Conversation alone should be enough to build the matrix.</span></div>
        <div><i data-lucide="paperclip"></i><span>Files and screenshots are optional confidence add-ons.</span></div>
        <div><i data-lucide="package-check"></i><span>The score is based on Product and Engineering handoff usefulness.</span></div>
      </div>
    `;
  }
  return `
    <div class="test-score-hero ${scoreTone(result.score)}">
      <div>
        <p class="eyebrow">${escapeHtml(result.mode || "Extraction Test")}</p>
        <h3>${result.score}% ${escapeHtml(testScoreLabel(result.score))}</h3>
        <p>${escapeHtml(result.summary || "Scored against the handoff rubric.")}</p>
      </div>
      <div class="test-score-ring" style="--test-score:${result.score};">
        <span>${result.score}%</span>
      </div>
    </div>
    <div class="test-criteria-list">
      ${result.criteria.map((item) => testCriterionItem(item)).join("")}
    </div>
    <div class="test-preview-grid">
      <div>
        <strong>Extracted steps</strong>
        <p>${escapeHtml(result.extractedSteps || "No steps extracted yet.")}</p>
      </div>
      <div>
        <strong>Follow-up gaps</strong>
        <p>${escapeHtml(result.gaps || "No major gaps found.")}</p>
      </div>
    </div>
  `;
}

function testCriterionItem(item) {
  return `
    <div class="test-criterion ${item.pass ? "pass" : "miss"}">
      <span><i data-lucide="${item.pass ? "check-circle-2" : "circle-alert"}"></i></span>
      <div>
        <strong>${escapeHtml(item.label)}</strong>
        <p>${escapeHtml(item.detail)}</p>
      </div>
    </div>
  `;
}

function loadSelectedTestScenario() {
  const scenario = getSelectedTestScenario();
  state.testLab = state.testLab || structuredClone(defaultState.testLab);
  state.testLab.scenarioId = scenario.id;
  state.testLab.transcript = scenario.transcript;
  state.testLab.result = null;
  persistState();
  renderTestLab();
  toast(`Loaded ${scenario.title}.`);
}

async function runTestLabExtraction() {
  const transcript = els.testTranscriptInput?.value.trim() || "";
  if (!transcript) {
    toast("Load a sample or paste a test conversation first.");
    return;
  }
  if (!aiAvailable) {
    toast("Test Lab extraction needs server.mjs running with OPENAI_API_KEY.");
    return;
  }

  const scenario = getSelectedTestScenario();
  const original = els.runTestButton.innerHTML;
  els.runTestButton.disabled = true;
  els.runTestButton.innerHTML = `<i data-lucide="loader"></i> Testing`;
  refreshIcons();
  try {
    const testState = buildTestState(scenario);
    const extraction = await requestJson("/api/extract", {
      method: "POST",
      body: {
        currentSection: "submitted",
        answer: transcript,
        transcript,
        state: testState
      }
    });
    state.testLab = state.testLab || structuredClone(defaultState.testLab);
    state.testLab.scenarioId = scenario.id;
    state.testLab.transcript = transcript;
    state.testLab.result = scoreExtractionResult(extraction, scenario, "Sample Extraction Test");
    persistState();
    renderTestLab();
    toast(`Test scored ${state.testLab.result.score}%.`);
  } catch (error) {
    toast(String(error.message || error));
  } finally {
    els.runTestButton.disabled = !aiAvailable;
    els.runTestButton.innerHTML = original;
    refreshIcons();
  }
}

function scoreCurrentIntake() {
  const scenario = getSelectedTestScenario();
  state.testLab = state.testLab || structuredClone(defaultState.testLab);
  state.testLab.result = scoreExtractionResult(currentStateAsExtraction(), scenario, "Current Intake Score");
  persistState();
  renderTestLab();
  toast(`Current intake scored ${state.testLab.result.score}%.`);
}

function getSelectedTestScenario() {
  const id = state.testLab?.scenarioId || els.testScenarioSelect?.value || testScenarios[0].id;
  return testScenarios.find((scenario) => scenario.id === id) || testScenarios[0];
}

function buildTestState(scenario) {
  const testState = structuredClone(defaultState);
  testState.fields.submittedIdea = scenario.transcript.split("\n")[0].replace(/^Domain-submitted idea:\s*/i, "");
  testState.fields.domain = scenario.domain;
  testState.fields.workflowCategory = scenario.id.includes("insurance") ? "Post-delivery synthesis" : "Client delivery execution";
  testState.fields.useCaseArchetype = inferUseCaseArchetypeFromText(scenario.transcript).label;
  testState.fields.availableTooling = "Microsoft 365 Copilot and ChatGPT Enterprise";
  testState.activeSection = "idea";
  return testState;
}

function currentStateAsExtraction() {
  return {
    summary: state.fields.currentStateSummary || state.fields.workflowName || "Current intake scored from captured browser state.",
    fields: state.fields,
    newRecords: {
      steps: state.steps || [],
      data: state.data || [],
      systems: state.systems || [],
      decisions: state.decisions || [],
      patterns: state.patterns || []
    },
    ideas: state.ideas || [],
    progressNotes: reviewFollowUps().join(" "),
    nextQuestion: currentValidationStage().question
  };
}

function scoreExtractionResult(extraction, scenario, mode) {
  const fields = extraction.fields || {};
  const records = extraction.newRecords || {};
  const steps = Array.isArray(records.steps) ? records.steps : [];
  const data = Array.isArray(records.data) ? records.data : [];
  const systems = Array.isArray(records.systems) ? records.systems : [];
  const decisions = Array.isArray(records.decisions) ? records.decisions : [];
  const allText = [
    extraction.summary,
    extraction.progressNotes,
    extraction.nextQuestion,
    Object.values(fields).join(" "),
    stringifyRecords(steps),
    stringifyRecords(data),
    stringifyRecords(systems),
    stringifyRecords(decisions)
  ].join(" ").toLowerCase();
  const stepDetailScore = steps.length ? Math.round(steps.reduce((sum, step) => {
    const captured = ["actor", "tool", "input", "dataHandling", "output", "handoff", "trigger", "time", "decision", "dataSensitivity"].filter((key) => isCapturedValue(step[key])).length;
    return sum + captured / 10;
  }, 0) / steps.length * 100) : 0;
  const criteria = [
    testCriterion("Submitted idea preserved", isCapturedValue(fields.submittedIdea) || isCapturedValue(fields.submittedWorkflowTask), fields.submittedIdea || fields.submittedWorkflowTask || "Submitted idea missing."),
    testCriterion("Workflow boundary captured", [fields.workflowName, fields.domain, fields.startPoint, fields.endPoint].filter(isCapturedValue).length >= 3, `${fields.workflowName || "Workflow TBD"} / ${fields.startPoint || "start TBD"} -> ${fields.endPoint || "end TBD"}`),
    testCriterion("A-Z process has 5+ steps", steps.length >= 5, `${steps.length} step${steps.length === 1 ? "" : "s"} extracted.`),
    testCriterion("Step details are usable", stepDetailScore >= 45, `${stepDetailScore}% of core step cells captured across actor, tool, input, output, handoff, time, decision, and sensitivity.`),
    testCriterion("Data sensitivity captured", keywordHit(allText, scenario.keywords.sensitivity) || data.some((item) => isCapturedValue(item.sensitivity)) || steps.some((step) => isCapturedValue(step.dataSensitivity)), "Looks for client/confidential/regulated/PII/financial sensitivity in the extraction."),
    testCriterion("Access mode or source constraint found", keywordHit(allText, scenario.keywords.access) || steps.some((step) => isCapturedValue(step.accessMode)), "Checks whether direct system access, exports, transcripts, files, or screenshots are captured as source/access constraints."),
    testCriterion("Capacity and role impact captured", keywordHit(allText, scenario.keywords.capacity) || isCapturedValue(fields.capacityTeamCompositionImpact), fields.capacityTeamCompositionImpact || "Capacity impact missing or too vague."),
    testCriterion("Human judgment separated", decisions.length > 0 || steps.some((step) => isCapturedValue(step.decision)), `${decisions.length} decision record${decisions.length === 1 ? "" : "s"} plus step-level decisions.`),
    testCriterion("Product/Engineering questions surfaced", keywordHit(allText, scenario.keywords.productEngineering) || isCapturedValue(fields.productClarifications) || isCapturedValue(fields.engineeringClarifications) || isCapturedValue(fields.engineeringUnknowns), "Checks for build/data/tooling/traceability questions Product and Engineering need."),
    testCriterion("Optional evidence treated correctly", optionalEvidenceHandled(allText, scenario), scenario.optionalEvidence.length ? `Scenario mentions ${scenario.optionalEvidence.join(", ")} as optional support.` : "No artifact in scenario.")
  ];
  const score = Math.round(criteria.filter((item) => item.pass).length / criteria.length * 100);
  const gaps = criteria.filter((item) => !item.pass).map((item) => item.label).join("; ");
  return {
    mode,
    scenarioId: scenario.id,
    sourceFile: scenario.sourceFile,
    score,
    summary: extraction.summary || `${scenario.expectedWorkflow} evaluated against handoff criteria.`,
    criteria,
    extractedSteps: steps.map((step, index) => `${index + 1}. ${step.name || step.action || "Untitled step"}`).join(" | "),
    gaps,
    runAt: new Date().toISOString()
  };
}

function testCriterion(label, pass, detail) {
  return { label, pass: Boolean(pass), detail: String(detail || "") };
}

function keywordHit(text, keywords = []) {
  return keywords.some((keyword) => text.includes(String(keyword).toLowerCase()));
}

function optionalEvidenceHandled(text, scenario) {
  if (!scenario.optionalEvidence?.length) return true;
  const mentionsEvidence = ["screenshot", "screenshots", "file", "files", "artifact", "example", "evidence", "export", "photo"].some((term) => text.includes(term));
  const blocksWithoutEvidence = ["required upload", "must upload", "cannot proceed", "blocked without", "not enough evidence"].some((term) => text.includes(term));
  return mentionsEvidence && !blocksWithoutEvidence;
}

function stringifyRecords(records = []) {
  return records.map((record) => Object.values(record || {}).join(" ")).join(" ");
}

function scoreTone(score) {
  if (score >= 80) return "strong";
  if (score >= 60) return "medium";
  return "low";
}

function testScoreLabel(score) {
  if (score >= 80) return "handoff-ready";
  if (score >= 60) return "needs light follow-up";
  if (score >= 40) return "discovery gaps remain";
  return "not ready";
}

function evidenceArtifactCard(artifact, mode = "compact") {
  const records = normalizeSuggestedRecords(artifact.suggestedRecords);
  const status = artifact.applied ? "applied" : artifact.status || "uploaded";
  const count = evidenceSuggestionCount(artifact);
  const questions = artifact.followUpQuestions || [];
  const fields = (artifact.suggestedFieldUpdates || []).slice(0, mode === "compact" ? 3 : 12);
  const links = evidenceLinksForArtifact(artifact).slice(0, mode === "compact" ? 4 : 14);
  const full = mode === "full";
  return `
    <article class="evidence-card ${escapeHtml(status)}">
      <div class="evidence-card-heading">
        <span><i data-lucide="${evidenceIcon(artifact)}"></i></span>
        <div>
          <strong>${escapeHtml(artifact.fileName)}</strong>
          <p>${escapeHtml(artifact.artifactType || artifact.sourceKind || "Uploaded artifact")} · ${escapeHtml(status)}</p>
        </div>
        <small>${escapeHtml(artifact.confidence || "unknown")}</small>
      </div>
      <p class="evidence-summary">${escapeHtml(artifact.summary || artifact.textPreview || "Waiting for analysis.")}</p>
      ${fields.length ? `<div class="evidence-field-list">${fields.map((item) => `<span title="${escapeHtml(item.rationale || "")}">${escapeHtml(fieldLabelForKey(item.key))}</span>`).join("")}</div>` : ""}
      ${links.length ? `<div class="evidence-link-list">${links.map((link) => `<span title="${escapeHtml(link.rationale || link.value || link.question || "")}">${escapeHtml(link.route)} · ${escapeHtml(link.targetType)} · ${escapeHtml(truncateUi(link.targetLabel, 42))}</span>`).join("")}</div>` : ""}
      ${full && artifact.textPreview ? `<div class="evidence-preview"><strong>Preview</strong><p>${escapeHtml(artifact.textPreview)}</p></div>` : ""}
      ${full ? evidenceRecordSummary(records) : ""}
      ${full && questions.length ? `<div class="evidence-questions"><strong>Follow-up questions</strong><ol>${questions.map((question) => `<li>${escapeHtml(question)}</li>`).join("")}</ol></div>` : ""}
      ${artifact.warnings?.length ? `<div class="evidence-warning">${artifact.warnings.map((warning) => escapeHtml(warning)).join("<br />")}</div>` : ""}
      <div class="evidence-actions">
        <span>${count} suggestion${count === 1 ? "" : "s"}</span>
        <button class="secondary-button compact" data-evidence-action="review" data-evidence-id="${escapeHtml(artifact.id)}" type="button">
          <i data-lucide="search-check"></i>
          Review
        </button>
        <button class="primary-button compact" data-evidence-action="apply" data-evidence-id="${escapeHtml(artifact.id)}" type="button" ${artifact.applied || artifact.status === "analyzing" || artifact.status === "error" ? "disabled" : ""}>
          <i data-lucide="check"></i>
          Apply
        </button>
        <button class="secondary-button compact" data-evidence-action="dismiss" data-evidence-id="${escapeHtml(artifact.id)}" type="button" ${artifact.applied ? "disabled" : ""}>
          <i data-lucide="x"></i>
          Ignore
        </button>
      </div>
    </article>
  `;
}

function evidenceRecordSummary(records) {
  const items = [
    ["Steps", records.steps.length],
    ["Data", records.data.length],
    ["Systems", records.systems.length],
    ["Decisions", records.decisions.length],
    ["Patterns", records.patterns.length]
  ].filter(([, count]) => count);
  if (!items.length) return "";
  return `
    <div class="evidence-record-summary">
      ${items.map(([label, count]) => `<span>${count} ${label}</span>`).join("")}
    </div>
  `;
}

function bindEvidenceActions(root) {
  root.querySelectorAll("[data-evidence-action]").forEach((button) => {
    button.addEventListener("click", () => {
      const id = button.dataset.evidenceId;
      const action = button.dataset.evidenceAction;
      if (action === "apply") applyEvidenceArtifact(id);
      if (action === "dismiss") dismissEvidenceArtifact(id);
      if (action === "review") reviewEvidenceArtifact(id);
    });
  });
}

function evidenceIcon(artifact = {}) {
  if (artifact.sourceKind === "note") return "message-square-text";
  if (artifact.sourceKind === "screenshot") return "image";
  if (artifact.sourceKind === "spreadsheet") return "table-2";
  if (artifact.sourceKind === "document") return "file-text";
  return "paperclip";
}

function buildCaptureRecap(result, answer, routedNextQuestion = "") {
  const step = getCurrentStep();
  const fields = step ? stepFieldStatusList(step).filter((item) => item.status === "captured").map((item) => item.label) : [];
  const nextQuestion = routedNextQuestion || nextQuestionAfterCapture(result);
  const translationLens = buildTranslationLens(result, answer, nextQuestion);
  return {
    title: step ? `Captured against Step ${getCurrentStepIndex() + 1}` : "Captured intake context",
    summary: result.summary || answer.slice(0, 220),
    confidence: result.confidence || "medium",
    fields,
    translationLens,
    nextQuestion,
    time: new Date().toISOString()
  };
}

function buildTranslationLens(result = {}, answer = "", routedNextQuestion = "") {
  const fields = result.fields || {};
  const records = result.newRecords || {};
  const inferred = [
    fields.workflowCategory && fields.workflowCategory !== "unknown" ? `Workflow category -> ${fields.workflowCategory}` : "",
    fields.practice && fields.practice !== "unknown" ? `Practice -> ${fields.practice}` : "",
    fields.projectType && fields.projectType !== "unknown" ? `Project type -> ${fields.projectType}` : "",
    fields.workflowName ? `Workflow name -> ${fields.workflowName}` : "",
    fields.commercialContext && fields.commercialContext !== "Unknown" && fields.commercialContext !== "unknown" ? `Commercial context -> ${fields.commercialContext}` : "",
    fields.commercialValuePath && fields.commercialValuePath !== "unknown" ? `Value path -> ${fields.commercialValuePath}` : "",
    fields.kpiTypes ? `KPI type -> ${fields.kpiTypes}` : "",
    fields.governancePath && fields.governancePath !== "Multiple / TBD" ? `Post-build review path -> ${fields.governancePath}` : "",
    fields.buildReadiness && fields.buildReadiness !== "unknown" ? `Build readiness -> ${fields.buildReadiness}` : "",
    records.steps?.length ? `Process map -> ${records.steps.length} step${records.steps.length === 1 ? "" : "s"} captured` : "",
    records.data?.length ? `Data handling -> ${records.data.length} categor${records.data.length === 1 ? "y" : "ies"} captured` : "",
    records.systems?.length ? `Systems/tools -> ${records.systems.length} captured` : "",
    records.decisions?.length ? `Human decisioning -> ${records.decisions.length} point${records.decisions.length === 1 ? "" : "s"} captured` : ""
  ].filter(Boolean).slice(0, 8);

  const missing = [
    !(records.steps || []).length && !state.steps.length ? "rough A-to-Z process steps" : "",
    !(records.data || []).length && !state.data.length ? "data categories and sensitivity" : "",
    !(records.systems || []).length && !state.systems.length ? "systems/tools and access mode" : "",
    !fields.businessOutcome && !state.fields.businessOutcome ? "business outcome/value hypothesis" : "",
    !fields.commercialContext || fields.commercialContext === "Unknown" || fields.commercialContext === "unknown" ? "commercial context can be supplemented later" : "",
    !fields.kpiTypes && !state.fields.kpiTypes ? "KPI/value metric can be supplemented later" : "",
    (!fields.msaBoundary || fields.msaBoundary === "Unknown") && state.fields.msaBoundary === "Unknown" ? "basic data boundary for later governance" : "",
    routedNextQuestion ? `next question: ${routedNextQuestion}` : ""
  ].filter(Boolean).slice(0, 6);

  return {
    heard: truncateUi(answer, 220),
    inferred,
    missing
  };
}

function buildReviewGate() {
  const items = reviewCompletenessItems();
  const totalWeight = items.reduce((sum, item) => sum + (item.weight || 1), 0);
  const overall = Math.round(items.reduce((sum, item) => sum + item.score * (item.weight || 1), 0) / totalWeight);
  const followUps = reviewFollowUps();
  const completionQuestions = topCompletionQuestions(4);
  return {
    items,
    overall,
    label: handoffReadinessLabel(overall),
    summary: handoffReadinessSummary(overall, followUps),
    followUps,
    completionQuestions,
    pilot: pilotReadinessItems(),
    handoff: buildHandoffQuestions()
  };
}

function topCompletionQuestions(limit = 4) {
  return topCompletionQuestionItems(limit, { includeSupplemental: true }).map((item) => item.question);
}

function topCompletionQuestionItems(limit = 4, { includeSupplemental = true } = {}) {
  const buckets = {
    ask: [],
    infer: [],
    supplement: []
  };
  const seen = new Set();
  const add = (question, options = {}) => {
    if (!question) return;
    const normalized = cleanQuestionLabel(question);
    if (!normalized || seen.has(normalized)) return;
    seen.add(normalized);
    const classified = classifyCompletionQuestion(normalized, options);
    buckets[classified.bucket].push(classified);
  };
  const focus = validQuestionFocus(state.questionFocus);
  const stage = workflowInterviewStage();

  if (focus !== "auto" && stage.shouldShowHandoffGaps) {
    topHandoffChecklistQuestions(5, focus).forEach((question) => add(question, { lane: questionFocusLabel(focus), source: "Focus filter" }));
  }

  const archetype = activeUseCaseArchetype();
  if (!stage.submittedCaptured) {
    add(OPENING_DISCOVERY_QUESTION, { lane: "Starting point", priority: 100, source: "Intake guide" });
    if (archetype.id === "unknown") {
      add(archetypeFollowUpQuestion(archetype), { bucket: "infer", lane: "Lens", treatment: "Can infer", source: "Use-case lens" });
    }
    return orderedCompletionQuestions(buckets, includeSupplemental, limit);
  }

  if (archetype.id === "unknown") {
    add(archetypeFollowUpQuestion(archetype), { bucket: "infer", lane: "Lens", treatment: "Can infer", source: "Use-case lens" });
  }
  if (state.fields.practice === "unknown") {
    add(DOMAIN_CONTEXT_QUESTION, { lane: "Context", priority: 95, source: "Practice/domain" });
  }
  if (!isCapturedValue(state.fields.submittedWhereToday) && !isCapturedValue(state.fields.engagementProjectType)) {
    add(WORK_CONTEXT_QUESTION, { lane: "Context", priority: 92, source: "Work context" });
  }
  if (stage.overview) {
    add(stage.overview.text, { lane: "Workflow overview", priority: stage.hasProcessSkeleton ? 99 : 98, source: stage.overview.source });
  }

  if (!stage.hasProcessSkeleton) {
    if (!stage.overview && stage.signals.componentOverviewCaptured) {
      add(PROCESS_MAP_QUESTION, { lane: "Workflow", priority: 100, source: "A-Z process" });
    }
    if (stage.isWorkshop && stage.signals.frameCaptured && !isCapturedValue(state.fields.expectedWorkshopOutput)) {
      add("What does the workshop package need to include at the end: agenda, pre-read, deck, facilitator guide, research pack, Miro or Mural board, exercises, stakeholder notes, or something else?", { lane: "Output", priority: 86 });
    }
    return orderedCompletionQuestions(buckets, includeSupplemental, limit);
  }

  if (stage.isWorkshop && !isCapturedValue(state.fields.expectedWorkshopOutput)) {
    add("What does the workshop package need to include: agenda, pre-read, deck, facilitator guide, research pack, Miro or Mural board, exercises, or stakeholder notes?", { lane: "Output", priority: 88 });
  }
  if (stage.isWorkshop && !isCapturedValue(state.fields.participantProfile)) {
    add("Who are the workshop participants and decision-makers, and what do they need to walk in prepared?", { lane: "Users", priority: 82 });
  }
  if (!state.steps.length && (!stage.overview || isSameQuestion(stage.overview.text, PROCESS_MAP_QUESTION))) {
    add(PROCESS_MAP_QUESTION, { lane: "Workflow", priority: 100, source: "A-Z process" });
  } else {
    const gap = firstMatrixGap();
    if (gap) add(`For "${gap.stepName}", ${gap.prompt}?`, { lane: "Step detail", priority: 98, source: gap.label });
  }
  if (!state.data.length || state.steps.some((step) => !isCapturedValue(step.dataSensitivity))) {
    add("What data is handled at each major step, and is it public, internal, client confidential, regulated, PII, financial, legal, or unknown?", { lane: "Data", priority: 86 });
  }
  if (!state.systems.length && !state.steps.some((step) => isCapturedValue(step.tool))) {
    add("What tools, systems, folders, trackers, decks, databases, or repositories are used for each step?", { lane: "Tools", priority: 90 });
  }
  if (!state.steps.some((step) => isCapturedValue(step.accessMode))) {
    add("How is the work accessed today: direct system access, Microsoft 365 files, exports/screenshots, transcripts, or user-provided inputs?", { lane: "Access", priority: 94 });
  }
  if (!state.decisions.length && !state.steps.some((step) => isCapturedValue(step.decision))) {
    add("Where does human judgment, manager review, approval, escalation, or quality control happen?", { lane: "Human review", priority: 84 });
  }
  if (stage.isWorkshop && state.fields.commercialContext === "unknown") {
    add("If you know it, what commercial context applies to this workshop prep pattern; otherwise Finance, Ops, Account Reporting, PMO, or Product can supplement it later?", { lane: "Business", bucket: "supplement", treatment: "Supplement later", source: "Finance/account context" });
  }
  if (!isCapturedValue(state.fields.averageDuration) || !isCapturedValue(state.fields.runsPerPeriod)) {
    add("If you know it, how often does this happen, how long does it take today, and where is most of the time spent?", { lane: "Business", bucket: "supplement", treatment: "Supplement later", source: "Ops/PMO can help" });
  }
  if (!isCapturedValue(state.fields.kpiTypes)) {
    add("Which value signal seems most relevant: time saved, delivery acceleration, quality, rework reduction, risk reduction, reuse, adoption, or client experience?", { lane: "Business", bucket: "supplement", treatment: "Supplement later" });
  }
  if (state.fields.msaBoundary === "Unknown" || state.fields.deploymentEnvironment === "Unknown") {
    add("What basic data boundary should we note for later governance review: internal only, sanitized artifacts, client VDI or tenant, approved sandbox, or MSA/client approval likely?", { lane: "Gov input", bucket: "supplement", treatment: "Later review input" });
  }
  if (!isCapturedValue(state.fields.successMetrics)) {
    add("If known, what would prove the pilot worked: hours saved, cycle-time reduction, quality improvement, reuse, or adoption?", { lane: "Business", bucket: "supplement", treatment: "Supplement later" });
  }

  if (stage.shouldShowHandoffGaps) {
    topHandoffChecklistQuestions(focus === "auto" ? 5 : 3, "auto").forEach((question) => add(question, { source: "Readiness inspector" }));
    reviewFollowUps().forEach((question) => add(question, { source: "Review gap" }));
  }

  return orderedCompletionQuestions(buckets, includeSupplemental, limit);
}

function orderedCompletionQuestions(buckets, includeSupplemental = true, limit = 4) {
  Object.values(buckets).forEach((list) => list.sort((a, b) => b.priority - a.priority));
  const ordered = includeSupplemental
    ? [...buckets.ask, ...buckets.infer, ...buckets.supplement]
    : [...buckets.ask, ...buckets.infer];
  return ordered.slice(0, limit);
}

function classifyCompletionQuestion(question, options = {}) {
  const text = String(question || "");
  const supplementPattern = /\b(commercial|capacity|margin|fixed[- ]fee|dollar|cost rate|staffing|pilot group|pilot worked|success metrics|KPI|hours saved|how often|frequency|deployment environment|governance|MSA|client approval|business owner|owns adoption|signoff)\b/i;
  const inferPattern = /\b(archetype|use-case pattern|candidate AI assist|AI assist actually fit|solution type|tool fit)\b/i;
  const source = options.source || "Discovery gap";
  if (options.bucket === "supplement" || supplementPattern.test(text)) {
    return {
      question,
      lane: options.lane || "Supplement",
      treatment: options.treatment || "Supplement later",
      bucket: "supplement",
      priority: options.priority ?? 25,
      source
    };
  }
  if (options.bucket === "infer" || inferPattern.test(text)) {
    return {
      question,
      lane: options.lane || "AI lens",
      treatment: options.treatment || "Can infer",
      bucket: "infer",
      priority: options.priority ?? 40,
      source
    };
  }
  return {
    question,
    lane: options.lane || "Discovery",
    treatment: options.treatment || "Ask now",
    bucket: "ask",
    priority: options.priority ?? 70,
    source
  };
}

function buildHandoffQuestions() {
  const archetype = activeUseCaseArchetype();
  const product = [
    archetype.id !== "unknown" ? "" : "Which use-case archetype best fits this submitted idea: testing/QA, requirements, governance summaries, agile planning, document review, data quality, risk assessment, analytics, UAT, research, workshop, pursuit, or post-delivery assets?",
    state.fields.workflowCategory !== "unknown" ? "" : "Which workflow category should Product use: client delivery execution, pre-delivery/workshop prep, pursuit, internal enablement, post-delivery synthesis, or other?",
    state.fields.practice !== "unknown" ? "" : "Which practice/domain should own this opportunity: Banking, Insurance, Strategy, Fraud & Risk, Cybersecurity, Data, Tech, Capital Markets, or Wealth Asset Management?",
    state.fields.projectType !== "unknown" ? "" : "Which project type best describes the work: regulatory/compliance, risk/controls, data/analytics, technology delivery, process transformation, PMO, model validation, reporting, run-the-bank, or strategy/advisory?",
    state.fields.commercialContext !== "unknown" ? "" : "What commercial context applies: paid project, unpaid investment, pursuit support, change-order candidate, embedded delivery, or internal capability build?",
    state.fields.commercialValuePath !== "unknown" ? "" : "What is the primary value path: capacity, team flexibility, margin protection, fixed-fee improvement, pursuit conversion, revenue enablement, quality, or speed?",
    state.fields.workflowCategory === "Pre-delivery / workshop prep" && !state.fields.expectedWorkshopOutput ? "For workshop prep, what does a ready-to-run workshop package include?" : "",
    state.fields.ideaValidationStatus !== "unknown" ? "" : "Is the original submitted idea validated as one workflow, or should it be clarified, split, or deprioritized?",
    state.fields.candidateAiAssistValidation ? "" : "Does the submitted candidate AI assist actually fit the discovered workflow, and where does it not fit?",
    state.fields.mvpScope ? "" : "What is the smallest user-facing pilot slice Product should define first?",
    state.fields.successMetrics ? "" : "Which success metrics should Product use to prove value: hours saved, speed, quality, margin/capacity, reuse, or adoption?",
    state.fields.kpiTypes ? "" : "Which KPI type should be used in the value case and pilot dashboard?",
    state.fields.businessOwner ? "" : "Who owns adoption, workflow changes, and signoff for this use case?",
    state.fields.outputConsumer ? "" : "Who consumes the final output, and what does a good user experience need to look like for them?",
    state.fields.reusePotential ? "" : "Could this workflow or reusable asset apply across other domains, clients, or engagement types?"
  ].filter(Boolean);

  const engineering = [
    state.fields.engineeringClarifications ? "" : "Which engineering clarifications remain from the submitted idea and evidence review?",
    state.steps.some((step) => isCapturedValue(step.accessMode)) ? "" : "For each source, will the solution use direct system access, Microsoft 365 files, exports, screenshots, transcripts, or manual user-provided inputs?",
    state.systems.length || state.steps.some((step) => isCapturedValue(step.tool)) ? "" : "Which source systems, folders, trackers, templates, repositories, or databases must Engineering investigate?",
    state.data.length || state.steps.some((step) => isCapturedValue(step.dataSensitivity)) ? "" : "What data sources and sensitivity levels are involved at each step?",
    state.fields.deploymentEnvironment !== "Unknown" ? "" : "Where would the solution run: company internal, client VDI, client tenant, approved sandbox, on-prem/restricted, SaaS approved tool, or unknown?",
    state.fields.solutionType !== "unknown" ? "" : "What initial solution type should Engineering evaluate: prompt/playbook, Copilot assistant, agent, workflow automation, RAG search, document intelligence, analytics model, or review tool?",
    state.steps.some((step) => isCapturedValue(step.handoff)) ? "" : "Where are the system or human handoffs that may require connectors, actions, or task routing?",
    state.steps.some((step) => isCapturedValue(step.output)) ? "" : "What structured outputs should the solution produce for downstream tools or reviewers?",
    "What identity, permission, logging, evaluation, monitoring, and audit requirements apply in the client environment?"
  ].filter(Boolean);

  const governance = [
    state.fields.msaBoundary !== "Unknown" ? "" : "Confirm whether the solution is internal only, client-approved with no production data, sanitized/exported artifacts, client-data access approval, or likely MSA review.",
    state.fields.governancePath !== "Multiple / TBD" ? "" : "Confirm the likely governance path: no review, standard AI review, privacy, model risk, cyber, legal/MSA, client approval, or multiple.",
    dataSignalLabel() === "Sensitive data present" ? "Confirm whether client confidential, regulated, PII, financial, or legal data can be used in approved AI tools, and under what controls." : "Confirm data policy even if the current interview suggests no sensitive data.",
    state.steps.some((step) => isCapturedValue(step.decision)) || state.decisions.length ? "" : "Where must accountable human approval remain in the workflow?",
    state.steps.some((step) => isCapturedValue(step.exceptions)) ? "" : "Which exceptions, variations, or relationship judgment steps are poor AI candidates and should stay human-led?",
    "What evidence, citations, source notes, and review trail are required before client-facing use?"
  ].filter(Boolean);

  const business = [
    isCapturedValue(state.fields.runsPerPeriod) && isCapturedValue(state.fields.averageDuration) ? "" : "How often does this workflow happen, how long does it take today, and how much analyst/manager capacity could be released?",
    isCapturedValue(state.fields.hoursSavedHypothesis) ? "" : "What is the initial hours-saved hypothesis per run, per month, or per engagement?",
    isCapturedValue(state.fields.commercialValuePath) && state.fields.commercialValuePath !== "unknown" ? "" : "Which value path should we use: capacity creation, team flexibility, margin protection, delivery speed, quality, reuse, or pursuit conversion?",
    isCapturedValue(state.fields.marginImpactHypothesis) ? "" : "Is there a fixed-fee margin, staffing flexibility, or delivery economics benefit we should estimate?",
    isCapturedValue(state.fields.capacityTeamCompositionImpact) ? "" : "Could this change the staffing mix, free senior capacity, or let junior team members handle more of the work?",
    isCapturedValue(state.fields.qualityImpactHypothesis) ? "" : "What quality, consistency, rework, or client experience improvement would prove value?",
    isCapturedValue(state.fields.reusePotential) ? "" : "Can this become a reusable delivery asset across practices, clients, or similar engagements?",
    isCapturedValue(state.fields.successMetrics) ? "" : "What baseline and KPI should we capture before a pilot so value can be tested credibly?"
  ].filter(Boolean);

  return {
    product: product.length ? product : ["Product questions look light; review MVP, adoption, and metrics before build approval."],
    engineering: engineering.length ? engineering : ["Engineering questions look light; validate connectors, identity, logging, and data access before build."],
    governance: governance.length ? governance : ["Governance input questions look light; capture data policy, human review, and audit expectations for the later post-build review."],
    business: business.length ? business : ["Business questions look light; validate the value baseline, KPI proof, and capacity or dollar impact before prioritization."]
  };
}

function reviewCompletenessItems() {
  return [
    reviewScore("Submitted Idea", "clipboard-list", [
      state.fields.submittedIdea,
      state.fields.submittedWorkflowTask,
      activeUseCaseArchetype().id !== "unknown",
      state.fields.workflowCategory !== "unknown",
      state.fields.submittedCandidateAiAssist || state.fields.submittedWhereToday,
      state.fields.submittedExpectedImpact || state.fields.valueHypothesis,
      state.fields.submittedNotes || state.fields.openQuestions,
      state.fields.ideaValidationStatus !== "unknown",
      state.fields.buildReadiness !== "unknown",
      state.fields.primaryTimeDriver
    ], "Original domain ask preserved separately from validated workflow, category, and solution hypothesis.", 0.75),
    reviewScore("Workflow Frame", "route", [
      state.fields.workflowName,
      state.fields.domain,
      state.fields.engagementProjectType,
      state.fields.projectPhase,
      state.fields.deliverableType,
      state.fields.outputConsumer,
      state.fields.startPoint,
      state.fields.endPoint,
      state.fields.businessOutcome
    ], "Workflow name, practice/domain, project phase, deliverable, audience, and outcome.", 1.25),
    reviewScore("A-Z Process", "list-ordered", [
      state.steps.length >= 3,
      matrixCompletionScore() >= 40,
      matrixCompletionScore() >= 70,
      state.mapReviews.some((item) => item.status === "confirmed")
    ], "Rough process list, step-level detail, and map confirmation.", 1.35),
    reviewScore("Data Handling", "database", [
      state.data.length,
      state.data.some((item) => isCapturedValue(item.category)),
      state.data.some((item) => isCapturedValue(item.sensitivity)) || state.steps.some((step) => isCapturedValue(step.dataSensitivity)),
      state.data.some((item) => isCapturedValue(item.avoidRaw) || isCapturedValue(item.splitNotes))
    ], "Data categories, sensitivity, and whether raw client data can be avoided.", 1.15),
    reviewScore("Tools & Systems", "monitor-cog", [
      state.systems.length || uniqueStepToolCount(),
      state.steps.some((step) => isCapturedValue(step.tool)),
      state.steps.some((step) => isCapturedValue(step.toolFit) || inferToolFit(step).label !== "Assess after intake")
    ], "Where the work happens today and fit with M365 Copilot or ChatGPT Enterprise.", 1.2),
    reviewScore("Human Controls", "git-branch", [
      state.decisions.length,
      state.steps.some((step) => isCapturedValue(step.decision)),
      riskSignalLabel() !== "Not captured",
      state.decisions.some((item) => isCapturedValue(item.approval) || isCapturedValue(item.criteria))
    ], "Human review, approvals, failure impact, and escalation logic.", 1.05),
    reviewScore("Value Metrics", "chart-no-axes-combined", [
      state.fields.runsPerPeriod,
      state.fields.averageDuration,
      state.fields.biggestPain,
      state.fields.hoursSavedHypothesis,
      state.fields.marginImpactHypothesis,
      state.fields.qualityImpactHypothesis,
      state.fields.reusePotential,
      state.fields.capacityTeamCompositionImpact,
      state.fields.kpiTypes,
      state.fields.qualityBenefits
    ], "Directional value signals: frequency, time, pain, KPI type, quality, reuse, and supplement-later business metrics.", 0.4),
    reviewScore("Lifecycle & Gate", "milestone", [
      lifecycleCurrentStage(),
      state.fields.lifecycleStatus,
      state.fields.practice !== "unknown",
      state.fields.projectType !== "unknown",
      state.fields.priority,
      state.fields.automationPotential,
      gateAssessment().overall >= 55
    ], "AI Infusion lifecycle stage, owner path, priority, automation potential, and Gate A signal.", 0.55),
    reviewScore("Governance Inputs", "shield-check", [
      state.fields.msaBoundary !== "Unknown",
      inferOverallDataSensitivity() !== "Unknown",
      state.fields.deploymentEnvironment !== "Unknown",
      governanceRoute().path !== "Multiple / TBD",
      state.fields.fieldConfidence
    ], "Basic MSA boundary, data sensitivity, deployment environment, review lane, and confidence for post-build review.", 0.35),
    reviewScore("PDR Inputs", "package-check", [
      state.fields.solutionHypothesis,
      state.fields.mvpScope,
      state.fields.userStories,
      state.fields.acceptanceCriteria,
      state.fields.successMetrics,
      state.fields.toolFitRecommendation
    ], "Product-style scope, stories, acceptance criteria, metrics, and tool fit.", 0.85),
    reviewScore("Pilot Support", "target", [
      state.fields.pilotCandidate,
      state.fields.followUpOwner,
      state.fields.playbackConfirmed === "yes"
    ], "Pilot owner, follow-up owner, and workflow playback confirmation. Artifacts are optional confidence boosters.", 0.25)
  ];
}

function reviewScore(label, icon, signals, detail, weight = 1) {
  const captured = signals.filter((value) => {
    if (typeof value === "boolean") return value;
    if (typeof value === "number") return value > 0;
    return isCapturedValue(value);
  }).length;
  const score = Math.round((captured / signals.length) * 100);
  const status = score >= 75 ? "Ready" : score >= 35 ? "Partial" : "Missing";
  return {
    label,
    icon,
    score,
    status,
    statusClass: status.toLowerCase(),
    detail,
    weight
  };
}

function matrixCompletionScore() {
  if (!state.steps.length) return 0;
  const requiredFields = matrixFields.filter(([, , required]) => required);
  const total = state.steps.length * requiredFields.length;
  const captured = state.steps.reduce((sum, step) => {
    return sum + requiredFields.filter(([key]) => String(stepFieldValue(step, key) || "").trim()).length;
  }, 0);
  return Math.round((captured / total) * 100);
}

function handoffReadinessLabel(score) {
  if (score >= 78) return "Ready for Product Review";
  if (score >= 58) return "Needs Light Follow-Up";
  if (score >= 35) return "Discovery Still In Progress";
  return "Early Intake";
}

function handoffReadinessSummary(score, followUps) {
  if (score >= 78) return "The intake has enough structure to draft a PDR and identify an MVP pilot, with normal review by Product and Engineering.";
  if (followUps.length) return `Capture the top ${Math.min(3, followUps.length)} follow-up items before treating this as a Product/Engineering handoff.`;
  return "Keep the conversation focused on the workflow frame, A-Z steps, data handling, tools, decisions, and directional value signals.";
}

function reviewFollowUps() {
  const gap = firstMatrixGap();
  const sensitiveData = dataSignalLabel() === "Sensitive data present";
  const archetype = activeUseCaseArchetype();
  const items = [];
  if (!isCapturedValue(state.fields.submittedIdea) && !isCapturedValue(state.fields.submittedWorkflowTask)) {
    items.push("Capture the original submitted idea row before validating or reshaping the workflow.");
  }
  if (archetype.id === "unknown") {
    items.push("Classify the use-case archetype so the app can route questions for testing, governance summaries, document review, data quality, analytics, research, workshop, pursuit, or post-delivery patterns.");
  }
  if (state.fields.workflowCategory === "unknown") {
    items.push("Classify the workflow category so workshop prep, pursuit, internal enablement, and post-delivery synthesis are not forced into client delivery.");
  }
  if (state.fields.ideaValidationStatus === "unknown") {
    items.push("Validate whether the submitted idea is accurate, needs clarification, should be split, or is not a good AI candidate.");
  }
  if (state.fields.commercialContext === "unknown" || state.fields.commercialValuePath === "unknown") {
    items.push("If known, note commercial context and value path; otherwise mark them for Finance, Ops, Account Reporting, PMO, or Product to supplement later.");
  }
  if (state.fields.workflowCategory === "Pre-delivery / workshop prep" && !isCapturedValue(state.fields.expectedWorkshopOutput)) {
    items.push("For workshop prep, capture the expected ready-to-run output across pre-client or in-delivery contexts: agenda, pre-read, deck, board, facilitator guide, research pack, or exercise template.");
  }
  if (archetype.id !== "unknown" && !state.steps.length) {
    items.push(archetype.firstQuestion);
  }
  if (!isCapturedValue(state.fields.workflowName) || !isCapturedValue(state.fields.domain)) {
    items.push("Name the workflow and confirm the practice, domain, or client project area it belongs to.");
  }
  if (!state.steps.length) {
    items.push("Ask for the rough numbered A-to-Z workflow before diving into tools or automation ideas.");
  } else if (gap) {
    items.push(`For "${gap.stepName}", capture ${gap.label.toLowerCase()}: ${gap.prompt}.`);
  }
  if (!state.data.length) {
    items.push("Capture the input data, in-process handling, output data, and whether raw client data can be avoided.");
  }
  if (state.steps.length && state.steps.some((step) => !isCapturedValue(step.dataSensitivity))) {
    items.push("For each step, mark data sensitivity as public, internal, client confidential, regulated, PII, financial, legal, or unknown.");
  }
  if (state.steps.length && state.steps.every((step) => !isCapturedValue(step.exceptions))) {
    items.push("Ask whether any steps have exceptions, variations, branch paths, or special handling.");
  }
  if (sensitiveData && !state.data.some((item) => isCapturedValue(item.avoidRaw) || isCapturedValue(item.splitNotes))) {
    items.push("Sensitive data is present. Confirm anonymization, summarized inputs, metadata-only options, or split-solution boundaries.");
  }
  if (!state.systems.length && !state.steps.some((step) => isCapturedValue(step.tool))) {
    items.push("Map where each step happens today: Teams, Outlook, SharePoint, Excel, PowerPoint, trackers, web apps, databases, or repositories.");
  }
  if (!state.decisions.length && !state.steps.some((step) => isCapturedValue(step.decision))) {
    items.push("Identify human review, approval, escalation, and quality-control decision points.");
  }
  if (!isCapturedValue(state.fields.hoursSavedHypothesis) && !isCapturedValue(state.fields.averageDuration)) {
    items.push("Get baseline duration, frequency, and the first hours-saved or capacity hypothesis.");
  }
  if (!isCapturedValue(state.fields.mvpScope)) {
    items.push("Choose the smallest pilot slice: one step, one deliverable, or one domain team to test first.");
  }
  if ((state.evidenceArtifacts || []).some((artifact) => artifact.status === "uploaded" || artifact.status === "reviewed")) {
    items.push("If uploaded artifacts are useful, review and apply the optional evidence suggestions; otherwise continue with conversation-only intake.");
  }
  if (!state.mapReviews.some((item) => item.status === "confirmed")) {
    items.push("Show the process map and ask the user to confirm, reorder, or add missing steps.");
  }
  return items.slice(0, 7);
}

function pilotReadinessItems() {
  const blueprint = buildSolutionBlueprint();
  return [
    {
      label: "Baseline Measurable",
      ready: isCapturedValue(state.fields.averageDuration) || isCapturedValue(state.fields.hoursSavedHypothesis),
      detail: state.fields.averageDuration || state.fields.hoursSavedHypothesis || "Need current time, volume, or cost baseline."
    },
    {
      label: "Pilot Slice Clear",
      ready: isCapturedValue(state.fields.mvpScope) || isCapturedValue(state.fields.pilotCandidate),
      detail: state.fields.mvpScope || state.fields.pilotCandidate || blueprint.mvpSlice
    },
    {
      label: "Success Metrics",
      ready: isCapturedValue(state.fields.successMetrics) || isCapturedValue(state.fields.qualityImpactHypothesis),
      detail: state.fields.successMetrics || state.fields.qualityImpactHypothesis || "Need hours saved, speed, quality, margin/capacity, and reuse metrics."
    },
    {
      label: "Data Boundary",
      ready: state.data.length > 0 && dataSignalLabel() !== "Not captured",
      detail: dataSignalLabel()
    },
    {
      label: "Human Review Path",
      ready: state.decisions.length > 0 || state.steps.some((step) => isCapturedValue(step.decision)),
      detail: riskSignalLabel()
    }
  ];
}

