function backlogItem(item) {
  return `
    <div class="backlog-item">
      <span>${escapeHtml(item.type)}</span>
      <div>
        <strong>${escapeHtml(item.title)}</strong>
        <p>${escapeHtml(item.acceptance)}</p>
      </div>
    </div>
  `;
}

function buildSolutionBlueprint() {
  const readinessScores = productReadinessScores();
  const readiness = Math.round(readinessScores.reduce((sum, item) => sum + item.score, 0) / readinessScores.length);
  const pattern = recommendedSolutionPattern();
  const agentRoles = recommendedAgentRoles();
  const gate = gateAssessment();
  return {
    pattern: pattern.label,
    rationale: pattern.rationale,
    readiness,
    gateDecision: gate.decision,
    gateScore: gate.overall,
    toolStack: recommendedToolStack(pattern.label),
    mvpSlice: recommendedMvpSlice(),
    pilotPlan: recommendedPilotPlan(),
    controls: recommendedControls(),
    agentRoles,
    backlog: backlogSeed(pattern.label, agentRoles)
  };
}

