function recommendedSolutionPattern() {
  const stepCount = state.steps.length;
  const toolCount = uniqueCount(state.systems, "name") || uniqueStepToolCount();
  const decisionCount = state.decisions.length + state.steps.filter((step) => isCapturedValue(step.decision)).length;
  const dataSensitive = dataSignalLabel() === "Sensitive data present";
  const text = `${state.fields.solutionHypothesis} ${state.fields.toolFitRecommendation} ${state.steps.map((step) => `${step.action} ${step.toolFit || inferToolFit(step).label}`).join(" ")}`.toLowerCase();
  if (text.includes("copilot studio") || text.includes("agent") || stepCount >= 5 || toolCount >= 3 || decisionCount >= 2) {
    return {
      label: "Multi-agent Copilot + ChatGPT Enterprise workflow",
      rationale: "The workflow has enough step, tool, handoff, or decision complexity to benefit from coordinated agents with human review gates."
    };
  }
  if (dataSensitive) {
    return {
      label: "Governed ChatGPT Enterprise workspace with human review",
      rationale: "The intake indicates sensitive data, so the first build should emphasize controlled inputs, anonymization, evidence traceability, and review."
    };
  }
  if (text.includes("sharepoint") || text.includes("excel") || text.includes("powerpoint") || text.includes("teams") || text.includes("outlook")) {
    return {
      label: "Microsoft 365 Copilot workflow",
      rationale: "The work appears to live in Microsoft 365 artifacts, making Copilot a strong first implementation path."
    };
  }
  return {
    label: "ChatGPT Enterprise guided workflow",
    rationale: "The current signal suggests a lightweight assistant can capture context, transform inputs, generate draft outputs, and preserve human review."
  };
}

function uniqueStepToolCount() {
  const tools = state.steps
    .flatMap((step) => String(step.tool || "").split(/[,;/]/))
    .map((tool) => tool.trim().toLowerCase())
    .filter(Boolean);
  return new Set(tools).size;
}

function recommendedToolStack(patternLabel) {
  if (patternLabel.includes("Multi-agent")) {
    return "ChatGPT Enterprise for synthesis and reasoning, Microsoft 365 Copilot for Office artifacts, Copilot Studio or agent actions for routing and repeatable orchestration.";
  }
  if (patternLabel.includes("Microsoft 365")) {
    return "Microsoft 365 Copilot with SharePoint/Teams/Outlook/Office context, plus ChatGPT Enterprise for complex reasoning or reusable prompt assets.";
  }
  return "ChatGPT Enterprise project/GPT-style workspace with reusable instructions, files, skills, and optional connectors; escalate to Copilot where Microsoft 365 context is primary.";
}

function recommendedMvpSlice() {
  const candidate = state.steps.find((step) => {
    const pattern = inferAiPattern(step).label.toLowerCase();
    return ["summarize", "extract", "generate", "search", "review"].some((term) => pattern.includes(term));
  }) || state.steps[0];
  if (!candidate) return "Capture the A-Z workflow first, then choose one high-volume or high-friction step as the MVP.";
  return `Start with "${candidate.name || candidate.action || "the first high-friction step"}" and prove value with human-reviewed output before expanding to the full workflow.`;
}

function recommendedPilotPlan() {
  const metric = state.fields.hoursSavedHypothesis || state.fields.averageDuration || "time saved per run";
  const audience = state.fields.outputConsumer || "delivery team reviewers";
  return `Run a 2-4 week pilot on 3-5 real or sanitized examples, compare against the current manual baseline, and measure ${metric}, quality, rework, and reviewer confidence with ${audience}.`;
}

function recommendedControls() {
  const dataSignal = dataSignalLabel();
  const riskSignal = riskSignalLabel();
  if (dataSignal === "Sensitive data present") {
    return "Use data minimization, anonymized examples, human approval before client-facing outputs, and audit notes for source documents and transformations.";
  }
  if (riskSignal.includes("Human review")) {
    return "Keep human review gates for decision points, client-facing deliverables, and exceptions; log assumptions and source evidence.";
  }
  return "Use human review for final outputs, source traceability, prompt/version control, and a simple error/rework log during pilot.";
}

function recommendedAgentRoles() {
  const roles = [
    {
      name: "Workflow Orchestrator",
      job: "Routes the user through the current-state steps, checks missing intake fields, and decides when to ask follow-ups.",
      tool: "ChatGPT Enterprise or Copilot agent",
      icon: "workflow"
    },
    {
      name: "Context Retriever",
      job: "Finds approved source artifacts, prior work, templates, project files, and relevant Microsoft 365 context.",
      tool: "Microsoft 365 Copilot / connectors",
      icon: "search"
    },
    {
      name: "Extraction Analyst",
      job: "Extracts entities, decisions, data categories, assumptions, and action items from source material.",
      tool: "ChatGPT Enterprise",
      icon: "scan-text"
    },
    {
      name: "Synthesis Drafter",
      job: "Creates the first draft of the deliverable, summary, deck notes, agenda, tracker update, or comms output.",
      tool: "ChatGPT Enterprise + Microsoft 365 Copilot",
      icon: "file-pen-line"
    },
    {
      name: "Quality Reviewer",
      job: "Checks output against source evidence, client sensitivity, completeness, tone, and human approval criteria.",
      tool: "Human-in-the-loop + AI review checklist",
      icon: "badge-check"
    }
  ];
  if (state.steps.some((step) => inferAiPattern(step).label.toLowerCase().includes("generate"))) return roles;
  return roles.filter((role) => role.name !== "Synthesis Drafter" || state.steps.length >= 2);
}

function backlogSeed(patternLabel, agentRoles = recommendedAgentRoles()) {
  const workflowName = state.fields.workflowName || "workflow";
  const firstStep = state.steps[0]?.name || state.steps[0]?.action || "first captured step";
  return [
    {
      type: "Epic",
      title: `Pilot ${patternLabel} for ${workflowName}`,
      acceptance: "Pilot can run on approved examples, produce reviewed outputs, and report value metrics against baseline."
    },
    {
      type: "Story",
      title: `As a delivery team member, I can run an AI-assisted flow for ${firstStep}`,
      acceptance: "User can provide or select approved inputs, receive a structured draft/output, and see assumptions and source notes."
    },
    {
      type: "Story",
      title: "As a reviewer, I can approve, correct, or reject AI output",
      acceptance: "Human feedback is captured with reason codes for quality, risk, missing data, and client sensitivity."
    },
    {
      type: "Story",
      title: "As Product, I can measure pilot value",
      acceptance: "The workflow captures time saved, rework avoided, quality signal, reuse potential, and user adoption notes."
    },
    ...agentRoles.slice(0, 3).map((role) => ({
      type: "Capability",
      title: role.name,
      acceptance: role.job
    }))
  ];
}

function matrixCellMeta(rowLabel, value, step = {}) {
  const trimmed = String(value || "").trim();
  if (rowLabel === "AI Pattern" || rowLabel === "Likely Tool Fit") {
    if (!isCapturedValue(trimmed)) return { className: "matrix-missing", title: "AI pattern not ready yet" };
    const captured = rowLabel === "AI Pattern" ? step.pattern : step.toolFit;
    return captured ? { className: "matrix-captured", title: "Captured from interview" } : { className: "matrix-inferred", title: "Inferred after intake from step wording and assumed tooling" };
  }
  if (rowLabel === "Pain/Risk") {
    const explicit = Boolean(String(step.pain || step.risk || "").trim());
    const inferred = inferPainRisk(step);
    if (explicit || ["warn", "risk", "review"].includes(inferred.level)) {
      return { className: explicit ? "matrix-review" : "matrix-inferred", title: explicit ? "Captured risk or pain point, review for accuracy" : "Inferred risk or pain point" };
    }
    return { className: "matrix-inferred", title: "Inferred low risk because no issue has been captured yet" };
  }
  if (!isCapturedValue(trimmed)) {
    return { className: "matrix-missing", title: "Missing or not yet confirmed" };
  }
  if (rowLabel === "Human Decision / Approval") {
    return { className: "matrix-review", title: "Captured human decision point, confirm owner and criteria" };
  }
  return { className: "matrix-captured", title: "Captured from interview or manual entry" };
}

function evidencePdrSummary() {
  const artifacts = state.evidenceArtifacts || [];
  if (!artifacts.length) return "No evidence artifacts uploaded yet.";
  return artifacts
    .map((artifact, index) => {
      const status = artifact.applied ? "applied" : artifact.status || "uploaded";
      const questions = artifact.followUpQuestions?.length ? ` Follow-ups: ${artifact.followUpQuestions.join(" | ")}` : "";
      return `${index + 1}. ${artifact.fileName} (${artifact.artifactType || artifact.sourceKind || "artifact"}, ${status}, ${artifact.confidence || "unknown"} confidence): ${artifact.summary || "No summary."}${questions}`;
    })
    .join("\n");
}

