function getSectionStatus(section) {
  let total = 1;
  let captured = 0;
  let missing = [];
  if (section.fields) {
    const visibleFields = section.fields.filter(shouldShowField);
    total = visibleFields.length || 1;
    visibleFields.forEach(([key, label]) => {
      if (isCapturedValue(state.fields[key])) captured += 1;
      else missing.push(label);
    });
  } else if (section.recordType === "steps") {
    if (!state.steps.length) {
      total = 1;
      captured = 0;
      missing = ["Rough numbered A-to-Z process list"];
    } else {
      const requiredFields = matrixFields.filter(([, , required]) => required);
      total = state.steps.length * requiredFields.length;
      state.steps.forEach((step, index) => {
        requiredFields.forEach(([key, label]) => {
          if (String(stepFieldValue(step, key) || "").trim()) captured += 1;
          else missing.push(`Step ${index + 1}: ${label}`);
        });
      });
    }
  } else if (section.recordType) {
    total = 1;
    captured = state[section.recordType].length ? 1 : 0;
    if (!captured) missing = [section.label];
  }
  const ratio = captured / total;
  if (ratio >= 0.75) return { label: "Complete", className: "complete", confidence: "high", missing };
  if (ratio > 0) return { label: "Partial", className: "partial", confidence: "medium", missing };
  return { label: "Open", className: "", confidence: "unknown", missing };
}

function isCapturedValue(value) {
  const normalized = String(value || "").trim().toLowerCase();
  return Boolean(normalized && !["unknown", "not asked", "tbd", "n/a", "na"].includes(normalized));
}

function calculateProgress() {
  const visible = getVisibleSections();
  const completed = visible.filter((section) => getSectionStatus(section).label === "Complete").length;
  return {
    completed,
    total: visible.length,
    percent: Math.round((completed / visible.length) * 100)
  };
}

function calculateDiscoverySessionProgress(sectionProgressPercent = 0) {
  const signals = workflowOverviewSignals();
  let score = 0;

  if (isSubmittedTopicCaptured()) score += 10;
  if (signals.frameCaptured) score += 14;
  if (signals.toolCaptured) score += 5;
  if (signals.dataCaptured) score += 5;
  if (signals.outputCaptured) score += 5;
  if (signals.componentOverviewCaptured) score += 4;
  if (state.steps.length) score += 18;

  const requiredStepFields = ["actor", "tool", "accessMode", "input", "output"];
  if (state.steps.length) {
    const totalFields = state.steps.length * requiredStepFields.length;
    const capturedFields = state.steps.reduce((sum, step) => {
      return sum + requiredStepFields.filter((key) => isCapturedValue(stepFieldValue(step, key))).length;
    }, 0);
    score += Math.round((capturedFields / totalFields) * 24);
  }

  if (state.steps.some((step) => isCapturedValue(step.decision)) || state.decisions.length) score += 5;
  if (state.steps.some((step) => isCapturedValue(step.dataSensitivity)) || state.data.length) score += 4;
  if (state.steps.some((step) => isCapturedValue(step.tool)) || state.systems.length) score += 3;

  score += Math.round(sectionProgressPercent * 0.04);
  // A document pre-fill populates state.workflowGrid (not legacy state.steps),
  // so reflect that captured data too. Math.max avoids double-counting and
  // keeps the bar from dropping as the live interview later fills legacy steps.
  return Math.max(0, Math.min(100, Math.max(score, gridSessionScore())));
}

// Session-progress contribution from a pre-filled workflowGrid. A fully
// pre-filled document (every doc-extractable field captured) reads ~60%.
// Pain/Friction and aiPattern are excluded — neither comes from a document.
function gridSessionScore() {
  const steps = state.workflowGrid?.steps;
  if (!Array.isArray(steps) || steps.length === 0) return 0;
  const excluded = new Set(["aiPattern", "painFriction"]);
  let total = 0;
  let filled = 0;
  steps.forEach((step) => {
    Object.entries(step.cells || {}).forEach(([key, cell]) => {
      if (excluded.has(key)) return;
      total += 1;
      if (cell && cell.value) filled += 1;
    });
  });
  if (!total) return 20;
  return Math.max(0, Math.min(100, 20 + Math.round((filled / total) * 40)));
}

// Human labels for grid field keys (used by the unknown-cell list).
const GRID_FIELD_LABELS = {
  name: "Workflow Step",
  description: "Description",
  personaActors: "Persona/Actors",
  systemsTools: "Systems/Tools",
  dataProcessing: "Data Processing",
  rulesDecisionLogic: "Rules/Decision logic",
  output: "Output",
  trigger: "Trigger",
  handoff: "Handoff",
  humanCheckpoint: "Human checkpoint",
  timeTaken: "Time Taken",
  frequencyVolume: "Frequency/Volume",
  painFriction: "Pain/Friction",
  dataSensitivity: "Data Sensitivity",
  exceptionBranching: "Exception Branching",
  regulatoryContext: "Regulatory/Compliance",
  aiPattern: "AI Pattern"
};

// All grid step cells that count toward coverage (excludes the step name label
// and aiPattern, which is generated later, never captured).
function gridCellsForCoverage() {
  const steps = state.workflowGrid?.steps;
  if (!Array.isArray(steps)) return [];
  const out = [];
  steps.forEach((step, index) => {
    Object.entries(step.cells || {}).forEach(([key, cell]) => {
      if (key === "name" || key === "aiPattern") return;
      out.push({
        key,
        cell,
        stepName: step.cells?.name?.value?.trim() || `Step ${index + 1}`
      });
    });
  });
  return out;
}

// Coverage = confirmed + inferred (unknown does NOT count). Addressed also
// includes unknown (asked, even if no answer was available).
function gridCoverageStats() {
  const cells = gridCellsForCoverage();
  const total = cells.length;
  let covered = 0;
  let unknown = 0;
  cells.forEach(({ cell }) => {
    const cellState = cell?.state;
    if (cellState === "confirmed" || cellState === "inferred") covered += 1;
    else if (cellState === "unknown") unknown += 1;
  });
  const addressed = covered + unknown;
  return {
    total,
    covered,
    unknown,
    addressed,
    coveragePct: total ? Math.round((covered / total) * 100) : 0,
    addressedPct: total ? Math.round((addressed / total) * 100) : 0
  };
}

// Cells the interview raised but the interviewee could not answer.
function unknownGridCells() {
  return gridCellsForCoverage()
    .filter(({ cell }) => cell?.state === "unknown")
    .map(({ stepName, key }) => ({ stepName, label: GRID_FIELD_LABELS[key] || key }));
}

function updateProgressUi() {
  const progress = calculateProgress();
  if (els.progressPercent) els.progressPercent.textContent = `${progress.percent}%`;
  if (els.progressPercentMirror) {
    els.progressPercentMirror.textContent = `${progress.percent}%`;
  }
  if (els.progressFill) els.progressFill.style.width = `${progress.percent}%`;
  if (els.discoveryCompletionPill && els.discoveryCompletionLabel && els.discoveryCompletionFill) {
    const sessionCompletion = calculateDiscoverySessionProgress(progress.percent);
    els.discoveryCompletionPill.style.setProperty("--completion", `${sessionCompletion}%`);
    els.discoveryCompletionLabel.textContent = `Session ${sessionCompletion}%`;
    els.discoveryCompletionFill.style.width = `${sessionCompletion}%`;
  }
}

function progressSummary() {
  const visible = getVisibleSections();
  const complete = visible.filter((s) => getSectionStatus(s).label === "Complete").map((s) => s.label);
  const partial = visible.filter((s) => getSectionStatus(s).label === "Partial").map((s) => s.label);
  const open = visible.filter((s) => getSectionStatus(s).label === "Open").map((s) => s.label);
  return `Progress: ${calculateProgress().percent}%\nComplete: ${complete.join(", ") || "None"}\nIn progress: ${partial.join(", ") || "None"}\nRemaining: ${open.join(", ") || "None"}`;
}

function getVisibleSections() {
  return sections.filter((section) => !section.postIntake);
}

function getActiveSection() {
  const section = sections.find((item) => item.id === state.activeSection) || sections[0];
  return section.postIntake ? sections[0] : section;
}

// --- Workflow grid (Stage 0 plumbing) ----------------------------------
// Parallel data model behind the "intelligent interview" workflow grid:
// columns are ordered STEPS, rows are a fixed 15-field SCHEMA. Each cell
// carries a value plus a state and confidence signal (drives later
// color-coding / escalation). This is additive and runs PARALLEL to the
// existing `state.steps` array — nothing here touches the live render path.

// Ordered schema keys for a grid step's cells (rows of the grid).
const GRID_CELL_KEYS = [
  "name",               // 1  Workflow Step (name)
  "description",        // 2  Description
  "personaActors",      // 3  Persona/Actors
  "systemsTools",       // 4  Systems/Tools
  "dataProcessing",     // 5  Data Processing
  "rulesDecisionLogic", // 6  Rules/Decision logic
  "output",             // 7  Output
  "trigger",            // 8  Trigger
  "handoff",            // 9  Handoff
  "humanCheckpoint",    // 10 Human checkpoint
  "timeTaken",          // 11 Time Taken
  "frequencyVolume",    // 12 Frequency/Volume
  "painFriction",       // 13 Pain/Friction
  "dataSensitivity",    // 14 Data Sensitivity (step-level)
  "exceptionBranching", // 15 Exception Branching
  "regulatoryContext",  // 16 Regulatory/Compliance Context
  "aiPattern"           // 17 AI Pattern (generated later; value = array of newAiPatternEntry())
];

// Uniform cell shape so later color-coding/escalation can treat all 17
// fields the same way.
// state:      "empty" | "inferred" | "confirmed" | "unknown"
// unknown = raised in interview; interviewee could not provide a specific answer
// confidence: "" | number (0-1, universal confidence framework)
function newGridCell() {
  // source = provenance of the captured value (PR 30): one of
  // user-stated | user-edited | doc-extracted | ai-inferred, or "" while empty.
  return { value: "", state: "empty", confidence: "", source: "" };
}

// One entry inside an aiPattern cell's value array (multiple patterns, each
// with its own confidence rating). pattern ∈ referenceLists.aiPatterns.
function newAiPatternEntry() {
  return { pattern: "", confidence: "" };
}

// An ordered grid step: a stable id, an explicit chain link (this step's
// Output conceptually flows to the next step's Trigger), and the 17 cells.
function newGridStep() {
  const cells = {};
  GRID_CELL_KEYS.forEach((key) => {
    cells[key] = newGridCell();
  });
  return {
    id: makeId("gridstep"),
    nextStepId: "", // chain: this step's Output -> next step's Trigger
    cells
  };
}

// Workflow-level container: a migration anchor, the one workflow-level field
// (overall Data Sensitivity baseline, itself a cell so it can be inferred/
// confirmed too), and the ordered array of steps.
function newWorkflowGrid() {
  return {
    schemaVersion: 1,
    dataSensitivityBaseline: newGridCell(),
    // Frozen once Q3 step confirmation completes and drilling begins: no NEW
    // steps may be added after this, though existing steps keep updating.
    stepListLocked: false,
    steps: []
  };
}

// --- Grid cell accessor layer (PR 30, Slice 1) -------------------------------
// ALL workflowGrid step-cell reads/writes go through getField()/patchField();
// no direct cell mutation anywhere else (test/accessor.test.mjs guards this).
// Provenance (cell.source) derives only from the write path that captured the
// value — the harvest payload, a document extraction, or a user edit — never
// from the AI reply's narration of what it "captured".
// (dataSensitivityBaseline is a workflow-level cell outside this per-step API.)

const GRID_SOURCE_RANK = { "user-edited": 3, "user-stated": 3, "doc-extracted": 2, "ai-inferred": 1 };

const GRID_CELL_LAYER = {
  name: "layer1", description: "layer1", trigger: "layer1", output: "layer1",
  handoff: "layer1", frequencyVolume: "layer1", timeTaken: "layer1", systemsTools: "layer1",
  personaActors: "layer2", painFriction: "layer2", rulesDecisionLogic: "layer2",
  exceptionBranching: "layer2", humanCheckpoint: "layer2",
  dataProcessing: "layer3", dataSensitivity: "layer3", regulatoryContext: "layer3",
  aiPattern: "meta" // generated, never harvested; carries an array value
};

// True when every one of the 9 live-grid fields is captured somewhere in the
// grid (any step, state confirmed/inferred). Used on session load: a complete
// grid means a persisted currentQuestionOverride is stale and must not resurface
// as the intro question next to an "all key areas covered" suggestion.
function gridCoverageComplete(grid) {
  const steps = Array.isArray(grid?.steps) ? grid.steps : [];
  if (!steps.length) return false;
  return LIVE_GRID_LAYERS.every((layer) => layer.fields.every((field) =>
    steps.some((step) => field.cells.some((key) => {
      const cell = step?.cells?.[key];
      return cell && cell.value && (cell.state === "confirmed" || cell.state === "inferred");
    }))
  ));
}

// Cells saved before provenance existed derive source from their state.
function deriveLegacyCellSource(state) {
  if (state === "confirmed") return "user-stated";
  if (state === "inferred") return "ai-inferred";
  return "";
}

// Read accessor. step defaults to the current interview step; layer (when
// given) is validated against the cell's canonical layer — a mismatch warns
// but never blocks the read.
function getField(step, layer, cellKey) {
  if (!GRID_CELL_KEYS.includes(cellKey)) return null;
  if (layer && GRID_CELL_LAYER[cellKey] !== layer) {
    console.warn(`[grid] getField layer mismatch: ${cellKey} is ${GRID_CELL_LAYER[cellKey]}, not ${layer}`);
  }
  const target = step || currentGridStep();
  return target?.cells?.[cellKey] || null;
}

// Write accessor — the ONLY place a step cell is mutated. Returns true when
// the cell changed. Rules:
//   - source must be one of GRID_SOURCE_RANK's keys;
//   - provenance precedence: user-edited/user-stated > doc-extracted >
//     ai-inferred. Upgrades apply; a lower-provenance write over a captured
//     higher-provenance value is refused AND logged — never a silent downgrade;
//   - equal provenance: only a higher confidence improves the cell, unless
//     options.refresh (re-extraction replaces same-provenance values);
//   - options.state === "unknown" records "asked but couldn't answer", only
//     while the cell holds no real answer;
//   - aiPattern accepts an array value (pattern entries); all other cells are
//     trimmed strings.
// Slice 2 wires question retirement here: every accepted patch is the single
// point where a captured field can retire its open questions.
function patchField(step, layer, cellKey, value, source, confidence, options = {}) {
  if (!GRID_CELL_KEYS.includes(cellKey)) return false;
  if (!GRID_SOURCE_RANK[source]) {
    console.warn(`[grid] patchField rejected unknown source "${source}" for ${cellKey}`);
    return false;
  }
  if (layer && GRID_CELL_LAYER[cellKey] !== layer) {
    console.warn(`[grid] patchField layer mismatch: ${cellKey} is ${GRID_CELL_LAYER[cellKey]}, not ${layer}`);
  }
  const target = step || currentGridStep();
  if (!target?.cells) return false;
  const existing = target.cells[cellKey];

  if (options.state === "unknown") {
    if (!existing || existing.state === "empty") {
      target.cells[cellKey] = { value: "", state: "unknown", confidence: 0, source };
      return true;
    }
    return false;
  }

  const isArrayValue = Array.isArray(value);
  const clean = isArrayValue ? value : (typeof value === "string" ? value.trim() : "");
  if (!clean || (isArrayValue && !clean.length)) return false;
  const conf = typeof confidence === "number" ? confidence : 0;

  const hasCaptured = existing && existing.value && existing.state !== "empty" && existing.state !== "unknown";
  const existingRank = hasCaptured
    ? (GRID_SOURCE_RANK[existing.source] || GRID_SOURCE_RANK[deriveLegacyCellSource(existing.state)] || 0)
    : 0;
  const incomingRank = GRID_SOURCE_RANK[source];

  if (incomingRank < existingRank) {
    console.info(`[grid] kept ${existing.source || existing.state} ${cellKey} over lower-provenance ${source} write`);
    return false;
  }
  if (incomingRank === existingRank && existingRank > 0 && !options.refresh) {
    const existingConfidence = typeof existing.confidence === "number" ? existing.confidence : -1;
    if (conf <= existingConfidence) return false; // same provenance: only improve
  }

  const cellState = options.state || (incomingRank >= 3 ? "confirmed" : "inferred");
  target.cells[cellKey] = { value: clean, state: cellState, confidence: conf, source };
  // Slice 2: every accepted capture is the one place questions retire. The
  // typeof guard keeps extraction-test sandboxes (which evaluate patchField in
  // isolation) working. "unknown" recordings deliberately do NOT retire — the
  // question may legitimately be re-asked later.
  if (typeof retireQuestionsForCell === "function") retireQuestionsForCell(cellKey, source, conf);
  return true;
}

function normalizeGridCell(cell) {
  const base = newGridCell();
  if (!cell || typeof cell !== "object") return base;
  const merged = { ...base, ...cell };
  // Back-compat (PR 30): cells saved before provenance existed derive source
  // from their state — confirmed → user-stated, inferred → ai-inferred.
  if (!merged.source) merged.source = deriveLegacyCellSource(merged.state);
  return merged;
}

function normalizeGridStep(step) {
  const base = newGridStep();
  if (!step || typeof step !== "object") return base;
  const cells = {};
  GRID_CELL_KEYS.forEach((key) => {
    cells[key] = normalizeGridCell(step.cells?.[key]);
  });
  return {
    ...base,
    ...step,
    id: step.id || base.id,
    nextStepId: step.nextStepId || "",
    cells
  };
}

// Backward-compatible loader: old sessions have no `workflowGrid` key and get
// a fresh empty default; partially-written grids get every cell back-filled.
function normalizeWorkflowGrid(grid) {
  const base = newWorkflowGrid();
  if (!grid || typeof grid !== "object") return base;
  return {
    ...base,
    ...grid,
    schemaVersion: grid.schemaVersion || base.schemaVersion,
    dataSensitivityBaseline: normalizeGridCell(grid.dataSensitivityBaseline),
    stepListLocked: Boolean(grid.stepListLocked),
    steps: Array.isArray(grid.steps) ? grid.steps.map(normalizeGridStep) : []
  };
}

function newRecord(type) {
  const templates = {
    steps: { name: "", actor: "", tool: "", accessMode: "", action: "", input: "", dataHandling: "", output: "", handoff: "", trigger: "", time: "", decision: "", pain: "", risk: "", exceptions: "", dataSensitivity: "", pattern: "", toolFit: "", evidenceConfidence: "", interviewNotes: "", openQuestions: "" },
    data: { category: "", source: "", format: "", sensitivity: "", usageMode: "", processing: "", tool: "", storage: "", access: "", avoidRaw: "", splitNotes: "" },
    systems: { name: "", purpose: "", access: "", owner: "", integration: "", clientData: "" },
    decisions: { decision: "", owner: "", criteria: "", risk: "", approval: "", escalation: "" },
    patterns: { step: "", pattern: "", riskNote: "", toolFit: "" }
  };
  return structuredClone(templates[type]);
}

function recordLabel(type) {
  return {
    steps: "Step",
    data: "Data Category",
    systems: "System/Tool",
    decisions: "Decision",
    patterns: "Pattern"
  }[type];
}

function recordTitle(type, record, index) {
  if (type === "steps") return record.name || `Step ${index + 1}`;
  if (type === "data") return record.category || `Data Category ${index + 1}`;
  if (type === "systems") return record.name || `System/Tool ${index + 1}`;
  if (type === "decisions") return record.decision || `Decision ${index + 1}`;
  return record.step || `Pattern ${index + 1}`;
}

function persistState() {
  ensureSessionMeta();
  ensureDrilldownState();
  state.sessionMeta.updatedAt = new Date().toISOString();
  localStorage.setItem(CURRENT_STATE_KEY, JSON.stringify(state));
  saveSessionToLibrary(state);
  scheduleServerSessionSave();
}

function ensureDrilldownState() {
  state.drilldown = {
    ...structuredClone(defaultState.drilldown),
    ...(state.drilldown || {})
  };
  if (state.steps?.length && state.drilldown.status === "waitingForSteps") {
    state.drilldown.skeletonConfirmed = true;
    state.drilldown.status = "active";
    lockWorkflowStepList();
  }
  return state.drilldown;
}

function ensureSessionMeta(target = state, options = {}) {
  const now = new Date().toISOString();
  const existing = target.sessionMeta || {};
  target.sessionMeta = {
    ...structuredClone(defaultState.sessionMeta),
    ...existing
  };
  if (!target.sessionMeta.id || options.forceNew) {
    target.sessionMeta.id = makeId("session");
  }
  if (!target.sessionMeta.createdAt || options.forceNew) {
    target.sessionMeta.createdAt = now;
  }
  if (!target.sessionMeta.updatedAt || options.forceNew || !options.preserveUpdatedAt) {
    target.sessionMeta.updatedAt = existing.updatedAt && options.preserveUpdatedAt ? existing.updatedAt : now;
  }
  const derivedName = deriveSessionName(target);
  if (!target.sessionMeta.name || target.sessionMeta.name === "Untitled discovery") {
    target.sessionMeta.name = derivedName;
  }
  if (!target.sessionMeta.source) target.sessionMeta.source = "Live discovery";
  if (!target.sessionMeta.dataClassification) target.sessionMeta.dataClassification = "Unknown";
  if (!target.sessionMeta.status) target.sessionMeta.status = "Discovery";
  return target.sessionMeta;
}

function deriveSessionName(target = state) {
  const fields = target.fields || {};
  const candidate = fields.workflowName || fields.submittedWorkflowTask || fields.submittedIdea || "";
  const trimmed = String(candidate).replace(/\s+/g, " ").trim();
  return trimmed ? truncateUi(trimmed, 72) : "Untitled discovery";
}

function loadState() {
  try {
    const saved = localStorage.getItem(CURRENT_STATE_KEY);
    if (!saved) return normalizeLoadedState({});
    return normalizeLoadedState(JSON.parse(saved));
  } catch {
    return normalizeLoadedState({});
  }
}

function normalizeLoadedState(parsed = {}) {
  const merged = {
    ...structuredClone(defaultState),
    ...parsed,
    sessionMeta: {
      ...structuredClone(defaultState.sessionMeta),
      ...(parsed.sessionMeta || {})
    },
    pilotControls: {
      ...structuredClone(defaultState.pilotControls),
      ...(parsed.pilotControls || {})
    },
    pilotFeedback: {
      ...structuredClone(defaultState.pilotFeedback),
      ...(parsed.pilotFeedback || {})
    },
    pilotFeedbackLog: Array.isArray(parsed.pilotFeedbackLog) ? parsed.pilotFeedbackLog : [],
    questionHistory: Array.isArray(parsed.questionHistory)
      ? parsed.questionHistory.filter((entry) => entry && typeof entry === "object" && entry.intent)
      : [],
    pilotGuide: {
      ...structuredClone(defaultState.pilotGuide),
      ...(parsed.pilotGuide || {}),
      completed: Array.isArray(parsed.pilotGuide?.completed) ? parsed.pilotGuide.completed : []
    },
    pilotLiveTest: {
      ...structuredClone(defaultState.pilotLiveTest),
      ...(parsed.pilotLiveTest || {})
    },
    testingRelease: {
      ...structuredClone(defaultState.testingRelease),
      ...(parsed.testingRelease || {})
    },
    fields: {
      ...structuredClone(defaultState.fields),
      ...(parsed.fields || {})
    },
    evidenceWorkbench: {
      ...structuredClone(defaultState.evidenceWorkbench),
      ...(parsed.evidenceWorkbench || {})
    },
    steps: (parsed.steps || []).map((step) => ({ ...newRecord("steps"), ...step })),
    data: (parsed.data || []).map((item) => ({ ...newRecord("data"), ...item })),
    systems: (parsed.systems || []).map((item) => ({ ...newRecord("systems"), ...item })),
    decisions: (parsed.decisions || []).map((item) => ({ ...newRecord("decisions"), ...item })),
    patterns: (parsed.patterns || []).map((item) => ({ ...newRecord("patterns"), ...item })),
    workflowGrid: normalizeWorkflowGrid(parsed.workflowGrid),
    drilldown: {
      ...structuredClone(defaultState.drilldown),
      ...(parsed.drilldown || {})
    },
    documentEntry: {
      ...structuredClone(defaultState.documentEntry),
      ...(parsed.documentEntry || {})
    },
    // The File cannot be restored after a reload (pendingUploadFile is reset),
    // so never trust a persisted selection — start with no held document.
    uploadedDocument: null,
    evidenceArtifacts: (parsed.evidenceArtifacts || []).map((item) => ({
      ...item,
      suggestedRecords: normalizeSuggestedRecords(item.suggestedRecords),
      suggestedFieldUpdates: Array.isArray(item.suggestedFieldUpdates) ? item.suggestedFieldUpdates : [],
      suggestedIdeas: Array.isArray(item.suggestedIdeas) ? item.suggestedIdeas : [],
      followUpQuestions: Array.isArray(item.followUpQuestions) ? item.followUpQuestions : [],
      warnings: Array.isArray(item.warnings) ? item.warnings : [],
      evidenceLinks: Array.isArray(item.evidenceLinks) ? item.evidenceLinks.map((link) => normalizeEvidenceLink(link, item)) : []
    }))
  };
  const legacySectionMap = {
    submitted: "idea",
    systems: "workflow",
    data: "workflow",
    steps: "workflow",
    decisions: "blueprint",
    time: "value",
    trigger: "blueprint",
    patterns: "aiFit",
    closeout: "review",
    package: "review"
  };
  if (legacySectionMap[merged.activeSection]) merged.activeSection = legacySectionMap[merged.activeSection];
  merged.questionFocus = validQuestionFocus(merged.questionFocus);
  if (isGenericStartingTopic(merged.fields.submittedIdea)) merged.fields.submittedIdea = "";
  if (isGenericStartingTopic(merged.fields.submittedWorkflowTask)) merged.fields.submittedWorkflowTask = "";
  const hasSubmittedIdea = isSpecificSubmittedTopic(merged.fields.submittedIdea) || isSpecificSubmittedTopic(merged.fields.submittedWorkflowTask);
  if (!hasSubmittedIdea && (!parsed.fields || !("submittedIdea" in parsed.fields)) && merged.activeSection === "workflow") {
    merged.activeSection = "idea";
    merged.currentQuestionOverride = "";
    merged.currentQuestionSource = "Intake guide";
  }
  if (isLegacyDiscoveryQuestion(merged.currentQuestionOverride)) {
    merged.currentQuestionOverride = "";
    merged.currentQuestionSource = "Updated intake flow";
  }
  if (isPrematureSupplementalQuestion(merged.currentQuestionOverride, merged)) {
    merged.currentQuestionOverride = PROCESS_MAP_QUESTION;
    merged.currentQuestionSource = "A-Z process";
    merged.activeSection = "workflow";
  }
  // Phase 1 Frame Builder: a persisted "confirmSkeleton" status is the rough
  // frame awaiting confirmation (State 2) and must survive a reload, so it is no
  // longer auto-advanced here. Only the proceed-permission shortcut still jumps
  // straight into the step-by-step deep dive.
  if (merged.steps.length && isProceedPermissionQuestion(merged.currentQuestionOverride)) {
    merged.drilldown.status = "active";
    merged.drilldown.skeletonConfirmed = true;
    if (merged.workflowGrid) merged.workflowGrid.stepListLocked = true;
    merged.activeSection = "workflow";
    merged.currentQuestionOverride = "";
    merged.currentQuestionSource = "Step-by-step interview";
  }
  // PR 30 (carried from PR 29): when the loaded grid already covers all 9
  // live-grid fields, a persisted question override is stale — clear it so
  // currentQuestion derives from grid coverage, consistent with the
  // "all key areas covered" suggestion state.
  if (merged.currentQuestionOverride && gridCoverageComplete(merged.workflowGrid)) {
    merged.currentQuestionOverride = "";
    merged.currentQuestionSource = "Grid coverage";
  }
  // #2 (interim — revisit PR 30): when a loaded session carried its name only on
  // the grid, backfill it onto sessionMeta/fields so the metadata surfaces that
  // still read the legacy model rehydrate. Runs before ensureSessionMeta so the
  // derived session name picks it up too.
  const loadedGridName = (merged.workflowGrid?.workflowName || "").trim();
  if (loadedGridName) {
    if (!merged.sessionMeta.workflowName) merged.sessionMeta.workflowName = loadedGridName;
    if (!merged.fields.workflowName) merged.fields.workflowName = loadedGridName;
  }
  ensureSessionMeta(merged, { preserveUpdatedAt: true });
  return merged;
}

function updateSessionMetadataFromControls() {
  const meta = ensureSessionMeta();
  meta.name = els.sessionNameInput?.value.trim() || deriveSessionName();
  meta.owner = els.sessionOwnerInput?.value.trim() || "";
  meta.dataClassification = els.sessionDataClassificationSelect?.value || "Unknown";
  meta.status = els.sessionStatusSelect?.value || "Discovery";
  persistState();
  renderSessionLibrary();
}

function getSessionLibrary() {
  try {
    const parsed = JSON.parse(localStorage.getItem(SESSION_LIBRARY_KEY) || "[]");
    return Array.isArray(parsed) ? parsed.filter((entry) => entry?.id && entry?.state) : [];
  } catch {
    return [];
  }
}

function getCombinedSessionLibrary() {
  const local = getSessionLibrary().map((entry) => ({ ...entry, serverStored: Boolean(serverSessions.some((item) => item.id === entry.id)) }));
  const seen = new Set(local.map((entry) => entry.id));
  const remote = serverSessions
    .filter((entry) => entry?.id && !seen.has(entry.id))
    .map((entry) => ({ ...entry, remoteOnly: true, serverStored: true }));
  return [...local, ...remote].sort((a, b) => String(b.updatedAt || "").localeCompare(String(a.updatedAt || "")));
}

function writeSessionLibrary(entries) {
  try {
    localStorage.setItem(SESSION_LIBRARY_KEY, JSON.stringify(entries.slice(0, 40)));
  } catch (error) {
    console.warn("Session library save failed", error);
  }
}

function saveSessionToLibrary(sessionState = state) {
  const entry = sessionLibraryEntryFromState(sessionState);
  const library = getSessionLibrary().filter((item) => item.id !== entry.id);
  library.unshift(entry);
  writeSessionLibrary(library);
}

function scheduleServerSessionSave() {
  window.clearTimeout(serverSyncTimer);
  serverSyncTimer = window.setTimeout(() => saveSessionToServer(state), 900);
}

async function syncSessionsFromServer() {
  try {
    const payload = await requestJson("/api/sessions");
    serverSessions = Array.isArray(payload.sessions) ? payload.sessions : [];
    renderSessionLibrary();
    renderSavedSessionsPanel();
  } catch (error) {
    console.warn("Server session sync unavailable", error.message);
  }
}

async function syncPackagesFromServer() {
  try {
    const payload = await requestJson("/api/packages");
    serverPackages = Array.isArray(payload.packages) ? payload.packages : [];
    renderLiveTestCommandCenter();
  } catch (error) {
    console.warn("Server package sync unavailable", error.message);
  }
}

async function saveSessionToServer(sessionState = state, options = {}) {
  try {
    const response = await requestJson("/api/sessions", {
      method: "POST",
      body: { state: compactSessionStateForLibrary(sessionState) }
    });
    if (response.summary) {
      serverSessions = [response.summary, ...serverSessions.filter((entry) => entry.id !== response.summary.id)];
      renderSessionLibrary();
      renderSavedSessionsPanel();
    }
    if (options.immediate) toast("Session saved to server files.");
  } catch (error) {
    console.warn("Server session save unavailable", error.message);
    if (options.immediate) toast("Saved in browser. Server file save unavailable.");
  }
}

function sessionLibraryEntryFromState(sessionState = state) {
  ensureSessionMeta(sessionState);
  const summary = sessionSummaryMeta(sessionState);
  return {
    ...summary,
    state: compactSessionStateForLibrary(sessionState)
  };
}

function compactSessionStateForLibrary(sessionState = state) {
  const clone = structuredClone(sessionState);
  clone.evidenceArtifacts = (clone.evidenceArtifacts || []).map((artifact) => ({
    ...artifact,
    dataUrl: "",
    rawContent: ""
  }));
  // Persist the computed 10-principle opportunity scoring onto each grid step so
  // tier / priority / principleScores travel with the saved session JSON. The
  // clone is disposable, so this never mutates live state.
  if (Array.isArray(clone.workflowGrid?.steps)) {
    clone.workflowGrid.steps = clone.workflowGrid.steps.map((step) => {
      const meta = getStepOpportunityMeta(step);
      return { ...step, opportunity: { tier: meta.tier, priority: meta.priority, principleScores: meta.principleScores } };
    });
  }
  return clone;
}

function sessionSummaryMeta(sessionState = state) {
  const meta = ensureSessionMeta(sessionState, { preserveUpdatedAt: true });
  const fields = sessionState.fields || {};
  return {
    id: meta.id,
    name: meta.name || deriveSessionName(sessionState),
    owner: meta.owner || "",
    source: meta.source || "Live discovery",
    dataClassification: meta.dataClassification || "Unknown",
    status: meta.status || "Discovery",
    lastPackagePath: meta.lastPackagePath || "",
    createdAt: meta.createdAt || "",
    updatedAt: meta.updatedAt || "",
    // #1 (interim canonical rule — revisit PR 30): fall back to the grid name so
    // an unnamed grid session lists its workflow title instead of "Untitled".
    workflowName: meta.workflowName || sessionState.workflowGrid?.workflowName || fields.workflowName || fields.submittedWorkflowTask || "",
    engagementContext: meta.engagementContext || "",
    category: fields.workflowCategory && fields.workflowCategory !== "unknown" ? fields.workflowCategory : "Category TBD",
    domain: fields.domain || "",
    readiness: fields.buildReadiness || "unknown",
    stepCount: sessionState.workflowGrid?.steps?.length || sessionState.steps?.length || 0,
    dataCount: sessionState.data?.length || 0,
    systemCount: sessionState.systems?.length || 0,
    decisionCount: sessionState.decisions?.length || 0
  };
}

// === Phase 9c: Settings panel ==============================================
// Injects a ⚙ Settings button into the top-bar trio and opens a modal (same
// overlay style as the mode picker). Lets the user set a runtime OpenAI key
// and a blended-rate override. Built entirely in JS; inline hex only.
function injectSettingsButton() {
  const trio = document.querySelector(".topbar-trio");
  if (!trio || document.getElementById("settingsButton")) return;
  const btn = document.createElement("button");
  btn.id = "settingsButton";
  btn.type = "button";
  btn.className = "topbar-trio-button";
  btn.title = "Settings";
  btn.innerHTML = `<i data-lucide="settings"></i>Settings`;
  trio.appendChild(btn);
  btn.addEventListener("click", openSettingsModal);
  refreshIcons();
}

// Fetch the current settings on load so the business case picks up any rate
// override. Best-effort — falls back to role-based rates if it fails.
async function loadSettings() {
  try {
    const data = await requestJson("/api/settings");
    state.settings = { rateOverride: data?.rateOverride ?? null };
    render();
  } catch {
    /* leave state.settings unset — computeBusinessCase falls back to role rates */
  }
}

function closeSettingsModal() {
  document.getElementById("settingsModal")?.remove();
}

function openSettingsModal() {
  closeSettingsModal();
  const inputBase = "box-sizing:border-box;background:#0d1b2e;border:1px solid #1e3350;color:#ffffff;border-radius:6px;padding:10px;font-size:13px;";
  const saveBtn = "background:#00d4b4;color:#0d1b2e;border:none;border-radius:6px;padding:8px 16px;font-size:13px;font-weight:600;cursor:pointer;";
  const overlay = document.createElement("div");
  overlay.id = "settingsModal";
  overlay.style.cssText = "position:fixed;inset:0;background:#0a1525;display:flex;align-items:center;justify-content:center;z-index:1000;padding:24px;";
  overlay.innerHTML = `
    <div style="background:#162438;border:1px solid #1e3350;border-radius:12px;padding:32px;max-width:480px;width:100%;box-sizing:border-box;">
      <div style="color:#ffffff;font-size:18px;font-weight:700;margin-bottom:20px;">Settings</div>
      <div style="margin-bottom:24px;">
        <label style="color:#8899aa;font-size:12px;display:block;margin-bottom:6px;">OpenAI API Key</label>
        <input id="settingsApiKeyInput" type="password" placeholder="sk-..." style="${inputBase}width:100%;" />
        <div style="display:flex;align-items:center;gap:12px;margin-top:10px;">
          <button id="settingsSaveKeyBtn" type="button" style="${saveBtn}">Save key</button>
          <span id="settingsAiStatus" style="font-size:12px;color:#8899aa;">Checking…</span>
        </div>
      </div>
      <div style="margin-bottom:24px;">
        <label style="color:#8899aa;font-size:12px;display:block;margin-bottom:2px;">Blended rate override (USD/hr)</label>
        <div style="color:#445566;font-size:11px;margin-bottom:6px;">Leave blank to use role-based rates ($75–$200/hr)</div>
        <input id="settingsRateInput" type="number" min="1" max="999" placeholder="—" style="${inputBase}width:120px;" />
        <div style="margin-top:10px;">
          <button id="settingsSaveRateBtn" type="button" style="${saveBtn}">Save rate</button>
        </div>
      </div>
      <div style="text-align:center;">
        <span id="settingsCloseLink" role="button" tabindex="0" style="color:#8899aa;font-size:13px;cursor:pointer;">Close</span>
      </div>
    </div>`;
  document.body.appendChild(overlay);
  overlay.querySelector("#settingsSaveKeyBtn").addEventListener("click", saveSettingsApiKey);
  overlay.querySelector("#settingsSaveRateBtn").addEventListener("click", saveSettingsRate);
  overlay.querySelector("#settingsCloseLink").addEventListener("click", closeSettingsModal);
  refreshSettingsModal();
}

// Prefill the AI status line and rate field from GET /api/settings.
async function refreshSettingsModal() {
  let data = null;
  try { data = await requestJson("/api/settings"); } catch { data = null; }
  const aiEnabled = Boolean(data && data.aiEnabled);
  const status = document.getElementById("settingsAiStatus");
  if (status) {
    status.textContent = aiEnabled ? "AI enabled" : "AI not configured";
    status.style.color = aiEnabled ? "#00d4b4" : "#8899aa";
  }
  if (data) {
    state.settings = { rateOverride: data.rateOverride ?? null };
    const rateInput = document.getElementById("settingsRateInput");
    if (rateInput) rateInput.value = data.rateOverride != null ? String(data.rateOverride) : "";
  }
}

async function saveSettingsApiKey() {
  const input = document.getElementById("settingsApiKeyInput");
  const apiKey = (input?.value || "").trim();
  if (!apiKey) { toast("Enter an API key first"); return; }
  try {
    await requestJson("/api/settings/apikey", { method: "POST", body: { apiKey } });
    toast("API key updated");
    refreshSettingsModal();
  } catch (error) {
    toast(error.message || "Could not update API key");
  }
}

async function saveSettingsRate() {
  const input = document.getElementById("settingsRateInput");
  const raw = (input?.value || "").trim();
  let rateOverride;
  if (raw === "") {
    rateOverride = null;
  } else {
    const n = Number(raw);
    if (!Number.isInteger(n) || n < 1 || n > 999) {
      toast("Enter a whole number between 1 and 999, or leave blank");
      return;
    }
    rateOverride = n;
  }
  try {
    const data = await requestJson("/api/settings/rate", { method: "PATCH", body: { rateOverride } });
    state.settings = { rateOverride: data.rateOverride ?? null };
    if (data.rateOverride != null) toast(`Rate updated to $${data.rateOverride}/hr`);
    else toast("Rate cleared — using role-based rates");
    render();
  } catch (error) {
    toast(error.message || "Could not update rate");
  }
}

// PR 17: full-screen mode picker shown when the user clicks "New". Replaces the
// old confirm() guard inside createNewSession — the modal carries the save
// warning instead. Built entirely in JS (no index.html / CSS changes); inline
// hex only, hover handled via JS so no new CSS variables are introduced.
function openDiscoveryModePicker() {
  closeDiscoveryModePicker(); // idempotent — never stack overlays
  const hasContent = sessionHasContent();
  const warning = hasContent
    ? `<div style="color:#8899aa;font-size:13px;margin-bottom:16px;">Your current session will be saved before starting.</div>`
    : "";
  const card = (mode, icon, title, subtitle) => `
    <div data-mode-card="${mode}" role="button" tabindex="0" style="flex:1;min-width:240px;background:#0d1b2e;border:1px solid #1e3350;border-radius:8px;padding:24px;cursor:pointer;transition:border-color 0.15s ease;">
      <div style="font-size:30px;line-height:1;margin-bottom:12px;">${icon}</div>
      <div style="color:#e8f4ff;font-size:16px;font-weight:600;margin-bottom:6px;">${title}</div>
      <div style="color:#8899aa;font-size:13px;line-height:1.5;">${subtitle}</div>
    </div>`;
  const overlay = document.createElement("div");
  overlay.id = "discoveryModePicker";
  overlay.style.cssText = "position:fixed;inset:0;background:#0a1525;display:flex;align-items:center;justify-content:center;z-index:1000;padding:24px;";
  overlay.innerHTML = `
    <div style="background:#162438;border:1px solid #1e3350;border-radius:12px;padding:32px;max-width:760px;width:100%;box-sizing:border-box;">
      <div style="color:#ffffff;font-size:20px;font-weight:600;margin-bottom:16px;">Start a new discovery</div>
      ${warning}
      <div style="display:flex;gap:16px;flex-wrap:wrap;">
        ${card("interview", "🎙️", "Run an interview", "Ask me questions one at a time")}
        ${card("document", "📄", "Analyse a document", "Upload a file and I'll extract the workflow")}
      </div>
      <div style="text-align:center;margin-top:20px;">
        <span data-mode-cancel role="button" tabindex="0" style="color:#8899aa;font-size:13px;cursor:pointer;">Cancel</span>
      </div>
    </div>`;
  overlay.querySelectorAll("[data-mode-card]").forEach((el) => {
    el.addEventListener("mouseenter", () => { el.style.borderColor = "#00d4b4"; });
    el.addEventListener("mouseleave", () => { el.style.borderColor = "#1e3350"; });
    el.addEventListener("click", () => startDiscoveryInMode(el.dataset.modeCard));
  });
  overlay.querySelector("[data-mode-cancel]")?.addEventListener("click", closeDiscoveryModePicker);
  document.body.appendChild(overlay);
}

function closeDiscoveryModePicker() {
  document.getElementById("discoveryModePicker")?.remove();
}

// Picks a mode card: close the overlay, save the current session if it has
// content, then start a fresh session in the chosen appMode.
function startDiscoveryInMode(mode) {
  closeDiscoveryModePicker();
  if (sessionHasContent()) persistState();
  createNewSession({ appMode: mode === "document" ? "document" : "interview" });
}

function createNewSession(options = {}) {
  if (sessionHasContent()) persistState();
  state = structuredClone(defaultState);
  ensureSessionMeta(state, { forceNew: true });
  state.appMode = options.appMode || "analysis";
  state.activeWorkbenchTab = options.activeWorkbenchTab || "library";
  persistState();
  render();
  toast("New discovery session started.");
}

function duplicateCurrentSession() {
  persistState();
  const copy = normalizeLoadedState(structuredClone(state));
  copy.sessionMeta = {
    ...copy.sessionMeta,
    id: makeId("session"),
    name: `Copy of ${state.sessionMeta?.name || deriveSessionName(state)}`,
    source: "Duplicate",
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
  copy.appMode = "analysis";
  copy.activeWorkbenchTab = "library";
  state = copy;
  persistState();
  render();
  toast("Duplicated into a new working session.");
}

async function duplicateSavedSession(id) {
  const entry = getCombinedSessionLibrary().find((item) => item.id === id);
  const savedState = await getSessionStateById(id);
  if (!entry || !savedState) return;
  persistState();
  const copy = normalizeLoadedState(structuredClone(savedState));
  copy.sessionMeta = {
    ...copy.sessionMeta,
    id: makeId("session"),
    name: `Copy of ${entry.name || deriveSessionName(copy)}`,
    source: `Duplicate of ${entry.name || "saved session"}`,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
  copy.appMode = "analysis";
  copy.activeWorkbenchTab = "library";
  state = copy;
  persistState();
  render();
  toast("Saved session duplicated.");
}

async function loadSessionFromLibrary(id) {
  const entry = getCombinedSessionLibrary().find((item) => item.id === id);
  const savedState = await getSessionStateById(id);
  // PR 29 Bug A diagnostic (temporary): log the requested id vs what actually
  // resolved, so we can tell a wrong-fetch from a stale-render. Remove once the
  // root cause is confirmed.
  console.info("[session-load]", {
    requestedId: id,
    clickedName: entry?.name,
    resolved: savedState
      ? {
          sessionId: savedState.sessionMeta?.id,
          idMatchesRequest: savedState.sessionMeta?.id === id,
          metaWorkflowName: savedState.sessionMeta?.workflowName || "",
          gridWorkflowName: savedState.workflowGrid?.workflowName || "",
          gridSteps: savedState.workflowGrid?.steps?.length || 0,
          legacySteps: savedState.steps?.length || 0
        }
      : null
  });
  if (!entry || !savedState) {
    // #4: surface the previously-silent failure instead of leaving the prior
    // session on screen with no feedback.
    toast("Couldn't load that session — its saved data wasn't found.");
    return;
  }
  persistState();
  state = normalizeLoadedState(savedState);
  state.appMode = "analysis";
  state.activeWorkbenchTab = "library";
  persistState();
  render();
  toast(`${entry.name || "Session"} loaded.`);
}

async function deleteSessionFromLibrary(id) {
  const entry = getCombinedSessionLibrary().find((item) => item.id === id);
  if (!entry) return;
  const isCurrent = id === state.sessionMeta?.id;
  const message = isCurrent
    ? "Delete the current saved session and start a new blank intake?"
    : `Delete "${entry.name || "this saved session"}" from the local library?`;
  if (!confirm(message)) return;
  const library = getSessionLibrary().filter((item) => item.id !== id);
  writeSessionLibrary(library);
  try {
    await requestJson(`/api/sessions/${encodeURIComponent(id)}`, { method: "DELETE" });
    serverSessions = serverSessions.filter((item) => item.id !== id);
  } catch (error) {
    console.warn("Could not delete server session", error.message);
  }
  if (isCurrent) {
    state = structuredClone(defaultState);
    ensureSessionMeta(state, { forceNew: true });
    state.appMode = "analysis";
    state.activeWorkbenchTab = "library";
    persistState();
    render();
    toast("Session deleted. New blank intake started.");
    return;
  }
  renderSessionLibrary();
  toast("Saved session deleted.");
}

async function getSessionStateById(id) {
  const local = getSessionLibrary().find((item) => item.id === id);
  if (local?.state) return local.state;
  try {
    const payload = await requestJson(`/api/sessions/${encodeURIComponent(id)}`);
    if (payload.state) {
      const normalized = normalizeLoadedState(payload.state);
      // PR 16: carry the disk-persisted outcome status onto sessionMeta so the
      // Recipe Book pill reflects it after a load.
      if (payload.outcomeStatus) {
        normalized.sessionMeta = normalized.sessionMeta || {};
        normalized.sessionMeta.outcomeStatus = payload.outcomeStatus;
      }
      saveSessionToLibrary(normalized);
      return normalized;
    }
  } catch (error) {
    console.warn("Could not load server session", error.message);
    toast("Could not load that saved session from server files.");
  }
  return null;
}

async function loadSessionFromUrlParam() {
  const params = new URLSearchParams(window.location.search);
  const id = params.get("session");
  if (!id) return false;
  const savedState = await getSessionStateById(id);
  if (!savedState) return false;
  state = normalizeLoadedState(savedState);
  state.appMode = state.appMode || "analysis";
  state.activeWorkbenchTab = state.activeWorkbenchTab || "library";
  persistState();
  window.history.replaceState({}, "", window.location.pathname);
  render();
  toast(`${state.sessionMeta?.name || "Session"} loaded.`);
  return true;
}

